      description: t('builtinSkills.editingRecipesDesc', { ns: 'copilot', defaultValue: 'Common modification operations with code examples (characters, items, documents, regions, etc.)' }),
      content: BUILTIN_EDITING_RECIPES
    },
    {
      id: BUILTIN_SKILL_IDS.ADVANCED_TUNING,
      title: t('builtinSkills.advancedTuningTitle', { ns: 'copilot', defaultValue: '[Built-in] Advanced Tuning' }),
      description: t('builtinSkills.advancedTuningDesc', { ns: 'copilot', defaultValue: 'CustomComponent operations, condition-driven documents, batch modifications' }),
