/**
 * Image Utilities
 *
 * Handles image file reading, compression/resizing, and IndexedDB persistence.
 * Images are stored in IndexedDB (not localStorage) to avoid size limits.
 */

import i18next from 'i18next'
import type { UploadedFile } from './types'

// ============================================================================
// Constants
// ============================================================================

export const IMAGE_EXTENSIONS = ['png', 'jpg', 'jpeg', 'gif', 'webp']
export const IMAGE_ACCEPT = '.png,.jpg,.jpeg,.gif,.webp'

const MAX_DIMENSION = 1536
const MAX_SIZE_BYTES = 5 * 1024 * 1024 // 5MB after compression

const DB_NAME = 'copilot-images'
const DB_VERSION = 1
const STORE_NAME = 'images'

// ============================================================================
// Image Reading & Compression
// ============================================================================

/**
 * Read an image file, optionally resize if too large, and return as UploadedFile.
 */
export async function readImageFile(file: File): Promise<UploadedFile> {
    const originalDataUrl = await fileToDataUrl(file)
    const mimeType = file.type || 'image/png'

    // Load image to get dimensions
    const img = await loadImage(originalDataUrl)
    const { width, height } = img

    let resultDataUrl = originalDataUrl
    let resultSize = file.size

    // Resize if exceeds max dimension
    if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
        const scale = MAX_DIMENSION / Math.max(width, height)
        const newWidth = Math.round(width * scale)
        const newHeight = Math.round(height * scale)

        const canvas = document.createElement('canvas')
        canvas.width = newWidth
        canvas.height = newHeight
        const ctx = canvas.getContext('2d')!
        ctx.drawImage(img, 0, 0, newWidth, newHeight)

        // Use JPEG for photos (smaller), keep PNG for transparency
        const outputType = mimeType === 'image/png' ? 'image/png' : 'image/jpeg'
        const quality = outputType === 'image/jpeg' ? 0.85 : undefined
        resultDataUrl = canvas.toDataURL(outputType, quality)
        resultSize = dataUrlToSize(resultDataUrl)
    }

    // If still too large, try lower quality JPEG
    if (resultSize > MAX_SIZE_BYTES) {
        const canvas = document.createElement('canvas')
        const scale = Math.min(1, MAX_DIMENSION / Math.max(width, height))
        canvas.width = Math.round(width * scale)
        canvas.height = Math.round(height * scale)
        const ctx = canvas.getContext('2d')!
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height)

        for (const q of [0.7, 0.5, 0.3]) {
            resultDataUrl = canvas.toDataURL('image/jpeg', q)
            resultSize = dataUrlToSize(resultDataUrl)
            if (resultSize <= MAX_SIZE_BYTES) break
        }

        if (resultSize > MAX_SIZE_BYTES) {
            throw new Error(i18next.t('common:imageTooLarge', { size: MAX_SIZE_BYTES / 1024 / 1024 }))
        }
    }

    return {
        name: file.name,
        content: '', // Images don't use text content
        type: 'image',
        size: resultSize,
        uploadedAt: Date.now(),
        dataUrl: resultDataUrl,
        mimeType,
    }
}

function fileToDataUrl(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
        const reader = new FileReader()
        reader.onload = () => resolve(reader.result as string)
        reader.onerror = () => reject(reader.error)
        reader.readAsDataURL(file)
    })
}

function loadImage(src: string): Promise<HTMLImageElement> {
    return new Promise((resolve, reject) => {
        const img = new Image()
        img.onload = () => resolve(img)
        img.onerror = () => reject(new Error('Failed to load image'))
        img.src = src
    })
}

function dataUrlToSize(dataUrl: string): number {
    // data:image/...;base64, prefix then base64 data
    const base64 = dataUrl.split(',')[1] || ''
    return Math.ceil(base64.length * 3 / 4)
}

// ============================================================================
// IndexedDB Storage
// ============================================================================

interface StoredImage {
    name: string
    dataUrl: string
    mimeType: string
    size: number
    uploadedAt: number
}

function openDB(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, DB_VERSION)
        request.onerror = () => reject(request.error)
        request.onsuccess = () => resolve(request.result)
        request.onupgradeneeded = (event) => {
            const db = (event.target as IDBOpenDBRequest).result
            if (!db.objectStoreNames.contains(STORE_NAME)) {
                db.createObjectStore(STORE_NAME, { keyPath: 'name' })
            }
        }
    })
}

export async function saveImageToDB(file: UploadedFile): Promise<void> {
    const db = await openDB()
    const tx = db.transaction(STORE_NAME, 'readwrite')
    const store = tx.objectStore(STORE_NAME)
    const record: StoredImage = {
        name: file.name,
        dataUrl: file.dataUrl || '',
        mimeType: file.mimeType || 'image/png',
        size: file.size,
        uploadedAt: file.uploadedAt,
    }
    store.put(record)
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve()
        tx.onerror = () => reject(tx.error)
    })
}

export async function loadAllImagesFromDB(): Promise<UploadedFile[]> {
    try {
        const db = await openDB()
        const tx = db.transaction(STORE_NAME, 'readonly')
        const store = tx.objectStore(STORE_NAME)
        const request = store.getAll()
        return new Promise((resolve, reject) => {
            request.onsuccess = () => {
                const records = request.result as StoredImage[]
                resolve(records.map(r => ({
                    name: r.name,
                    content: '',
                    type: 'image' as const,
                    size: r.size,
                    uploadedAt: r.uploadedAt,
                    dataUrl: r.dataUrl,
                    mimeType: r.mimeType,
                })))
            }
            request.onerror = () => reject(request.error)
        })
    } catch (e) {
        console.error('Failed to load images from IndexedDB:', e)
        return []
    }
}

export async function removeImageFromDB(filename: string): Promise<void> {
    const db = await openDB()
    const tx = db.transaction(STORE_NAME, 'readwrite')
    const store = tx.objectStore(STORE_NAME)
    store.delete(filename)
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve()
        tx.onerror = () => reject(tx.error)
    })
}

export async function clearAllImagesFromDB(): Promise<void> {
    const db = await openDB()
    const tx = db.transaction(STORE_NAME, 'readwrite')
    const store = tx.objectStore(STORE_NAME)
    store.clear()
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve()
        tx.onerror = () => reject(tx.error)
    })
}

/src/api/localSaveStorage.ts:
/**
 * Local Save Storage — IndexedDB-backed with in-memory cache
 *
 * Replaces localStorage for editor local saves.
 * Provides synchronous read API via in-memory cache,
 * with asynchronous persistence to IndexedDB (virtually unlimited storage).
 */

import type { StateData } from './types'

export interface LocalSaveSlot {
  id: string
  name: string
  createdAt: string
  updatedAt: string
  preview?: {
    creaturesCount: number
    regionsCount: number
    organizationsCount: number
  }
}

export interface LocalSavesIndex {
  slots: LocalSaveSlot[]
  lastUsedSlotId?: string
}

// ============================================================================
// IndexedDB constants
// ============================================================================

const DB_NAME = 'local-saves'
const DB_VERSION = 1
const INDEX_STORE = 'index'   // single record keyed by 'main'
const DATA_STORE = 'saves'    // keyed by slotId

// ============================================================================
// In-memory cache
// ============================================================================

let _index: LocalSavesIndex = { slots: [] }
const _dataCache = new Map<string, StateData>()
let _cacheInitialized = false
let _dbInstance: IDBDatabase | null = null
let _initPromise: Promise<void> | null = null

// ============================================================================
// IndexedDB helpers
// ============================================================================

function openDB(): Promise<IDBDatabase> {
  if (_dbInstance) return Promise.resolve(_dbInstance)

  return new Promise<IDBDatabase>((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION)

    request.onupgradeneeded = () => {
      const db = request.result
      if (!db.objectStoreNames.contains(INDEX_STORE)) {
        db.createObjectStore(INDEX_STORE)
      }
      if (!db.objectStoreNames.contains(DATA_STORE)) {
        db.createObjectStore(DATA_STORE)
      }
    }

    request.onsuccess = () => {
      _dbInstance = request.result
      resolve(_dbInstance)
    }

    request.onerror = () => {
      console.error('[LocalSaves] Failed to open IndexedDB:', request.error)
      reject(request.error)
    }
  })
}

function idbGet<T>(storeName: string, key: string): Promise<T | undefined> {
  return openDB().then(db => {
    return new Promise<T | undefined>((resolve, reject) => {
      const tx = db.transaction(storeName, 'readonly')
      const request = tx.objectStore(storeName).get(key)
      request.onsuccess = () => resolve(request.result as T | undefined)
      request.onerror = () => reject(request.error)
    })
  })
}

function idbPut(storeName: string, key: string, value: unknown): void {
  openDB().then(db => {
    const tx = db.transaction(storeName, 'readwrite')
    tx.objectStore(storeName).put(value, key)
  }).catch(e => {
    console.error('[LocalSaves] Failed to persist:', e)
  })
}

function idbDelete(storeName: string, key: string): void {
  openDB().then(db => {
    const tx = db.transaction(storeName, 'readwrite')
    tx.objectStore(storeName).delete(key)
  }).catch(e => {
    console.error('[LocalSaves] Failed to delete:', e)
  })
}

function idbGetAllKeys(storeName: string): Promise<string[]> {
  return openDB().then(db => {
    return new Promise<string[]>((resolve, reject) => {
      const tx = db.transaction(storeName, 'readonly')
      const request = tx.objectStore(storeName).getAllKeys()
      request.onsuccess = () => resolve(request.result as string[])
      request.onerror = () => reject(request.error)
    })
  })
}

// ============================================================================
// Migration from localStorage
// ============================================================================

const LEGACY_SAVES_KEY = 'state-data-editor-local-saves'
const LEGACY_INDEX_KEY = 'state-data-editor-local-saves-index'

function migrateFromLocalStorage(): void {
  try {
    // Migrate index
    const rawIndex = localStorage.getItem(LEGACY_INDEX_KEY)
    if (rawIndex) {
      const index: LocalSavesIndex = JSON.parse(rawIndex)
      _index = index
      idbPut(INDEX_STORE, 'main', index)

      // Migrate each save slot's data
      for (const slot of index.slots) {
        const rawData = localStorage.getItem(`${LEGACY_SAVES_KEY}-${slot.id}`)
        if (rawData) {
          const data = JSON.parse(rawData)
          // Store raw (denormalized) data in IDB, same as was in localStorage
          idbPut(DATA_STORE, slot.id, data)
          // Also populate cache with normalized version
          _dataCache.set(slot.id, data)
        }
      }

      // Clean up localStorage
      localStorage.removeItem(LEGACY_INDEX_KEY)
      for (const slot of index.slots) {
        localStorage.removeItem(`${LEGACY_SAVES_KEY}-${slot.id}`)
      }

      console.log(`[LocalSaves] Migrated ${index.slots.length} saves from localStorage to IndexedDB`)
    }
  } catch (e) {
    console.error('[LocalSaves] localStorage migration failed:', e)
  }
}

// ============================================================================
// Initialization
// ============================================================================

async function loadFromDB(): Promise<void> {
  if (_cacheInitialized) return

  try {
    const db = await openDB()

    // Load index
    const storedIndex = await idbGet<LocalSavesIndex>(INDEX_STORE, 'main')
    if (storedIndex) {
      _index = storedIndex
    }

    // Load all save data into cache
    const keys = await idbGetAllKeys(DATA_STORE)
    for (const key of keys) {
      const raw = await new Promise<unknown>((resolve, reject) => {
        const tx = db.transaction(DATA_STORE, 'readonly')
        const request = tx.objectStore(DATA_STORE).get(key)
        request.onsuccess = () => resolve(request.result)
        request.onerror = () => reject(request.error)
      })
      if (raw) {
        _dataCache.set(key, raw as StateData)
      }
    }

    _cacheInitialized = true

    // If IDB was empty, try migrating from localStorage
    if (!storedIndex) {
      migrateFromLocalStorage()
    }
  } catch (e) {
    console.error('[LocalSaves] Failed to load from IndexedDB:', e)
    // Fallback: try migration
    migrateFromLocalStorage()
    _cacheInitialized = true
  }
}

/**
 * Initialize local save storage. Call once at app startup.
 * Safe to call multiple times — only the first call does work.
 */
export function initLocalSaveStorage(): Promise<void> {
  if (!_initPromise) {
    _initPromise = loadFromDB()
  }
  return _initPromise
}

// ============================================================================
// Public API (synchronous reads, async persistence)
// ============================================================================

export function getLocalSavesIndex(): LocalSavesIndex {
  return _index
}

export function getLocalSaveData(slotId: string): StateData | null {
  return _dataCache.get(slotId) ?? null
}

export function saveLocalSaveData(slotId: string, data: StateData, slotName: string): void {
  // Stamp v2 version flag
  const dataWithVersion = { ...data, _save_version: 'v2' as const }
  // Update data cache & persist
  _dataCache.set(slotId, dataWithVersion)
  idbPut(DATA_STORE, slotId, dataWithVersion)

  // Update index
  const now = new Date().toISOString()
  const preview = {
    creaturesCount: Array.isArray(data.Creatures) ? data.Creatures.length : 0,
    regionsCount: Array.isArray(data.Regions) ? data.Regions.length : 0,
    organizationsCount: Array.isArray(data.Organizations) ? data.Organizations.length : 0,
  }

  const existingIdx = _index.slots.findIndex(s => s.id === slotId)
  if (existingIdx >= 0) {
    _index.slots[existingIdx] = {
      ..._index.slots[existingIdx],
      name: slotName,
      updatedAt: now,
      preview,
    }
  } else {
    _index.slots.push({
      id: slotId,
      name: slotName,
      createdAt: now,
      updatedAt: now,
      preview,
    })
  }

  _index.lastUsedSlotId = slotId
  idbPut(INDEX_STORE, 'main', _index)
}

export function deleteLocalSave(slotId: string): void {
  _dataCache.delete(slotId)
  idbDelete(DATA_STORE, slotId)

  _index.slots = _index.slots.filter(s => s.id !== slotId)
  if (_index.lastUsedSlotId === slotId) {
    _index.lastUsedSlotId = _index.slots[0]?.id
  }
  idbPut(INDEX_STORE, 'main', _index)
}

export function generateSlotId(): string {
  return `slot-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`
}

/src/api/sandboxExecutor.ts:
/**
 * JavaScript 沙箱执行器
 * 
 * 使用 iframe + postMessage 模式实现安全的代码执行环境。
 * 沙箱内代码可以通过 tools 对象调用宿主提供的工具。
 */

import i18next from 'i18next'
import type { SaveMemoryParams } from './types'

// ============================================================================
// 类型定义
// ============================================================================

/**
 * 沙箱工具回调函数
 */
export interface SandboxToolCallbacks {
  getStateContent: (path: string) => Promise<any>
  setStateContent: (path: string, value: any) => Promise<boolean>
  getMemoryContent: (ids: string | string[]) => Promise<string>
  saveMemory: (params: SaveMemoryParams) => Promise<string>
}

/**
 * 执行选项
 */
export interface SandboxExecuteOptions {
  timeout?: number  // 默认 5000ms
  callbacks: SandboxToolCallbacks
}

/**
 * 执行结果
 */
export interface SandboxExecuteResult {
  success: boolean
  result?: any
  logs: string[]
  error?: string
}

/**
 * 来自 iframe 的消息类型
 */
interface SandboxMessage {
  type: 'tool_call' | 'execution_complete' | 'execution_error'
  callId?: string
  toolName?: string
  params?: any
  result?: any
  logs?: string[]
  error?: string
}

// ============================================================================
// 沙箱执行器
// ============================================================================

export class SandboxExecutor {
  private iframe: HTMLIFrameElement | null = null
  private messageHandler: ((event: MessageEvent) => void) | null = null

  /**
   * 执行 JavaScript 代码
   */
  async execute(code: string, options: SandboxExecuteOptions): Promise<SandboxExecuteResult> {
    const timeout = options.timeout || 5000
    
    return new Promise((resolve) => {
      // 创建 iframe
      this.iframe = this.createIframe()
      
      // 设置超时
      const timeoutId = setTimeout(() => {
        this.cleanup()
        resolve({
          success: false,
          logs: [],
          error: i18next.t('common:executionTimeout', { timeout })
        })
      }, timeout)
      
      // 处理来自 iframe 的消息
      this.messageHandler = async (event: MessageEvent) => {
        // 安全检查：只处理来自我们 iframe 的消息
        if (event.source !== this.iframe?.contentWindow) return
        
        const message = event.data as SandboxMessage
        
        if (message.type === 'tool_call') {
          // 处理工具调用
          try {
            let result: any
            
            switch (message.toolName) {
              case 'get_state_content':
                result = await options.callbacks.getStateContent(message.params?.path)
                break
              case 'setStateContent':
                result = await options.callbacks.setStateContent(
                  message.params?.path,
                  message.params?.value
                )
                break
              case 'get_memory_content':
                result = await options.callbacks.getMemoryContent(message.params?.ids)
                break
              case 'save_memory':
                result = await options.callbacks.saveMemory(message.params)
                break
              default:
                throw new Error(i18next.t('common:unknownTool', { name: message.toolName }))
            }
            
            // 返回结果给 iframe
            this.iframe?.contentWindow?.postMessage({
              callId: message.callId,
              result
            }, '*')
          } catch (err) {
            // 返回错误给 iframe
            this.iframe?.contentWindow?.postMessage({
              callId: message.callId,
              error: (err as Error).message
            }, '*')
          }
        } else if (message.type === 'execution_complete') {
          // 执行完成
          clearTimeout(timeoutId)
          this.cleanup()
          resolve({
            success: true,
            result: message.result,
            logs: message.logs || []
          })
        } else if (message.type === 'execution_error') {
          // 执行出错
          clearTimeout(timeoutId)
          this.cleanup()
          resolve({
            success: false,
            logs: message.logs || [],
            error: message.error
          })
        }
      }
      
      window.addEventListener('message', this.messageHandler)
      
      // 注入代码到 iframe
      this.iframe.srcdoc = this.buildSrcdoc(code)
      document.body.appendChild(this.iframe)
    })
  }

  /**
   * 创建隐藏的 iframe
   */
  private createIframe(): HTMLIFrameElement {
    const iframe = document.createElement('iframe')
    iframe.sandbox.add('allow-scripts')
    iframe.style.display = 'none'
    return iframe
  }

  /**
   * 构建 iframe 的 srcdoc
   */
  private buildSrcdoc(userCode: string): string {
    // 转义用户代码中的特殊字符
    const escapedCode = userCode
      .replace(/\\/g, '\\\\')
      .replace(/`/g, '\\`')
      .replace(/\$/g, '\\$')

    return `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
</head>
<body>
<script>
(async function() {
  // 存储待处理的工具调用
  const pendingCalls = new Map();
  
  // 调用宿主工具
  function callParent(toolName, params) {
    return new Promise((resolve, reject) => {
      const callId = Math.random().toString(36).substring(2) + Date.now().toString(36);
      pendingCalls.set(callId, { resolve, reject });
      parent.postMessage({ type: 'tool_call', callId, toolName, params }, '*');
    });
  }
  
  // 监听宿主返回的结果
  window.addEventListener('message', (event) => {
    const { callId, result, error } = event.data;
    if (callId && pendingCalls.has(callId)) {
      const { resolve, reject } = pendingCalls.get(callId);
      pendingCalls.delete(callId);
      if (error) reject(new Error(error));
      else resolve(result);
    }
  });
  
  // 暴露给用户代码的 tools 对象
  const tools = {
    getStateContent: (path) => callParent('get_state_content', { path }),
    setStateContent: (path, value) => callParent('setStateContent', { path, value }),
    getMemory: (ids) => callParent('get_memory_content', { ids }),
    saveMemory: (params) => callParent('save_memory', params),
  };
  
  // 捕获 console.log
  const consoleLogs = [];
  const originalLog = console.log;
  console.log = function(...args) {
    consoleLogs.push(args.map(a => {
      try {
        return typeof a === 'object' ? JSON.stringify(a) : String(a);
      } catch {
        return String(a);
      }
    }).join(' '));
    originalLog.apply(console, args);
  };
  
  // 执行用户代码
  try {
    const userFunction = new Function('tools', \`
      return (async () => {
        \${escapedCode}
      })();
    \`);
    
    const result = await userFunction(tools);
    
    parent.postMessage({
      type: 'execution_complete',
      result: result,
      logs: consoleLogs
    }, '*');
  } catch (err) {
    parent.postMessage({
      type: 'execution_error',
      error: err.message || String(err),
      logs: consoleLogs
    }, '*');
  }
})();
<\/script>
</body>
</html>
    `.trim()
  }

  /**
   * 清理资源
   */
  private cleanup(): void {
    if (this.messageHandler) {
      window.removeEventListener('message', this.messageHandler)
      this.messageHandler = null
    }
    if (this.iframe && this.iframe.parentNode) {
      this.iframe.parentNode.removeChild(this.iframe)
    }
    this.iframe = null
  }

  /**
   * 销毁执行器
   */
  destroy(): void {
    this.cleanup()
  }
}

// 导出单例
export const sandboxExecutor = new SandboxExecutor()

