/** 格式化单条事件变更为可读字符串 */
export function formatEventChange(c: unknown): string {
  if (typeof c === 'string') return c
  if (c && typeof c === 'object' && 'option' in c) {
    const r = c as EventUpdateRecommendation
    return `[${r.option}] event:${r.event_id}: ${r.suggestion}`
  }
  return String(c)
}

