  border: 1px solid rgba(255, 255, 255, 0.08);
  color: var(--paper-text-tertiary);
  font-size: 11px;
  padding: 2px 8px;
  border-radius: var(--paper-radius-md);
  cursor: pointer;
  transition: all 0.15s;
}

.message-action-btn:hover {
  background: rgba(255, 255, 255, 0.1);
  color: var(--paper-text-secondary);
  border-color: rgba(255, 255, 255, 0.15);
}

/* ============================================================================
   Enhanced Code Blocks
   ============================================================================ */

.code-block-wrapper {
  margin: 0.5em 0;
  border-radius: var(--paper-radius-lg);
  border: 1px solid var(--paper-border-color);
  overflow: hidden;
}

.code-block-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 12px;
  background: rgba(0, 0, 0, 0.35);
  border-bottom: 1px solid var(--paper-border-color);
}

.code-block-lang {
  font-size: 11px;
  color: var(--paper-text-tertiary);
  font-family: var(--paper-font-mono);
  text-transform: lowercase;
}

.code-block-copy {
  background: none;
  border: none;
  color: var(--paper-text-tertiary);
  cursor: pointer;
  font-size: 12px;
  padding: 2px 6px;
  border-radius: var(--paper-radius-sm);
  transition: all 0.15s;
}

.code-block-copy:hover {
  background: rgba(255, 255, 255, 0.1);
  color: var(--paper-text-secondary);
}

.code-block-wrapper pre {
  margin: 0;
  padding: var(--paper-space-3);
  background: var(--paper-bg-primary);
  overflow-x: auto;
  border: none;
  border-radius: 0;
}

.code-block-wrapper pre code {
  background: none;
  padding: 0;
  font-size: 0.85em;
  color: var(--paper-text-primary);
  font-family: var(--paper-font-mono);
}

/* Syntax highlighting via CSS - keyword colors for common tokens */
.code-block-wrapper pre code .keyword {
  color: #c792ea;
}

.code-block-wrapper pre code .string {
  color: #c3e88d;
}

.code-block-wrapper pre code .comment {
  color: #546e7a;
  font-style: italic;
}

.code-block-wrapper pre code .number {
  color: #f78c6c;
}

