/* ============================================================================
   API 配置模态框样式 - Dopamine 适配版
   ============================================================================ */

.header-actions {
  display: flex;
  gap: var(--paper-space-2);
  align-items: center;
}

.btn-save-header {
  padding: 6px 16px;
  border: 2px solid rgba(255, 255, 255, 0.1);
  border-radius: var(--paper-radius-md);
  background: var(--paper-electric-blue);
  color: var(--paper-bg-primary);
  cursor: pointer;
  font-size: var(--paper-font-size-sm);
  font-weight: var(--paper-font-weight-bold);
  transition: all var(--paper-transition-fast);
  box-shadow: 0 4px 12px var(--paper-electric-blue-alpha);
}

.btn-save-header:hover {
  background: var(--paper-electric-blue);
  filter: brightness(1.1);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px var(--paper-electric-blue-alpha);
}

.btn-import-export {
  padding: 6px 12px;
  border: 1.5px solid var(--paper-border-color);
  border-radius: var(--paper-radius-md);
  background: var(--paper-bg-secondary);
  color: var(--paper-text-secondary);
  cursor: pointer;
  font-size: var(--paper-font-size-xs);
  transition: all var(--paper-transition-fast);
  font-weight: var(--paper-font-weight-medium);
}

.btn-import-export:hover {
  background: var(--paper-bg-tertiary);
  color: var(--paper-text-primary);
  border-color: var(--paper-electric-blue);
}

/* 模型标签页 - 紧凑横向排列 */
.model-tabs {
  display: flex;
  gap: var(--paper-space-1);
  margin-bottom: var(--paper-space-3);
  background: var(--paper-bg-secondary);
  padding: var(--paper-space-1);
  border-radius: var(--paper-radius-lg);
  border: 1px solid var(--paper-border-color);
}

.model-tab {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--paper-space-1);
  padding: var(--paper-space-2) var(--paper-space-1);
  border: none;
  border-radius: var(--paper-radius-sm);
  background: transparent;
  color: var(--paper-text-tertiary);
  cursor: pointer;
  transition: all var(--paper-transition-fast);
  font-size: var(--paper-font-size-sm);
  font-weight: var(--paper-font-weight-medium);
}

.model-tab:hover {
  background: var(--paper-bg-content);
  color: var(--paper-text-secondary);
}

.model-tab.active {
  background: var(--paper-electric-blue);
  color: var(--paper-bg-primary);
  font-weight: var(--paper-font-weight-bold);
  box-shadow: 0 4px 12px rgba(65, 137, 232, 0.3);
}

.tab-icon {
  font-size: 1rem;
}

.tab-label {
  white-space: nowrap;
}

.model-desc {
  text-align: center;
  color: var(--paper-text-tertiary);
  font-size: var(--paper-font-size-xs);
  margin-bottom: var(--paper-space-3);
}

/* 表单样式 - 紧凑版 */
.config-form {
  display: flex;
  flex-direction: column;
  gap: var(--paper-space-3);
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: var(--paper-space-1);
}

.form-group label {
  color: var(--paper-text-secondary);
  font-size: var(--paper-font-size-xs);
  font-weight: var(--paper-font-weight-bold);
  letter-spacing: 0.02em;
}

.form-group input,
.form-group select {
  padding: 8px 12px;
  border: 1.5px solid var(--paper-border-color);
  border-radius: var(--paper-radius-md);
  background: var(--paper-bg-tertiary);
  color: var(--paper-text-primary);
  font-size: var(--paper-font-size-sm);
  transition: all var(--paper-transition-fast);
  width: 100%;
  box-sizing: border-box;
}

.form-group input:focus,
.form-group select:focus {
  outline: none;
  border-color: var(--paper-electric-blue);
  background: var(--paper-bg-secondary);
  box-shadow: 0 0 0 3px rgba(65, 137, 232, 0.15);
}

.form-group input::placeholder {
  color: var(--paper-text-tertiary);
}

.form-group select {
  cursor: pointer;
}

.form-group select option {
  background: var(--paper-bg-primary);
  color: var(--paper-text-primary);
}

.hint {
  color: var(--paper-text-tertiary);
  font-size: var(--paper-font-size-xs);
}

/* 三列布局 */
.form-row-3 {
  display: grid;
  grid-template-columns: 1.2fr 1fr 1fr;
  gap: 0.75rem;
}

/* 两列布局 */
.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
}

/* 高级选项折叠 */
.advanced-toggle {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0;
  border: none;
  background: transparent;
  color: #718096;
  cursor: pointer;
  font-size: 0.8rem;
  transition: color 0.2s;
}

.advanced-toggle:hover {
  color: #a0aec0;
}

.advanced-options {
  padding: 0.75rem;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 8px;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.advanced-options .hint {
  text-align: center;
  margin-top: 0.25rem;
}

/* 模式切换按钮组 */
.config-mode-toggle {
  display: flex;
  gap: var(--paper-space-1);
  margin-bottom: var(--paper-space-4);
  background: var(--paper-bg-secondary);
  padding: var(--paper-space-1);
  border-radius: var(--paper-radius-lg);
  border: 1px solid var(--paper-border-color);
}

.mode-btn {
  flex: 1;
  padding: 8px 12px;
  border: none;
  border-radius: var(--paper-radius-md);
  background: transparent;
  color: var(--paper-text-tertiary);
  cursor: pointer;
  transition: all var(--paper-transition-fast);
  font-size: var(--paper-font-size-sm);
  font-weight: var(--paper-font-weight-bold);
}

.mode-btn:hover {
  background: var(--paper-bg-content);
  color: var(--paper-text-secondary);
}

.mode-btn.active {
  background: var(--paper-candy-purple);
  color: var(--paper-bg-primary);
  box-shadow: 0 4px 12px rgba(189, 87, 246, 0.3);
}

/* 获取模型按钮行 */
.fetch-models-row {
  display: flex;
  align-items: center;
  gap: var(--paper-space-3);
}

.fetch-btn {
  padding: 8px 16px;
  border: 2px solid rgba(65, 137, 232, 0.3);
  border-radius: var(--paper-radius-md);
  background: rgba(65, 137, 232, 0.1);
  color: var(--paper-electric-blue);
  cursor: pointer;
  font-size: var(--paper-font-size-xs);
  font-weight: var(--paper-font-weight-bold);
  transition: all var(--paper-transition-fast);
  white-space: nowrap;
}

.fetch-btn:hover:not(:disabled) {
  background: rgba(65, 137, 232, 0.2);
  border-color: var(--paper-electric-blue);
  transform: translateY(-1px);
}

.fetch-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.model-count-hint {
  color: #48bb78;
  font-size: 0.75rem;
}

.fetch-error-hint {
  color: #fc8181;
  font-size: 0.75rem;
}

/* 测试连接按钮 */
.fetch-btn.test-btn {
  border-color: rgba(128, 90, 213, 0.4);
  background: rgba(128, 90, 213, 0.15);
  color: #b794f4;
}

.fetch-btn.test-btn:hover:not(:disabled) {
  background: rgba(128, 90, 213, 0.25);
  border-color: rgba(128, 90, 213, 0.6);
}

/* 测试结果 */
.test-results {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  padding: 0.5rem 0.75rem;
  background: rgba(0, 0, 0, 0.15);
  border-radius: 6px;
}

.test-item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.8rem;
  color: #a0aec0;
}

.test-item.success {
  color: #48bb78;
}

.test-item.fail {
  color: #fc8181;
}

