.alert-dialog-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10000;
  animation: fadeIn 0.2s ease-in-out;
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.alert-dialog-content {
  background: white;
  border-radius: 8px;
  padding: 24px;
  min-width: 300px;
  max-width: 500px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
  animation: slideIn 0.2s ease-out;
}

.alert-dialog-content.confirm-dialog {
  min-width: 350px;
}

.alert-dialog-content.choice-dialog {
  min-width: 320px;
  max-width: 400px;
}

@keyframes slideIn {
  from {
    transform: translateY(-20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

.alert-dialog-message {
  font-size: 16px;
  line-height: 1.5;
  color: #333;
  margin-bottom: 20px;
  word-break: break-word;
  white-space: pre-wrap;
}

.alert-dialog-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
}

.alert-dialog-button {
  padding: 8px 24px;
  border: none;
  border-radius: 4px;
  background-color: #1976d2;
  color: white;
  font-size: 14px;
  cursor: pointer;
  transition: background-color 0.2s;
}

.alert-dialog-button:hover {
  background-color: #1565c0;
}

.alert-dialog-button:active {
  background-color: #0d47a1;
}

.alert-dialog-button:focus {
  outline: 2px solid #1976d2;
  outline-offset: 2px;
}

.alert-dialog-button.cancel-button {
  background-color: #f5f5f5;
  color: #333;
}

.alert-dialog-button.cancel-button:hover {
  background-color: #e0e0e0;
}

.alert-dialog-button.cancel-button:active {
  background-color: #d5d5d5;
}

/* Choice Dialog 样式 */
.choice-dialog-title {
  font-size: 18px;
  font-weight: 600;
  color: #333;
  margin-bottom: 16px;
  text-align: center;
}

.choice-dialog-options {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-bottom: 16px;
}

.choice-option-button {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 16px;
  border: 1px solid #e0e0e0;
  border-radius: 8px;
  background: #fafafa;
  cursor: pointer;
  transition: all 0.2s;
  text-align: left;
}

.choice-option-button:hover {
  background: #f0f7ff;
  border-color: #1976d2;
}

.choice-option-button:active {
  background: #e3f2fd;
}

.choice-option-icon {
  font-size: 24px;
  flex-shrink: 0;
}

.choice-option-label {
  font-size: 15px;
  font-weight: 500;
  color: #333;
  flex: 1;
}

.choice-option-desc {
  font-size: 12px;
  color: #666;
  display: block;
  margin-top: 2px;
}

/* Prompt Dialog 样式 */
.alert-dialog-content.prompt-dialog {
  min-width: 350px;
}

.prompt-dialog-input {
  width: 100%;
  padding: 10px 12px;
  font-size: 14px;
  border: 1px solid #e0e0e0;
  border-radius: 4px;
  margin-bottom: 20px;
  box-sizing: border-box;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.prompt-dialog-input:focus {
  outline: none;
  border-color: #1976d2;
  box-shadow: 0 0 0 2px rgba(25, 118, 210, 0.2);
}

.prompt-dialog-input::placeholder {
  color: #999;
}

