import { useTranslation } from 'react-i18next'
import { CreatureEntity, TypeSchema, CreatureAttrField } from '../api/types'
import type { InfoDetailItem } from '../games/components/InfoModal'
import './CreaturePanel.css'

interface CreaturePanelProps {
  creature: CreatureEntity | null
  loading: boolean
  customComponentRegistry?: Map<string, { component_key: string, component_name: string, is_array: boolean, type_schema?: TypeSchema }>
  regionsRegistry: Map<string, { name: string }>
  locationsRegistry: Map<string, { name: string, description?: string }>
  organizationsRegistry: Map<string, { name: string }>
  creaturesRegistry: Map<string, { name: string }>
  attrFields?: CreatureAttrField[]
  onShowInfo: (info: { title: string, description?: string, details?: string[], structuredDetails?: InfoDetailItem[] }) => void
  onShowOrganization?: (organizationId: string) => void
  onShowLocation?: (regionId: string, locationId: string) => void
}

export default function CreaturePanel({
  creature,
  loading,
  customComponentRegistry,
  regionsRegistry,
  locationsRegistry,
  organizationsRegistry,
  creaturesRegistry,
  attrFields,
  onShowInfo,
  onShowOrganization,
  onShowLocation
}: CreaturePanelProps) {
  const { t } = useTranslation('game')

  if (!creature || !creature.Creature) {
    return (
      <div className="novel-player-panel">
        <h2>👤 {t('panel.characterInfo')}</h2>
        <div className="loading-text">
          {loading ? t('panel.loading') : t('panel.noCharacterSelected')}
        </div>
      </div>
    )
  }

  const attrs = creature.Creature
  const isPlayer = creature.is_player

  return (
    <div className="novel-player-panel">
      <h2>
        {isPlayer ? '👤' : '🎭'} {attrs?.name || t('panel.unknown')}
        {isPlayer && <span className="player-badge">{t('panel.playerBadge')}</span>}
      </h2>

      {attrs?.titles && attrs.titles.length > 0 && (
        <div className="player-title">{attrs.titles.join(' · ')}</div>
      )}

      {/* 基本信息 */}
      <div className="info-section">
        <h3>📋 {t('panel.basicInfo')}</h3>
        <div className="basic-info-list">
          {attrs.appearance && (
            <div className="info-item" style={{ borderLeftColor: '#8b5cf6' }}>
              <span className="label">👤 {t('panel.appearance')}</span>
              <div className="value" style={{ marginTop: '0.5rem' }}>{attrs.appearance.body}</div>
              <span className="label" style={{ marginTop: '0.75rem', display: 'block' }}>👔 {t('panel.clothing')}</span>
              <div className="value" style={{ marginTop: '0.5rem' }}>{attrs.appearance.clothing}</div>
            </div>
          )}
          {attrs.goal && (
            <div className="info-item" style={{ borderLeftColor: '#f97316' }}>
              <span className="label">🎯 {t('panel.goal')}</span>
              <div className="value" style={{ marginTop: '0.5rem' }}>{attrs.goal}</div>
            </div>
          )}
          {(attrs.gender || attrs.race) && (
            <div className="info-item" style={{ borderLeftColor: '#10b981' }}>
              {attrs.gender && <div><span className="label">{t('panel.gender')}</span> <strong>{attrs.gender}</strong></div>}
              {attrs.race && <div><span className="label">{t('panel.race')}</span> <strong>{attrs.race}</strong></div>}
            </div>
          )}
          {attrs.emotion && (
            <div className="info-item" style={{ borderLeftColor: '#ec4899' }}>
              <span className="label">💭 {t('panel.emotion')}</span>
              <div className="value" style={{ marginTop: '0.5rem' }}>{typeof attrs.emotion === 'string' ? attrs.emotion : JSON.stringify(attrs.emotion)}</div>
            </div>
          )}
          {attrs?.organization_id && (
            <div className="info-item" style={{ borderLeftColor: '#f59e0b' }}>
              <span className="label">🏛️ {t('panel.organization')}</span>
              <div
                className={onShowOrganization ? "value clickable" : "value"}
                onClick={() => onShowOrganization?.(attrs.organization_id!)}
                style={{ cursor: onShowOrganization ? 'pointer' : 'default', marginTop: '0.5rem' }}
              >
                {organizationsRegistry.get(attrs.organization_id)?.name || attrs.organization_id}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* 已知信息 */}
      {attrs?.known_infos && attrs.known_infos.length > 0 && (
        <div className="info-section">
          <h3>💡 {t('panel.knownInfos')}</h3>
          <div className="known-infos-list">
            {attrs.known_infos.map((info, idx) => (
              <div key={idx} className="known-info-entry">
                {info}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* 基础属性 */}
      {attrs?.attrs && Object.keys(attrs.attrs).length > 0 && (
        <div className="info-section">
          <h3>💪 {t('panel.attributes')}</h3>
          <div className="attributes-grid">
            {(attrFields && attrFields.length > 0
              ? attrFields.filter(f => attrs.attrs[f.field_name] !== undefined)
              : Object.keys(attrs.attrs).map(k => ({ field_name: k, hint: k, field_display_name: undefined as string | undefined }))
            ).map(f => (
              <div
                key={f.field_name}
                className="attr-item clickable"
                onClick={() => onShowInfo({
                  title: `💪 ${f.field_display_name || f.hint}`,
                  description: f.hint,
                  details: [
                    `${t('panel.currentValue')}: ${attrs.attrs[f.field_name]}`,
                    ...(f.field_display_name ? [`${t('panel.fieldName')}: ${f.field_name}`] : [])
                  ]
                })}
                style={{ cursor: 'pointer' }}
              >
                <span className="attr-label">{f.field_display_name || f.hint}</span>
                <span className="attr-value">{attrs.attrs[f.field_name]}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* 背包 */}
      {creature.Inventory?.items && creature.Inventory.items.length > 0 && (
        <div className="info-section">
          <h3>🎒 {t('panel.inventory')}</h3>
          <div className="inventory-list">
            {creature.Inventory.items.map((item, idx) => {
              const displayName = item.name || item.id
              const hasDetails = item.description || (item.details && item.details.length > 0)

              return (
                <div
                  key={idx}
                  className={hasDetails ? "inventory-item clickable" : "inventory-item"}
                  onClick={() => {
                    if (hasDetails) {
                      onShowInfo({
                        title: t('panel.itemTitle', { name: displayName }),
                        description: item.description,
                        details: item.details
                      })
                    }
                  }}
                  style={{ cursor: hasDetails ? 'pointer' : 'default' }}
                >
                  <span className="item-name">{item.equipped ? '🛡️' : '📦'} {displayName}</span>
                  <span className="item-count">×{item.count}</span>
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* 状态效果 */}
      {creature.StatusEffects?.status_effects && creature.StatusEffects.status_effects.length > 0 && (
        <div className="info-section">
          <h3>✨ {t('panel.statusEffects')}</h3>
          <div className="statuses-list">
            {creature.StatusEffects.status_effects.map((effect, idx) => {
              // 格式化 data 显示
              const displayData = effect.data !== undefined
                ? (typeof effect.data === 'object'
                    ? JSON.stringify(effect.data, null, 2)
                    : String(effect.data))
                : undefined

              return (
                <div
                  key={idx}
                  className="status-item clickable"
                  onClick={() => {
                    onShowInfo({
                      title: t('panel.statusEffectTitle', { name: effect.display_name || effect.instance_id }),
                      description: effect.remark,
                      details: [
                        ...(effect.add_at ? [t('panel.addedAt', { time: effect.add_at })] : []),
                        ...(effect.last_update_at ? [t('panel.lastUpdatedAt', { time: effect.last_update_at })] : []),
                        ...(displayData ? [t('panel.statusData', { data: displayData })] : [])
                      ]
                    })
                  }}
                  style={{ cursor: 'pointer' }}
                >
                  <span className="status-name">{effect.display_name || effect.instance_id}</span>
                  {effect.data !== undefined && (
                    <span className="status-value">
                      {typeof effect.data === 'object' ? '📋' : effect.data}
                    </span>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* 自定义组件 */}
      {creature.CustomComponents?.custom_components && creature.CustomComponents.custom_components.length > 0 && (
        <div className="info-section">
          <h3>🧩 {t('panel.customComponents')}</h3>
          <div className="custom-components-list">
            {creature.CustomComponents.custom_components.map((comp, idx) => {
              const regInfo = customComponentRegistry?.get(comp.component_key)
              const displayName = regInfo?.component_name || comp.component_key
              const schema = regInfo?.type_schema
              const isArray = regInfo?.is_array ?? false

              // 生成简短预览（面板内显示）
              const getPreview = (data: any): string => {
                if (data === null || data === undefined) return t('panel.noData')
                if (Array.isArray(data)) return t('panel.itemCount', { count: data.length })
                if (typeof data === 'object') {
                  const keys = Object.keys(data)
                  if (keys.length <= 2) return keys.map(k => `${k}: ${typeof data[k] === 'object' ? '...' : data[k]}`).join(', ')
                  return t('panel.fieldCount', { count: keys.length })
                }
                return String(data)
              }

              // 递归展平嵌套值为结构化详情行
              const flattenValue = (key: string, value: any, description?: string, depth = 0): InfoDetailItem[] => {
                if (value === null || value === undefined) {
                  return [{ fieldKey: key, label: description || key, value: '—' }]
                }
                if (Array.isArray(value)) {
                  if (value.length === 0) return [{ fieldKey: key, label: description || key, value: '—' }]
                  // 简单类型数组：合并为一行逗号分隔
                  if (value.every(v => typeof v !== 'object' || v === null)) {
                    return [{ fieldKey: key, label: description || key, value: value.map(v => String(v ?? '—')).join('、') }]
                  }
                  // 复杂数组：每个元素展开
                  const header: InfoDetailItem = { label: description || key, value: '', separator: true }
                  const items = value.flatMap((item, i) => {
                    const sep: InfoDetailItem = { label: `#${i + 1}`, value: '', separator: true }
                    if (typeof item === 'object' && item !== null) {
                      const rows = Object.entries(item).flatMap(([k, v]) => flattenValue(k, v, undefined, depth + 1))
                      return [sep, ...rows]
                    }
                    return [{ label: `#${i + 1}`, value: String(item) }]
                  })
                  return [header, ...items]
                }
                if (typeof value === 'object') {
                  if (depth > 0) {
                    const header: InfoDetailItem = { label: description || key, value: '', separator: true }
                    const rows = Object.entries(value).flatMap(([k, v]) => flattenValue(k, v, undefined, depth + 1))
                    return [header, ...rows]
                  }
                  return Object.entries(value).flatMap(([k, v]) => flattenValue(k, v, undefined, depth + 1))
                }
                return [{ fieldKey: key, label: description || key, value: String(value) }]
              }

              // 用 schema 生成结构化详情行（模态框内显示）
              const getStructuredDetails = (): InfoDetailItem[] => {
                const data = comp.data
                if (data === null || data === undefined) return [{ label: t('panel.noData'), value: '—' }]

                if (isArray && Array.isArray(data)) {
                  const itemSchema = schema?.items
                  return data.flatMap((item, i) => {
                    const separator: InfoDetailItem = { label: `#${i + 1}`, value: '', separator: true }
                    if (typeof item === 'object' && item !== null) {
                      const rows: InfoDetailItem[] = Object.entries(item).flatMap(([k, v]) => {
                        const desc = itemSchema?.properties?.[k]?.description
                        return flattenValue(k, v, desc || k)
                      })
                      return [separator, ...rows]
                    }
                    return [separator, { label: t('panel.value'), value: String(item) }]
                  })
                }

                if (typeof data === 'object' && !Array.isArray(data)) {
                  return Object.entries(data).flatMap(([k, v]) => {
                    const desc = schema?.properties?.[k]?.description
                    return flattenValue(k, v, desc || k)
                  })
                }

                return [{ label: t('panel.value'), value: String(data) }]
              }

              return (
                <div
                  key={idx}
                  className="custom-component-item"
                  onClick={() => {
                    onShowInfo({
                      title: `🧩 ${displayName}`,
                      description: isArray ? t('panel.listComponent', { count: Array.isArray(comp.data) ? comp.data.length : 0 }) : schema?.description,
                      structuredDetails: getStructuredDetails()
                    })
                  }}
                >
                  <span className="component-name">{displayName}</span>
                  <span className="component-preview">{getPreview(comp.data)}</span>
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* 关系 */}
      {creature.Relationship?.relationships && creature.Relationship.relationships.length > 0 && (
        <div className="info-section">
          <h3>💕 {t('panel.relationships')}</h3>
          <div className="relationships-list">
            {creature.Relationship.relationships.map((rel, idx) => {
              const targetName = creaturesRegistry.get(rel.target_creature_id)?.name || rel.target_creature_id
              return (
                <div key={idx} className="rel-item">
                  <span className="rel-target">{targetName}</span>
                  <span className="rel-name-value">{rel.name}( {rel.value})</span>
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* 位置 */}
      {creature.LocationRef && (
        <div className="info-section">
          <h3>📍 {t('panel.location')}</h3>
          <div className="location-info">
            <div
              className="location-combined clickable"
              onClick={() => {
                if (onShowLocation) {
                  onShowLocation(creature.LocationRef!.region_id, creature.LocationRef!.location_id)
                }
              }}
              style={{ cursor: onShowLocation ? 'pointer' : 'default' }}
            >
              <span className="location-label">{t('panel.regionLabel')}</span>
              <span className="location-value">
                {regionsRegistry.get(creature.LocationRef.region_id)?.name || creature.LocationRef.region_id}
              </span>
              <span className="location-separator">·</span>
              <span className="location-label">{t('panel.locationLabel')}</span>
              <span className="location-value">
                {locationsRegistry.get(creature.LocationRef.location_id)?.name || creature.LocationRef.location_id}
              </span>
            </div>
          </div>
        </div>
      )}

      {/* 日志 */}
      {creature.Log?.entries && creature.Log.entries.length > 0 && (
        <div className="info-section">
          <h3>📜 {t('panel.log')}</h3>
          <div className="creature-log">
            {creature.Log.entries.slice(-10).map((entry, idx) => (
              <div key={idx} className="log-entry">
                <div className="log-time">{entry.add_at}</div>
                <div className="log-content">{entry.content}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* 设定文档 */}
      {creature.BindSetting?.documents && creature.BindSetting.documents.length > 0 && (
        <div className="info-section">
          <h3>📚 {t('panel.settingDocs')}</h3>
          <div className="setting-docs-list">
            {creature.BindSetting.documents.map((doc, idx) => (
              <div
                key={idx}
                className={`setting-doc-item${doc.disable ? ' disabled' : ''}`}
                onClick={() => !doc.disable && onShowInfo({ title: `📄 ${doc.name}`, description: doc.content })}
              >
                <span className="setting-doc-name">{doc.name}</span>
                {doc.disable && <span className="setting-doc-badge disabled">{t('panel.disabled')}</span>}
                {doc.static_priority !== undefined && !doc.disable && (
                  <span className="setting-doc-badge priority">P{doc.static_priority}</span>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )

}

/src/components/GameInitEditor.css:
/* ============================================================================
   游戏初始化编辑器样式 - Modern Theme
   使用设计系统变量 (variables.css)
   ============================================================================ */

/* 外层 wrapper - 包含编辑器和 Copilot 面板 */
.game-init-editor-wrapper {
  display: flex;
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: var(--bg-primary);
}

.game-init-editor {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  height: 100%;
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-sans);
  overflow: hidden;
  transition: flex var(--transition-slow);
}

/* 当 Copilot 展开时的主编辑器 - 预留扩展 */

/* ========== 头部 ========== */
.editor-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-3) var(--spacing-6);
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border-bottom: 1px solid var(--border-color);
  flex-shrink: 0;
  height: var(--header-height);
}

.editor-header h2 {
  margin: 0;
  font-size: var(--font-size-xl);
  font-weight: var(--font-weight-semibold);
  color: var(--accent-primary);
  letter-spacing: var(--letter-spacing-tight);
}

/* ========== 工具栏 ========== */
.toolbar {
  display: flex;
  gap: var(--spacing-2);
  align-items: center;
}

/* 基础按钮 */
.btn-toolbar {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-2);
  padding: var(--spacing-2) var(--spacing-4);
  border: 1px solid transparent;
  border-radius: var(--radius-lg);
  background: var(--bg-secondary);
  color: var(--text-primary);
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-medium);
  cursor: pointer;
  transition: all var(--transition-fast);
  white-space: nowrap;
}

.btn-toolbar:hover:not(:disabled) {
  background: var(--bg-tertiary);
  border-color: var(--border-color-hover);
  transform: translateY(-1px);
}

.btn-toolbar:active:not(:disabled) {
  transform: translateY(0);
}

.btn-toolbar:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ========== 下拉菜单 ========== */
.dropdown-menu {
  position: relative;
  display: inline-block;
}

.dropdown-content {
  position: absolute;
  top: 100%;
  left: 0;
  margin-top: var(--spacing-1);
  min-width: 200px;
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  z-index: var(--z-dropdown);
  overflow: hidden;
  animation: dropdownFadeIn var(--transition-fast);
}

@keyframes dropdownFadeIn {
  from {
    opacity: 0;
    transform: translateY(-4px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.dropdown-content button {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  padding: var(--spacing-3) var(--spacing-4);
  border: none;
  background: transparent;
  color: var(--text-primary);
  text-align: left;
  cursor: pointer;
  font-size: var(--font-size-sm);
  transition: background var(--transition-fast);
}

.dropdown-content button:hover:not(:disabled) {
  background: var(--accent-blue-alpha);
}

.dropdown-content button:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.dropdown-content button.danger:hover {
  background: var(--accent-red-alpha);
  color: var(--accent-red);
}

.dropdown-content .shortcut {
  font-size: var(--font-size-xs);
  color: var(--text-tertiary);
  margin-left: var(--spacing-4);
  font-family: var(--font-mono);
}

.dropdown-divider {
  height: 1px;
  background: var(--border-color);
  margin: var(--spacing-1) 0;
}

/* ========== 按钮变体 ========== */
.btn-toolbar.btn-primary {
  background: linear-gradient(135deg, var(--accent-blue) 0%, #1d4ed8 100%);
  color: white;
  font-weight: var(--font-weight-semibold);
  border: none;
}

.btn-toolbar.btn-primary:hover:not(:disabled) {
  background: linear-gradient(135deg, #60a5fa 0%, var(--accent-blue) 100%);
  box-shadow: var(--shadow-glow-blue);
}

.btn-toolbar.btn-success {
  background: var(--accent-green);
  color: white;
  border: none;
}

.btn-toolbar.btn-success:hover:not(:disabled) {
  background: #34d399;
  box-shadow: 0 0 15px var(--accent-green-alpha);
}

.btn-toolbar.btn-game {
  background: linear-gradient(135deg, var(--accent-purple) 0%, #7c3aed 100%);
  color: white;
  font-weight: var(--font-weight-semibold);
  border: none;
}

.btn-toolbar.btn-game:hover:not(:disabled) {
  background: linear-gradient(135deg, #a78bfa 0%, var(--accent-purple) 100%);
  box-shadow: 0 0 20px var(--accent-purple-alpha);
  transform: translateY(-2px);
}

.btn-toolbar.btn-ai {
  background: linear-gradient(135deg, #f472b6 0%, #ec4899 100%);
  color: white;
  font-weight: var(--font-weight-semibold);
  border: none;
}

.btn-toolbar.btn-ai:hover:not(:disabled) {
  background: linear-gradient(135deg, #f9a8d4 0%, #f472b6 100%);
  box-shadow: 0 0 20px rgba(236, 72, 153, 0.3);
}

.btn-toolbar.btn-danger {
  background: var(--accent-red);
  color: white;
  border: none;
}

.btn-toolbar.btn-danger:hover:not(:disabled) {
  background: #f87171;
  box-shadow: 0 0 15px var(--accent-red-alpha);
}

.btn-toolbar.btn-settings {
  background: linear-gradient(135deg, var(--accent-primary) 0%, #d97706 100%);
  color: var(--text-inverse);
  border: none;
}

.btn-toolbar.btn-settings:hover:not(:disabled) {
  background: linear-gradient(135deg, #fbbf24 0%, var(--accent-primary) 100%);
  box-shadow: var(--shadow-glow-primary);
}

/* ========== 标签页导航 ========== */
.editor-tabs {
  display: flex;
  gap: var(--spacing-1);
  padding: var(--spacing-2) var(--spacing-4);
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  flex-wrap: wrap;
  flex-shrink: 0;
}

.tab-btn {
  position: relative;
  padding: var(--spacing-2) var(--spacing-4);
  border: none;
  border-radius: var(--radius-md) var(--radius-md) 0 0;
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-medium);
  transition: all var(--transition-fast);
}

.tab-btn:hover {
  background: var(--bg-tertiary);
  color: var(--text-primary);
}

.tab-btn.active {
  background: var(--bg-primary);
  color: var(--accent-primary);
  font-weight: var(--font-weight-semibold);
}

.tab-btn.active::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: var(--accent-primary);
  border-radius: var(--radius-full);
}

/* ========== 内容区域 ========== */
.editor-content {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: var(--spacing-6);
  background: var(--bg-primary);
}

/* ========== 编辑器区块 ========== */
.editor-section {
  margin-bottom: var(--spacing-8);
}

.editor-section h3 {
  margin: 0 0 var(--spacing-4);
  padding-bottom: var(--spacing-2);
  border-bottom: 2px solid var(--accent-primary);
  color: var(--accent-primary);
  font-size: var(--font-size-lg);
  font-weight: var(--font-weight-semibold);
  letter-spacing: var(--letter-spacing-tight);
}

/* ========== 表单网格 ========== */
.form-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-4);
}

@media (max-width: 768px) {
  .form-grid {
    grid-template-columns: 1fr;
  }
}

.form-grid.compact {
  display: grid;
  grid-template-columns: minmax(150px, 200px) 1fr auto;
  gap: var(--spacing-2);
  align-items: center;
}

/* ========== 表单组 ========== */
.form-group {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-1);
}

.form-group.full-width {
  grid-column: 1 / -1;
}

.form-group.flex-grow {
  flex: 1;
}

.form-group label {
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  font-weight: var(--font-weight-medium);
}

/* 输入框基础样式 */
.form-group input,
.form-group select,
.form-group textarea {
  padding: var(--spacing-3);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  background: var(--bg-secondary);
  color: var(--text-primary);
  font-size: var(--font-size-sm);
  transition: all var(--transition-fast);
}

.form-group input,
.form-group select {
  word-break: break-all;
  overflow: hidden;
  text-overflow: ellipsis;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  outline: none;
  border-color: var(--accent-blue);
  box-shadow: 0 0 0 3px var(--accent-blue-alpha);
}

.form-group input:hover:not(:focus),
.form-group select:hover:not(:focus),
.form-group textarea:hover:not(:focus) {
  border-color: var(--border-color-hover);
}

.form-group textarea {
  min-height: 80px;
  resize: vertical;
  overflow-y: auto;
  overflow-x: hidden;
  word-wrap: break-word;
  white-space: pre-wrap;
}

/* 全宽文本域 */
.full-textarea {
  width: 100%;
  min-height: 120px;
  padding: var(--spacing-3);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  background: var(--bg-secondary);
  color: var(--text-primary);
  font-size: var(--font-size-sm);
  resize: vertical;
  transition: all var(--transition-fast);
}

.full-textarea:focus {
  outline: none;
  border-color: var(--accent-blue);
  box-shadow: 0 0 0 3px var(--accent-blue-alpha);
}

.full-textarea:hover:not(:focus) {
  border-color: var(--border-color-hover);
}

/* ============================================================================
   列表项和卡片样式
   ============================================================================ */

/* 列表项容器 */
.list-items {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-4);
}

/* 列表项卡片头部 */
.list-item .item-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  margin-bottom: var(--spacing-4);
  flex-wrap: wrap;
}

.list-item .item-header label {
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  font-weight: var(--font-weight-semibold);
  flex-shrink: 0;
}

.list-item .item-header input[type="text"] {
  flex: 1;
  min-width: 200px;
  padding: var(--spacing-2) var(--spacing-3);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  background: var(--bg-tertiary);
  color: var(--accent-primary);
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-medium);
  transition: all var(--transition-fast);
}

.list-item .item-header input[type="text"]:focus {
  outline: none;
  border-color: var(--accent-blue);
  background: var(--bg-secondary);
  box-shadow: 0 0 0 3px var(--accent-blue-alpha);
}

.list-item .item-header input[type="text"]::placeholder {
  color: var(--text-tertiary);
}

/* 列表项 body 区域 */
.list-item .item-body {
  margin-top: var(--spacing-3);
}

.list-item .item-body label {
  display: block;
  margin-bottom: var(--spacing-2);
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  font-weight: var(--font-weight-semibold);
}

.list-item .item-body textarea {
  width: 100%;
  min-height: 150px;
  padding: var(--spacing-3);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  background: var(--bg-secondary);
  color: var(--text-primary);
  font-size: var(--font-size-sm);
  line-height: var(--line-height-relaxed);
  resize: vertical;
  font-family: var(--font-mono);
  transition: all var(--transition-fast);
  box-sizing: border-box;
  overflow-y: auto;
  overflow-x: hidden;
  word-wrap: break-word;
  white-space: pre-wrap;
}

.list-item .item-body textarea:focus {
  outline: none;
  border-color: var(--accent-blue);
  background: var(--bg-tertiary);
  box-shadow: 0 0 0 3px var(--accent-blue-alpha);
}

.list-item .item-body textarea:hover:not(:focus) {
  border-color: var(--border-color-hover);
}

.list-item .item-body textarea::placeholder {
  color: var(--text-tertiary);
  font-style: italic;
}

/* ========== 空状态提示 ========== */
.list-items .empty-state {
  padding: var(--spacing-12) var(--spacing-4);
  text-align: center;
  color: var(--text-tertiary);
  background: var(--bg-secondary);
  border: 2px dashed var(--border-color-hover);
  border-radius: var(--radius-xl);
}

.list-items .empty-state p {
  margin: var(--spacing-2) 0;
}

.list-items .empty-state p:first-child {
  font-size: var(--font-size-base);
  color: var(--text-secondary);
  font-weight: var(--font-weight-medium);
}

.list-items .empty-state .hint {
  font-size: var(--font-size-sm);
  color: var(--text-tertiary);
}

/* ========== 字段提示 ========== */
.field-hint {
  margin: var(--spacing-2) 0 var(--spacing-4) 0;
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  line-height: var(--line-height-normal);
}

.key-input {
  flex: 1;
  padding: var(--spacing-2) var(--spacing-3);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  background: var(--bg-secondary);
  color: var(--accent-primary);
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-semibold);
}

/* ========== 列表编辑器 ========== */
.list-editor {
  background: var(--bg-secondary);
  border-radius: var(--radius-xl);
  padding: var(--spacing-4);
  margin-bottom: var(--spacing-6);
  border: 1px solid var(--border-color);
}

.list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-4);
}

.list-header h4 {
  margin: 0;
  color: var(--text-secondary);
  font-size: var(--font-size-base);
  font-weight: var(--font-weight-medium);
}

.btn-group {
  display: flex;
  gap: var(--spacing-2);
}

/* 添加按钮 */
.btn-add {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-1);
  padding: var(--spacing-2) var(--spacing-3);
  border: none;
  border-radius: var(--radius-lg);
  background: var(--accent-green);
  color: white;
  cursor: pointer;
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-medium);
  transition: all var(--transition-fast);
}

.btn-add:hover {
  background: #34d399;
  transform: translateY(-1px);
  box-shadow: 0 4px 12px var(--accent-green-alpha);
}

/* ========== 列表项卡片 ========== */
.list-item {
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-xl);
  padding: var(--spacing-4);
  margin-bottom: var(--spacing-3);
  transition: all var(--transition-fast);
}

.list-item:hover {
  border-color: var(--border-color-hover);
}

.list-item.collapsible {
  padding: 0;
}

.list-item.collapsible .item-header {
  padding: var(--spacing-3) var(--spacing-4);
  margin-bottom: 0;
  cursor: pointer;
  transition: background var(--transition-fast);
  border-radius: var(--radius-xl);
  user-select: none;
}

.list-item.collapsible .item-header:hover {
  background: var(--bg-tertiary);
}

.list-item.collapsible> :not(.item-header) {
  padding: 0 var(--spacing-4) var(--spacing-4) var(--spacing-4);
}

/* 特殊卡片变体 */
.list-item.player-item {
  border-color: var(--accent-primary);
  box-shadow: 0 0 15px var(--accent-primary-alpha);
}

.list-item.region-item {
  border-left: 3px solid var(--accent-green);
}

.list-item.relationship-item {
  border-left: 3px solid #f472b6;
}

.list-item.entry-item {
  padding: var(--spacing-2);
}

/* Item Header */
.item-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-3);
  gap: var(--spacing-2);
}

.item-header-actions {
  display: flex;
  gap: var(--spacing-2);
  align-items: center;
}

/* 折叠按钮 */
.btn-collapse {
  width: 24px;
  height: 24px;
  padding: 0;
  border: none;
  background: var(--bg-tertiary);
  color: var(--text-secondary);
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-size: var(--font-size-xs);
  transition: all var(--transition-fast);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.btn-collapse:hover {
  background: var(--accent-blue-alpha);
  color: var(--accent-blue);
}

/* Item Title */
.item-title {
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  flex: 1;
}

/* Player Badge */
.player-badge {
  background: var(--accent-primary);
  color: var(--text-inverse);
  padding: var(--spacing-1) var(--spacing-2);
  border-radius: var(--radius-full);
  font-size: var(--font-size-xs);
  font-weight: var(--font-weight-bold);
}

/* 删除按钮 */
.btn-remove {
  width: 28px;
  height: 28px;
  border: none;
  border-radius: var(--radius-full);
  background: var(--accent-red);
  color: white;
  cursor: pointer;
  font-size: var(--font-size-lg);
  font-weight: var(--font-weight-bold);
  line-height: 1;
  transition: all var(--transition-fast);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
}

.btn-remove:hover {
  background: #f87171;
  transform: scale(1.1);
  box-shadow: 0 4px 12px var(--accent-red-alpha);
}

/* ========== 子列表 ========== */
.sub-list {
  background: var(--bg-tertiary);
  border-radius: var(--radius-lg);
  padding: var(--spacing-3);
  margin-top: var(--spacing-4);
}

.sub-list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-2);
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
}

.btn-add-small {
  padding: var(--spacing-1) var(--spacing-2);
  border: none;
  border-radius: var(--radius-sm);
  background: var(--bg-secondary);
  color: var(--text-primary);
  cursor: pointer;
  font-size: var(--font-size-xs);
  transition: all var(--transition-fast);
}

.btn-add-small:hover {
  background: var(--accent-blue-alpha);
  color: var(--accent-blue);
}

.sub-item {
  background: var(--bg-secondary);
  border-radius: var(--radius-sm);
  padding: var(--spacing-2);
  margin-bottom: var(--spacing-2);
}

.sub-item:last-child {
  margin-bottom: 0;
}

.btn-remove-small {
  width: 128px;
  height: 24px;
  border: none;
  border-radius: var(--radius-sm);
  background: var(--accent-red);
  color: white;
  cursor: pointer;
  font-size: var(--font-size-base);
  font-weight: var(--font-weight-bold);
  line-height: 1;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  transition: all var(--transition-fast);
}

.btn-remove-small:hover {
  background: #f87171;
}

/* ========== 属性编辑器 ========== */
.attrs-editor {
  margin-top: var(--spacing-4);
}

.attrs-editor>label {
  display: block;
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  margin-bottom: var(--spacing-2);
}

.attrs-grid {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: var(--spacing-2);
}

.attr-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  background: var(--bg-tertiary);
  border-radius: var(--radius-lg);
  padding: var(--spacing-2);
}

.attr-label {
  font-size: var(--font-size-xs);
  color: var(--accent-primary);
  font-weight: var(--font-weight-bold);
  margin-bottom: var(--spacing-1);
}

.attr-item input {
  width: 100%;
  padding: var(--spacing-1);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  background: var(--bg-secondary);
  color: var(--text-primary);
  text-align: center;
  font-size: 0.9rem;
}

/* ========== 玩家状态列表 ========== */
.player-state-list {
  background: var(--accent-primary-alpha);
  border: 1px dashed var(--accent-primary);
}

.state-item {
  background: var(--bg-secondary);
}

/* 空提示 */
.empty-hint {
  text-align: center;
  padding: var(--spacing-8);
  color: var(--text-tertiary);
  font-style: italic;
}

/* ========== 树形编辑器 ========== */
.tree-editor {
  padding: var(--spacing-2) 0;
}

.tree-node {
  background: var(--bg-secondary);
  border-left: 2px solid var(--border-color-hover);
  border-radius: var(--radius-sm);
  padding: var(--spacing-3);
  margin-bottom: var(--spacing-3);
  transition: border-color var(--transition-fast);
}

.tree-node:hover {
  border-left-color: var(--accent-primary);
}

.tree-node-parent {
  background: var(--accent-primary-alpha);
  border-left-color: var(--accent-primary);
  padding: var(--spacing-2) var(--spacing-3);
}

.tree-node-parent:hover {
  border-left-color: var(--accent-primary);
  background: rgba(245, 158, 11, 0.08);
}

.tree-node-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  margin-bottom: var(--spacing-2);
}

.tree-node-indent {
  color: var(--text-tertiary);
  font-family: var(--font-mono);
  flex-shrink: 0;
}

.tree-node-name-input {
  flex: 1;
  padding: var(--spacing-2) var(--spacing-3);
  border: 1px solid var(--accent-primary-alpha);
  border-radius: var(--radius-sm);
  background: var(--accent-primary-alpha);
  color: var(--accent-primary);
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-semibold);
  font-family: var(--font-mono);
  transition: all var(--transition-fast);
}

.tree-node-name-input:hover {
  border-color: var(--accent-primary);
  background: rgba(245, 158, 11, 0.12);
}

.tree-node-name-input:focus {
  outline: none;
  border-color: var(--accent-primary);
  background: rgba(245, 158, 11, 0.15);
  box-shadow: 0 0 0 3px var(--accent-primary-alpha);
}

.tree-node-path-static {
  flex: 1;
  color: var(--accent-primary);
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-semibold);
  font-family: var(--font-mono);
  padding: var(--spacing-2) var(--spacing-3);
}

.tree-node-path {
  font-weight: var(--font-weight-bold);
  color: var(--accent-primary);
  font-size: var(--font-size-sm);
  font-family: var(--font-mono);
}

.tree-node-actions {
  display: flex;
  gap: var(--spacing-1);
  flex-shrink: 0;
}

.tree-node-content {
  width: 100%;
  min-height: 80px;
  padding: var(--spacing-3);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  background: var(--bg-tertiary);
  color: var(--text-primary);
  font-size: var(--font-size-sm);
  resize: vertical;
  font-family: inherit;
  transition: all var(--transition-fast);
}

.tree-node-content:focus {
  outline: none;
  border-color: var(--accent-blue);
  box-shadow: 0 0 0 3px var(--accent-blue-alpha);
}

.tree-children {
  margin-top: 0.5rem;
  padding-left: 0.5rem;
}

/* 设定文档左右分栏布局 */
.setting-docs-split-container {
  display: flex;
  gap: 0;
  height: 600px;
  border: 1px solid #4a5568;
  border-radius: 6px;
  overflow: hidden;
  background: rgba(26, 26, 46, 0.3);
}

/* 左侧导航树 */
.setting-docs-nav {
  width: 300px;
  flex-shrink: 0;
  background: rgba(22, 33, 62, 0.5);
  border-right: 1px solid #4a5568;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.nav-header {
  padding: 0.75rem 1rem;
  background: rgba(45, 55, 72, 0.6);
  border-bottom: 1px solid #4a5568;
  color: #f8d56b;
  font-size: 0.9rem;
  flex-shrink: 0;
}

.nav-tree {
  flex: 1;
  overflow-y: auto;
  padding: 0.5rem;
}

/* 导航节点样式 */
.nav-node {
  margin-bottom: 0.25rem;
}

.nav-node-item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0.75rem;
  cursor: pointer;
  border-radius: 4px;
  transition: all 0.15s;
  font-size: 0.9rem;
  color: #cbd5e0;
  position: relative;
}

.nav-node-item:hover {
  background: rgba(74, 85, 104, 0.4);
  color: #e2e8f0;
}

.nav-node-item:hover .nav-node-actions {
  opacity: 1;
}

.nav-node-item.selected {
  background: rgba(74, 144, 217, 0.3);
  color: #f8d56b;
  font-weight: 500;
  box-shadow: inset 3px 0 0 #4a90d9;
}

.nav-node-item.branch {
  font-weight: 500;
  color: #a0aec0;
}

.nav-node-item.leaf {
  color: #e2e8f0;
}

.nav-node-icon {
  font-size: 1rem;
  flex-shrink: 0;
}

.nav-node-name {
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nav-node-actions {
  display: flex;
  gap: 0.25rem;
  opacity: 0;
  transition: opacity 0.15s;
}

.btn-icon-tiny {
  padding: 0.25rem 0.4rem;
  border: none;
  background: rgba(74, 85, 104, 0.6);
  color: #cbd5e0;
  border-radius: 3px;
  cursor: pointer;
  font-size: 0.7rem;
  transition: all 0.15s;
}

.btn-icon-tiny:hover {
  background: rgba(74, 85, 104, 0.9);
  color: #e2e8f0;
}

.btn-icon-tiny.danger:hover {
  background: rgba(197, 48, 48, 0.8);
  color: white;
}

.nav-node-children {
  margin-left: 0.5rem;
}

/* 右侧编辑器 */
.setting-docs-editor {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.doc-editor {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 1rem;
}

.doc-editor-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
  padding-bottom: 0.75rem;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.doc-path {
  flex: 1;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.5rem;
  color: #a0aec0;
  font-size: 0.9rem;
}

.path-separator {
  color: #718096;
}

.path-part {
  color: #cbd5e0;
}

.doc-name-input {
  background: rgba(45, 55, 72, 0.6);
  border: 1px solid #4a5568;
  border-radius: 4px;
  padding: 0.25rem 0.5rem;
  color: #f8d56b;
  font-size: 1rem;
  font-weight: 500;
  outline: none;
  transition: all 0.2s;
}

.doc-name-input:focus {
  border-color: #4a90d9;
  box-shadow: 0 0 0 2px rgba(74, 144, 217, 0.2);
}

.doc-actions {
  display: flex;
  gap: 0.5rem;
}

.btn-secondary-small {
  padding: 0.4rem 0.75rem;
  border: 1px solid #4a5568;
  border-radius: 4px;
  background: rgba(45, 55, 72, 0.6);
  color: #cbd5e0;
  cursor: pointer;
  font-size: 0.85rem;
  transition: all 0.2s;
}

.btn-secondary-small:hover {
  background: rgba(74, 85, 104, 0.6);
  border-color: #718096;
  color: #e2e8f0;
}

.doc-content {
  flex: 1;
  width: 100%;
  background: rgba(22, 33, 62, 0.3);
  border: 1px solid #4a5568;
  border-radius: 6px;
  padding: 1rem;
  color: #e0e0e0;
  font-size: 0.95rem;
  font-family: 'Consolas', 'Monaco', 'Courier New', monospace;
  line-height: 1.6;
  resize: none;
  outline: none;
  transition: all 0.2s;
}

.doc-content:focus {
  border-color: #4a90d9;
  box-shadow: 0 0 0 2px rgba(74, 144, 217, 0.1);
  background: rgba(22, 33, 62, 0.4);
}

.doc-content::placeholder {
  color: #718096;
  font-style: italic;
}

.doc-editor-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.empty-state {
  text-align: center;
  color: #718096;
}

.empty-icon {
  font-size: 4rem;
  margin-bottom: 1rem;
  opacity: 0.5;
}

.empty-text {
  font-size: 1.1rem;
  margin-bottom: 0.5rem;
  color: #a0aec0;
}

.empty-hint {
  font-size: 0.9rem;
  font-style: italic;
  color: #718096;
}

.empty-hint-small {
  text-align: center;
  color: #718096;
  font-size: 0.85rem;
  padding: 1.5rem 1rem;
  font-style: italic;
  line-height: 1.5;
}

/* 响应式 */
@media (max-width: 768px) {
  .editor-header {
    flex-direction: column;
    gap: 1rem;
  }

  .toolbar {
    flex-wrap: wrap;
    justify-content: center;
  }

  .editor-tabs {
    justify-content: center;
  }

  .attrs-grid {
    grid-template-columns: repeat(3, 1fr);
  }

  .form-grid {
    grid-template-columns: 1fr;
  }

  .setting-docs-split-container {
    flex-direction: column;
    height: auto;
  }

  .setting-docs-nav {
    width: 100%;
    max-height: 250px;
    border-right: none;
    border-bottom: 1px solid #4a5568;
  }

  .setting-docs-editor {
    min-height: 400px;
  }
}

.btn-ai {
  background: linear-gradient(135deg, #a78bfa 0%, #8b5cf6 100%);
  color: white;
  border: none;
  font-weight: bold;
}

.btn-ai:hover {
  background: linear-gradient(135deg, #b79bfb 0%, #9b6cf8 100%);
  box-shadow: 0 0 15px rgba(139, 92, 246, 0.4);
}

/* ============================================================================
   智能 Value 编辑器样式
   ============================================================================ */

.smart-value-editor {
  width: 100%;
}

.smart-value-editor.simple {
  display: flex;
  gap: 0.5rem;
  align-items: center;
}

.smart-value-editor.json {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.json-editor-toolbar {
  display: flex;
  gap: 0.5rem;
  align-items: center;
  padding: 0.3rem 0.5rem;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 4px;
  flex-wrap: wrap;
