.tree-panel {
  overflow-y: auto;
  padding: 0.5rem;
}

.tree-container {
  font-size: 0.85rem;
}

.tree-node {
  display: flex;
  align-items: center;
  padding: 0.3rem 0.4rem;
  margin: 0.1rem 0;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
}

.tree-node:hover {
  background: rgba(74, 85, 104, 0.5);
}

.tree-node.selected {
  background: linear-gradient(135deg, #4a90d9 0%, #2d6bb5 100%);
  color: white;
  font-weight: bold;
}

.tree-toggle {
  display: inline-block;
  width: 16px;
  text-align: center;
  margin-right: 0.25rem;
  user-select: none;
  font-size: 0.8rem;
}

.tree-name {
  flex: 1;
  user-select: none;
}

