}

.btn-tree-action {
  padding: 0.2rem 0.4rem;
  border: none;
  border-radius: 3px;
  background: rgba(45, 55, 72, 0.8);
  color: #e0e0e0;
  cursor: pointer;
  font-size: 0.8rem;
  transition: all 0.2s;
}

.btn-tree-action:hover {
