}

.tree-node.virtual-folder .tree-name {
  color: #90cdf4;
  font-style: italic;
}

.virtual-badge {
  margin-left: 0.3rem;
  font-size: 0.75rem;
  opacity: 0.7;
}

.tree-node.selected.virtual-folder .tree-name {
  color: white;
}

.path-readonly {
  background: rgba(45, 55, 72, 0.5) !important;
  color: #a0aec0 !important;
  cursor: not-allowed !important;
}

