}

.btn-format {
  background: #805ad5;
}

.btn-format:hover {
  background: #9f7aea;
}

.btn-apply {
  background: #48bb78;
}

.btn-apply:hover {
  background: #68d391;
}

.json-editor {
  width: 100%;
  min-height: 150px;
  padding: 0.75rem;
