  margin: 0 0 0.75rem 0;
  color: #e0e0e0;
  font-size: 1rem;
}

.validation-summary {
  display: flex;
  gap: 1rem;
  margin-bottom: 0.75rem;
  padding-bottom: 0.75rem;
  border-bottom: 1px solid #4a5568;
}

.validation-summary .error-count {
  color: #fc8181;
  font-weight: 600;
}

.validation-summary .warning-count {
  color: #fbd38d;
  font-weight: 600;
}

.validation-list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.validation-item {
  display: flex;
  gap: 0.75rem;
  align-items: flex-start;
  padding: 0.5rem 0.75rem;
  border-radius: 4px;
  font-size: 0.85rem;
}

.validation-item.error {
  background: rgba(229, 62, 62, 0.15);
  border-left: 3px solid #e53e3e;
}

.validation-item.warning {
  background: rgba(237, 137, 54, 0.15);
  border-left: 3px solid #ed8936;
}

.validation-path {
  font-family: 'Consolas', 'Monaco', monospace;
  font-size: 0.8rem;
  color: #a0aec0;
  white-space: nowrap;
}

.validation-message {
  color: #e2e8f0;
}

.validation-more {
  padding: 0.5rem;
  text-align: center;
  color: #a0aec0;
  font-size: 0.85rem;
}

.validation-errors,
.validation-warnings {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.validation-errors:last-child,
.validation-warnings:last-child {
  margin-bottom: 0;
}

.validation-error,
.validation-warning {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  padding: 0.5rem 0.75rem;
  border-radius: 4px;
  font-size: 0.85rem;
}

.validation-error {
  background: rgba(229, 62, 62, 0.15);
  border-left: 3px solid #e53e3e;
  color: #fc8181;
}

.validation-warning {
  background: rgba(237, 137, 54, 0.15);
  border-left: 3px solid #ed8936;
  color: #fbd38d;
}

.validation-error-icon,
.validation-warning-icon {
  flex-shrink: 0;
}

.validation-success {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0.75rem;
  background: rgba(72, 187, 120, 0.15);
  border-left: 3px solid #48bb78;
  border-radius: 4px;
  color: #68d391;
  font-size: 0.85rem;
}

/* 可折叠部分增强 */
.collapsible-section {
  margin-top: 1rem;
  border: 1px solid #2d3748;
  border-radius: 6px;
  overflow: hidden;
}

.collapsible-section .section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.75rem 1rem;
  background: rgba(45, 55, 72, 0.5);
  cursor: pointer;
  user-select: none;
  transition: background 0.2s;
}

.collapsible-section .section-header:hover {
  background: rgba(45, 55, 72, 0.8);
}

.collapsible-section .section-header h4 {
  margin: 0;
  font-size: 0.9rem;
  font-weight: 500;
}

.collapsible-section .section-content {
  padding: 1rem;
  background: rgba(26, 32, 44, 0.3);
}

/* 子编辑器网格布局 */
.skill-item,
.move-item {
  display: flex;
  gap: 0.5rem;
  align-items: center;
  padding: 0.5rem;
  background: rgba(45, 55, 72, 0.3);
  border-radius: 4px;
}

.skill-item select,
.move-item select {
  flex: 1;
  min-width: 120px;
}

.skill-item input[type="number"] {
  width: 80px;
}

/* 装备网格 */
.equipment-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 1rem;
}

.equipment-slot {
  padding: 0.75rem;
  background: rgba(45, 55, 72, 0.5);
  border-radius: 6px;
  border: 1px solid #4a5568;
}

.equipment-slot label {
  display: block;
  margin-bottom: 0.5rem;
  font-weight: 500;
  color: #e0e0e0;
}

/* 关系编辑 */
.relationship-item {
  background: rgba(246, 135, 179, 0.05);
  border-left: 3px solid #f687b3;
}

.relationship-grid {
  display: grid;
  grid-template-columns: 1fr 1fr auto;
  gap: 0.5rem;
  align-items: end;
}

/* 饰品列表 */
.accessories-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-top: 0.5rem;
}

.accessory-item {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  padding: 0.25rem 0.5rem;
  background: rgba(128, 90, 213, 0.2);
  border-radius: 4px;
  font-size: 0.85rem;
}

/* 字符串数组编辑器 */
.string-array-editor {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.string-array-editor .array-item {
  display: flex;
  gap: 0.5rem;
  align-items: center;
}

.string-array-editor .array-item input {
  flex: 1;
  min-width: 0;
}

.btn-remove-inline {
  padding: 0.4rem 0.6rem;
  background: rgba(239, 68, 68, 0.2);
  border: 1px solid #ef4444;
  border-radius: 4px;
  color: #ef4444;
  cursor: pointer;
  font-size: 0.85rem;
  transition: all 0.2s;
  white-space: nowrap;
}

.btn-remove-inline:hover {
  background: rgba(239, 68, 68, 0.3);
  border-color: #dc2626;
}

/* 属性编辑器 */
.attributes-editor {
  padding: 0.5rem;
  background: rgba(45, 55, 72, 0.3);
  border-radius: 6px;
}

.attributes-editor .form-group {
  margin-bottom: 0;
}

.attributes-editor .form-group label {
  font-size: 0.8rem;
  margin-bottom: 0.2rem;
}

.attributes-editor .form-group input {
  padding: 0.4rem;
  font-size: 0.9rem;
}

/* 切换开关风格的复选框 */
.checkbox-group {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-top: 0.5rem;
}

.checkbox-group label {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.4rem 0.75rem;
  background: rgba(45, 55, 72, 0.5);
  border-radius: 4px;
  cursor: pointer;
  user-select: none;
  transition: all 0.2s;
  font-size: 0.85rem;
}

.checkbox-group label:hover {
  background: rgba(45, 55, 72, 0.8);
}

.checkbox-group label.checked {
  background: rgba(72, 187, 120, 0.3);
  border: 1px solid rgba(72, 187, 120, 0.5);
}

/* ============================================================================
   TypeSchema 可视化编辑器样式
   ============================================================================ */

.type-schema-editor {
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 6px;
  padding: 0.75rem;
  background: rgba(26, 26, 46, 0.4);
}

.type-schema-editor.depth-0 {
  background: rgba(26, 26, 46, 0.6);
}

.type-schema-editor.depth-1 {
  background: rgba(45, 55, 72, 0.4);
  margin-left: 0.5rem;
}

.type-schema-editor.depth-2 {
  background: rgba(55, 65, 82, 0.4);
  margin-left: 0.5rem;
}

.type-schema-editor.depth-3,
.type-schema-editor.depth-4,
.type-schema-editor.depth-5 {
  background: rgba(65, 75, 92, 0.3);
  margin-left: 0.5rem;
}

/* 类型选择行 */
.schema-type-row {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  margin-bottom: 0.5rem;
}

.schema-type-select {
  flex: 0 0 auto;
  min-width: 150px;
  padding: 0.5rem 0.75rem;
  background: rgba(45, 55, 72, 0.8);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 4px;
  color: #e0e0e0;
  font-size: 0.9rem;
  cursor: pointer;
}

.schema-type-select:focus {
  outline: none;
  border-color: #4a90d9;
}

.schema-description {
  flex: 1;
  min-width: 0;
  padding: 0.5rem 0.75rem;
  background: rgba(45, 55, 72, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 4px;
  color: #e0e0e0;
  font-size: 0.85rem;
}

.schema-description::placeholder {
  color: #718096;
}

/* 属性区域 */
.schema-properties,
.schema-array-items {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px dashed rgba(255, 255, 255, 0.1);
}

.schema-section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.75rem;
  color: #f8d56b;
  font-size: 0.9rem;
}

/* 属性项 */
.schema-property-item {
  margin-bottom: 0.75rem;
  padding: 0.5rem;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 6px;
  border-left: 3px solid rgba(74, 144, 217, 0.5);
}

.property-header {
  display: flex;
  gap: 0.5rem;
  align-items: center;
  margin-bottom: 0.5rem;
}

.property-name {
  flex: 1;
  min-width: 0;
  padding: 0.4rem 0.6rem;
  background: rgba(45, 55, 72, 0.8);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 4px;
  color: #f8d56b;
  font-size: 0.85rem;
  font-family: monospace;
}

.required-checkbox {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.3rem 0.5rem;
  background: rgba(45, 55, 72, 0.5);
  border-radius: 4px;
  color: #a0aec0;
  font-size: 0.75rem;
  cursor: pointer;
  white-space: nowrap;
}

.required-checkbox input {
  margin: 0;
  cursor: pointer;
}

.required-checkbox:has(input:checked) {
  background: rgba(234, 179, 8, 0.2);
  color: #eab308;
}

.property-schema {
  margin-top: 0.25rem;
}

/* 数组元素编辑器 */
.array-items-editor {
  margin-left: 0.5rem;
}

/* 空状态提示 */
.schema-empty-hint {
  padding: 0.75rem;
  text-align: center;
  color: #718096;
  font-size: 0.85rem;
  font-style: italic;
  background: rgba(0, 0, 0, 0.1);
  border-radius: 4px;
}

/* 深度限制提示 */
.schema-depth-limit {
  padding: 0.5rem;
  background: rgba(239, 68, 68, 0.2);
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: 4px;
  color: #ef4444;
  font-size: 0.85rem;
  text-align: center;
}

/* ============================================================================
   SchemaValueEditor - 基于 Schema 的智能值编辑器
   ============================================================================ */

.schema-value-editor {
  width: 100%;
}

.schema-value-editor input,
.schema-value-editor select {
  width: 100%;
  padding: 0.5rem 0.75rem;
  background: rgba(45, 55, 72, 0.6);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 4px;
  color: #e0e0e0;
  font-size: 0.9rem;
}

.schema-value-editor input:focus,
.schema-value-editor select:focus {
  outline: none;
  border-color: #4a90d9;
}

.schema-value-hint {
  font-size: 0.8rem;
  color: #a0aec0;
  margin-bottom: 0.3rem;
  font-style: italic;
}

/* Object 类型值编辑器 */
.schema-value-editor.schema-object {
  border: 1px solid rgba(74, 144, 217, 0.3);
  border-radius: 6px;
  padding: 0.75rem;
  background: rgba(74, 144, 217, 0.05);
}

.schema-value-editor.schema-object.depth-1,
.schema-value-editor.schema-object.depth-2 {
  margin-left: 0.5rem;
  background: rgba(74, 144, 217, 0.08);
}

.schema-object-fields {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.schema-object-field {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

.schema-field-label {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  font-size: 0.85rem;
  color: #f8d56b;
  font-weight: 500;
}

.schema-field-label .required-mark {
  color: #ef4444;
  font-weight: bold;
}

.schema-field-label .field-description {
  cursor: help;
  font-size: 0.75rem;
  opacity: 0.7;
}

/* Array 类型值编辑器 */
.schema-value-editor.schema-array {
  border: 1px solid rgba(72, 187, 120, 0.3);
  border-radius: 6px;
  padding: 0.75rem;
  background: rgba(72, 187, 120, 0.05);
}

.schema-value-editor.schema-array.depth-1,
.schema-value-editor.schema-array.depth-2 {
  margin-left: 0.5rem;
  background: rgba(72, 187, 120, 0.08);
}

.schema-array-items-list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
}

.schema-array-item {
  padding: 0.5rem;
  background: rgba(0, 0, 0, 0.15);
  border-radius: 4px;
  border-left: 3px solid rgba(72, 187, 120, 0.5);
}

.array-item-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.4rem;
}

.array-item-index {
  font-size: 0.75rem;
  color: #718096;
  font-family: monospace;
}

.schema-null-value {
  color: #718096;
  font-style: italic;
  font-size: 0.9rem;
}

/* 状态值编辑区域 */
.status-value-section {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.template-info-box {
  padding: 0.5rem 0.75rem;
  background: rgba(248, 213, 107, 0.1);
  border: 1px solid rgba(248, 213, 107, 0.2);
  border-radius: 4px;
  font-size: 0.85rem;
}

.template-info-box .template-name {
  color: #f8d56b;
  font-weight: 500;
  margin-bottom: 0.25rem;
}

.template-info-box .template-desc {
  color: #a0aec0;
  font-size: 0.8rem;
}

.template-info-box .template-hint {
  color: #68d391;
  font-size: 0.8rem;
  margin-top: 0.25rem;
}

/* ============================================================================
   游戏选择卡片样式
   ============================================================================ */

.game-select-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  padding: 20px;
}

.game-card {
  padding: 24px;
  border: 2px solid #4a5568;
  border-radius: 8px;
  background: #2d3748;
  cursor: pointer;
  transition: all 0.2s;
  text-align: center;
}

.game-card:hover {
  border-color: #63b3ed;
  background: #3d4858;
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(99, 179, 237, 0.2);
}

.game-card:active {
  transform: translateY(0);
}

.game-card .game-icon {
  font-size: 48px;
  margin-bottom: 12px;
  transition: transform 0.2s;
}

.game-card:hover .game-icon {
  transform: scale(1.1);
}

.game-card h4 {
  margin: 0 0 8px 0;
  color: #f8d56b;
  font-size: 1.1rem;
  font-weight: 600;
}

.game-card p {
  margin: 0;
  font-size: 13px;
  color: #a0aec0;
  line-height: 1.4;
}

/* 优先级徽章样式 */
.priority-badge {
  display: inline-block;
  margin-left: 6px;
  padding: 1px 4px;
  background: #ffd700;
  color: #000;
  border-radius: 3px;
  font-size: 10px;
  font-weight: bold;
  vertical-align: middle;
}

.tree-name {
  flex: 1;
}

/* ============================================================================
   AI/游戏 弹窗样式
   ============================================================================ */

.ai-modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1500;
  backdrop-filter: blur(6px);
}

.ai-modal {
  background: linear-gradient(145deg, #1e2a3a 0%, #2d3748 100%);
  border-radius: 16px;
  min-width: 400px;
  max-width: 90vw;
  max-height: 85vh;
  box-shadow: 0 25px 80px rgba(0, 0, 0, 0.6), 0 0 0 1px rgba(255, 255, 255, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.15);
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.ai-modal .modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 20px;
  background: rgba(0, 0, 0, 0.2);
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.ai-modal .modal-header h3 {
  margin: 0;
  color: #f8d56b;
  font-size: 1.2rem;
}

.ai-modal .btn-close {
  background: transparent;
  border: none;
  color: #a0aec0;
  font-size: 1.2rem;
  cursor: pointer;
  padding: 4px 8px;
  border-radius: 4px;
  transition: all 0.2s;
}

.ai-modal .btn-close:hover {
  background: rgba(255, 255, 255, 0.1);
  color: #fff;
}

.ai-modal .modal-content {
  padding: 20px;
  overflow-y: auto;
  flex: 1;
  min-width: 0;
}

/* 游戏选择网格 */
.game-select-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
}

.game-card {
  background: rgba(45, 55, 72, 0.8);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  padding: 24px;
  text-align: center;
  cursor: pointer;
  transition: all 0.3s ease;
  color: #e0e0e0;
}

.game-card:hover {
  background: rgba(74, 85, 104, 0.9);
  border-color: rgba(248, 213, 107, 0.4);
  transform: translateY(-4px);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.3);
}

.game-card .game-icon {
  font-size: 3rem;
  margin-bottom: 12px;
}

.game-card h4 {
  margin: 0 0 8px 0;
  color: #f8d56b;
  font-size: 1.1rem;
}

.game-card p {
  margin: 0;
  color: #a0aec0;
  font-size: 0.9rem;
}

/* 移动对话框样式 */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.6);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  backdrop-filter: blur(4px);
}

.folder-option {
  transition: all 0.2s ease;
  color: #2d3748 !important;
  font-weight: 500;
}

.folder-option:hover {
  background-color: #e0e0e0 !important;
  transform: translateX(4px);
}

.folder-option:active {
