}

/* ============================================================================
   搜索过滤和实体复制功能样式
   ============================================================================ */

/* 搜索框样式 */
.search-filter-container {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 1rem;
  padding: 0.5rem;
  background: rgba(45, 55, 72, 0.5);
  border-radius: 8px;
}

.search-input {
  flex: 1;
  padding: 0.6rem 1rem;
  border: 1px solid #4a5568;
  border-radius: 6px;
  background: #2d3748;
  color: #e0e0e0;
  font-size: 0.9rem;
  transition: all 0.2s;
}

.search-input:focus {
  outline: none;
  border-color: #4a90d9;
  background: #364152;
  box-shadow: 0 0 0 3px rgba(74, 144, 217, 0.15);
}

.search-input::placeholder {
  color: #718096;
}

.search-result-count {
  font-size: 0.8rem;
  color: #a0aec0;
  white-space: nowrap;
  padding: 0 0.5rem;
}

.btn-clear-search {
  padding: 0.4rem 0.6rem;
  border: none;
  border-radius: 4px;
  background: #4a5568;
  color: #e0e0e0;
  cursor: pointer;
  font-size: 0.8rem;
  transition: all 0.2s;
}

.btn-clear-search:hover {
  background: #5a6778;
}

/* 复制按钮样式 */
.btn-copy {
  padding: 0.3rem 0.5rem;
  border: none;
  border-radius: 4px;
  background: #4a5568;
  color: #e0e0e0;
  cursor: pointer;
  font-size: 0.85rem;
  transition: all 0.2s;
  margin-left: 0.25rem;
}

.btn-copy:hover {
  background: #667eea;
  color: white;
  transform: scale(1.05);
}

.btn-copy:active {
  transform: scale(0.95);
}

/* item-header 操作按钮组 */
.item-header-buttons {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  margin-left: auto;
}

/* 高亮搜索匹配项 */
.list-item.search-match {
  border-color: #4a90d9;
  box-shadow: 0 0 0 1px rgba(74, 144, 217, 0.3);
}

/* 没有搜索结果时的提示 */
.no-results {
  text-align: center;
  padding: 2rem;
  color: #a0aec0;
  font-size: 0.95rem;
}

.no-results .icon {
  font-size: 2rem;
  margin-bottom: 0.5rem;
  display: block;
}

/* 禁用按钮样式 */
.btn-toolbar:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  background: #4a5568;
}

