}

.game-card {
  background: white;
  border-radius: 16px;
  padding: 2rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1rem;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  width: 320px;
  min-width: 280px;
  max-width: 360px;
}

.game-card:hover {
  transform: translateY(-8px);
  box-shadow: 0 12px 24px rgba(0, 0, 0, 0.2);
}

.game-icon {
  font-size: 4rem;
  width: 100px;
  height: 100px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  border-radius: 50%;
  box-shadow: 0 4px 12px rgba(102, 126, 234, 0.4);
}

.game-name {
  margin: 0;
  font-size: 1.5rem;
  color: #2d3748;
  font-weight: 700;
  text-align: center;
}

.game-description {
  margin: 0;
  color: #718096;
  text-align: center;
  line-height: 1.6;
  flex: 1;
}

.play-btn {
  padding: 0.75rem 2rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 1rem;
  font-weight: 600;
  transition: all 0.3s ease;
  width: 100%;
  margin-top: 0.5rem;
}

.play-btn:hover {
  transform: scale(1.05);
  box-shadow: 0 4px 12px rgba(102, 126, 234, 0.4);
}

.no-games {
  display: flex;
  align-items: center;
  justify-content: center;
  flex: 1;
  padding: 3rem;
}

.no-games p {
  color: white;
  font-size: 1.2rem;
  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);
}

/* 移动端适配 */
@media (max-width: 768px) {
  .selector-header {
    padding: 1rem 1.5rem;
    flex-direction: column;
    gap: 1rem;
    align-items: stretch;
  }
  
  .selector-header h1 {
    font-size: 1.5rem;
    text-align: center;
  }
  
  .selector-header .back-btn {
    width: 100%;
    text-align: center;
  }
  
  .games-grid {
    padding: 1.5rem;
    gap: 1.5rem;
    /* 在移动端，卡片垂直堆叠 */
