  }
  
  .game-description {
    font-size: 0.9rem;
  }
}

/* 更小的手机屏幕 */
@media (max-width: 480px) {
  .selector-header {
    padding: 1rem;
  }
  
  .selector-header h1 {
    font-size: 1.2rem;
  }
  
  .games-grid {
    padding: 1rem;
    gap: 1rem;
  }
  
  .game-card {
    padding: 1.25rem;
  }
  
  .game-icon {
    font-size: 2.5rem;
    width: 70px;
    height: 70px;
  }
}

