            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 2000,
            background: '#1a202c'
          }}>
            <TestGame onBack={handleBackToEditor} />
          </div>
        )}

        {activeGame === 'ink' && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 2000,
            background: '#1a202c'
          }}>
            <InkGame onBack={handleBackToEditor} />
          </div>
        )}

        {activeGame === 'custom_template' && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 2000,
            background: '#1a202c'
          }}>
            <CustomTemplateGame onBack={handleBackToEditor} />
          </div>
        )}

        {activeGame === 'custom' && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 2000,
            background: '#1a202c'
          }}>
            <Suspense fallback={<div>Loading...</div>}>
              <CustomGame onBack={handleBackToEditor} />
            </Suspense>
          </div>
        )}

        {/* API 配置模态框 */}
        <APIConfigModal
          isOpen={showAPIConfig}
          onClose={() => setShowAPIConfig(false)}
          onSave={() => { wbnConfigRef.current = loadCopilotConfigFromAPIConfig() }}
        />



        {/* (浮动窗口已移除) */}

        {/* Welcome Page Overlay (first-visit onboarding) */}
        {showWelcome && (
          <WelcomePage
            onComplete={handleWelcomeComplete}
            onSkip={handleWelcomeSkip}
          />
        )}
    </div>
  )
}

