.toast-container {
  position: fixed;
  bottom: 24px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 10001;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--paper-space-2, 8px);
  pointer-events: none;
}

.toast {
  display: flex;
  align-items: center;
  gap: var(--paper-space-2, 8px);
  padding: var(--paper-space-3, 12px) var(--paper-space-5, 20px);
  border-radius: var(--paper-radius-pill, 9999px);
  border: var(--paper-border-thick, 2.5px solid #1a1a2e);
  font-size: 0.875rem;
  font-weight: 700;
  color: var(--paper-text-primary, #1a1a2e);
  pointer-events: auto;
  cursor: pointer;
  user-select: none;
  white-space: nowrap;
  background: var(--paper-bg-secondary, #ffffff);
  box-shadow: var(--paper-shadow-hard, 4px 4px 0px #1a1a2e);
  animation: toastEnter 0.25s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
}

.toast-exit {
  animation: toastExit 0.2s ease-in forwards;
}

.toast-icon {
  font-size: 0.85rem;
  font-weight: 800;
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  flex-shrink: 0;
  border: 1.5px solid var(--paper-dark, #1a1a2e);
  box-shadow: 1px 1px 0px var(--paper-dark, #1a1a2e);
}

.toast-message {
  line-height: 1.4;
}

/* Types */
.toast-success {
  background: var(--paper-lime-green, #22e06a);
  color: #ffffff;
}

.toast-success .toast-icon {
  background: rgba(0, 0, 0, 0.1);
  color: var(--paper-dark, #1a1a2e);
}

.toast-info {
  background: var(--paper-electric-blue, #3b82ff);
  color: #ffffff;
}

.toast-info .toast-icon {
  background: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.toast-error {
  background: var(--paper-coral, #ff6b6b);
  color: #ffffff;
}

.toast-error .toast-icon {
  background: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

/* Animations */
@keyframes toastEnter {
  from {
    opacity: 0;
    transform: translateY(12px) scale(0.95);
    box-shadow: 0 0 0 transparent;
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
    box-shadow: var(--paper-shadow-hard, 4px 4px 0px #1a1a2e);
  }
}

@keyframes toastExit {
  from {
    opacity: 1;
    transform: translateY(0) scale(1);
    box-shadow: var(--paper-shadow-hard, 4px 4px 0px #1a1a2e);
  }

  to {
    opacity: 0;
    transform: translateY(-8px) scale(0.95);
    box-shadow: 0 0 0 transparent;
  }
}

/* Mobile */
@media (max-width: 768px) {
  .toast-container {
    bottom: 80px;
    left: 16px;
    right: 16px;
    transform: none;
  }

  .toast {
    white-space: normal;
    width: 100%;
    justify-content: center;
  }
}

