 */
import React from 'react'
import { useTranslation } from 'react-i18next'

export type SortOrder = 'original' | 'az' | 'za'

interface EntityCardGridProps {
  /** 排序模式 */
  sortOrder: SortOrder
  /** 排序变更回调 */
  onSortChange: (order: SortOrder) => void
  /** 操作按钮区域（添加按钮等） */
  actions?: React.ReactNode
