      </div>

      {/* Description */}
      <div className="form-group" style={{ marginTop: '12px' }}>
        <label>{t('regions.pathDescription')}</label>
        <textarea
          value={path.description || ''}
          onChange={e => onChange({ description: e.target.value })}
