          placeholder={t('world.flagRemarkPlaceholder')}
        />
      </div>
      <div style={{ textAlign: 'right' }}>
        <button className="btn-delete" onClick={onDelete}>{t('common:delete')}</button>
      </div>
    </div>
  )
}

