    color: var(--paper-text-secondary);
    margin: 0;
    line-height: var(--paper-line-height-normal);
}

/* ─── Step 1: API Config Form ────────────────────────────────────────── */

.welcome-api-form {
    width: 100%;
    display: flex;
    flex-direction: column;
    gap: var(--paper-space-4);
}

.welcome-form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--paper-space-4);
}

.welcome-form-group {
    display: flex;
    flex-direction: column;
    gap: var(--paper-space-2);
}

.welcome-form-group.full-width {
    grid-column: 1 / -1;
}

.welcome-form-group label {
    font-size: var(--paper-font-size-sm);
    font-weight: var(--paper-font-weight-semibold);
    color: var(--paper-text-primary);
}

.welcome-form-group input,
.welcome-form-group textarea {
    padding: var(--paper-space-3) var(--paper-space-4);
    border: 1.5px solid var(--paper-border-color);
    border-radius: var(--paper-radius-lg);
    background: var(--paper-bg-secondary);
    color: var(--paper-text-primary);
    font-size: var(--paper-font-size-base);
    font-family: var(--paper-font-body);
    transition: border-color var(--paper-transition-fast);
    outline: none;
}

.welcome-form-group input:focus,
.welcome-form-group textarea:focus {
    border-color: var(--paper-electric-blue);
}

.welcome-form-group textarea {
    min-height: 120px;
    resize: vertical;
    line-height: var(--paper-line-height-normal);
}

/* Model row with fetch button */
.welcome-model-row {
    display: flex;
    gap: var(--paper-space-2);
    align-items: flex-end;
}

.welcome-model-row .model-combobox {
    flex: 1;
}

/* ─── Buttons ────────────────────────────────────────────────────────── */

.welcome-btn-row {
    display: flex;
    gap: var(--paper-space-3);
    justify-content: center;
    margin-top: var(--paper-space-4);
}

.welcome-btn-primary {
    padding: var(--paper-space-3) var(--paper-space-8);
    border: 2px solid var(--paper-electric-blue);
    border-radius: var(--paper-radius-lg);
    background: var(--paper-electric-blue);
    color: var(--paper-text-inverse);
    font-size: var(--paper-font-size-base);
    font-weight: var(--paper-font-weight-bold);
    font-family: var(--paper-font-body);
    cursor: pointer;
    transition: all var(--paper-transition-fast);
}

.welcome-btn-primary:hover:not(:disabled) {
    filter: brightness(1.1);
    transform: translateY(-2px);
    box-shadow: var(--paper-shadow-md);
}

.welcome-btn-primary:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.welcome-btn-secondary {
    padding: var(--paper-space-3) var(--paper-space-6);
    border: 1.5px solid var(--paper-border-color);
    border-radius: var(--paper-radius-lg);
    background: var(--paper-bg-secondary);
    color: var(--paper-text-secondary);
    font-size: var(--paper-font-size-sm);
    font-weight: var(--paper-font-weight-medium);
    font-family: var(--paper-font-body);
    cursor: pointer;
    transition: all var(--paper-transition-fast);
}

.welcome-btn-secondary:hover {
    border-color: var(--paper-border-color-hover);
    color: var(--paper-text-primary);
}

/* ─── Test Connection Result ─────────────────────────────────────────── */

.welcome-test-result {
    font-size: var(--paper-font-size-sm);
    padding: var(--paper-space-2) var(--paper-space-3);
    border-radius: var(--paper-radius-md);
    text-align: center;
}

.welcome-test-result.success {
    color: var(--paper-lime-green);
    background: var(--paper-lime-green-alpha);
}

.welcome-test-result.error {
    color: var(--paper-hot-pink);
    background: var(--paper-hot-pink-alpha);
}

/* ─── Step 2: Starting Point Cards ───────────────────────────────────── */

.welcome-cards-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--paper-space-4);
    width: 100%;
    margin-bottom: var(--paper-space-6);
}

.welcome-card {
    background: var(--paper-bg-secondary);
    border: 2px solid var(--paper-border-color);
    border-radius: var(--paper-radius-xl);
    padding: var(--paper-space-6) var(--paper-space-4);
    text-align: center;
    cursor: pointer;
    transition: all 0.2s ease;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: var(--paper-space-2);
}

.welcome-card:hover {
    border-color: var(--paper-electric-blue);
    transform: translateY(-4px);
    box-shadow: var(--paper-shadow-lg);
    background: var(--paper-bg-content);
}

.welcome-card.selected {
    border-color: var(--paper-electric-blue);
    background: var(--paper-bg-content);
    box-shadow: var(--paper-shadow-md);
}

.welcome-card-icon {
    font-size: 2.5rem;
    margin-bottom: var(--paper-space-2);
}

.welcome-card h4 {
    margin: 0;
    color: var(--paper-text-primary);
    font-size: var(--paper-font-size-lg);
    font-weight: var(--paper-font-weight-bold);
    font-family: var(--paper-font-display);
}

.welcome-card p {
    margin: 0;
    color: var(--paper-text-secondary);
    font-size: var(--paper-font-size-sm);
    line-height: 1.4;
}

/* ─── Step 2: Input Detail Area ──────────────────────────────────────── */

.welcome-input-area {
    width: 100%;
    animation: welcome-slide-up 0.2s ease-out;
}

@keyframes welcome-slide-up {
    from { opacity: 0; transform: translateY(8px); }
    to { opacity: 1; transform: translateY(0); }
}

/* File upload zone */
.welcome-upload-zone {
    border: 2px dashed var(--paper-border-color);
    border-radius: var(--paper-radius-xl);
    padding: var(--paper-space-6);
    text-align: center;
    cursor: pointer;
    transition: all var(--paper-transition-fast);
    margin-bottom: var(--paper-space-4);
    background: var(--paper-bg-secondary);
}

.welcome-upload-zone:hover {
    border-color: var(--paper-electric-blue);
    background: var(--paper-bg-content);
}

.welcome-upload-zone-text {
    color: var(--paper-text-secondary);
    font-size: var(--paper-font-size-sm);
}

.welcome-upload-zone-hint {
    color: var(--paper-text-tertiary);
    font-size: var(--paper-font-size-xs);
    margin-top: var(--paper-space-2);
}

/* File list — compact wrapping tags */
.welcome-file-list {
    display: flex;
    flex-wrap: wrap;
    gap: var(--paper-space-2);
    margin-bottom: var(--paper-space-4);
}

.welcome-file-item {
    display: inline-flex;
    align-items: center;
    gap: var(--paper-space-2);
    padding: var(--paper-space-1) var(--paper-space-3);
    background: var(--paper-bg-tertiary);
    border-radius: var(--paper-radius-full);
    font-size: var(--paper-font-size-xs);
    color: var(--paper-text-primary);
    max-width: 280px;
}

.welcome-file-item-info {
    display: flex;
    align-items: center;
    gap: var(--paper-space-1);
    min-width: 0;
}

.welcome-file-item-name {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.welcome-file-item-meta {
    color: var(--paper-text-tertiary);
    font-size: var(--paper-font-size-xs);
    white-space: nowrap;
}

.welcome-file-remove {
    background: none;
    border: none;
    color: var(--paper-text-tertiary);
    cursor: pointer;
    padding: var(--paper-space-1);
    font-size: var(--paper-font-size-sm);
    transition: color var(--paper-transition-fast);
}

.welcome-file-remove:hover {
    color: var(--paper-hot-pink);
}

/* Lorebook summary — compact inline tag */
.welcome-lorebook-summary {
    display: inline-flex;
    align-items: center;
    gap: var(--paper-space-2);
    padding: var(--paper-space-1) var(--paper-space-3);
    background: var(--paper-bg-tertiary);
    border-radius: var(--paper-radius-full);
    max-width: 320px;
}

.welcome-lorebook-info {
    display: flex;
    align-items: center;
    gap: var(--paper-space-2);
    min-width: 0;
}

.welcome-lorebook-name {
    font-weight: var(--paper-font-weight-semibold);
    color: var(--paper-text-primary);
    font-size: var(--paper-font-size-xs);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.welcome-lorebook-meta {
    color: var(--paper-text-tertiary);
    font-size: var(--paper-font-size-xs);
    white-space: nowrap;
}

.welcome-error {
    color: var(--paper-hot-pink);
    font-size: var(--paper-font-size-sm);
    margin-bottom: var(--paper-space-3);
}

/* ─── Skip Link ──────────────────────────────────────────────────────── */

.welcome-skip {
    text-align: center;
    margin-top: var(--paper-space-8);
    color: var(--paper-text-tertiary);
    font-size: var(--paper-font-size-sm);
    cursor: pointer;
    background: none;
    border: none;
    font-family: var(--paper-font-body);
    transition: color var(--paper-transition-fast);
}

.welcome-skip:hover {
    color: var(--paper-text-secondary);
    text-decoration: underline;
}

/* ─── Back link in step 2 ────────────────────────────────────────────── */

.welcome-back {
    display: inline-flex;
    align-items: center;
    gap: var(--paper-space-1);
    color: var(--paper-text-tertiary);
    font-size: var(--paper-font-size-sm);
    cursor: pointer;
    background: none;
    border: none;
    font-family: var(--paper-font-body);
    margin-bottom: var(--paper-space-4);
    align-self: flex-start;
    transition: color var(--paper-transition-fast);
}

.welcome-back:hover {
    color: var(--paper-text-primary);
}

/* ─── Responsive ─────────────────────────────────────────────────────── */

@media (max-width: 768px) {
    .welcome-container {
        padding: var(--paper-space-4) var(--paper-space-3);
    }

    .welcome-cards-grid {
        grid-template-columns: 1fr;
    }

    .welcome-form-row {
        grid-template-columns: 1fr;
    }

    .welcome-title {
        font-size: var(--paper-font-size-2xl);
    }

    .welcome-model-row {
        flex-wrap: wrap;
    }

    .welcome-model-row .model-combobox {
        flex: 1 1 100%;
    }
}

/* 模型推荐区 - Welcome 页适配 */
.welcome-recommendations {
    margin-top: var(--paper-space-1);
}

