/**
 * WelcomePage - Full-screen onboarding for first-time users
 *
 * Step 1: API configuration (baseUrl + apiKey + model)
 * Step 2: Choose starting point (lorebook / files / idea) + input + launch WorldBuilder
 */
import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import type { LLMConfig, SetAPIConfigInput, UploadedFile } from '../../api/types'
import type { LorebookData } from '../../api/worldBuilderNextTypes'
import { parseSillyTavernLorebook } from '../../api/lorebookParser'
import {
    loadAPIConfigFromStorage,
    saveAPIConfigToStorage,
    syncAPIConfigToBackend,
    fetchAvailableModels,
    testAPIConnection,
    type EndpointTestResult,
} from '../APIConfigModal'
import { useFileStore } from '../../stores/fileStore'
import { useLorebookStore } from '../../stores/lorebookStore'
import LanguageSelector from '../../i18n/LanguageSelector'
import './WelcomePage.css'

// ─── Types ──────────────────────────────────────────────────────────────

export interface WelcomePageProps {
    onComplete: (result: WelcomeResult) => void
    onSkip: () => void
}

export interface WelcomeResult {
    startingPoint: 'lorebook' | 'files' | 'idea'
    prompt: string
}

type WelcomeStep = 'api-config' | 'starting-point'
type StartingPoint = 'lorebook' | 'files' | 'idea' | null

// ─── Inline Model Combobox (simplified) ─────────────────────────────────

const SimpleModelCombobox: React.FC<{
    value: string
    onChange: (v: string) => void
    models: string[]
    placeholder?: string
}> = ({ value, onChange, models, placeholder }) => {
    const [open, setOpen] = useState(false)
    const containerRef = useRef<HTMLDivElement>(null)

    useEffect(() => {
        const handler = (e: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
                setOpen(false)
            }
        }
        document.addEventListener('mousedown', handler)
        return () => document.removeEventListener('mousedown', handler)
    }, [])

    const filtered = useMemo(() => {
        if (!models.length) return []
        const q = value.toLowerCase()
        if (!q) return models
        return models.filter(m => m.toLowerCase().includes(q))
    }, [models, value])

    return (
        <div className="model-combobox" ref={containerRef} style={{ flex: 1 }}>
            <input
                type="text"
                placeholder={placeholder}
                value={value}
                onChange={e => { onChange(e.target.value); setOpen(true) }}
                onFocus={() => setOpen(true)}
            />
            {models.length > 0 && (
                <button
                    type="button"
                    className="model-combobox-toggle"
                    tabIndex={-1}
                    onClick={() => setOpen(o => !o)}
                >
                    ▾
                </button>
            )}
            {open && filtered.length > 0 && (
                <ul className="model-combobox-list">
                    {filtered.map(m => (
                        <li
                            key={m}
                            className={`model-combobox-item${m === value ? ' selected' : ''}`}
                            onMouseDown={e => { e.preventDefault(); onChange(m); setOpen(false) }}
                        >
                            {m}
                        </li>
                    ))}
                </ul>
            )}
        </div>
    )
}

// ─── Main Component ─────────────────────────────────────────────────────

const WelcomePage: React.FC<WelcomePageProps> = ({ onComplete, onSkip }) => {
    const { t } = useTranslation('editor')

    // Pre-load existing API config (for returning users)
    const existingConfig = useMemo(() => loadAPIConfigFromStorage(), [])
    const hasExistingConfig = !!(existingConfig.generationModel?.apiKey && existingConfig.generationModel?.baseUrl)

    // Wizard step — skip API config if already configured
    const [step, setStep] = useState<WelcomeStep>(hasExistingConfig ? 'starting-point' : 'api-config')

    // ── Step 1: API Config State (pre-fill from existing config) ──
    const [baseUrl, setBaseUrl] = useState(existingConfig.generationModel?.baseUrl || '')
    const [apiKey, setApiKey] = useState(existingConfig.generationModel?.apiKey || '')
    const [model, setModel] = useState(existingConfig.generationModel?.model || '')
    const [secondaryModel, setSecondaryModel] = useState(existingConfig.retrievalModel?.model || '')
    const [availableModels, setAvailableModels] = useState<string[]>([])
    const [isFetching, setIsFetching] = useState(false)
    const [testResult, setTestResult] = useState<EndpointTestResult | null>(null)
    const [isTesting, setIsTesting] = useState(false)

    const apiConfigInputRef = useRef<HTMLInputElement>(null)

    const handleImportAPIConfig = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return
        const reader = new FileReader()
        reader.onload = (event) => {
            try {
                const imported = JSON.parse(event.target?.result as string) as SetAPIConfigInput
                if (imported.generationModel || imported.retrievalModel || imported.updateModel) {
                    const gen = imported.generationModel
                    setBaseUrl(gen?.baseUrl || '')
                    setApiKey(gen?.apiKey || '')
                    setModel(gen?.model || '')
                    setSecondaryModel(imported.retrievalModel?.model || gen?.model || '')
                    // Also save to storage immediately so it persists
                    saveAPIConfigToStorage(imported)
                } else {
                    alert(t('apiConfig.importInvalid'))
                }
            } catch {
                alert(t('apiConfig.importFailed'))
            }
        }
        reader.readAsText(file)
        e.target.value = ''
    }, [t])

    const canProceedStep1 = baseUrl.trim() && apiKey.trim() && model.trim()

    const handleFetchModels = useCallback(async () => {
        if (!baseUrl.trim() || !apiKey.trim()) return
        setIsFetching(true)
        try {
            const models = await fetchAvailableModels(baseUrl.trim(), apiKey.trim())
            setAvailableModels(models)
        } catch (e: any) {
            console.error('Failed to fetch models:', e)
        } finally {
            setIsFetching(false)
        }
    }, [baseUrl, apiKey])

    const handleTestConnection = useCallback(async () => {
        if (!baseUrl.trim() || !apiKey.trim() || !model.trim()) return
        setIsTesting(true)
        setTestResult(null)
        try {
            const result = await testAPIConnection(baseUrl.trim(), apiKey.trim(), model.trim())
            setTestResult(result)
        } catch (e: any) {
            setTestResult({ success: false, latency: 0, error: e.message })
        } finally {
            setIsTesting(false)
        }
    }, [baseUrl, apiKey, model])

    const handleStep1Next = useCallback(async () => {
        if (!canProceedStep1) return
        const shared: LLMConfig = {
            baseUrl: baseUrl.trim(),
            apiKey: apiKey.trim(),
            temperature: 0.7,
            maxTokens: 20480,
        }
        const primary: LLMConfig = { ...shared, model: model.trim() }
        const secondary: LLMConfig = { ...shared, model: secondaryModel.trim() || model.trim() }
        const config: SetAPIConfigInput = {
            generationModel: primary,
            retrievalModel: secondary,
            updateModel: secondary,
        }
        saveAPIConfigToStorage(config)
        await syncAPIConfigToBackend().catch(() => {})
        setStep('starting-point')
    }, [canProceedStep1, baseUrl, apiKey, model, secondaryModel])

    // ── Step 2: Starting Point State ──
    const [selectedPoint, setSelectedPoint] = useState<StartingPoint>(null)
    const [prompt, setPrompt] = useState('')
    const [lorebookError, setLorebookError] = useState('')

    // File/Lorebook stores
    const storeFiles = useFileStore(s => s.files)
    const storeAddFile = useFileStore(s => s.addFile)
    const storeRemoveFile = useFileStore(s => s.removeFile)
    const storeLorebooks = useLorebookStore(s => s.lorebooks)
    const storeAddLorebook = useLorebookStore(s => s.addLorebook)
    const storeRemoveLorebook = useLorebookStore(s => s.removeLorebook)

    const initFiles = useFileStore(s => s.initFiles)
    const initLorebooks = useLorebookStore(s => s.initLorebooks)
    useEffect(() => { initFiles(); initLorebooks() }, [initFiles, initLorebooks])

    const fileInputRef = useRef<HTMLInputElement>(null)
    const lorebookInputRef = useRef<HTMLInputElement>(null)

    const handleFileUpload = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const fileList = e.target.files
        if (!fileList) return
        Array.from(fileList).forEach(file => {
            const reader = new FileReader()
            reader.onload = () => {
                const content = reader.result as string
                const ext = file.name.split('.').pop()?.toLowerCase() || ''
                const typeMap: Record<string, UploadedFile['type']> = {
                    md: 'md', json: 'json', txt: 'txt',
                    png: 'image', jpg: 'image', jpeg: 'image', gif: 'image', webp: 'image', svg: 'image',
                }
                storeAddFile({
                    name: file.name,
                    content,
                    type: typeMap[ext] || 'txt',
                    size: file.size,
                    uploadedAt: Date.now(),
                })
            }
            reader.readAsText(file)
        })
        e.target.value = ''
    }, [storeAddFile])

    const handleLorebookUpload = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const fileList = e.target.files
        if (!fileList) return
        setLorebookError('')
        Array.from(fileList).forEach(file => {
            const reader = new FileReader()
            reader.onload = () => {
                try {
                    const json = JSON.parse(reader.result as string)
                    const parsed = parseSillyTavernLorebook(json, file.name)
                    if (!parsed) {
                        setLorebookError(t('welcome.lorebookParseError'))
                        return
                    }
                    storeAddLorebook(parsed)
                } catch {
                    setLorebookError(t('welcome.lorebookParseError'))
                }
            }
            reader.readAsText(file)
        })
        e.target.value = ''
    }, [storeAddLorebook, t])

    const canStartBuilding = (() => {
        if (!selectedPoint) return false
        if (selectedPoint === 'lorebook') return storeLorebooks.length > 0
        if (selectedPoint === 'files') return storeFiles.length > 0
        if (selectedPoint === 'idea') return prompt.trim().length > 0
        return false
    })()

    const handleStartBuilding = useCallback(() => {
        if (!selectedPoint || !canStartBuilding) return

        // Build prompt with upload markers so the LLM knows what was uploaded
        const parts: string[] = []

        if (selectedPoint === 'lorebook') {
            for (const lb of storeLorebooks) {
                parts.push(`[Uploaded Lorebook] ${lb.name} (${lb.entries.length} entries, ${(lb.totalChars / 1000).toFixed(0)}K chars)`)
            }
        } else if (selectedPoint === 'files') {
            for (const f of storeFiles) {
                parts.push(`[Uploaded File] ${f.name}`)
            }
        }

        if (prompt.trim()) {
            parts.push(prompt.trim())
        } else if (selectedPoint !== 'idea') {
            parts.push(t('welcome.defaultPrompt'))
        }

        onComplete({ startingPoint: selectedPoint, prompt: parts.join('\n') })
    }, [selectedPoint, canStartBuilding, prompt, storeLorebooks, storeFiles, onComplete, t])

    const formatFileSize = (bytes: number) => {
        if (bytes < 1024) return `${bytes}B`
        if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)}KB`
        return `${(bytes / (1024 * 1024)).toFixed(1)}MB`
    }

    // ─── Render ───

    return (
        <div className="welcome-overlay paper-editor">
            <div className="welcome-lang-selector">
                <LanguageSelector />
            </div>
            <div className="welcome-container">
                {/* Step indicator */}
                <div className="welcome-steps">
                    <div className={`welcome-step-dot ${step === 'api-config' ? 'active' : 'completed'}`} />
                    <div className={`welcome-step-dot ${step === 'starting-point' ? 'active' : ''}`} />
                </div>

                {/* ────────── Step 1: API Config ────────── */}
                {step === 'api-config' && (
                    <>
                        <div className="welcome-header">
                            <h1 className="welcome-title">{t('welcome.title')}</h1>
                            <p className="welcome-subtitle">{t('welcome.subtitle')}</p>
                        </div>

                        <div className="welcome-api-form">
                            <div className="welcome-form-row">
                                <div className="welcome-form-group">
                                    <label>{t('welcome.baseUrlLabel')}</label>
                                    <input
                                        type="text"
                                        value={baseUrl}
                                        onChange={e => setBaseUrl(e.target.value)}
                                        placeholder={t('welcome.baseUrlPlaceholder')}
                                    />
                                </div>
                                <div className="welcome-form-group">
                                    <label>{t('welcome.apiKeyLabel')}</label>
                                    <input
                                        type="password"
                                        value={apiKey}
                                        onChange={e => setApiKey(e.target.value)}
                                        placeholder={t('welcome.apiKeyPlaceholder')}
                                    />
                                </div>
                            </div>

                            <div className="welcome-form-group">
                                <label>{t('welcome.secondaryModelLabel')}</label>
                                <div className="welcome-model-row">
                                    <SimpleModelCombobox
                                        value={secondaryModel}
                                        onChange={setSecondaryModel}
                                        models={availableModels}
                                        placeholder={t('welcome.secondaryModelPlaceholder')}
                                    />
                                    <button
                                        className="welcome-btn-secondary"
                                        onClick={handleFetchModels}
                                        disabled={isFetching || !baseUrl.trim() || !apiKey.trim()}
                                    >
                                        {isFetching ? t('welcome.fetchingModels') : t('welcome.fetchModels')}
                                    </button>
                                </div>
                            </div>

                            <div className="welcome-form-group">
                                <label>{t('welcome.primaryModelLabel')}</label>
                                <div className="welcome-model-row">
                                    <SimpleModelCombobox
                                        value={model}
                                        onChange={setModel}
                                        models={availableModels}
                                        placeholder={t('welcome.primaryModelPlaceholder')}
                                    />
                                </div>
                            </div>

                            {/* 模型推荐 */}
                            <details className="model-recommendations welcome-recommendations">
                                <summary className="recommendations-toggle">
                                    💡 {t('apiConfig.modelRecommendations')}
                                </summary>
                                <div className="recommendations-content">
                                    <div className="rec-section">
                                        <div className="rec-title">🔍🔄 {t('welcome.secondaryModelLabel')}</div>
                                        <p className="rec-desc">{t('apiConfig.recRetrievalDesc')}</p>
                                        <div className="rec-models">
                                            {['google/gemini-2.5-flash-lite', 'google/gemini-3.1-flash-lite-preview', 'x-ai/grok-4-fast'].map(m => (
                                                <button key={m} className="rec-model-chip" onClick={() => setSecondaryModel(m)}>{m}</button>
                                            ))}
                                        </div>
                                        <p className="rec-note">{t('apiConfig.recRetrievalNote')}</p>
                                    </div>
                                    <div className="rec-section">
                                        <div className="rec-title">✨ {t('welcome.primaryModelLabel')}</div>
                                        <p className="rec-desc">{t('apiConfig.recGenerationDesc')}</p>
                                        <div className="rec-models">
                                            {['deepseek/deepseek-v3.2', 'z-ai/glm-4.7', 'z-ai/glm-5', 'moonshotai/kimi-k2.5', 'xiaomi/mimo-v2-pro'].map(m => (
                                                <button key={m} className="rec-model-chip" onClick={() => setModel(m)}>{m}</button>
                                            ))}
                                        </div>
                                        <div className="rec-models">
                                            {['google/gemini-3.1-pro-preview', 'anthropic/claude-sonnet-4.6'].map(m => (
                                                <button key={m} className="rec-model-chip premium" onClick={() => setModel(m)}>{m}</button>
                                            ))}
                                        </div>
                                        <p className="rec-note">{t('apiConfig.recGenerationNote')}</p>
                                    </div>
                                    <p className="rec-footnote">{t('apiConfig.recFootnote')}</p>
                                </div>
                            </details>

                            {/* Test connection + Import config */}
                            <div className="welcome-btn-row" style={{ justifyContent: 'flex-start' }}>
                                <button
                                    className="welcome-btn-secondary"
                                    onClick={handleTestConnection}
                                    disabled={isTesting || !canProceedStep1}
                                >
                                    {isTesting ? t('welcome.testing') : t('welcome.testConnection')}
                                </button>
                                <input
                                    ref={apiConfigInputRef}
                                    type="file"
                                    accept=".json"
                                    style={{ display: 'none' }}
                                    onChange={handleImportAPIConfig}
                                />
                                <button
                                    className="welcome-btn-secondary"
                                    onClick={() => apiConfigInputRef.current?.click()}
                                >
                                    📥 {t('welcome.importConfig')}
                                </button>
                                {testResult && (
                                    <div className={`welcome-test-result ${testResult.success ? 'success' : 'error'}`}>
                                        {testResult.success
                                            ? t('welcome.testSuccess', { latency: testResult.latency })
                                            : t('welcome.testFailed', { error: testResult.error })
                                        }
                                    </div>
                                )}
                            </div>

                            {/* Next button */}
                            <div className="welcome-btn-row">
                                <button
                                    className="welcome-btn-primary"
                                    onClick={handleStep1Next}
                                    disabled={!canProceedStep1}
                                >
                                    {t('welcome.nextStep')}
                                </button>
                            </div>
                        </div>
                    </>
                )}

                {/* ────────── Step 2: Starting Point ────────── */}
                {step === 'starting-point' && (
                    <>
                        <button className="welcome-back" onClick={() => setStep('api-config')}>
                            ← {t('welcome.back')}
                        </button>

                        <div className="welcome-header">
                            <h1 className="welcome-title">{t('welcome.step2Title')}</h1>
                            <p className="welcome-subtitle">{t('welcome.step2Subtitle')}</p>
                        </div>

                        {/* Three cards */}
                        <div className="welcome-cards-grid">
                            <button
                                className={`welcome-card ${selectedPoint === 'lorebook' ? 'selected' : ''}`}
                                onClick={() => setSelectedPoint('lorebook')}
                            >
                                <div className="welcome-card-icon">📖</div>
                                <h4>{t('welcome.optionLorebook')}</h4>
                                <p>{t('welcome.optionLorebookDesc')}</p>
                            </button>
                            <button
                                className={`welcome-card ${selectedPoint === 'files' ? 'selected' : ''}`}
                                onClick={() => setSelectedPoint('files')}
                            >
                                <div className="welcome-card-icon">📁</div>
                                <h4>{t('welcome.optionFiles')}</h4>
                                <p>{t('welcome.optionFilesDesc')}</p>
                            </button>
                            <button
                                className={`welcome-card ${selectedPoint === 'idea' ? 'selected' : ''}`}
                                onClick={() => setSelectedPoint('idea')}
                            >
                                <div className="welcome-card-icon">💡</div>
                                <h4>{t('welcome.optionIdea')}</h4>
                                <p>{t('welcome.optionIdeaDesc')}</p>
                            </button>
                        </div>

                        {/* Input area based on selection */}
                        {selectedPoint && (
                            <div className="welcome-input-area">
                                {/* Lorebook upload */}
                                {selectedPoint === 'lorebook' && (
                                    <>
                                        <input
                                            ref={lorebookInputRef}
                                            type="file"
                                            accept=".json"
                                            multiple
                                            style={{ display: 'none' }}
                                            onChange={handleLorebookUpload}
                                        />
                                        {storeLorebooks.length === 0 ? (
                                            <div
                                                className="welcome-upload-zone"
                                                onClick={() => lorebookInputRef.current?.click()}
                                            >
                                                <div className="welcome-upload-zone-text">
                                                    📖 {t('welcome.lorebookUpload')}
                                                </div>
                                                <div className="welcome-upload-zone-hint">
                                                    {t('welcome.lorebookHint')}
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="welcome-file-list">
                                                {storeLorebooks.map(lb => (
                                                    <div key={lb.filename} className="welcome-lorebook-summary">
                                                        <div className="welcome-lorebook-info">
                                                            <span className="welcome-lorebook-name">📖 {lb.name}</span>
                                                            <span className="welcome-lorebook-meta">
                                                                {lb.entries.length} entries · {(lb.totalChars / 1000).toFixed(0)}K chars
                                                            </span>
                                                        </div>
                                                        <button
                                                            className="welcome-file-remove"
                                                            onClick={() => storeRemoveLorebook(lb.filename)}
                                                        >
                                                            ✕
                                                        </button>
                                                    </div>
                                                ))}
                                                <button
                                                    className="welcome-btn-secondary"
                                                    style={{ alignSelf: 'flex-start' }}
                                                    onClick={() => lorebookInputRef.current?.click()}
                                                >
                                                    + {t('welcome.addMore')}
                                                </button>
                                            </div>
                                        )}
                                        {lorebookError && <div className="welcome-error">{lorebookError}</div>}
                                        <div className="welcome-form-group" style={{ marginTop: 'var(--paper-space-4)' }}>
                                            <label>{t('welcome.additionalContext')}</label>
                                            <textarea
                                                value={prompt}
                                                onChange={e => setPrompt(e.target.value)}
                                                placeholder={t('welcome.additionalContextPlaceholder')}
                                            />
                                        </div>
                                    </>
                                )}

                                {/* File upload */}
                                {selectedPoint === 'files' && (
                                    <>
                                        <input
                                            ref={fileInputRef}
                                            type="file"
                                            accept=".md,.txt,.json,.png,.jpg,.jpeg,.gif,.webp,.svg"
                                            multiple
                                            style={{ display: 'none' }}
                                            onChange={handleFileUpload}
                                        />
                                        {storeFiles.length === 0 ? (
                                            <div
                                                className="welcome-upload-zone"
                                                onClick={() => fileInputRef.current?.click()}
                                            >
                                                <div className="welcome-upload-zone-text">
                                                    📁 {t('welcome.filesUpload')}
                                                </div>
                                                <div className="welcome-upload-zone-hint">
                                                    {t('welcome.filesAccepted')}
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="welcome-file-list">
                                                {storeFiles.map(f => (
                                                    <div key={f.name} className="welcome-file-item">
                                                        <div className="welcome-file-item-info">
                                                            <span className="welcome-file-item-name">{f.name}</span>
                                                            <span className="welcome-file-item-meta">{formatFileSize(f.size)}</span>
                                                        </div>
                                                        <button
                                                            className="welcome-file-remove"
                                                            onClick={() => storeRemoveFile(f.name)}
                                                        >
                                                            ✕
                                                        </button>
                                                    </div>
                                                ))}
                                                <button
                                                    className="welcome-btn-secondary"
                                                    style={{ alignSelf: 'flex-start' }}
                                                    onClick={() => fileInputRef.current?.click()}
                                                >
                                                    + {t('welcome.addMore')}
                                                </button>
                                            </div>
                                        )}
                                        <div className="welcome-form-group" style={{ marginTop: 'var(--paper-space-4)' }}>
                                            <label>{t('welcome.additionalContext')}</label>
                                            <textarea
                                                value={prompt}
                                                onChange={e => setPrompt(e.target.value)}
                                                placeholder={t('welcome.additionalContextPlaceholder')}
                                            />
                                        </div>
                                    </>
                                )}

                                {/* Idea text input */}
                                {selectedPoint === 'idea' && (
                                    <div className="welcome-form-group">
                                        <label>{t('welcome.ideaLabel')}</label>
                                        <textarea
                                            value={prompt}
                                            onChange={e => setPrompt(e.target.value)}
                                            placeholder={t('welcome.ideaPlaceholder')}
                                            style={{ minHeight: '180px' }}
                                        />
                                    </div>
                                )}

                                {/* Start Building button */}
                                <div className="welcome-btn-row">
                                    <button
                                        className="welcome-btn-primary"
                                        onClick={handleStartBuilding}
                                        disabled={!canStartBuilding}
                                    >
                                        {t('welcome.startBuilding')}
                                    </button>
                                </div>
                            </div>
                        )}
                    </>
                )}

                {/* Skip link */}
                <button className="welcome-skip" onClick={onSkip}>
                    {t('welcome.skip')}
                </button>
            </div>
        </div>
    )
}

export default WelcomePage

/src/components/world-builder/WorldBuild:
/* ============================================================================
   WorldBuilderBanner - 顶部横幅 UI
   嵌入主编辑器内容区顶部，显示世界构建进度和交互控件
   ============================================================================ */

.wbn-banner {
    position: relative;
    border-radius: var(--paper-radius-blob, 20px);
    border: var(--paper-border-thick, 2.5px solid #1a1a2e);
    box-shadow: var(--paper-shadow-hard, 4px 4px 0px #1a1a2e);
    margin: var(--paper-space-4, 16px) var(--paper-space-4, 16px);
    padding: 0;
    overflow: hidden;
    transition: transform 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1)), box-shadow 0.2s ease, border-color 0.3s;
    flex-shrink: 0;
    max-height: 70vh;
    display: flex;
    flex-direction: column;
    background: var(--paper-bg-secondary, #ffffff);
}

.wbn-banner:hover {
    transform: translateY(-2px);
    box-shadow: 6px 6px 0px var(--paper-dark, #1a1a2e);
}

.wbn-banner-scroll {
    overflow-y: auto;
    overflow-x: hidden;
    flex: 1;
    min-height: 0;
}

/* ---------- 状态色彩主题 ---------- */

/* ---------- 状态色彩主题 ---------- */

.wbn-banner--generating {
    background: linear-gradient(135deg, rgba(59, 130, 255, 0.05), rgba(168, 85, 247, 0.05));
    border-color: var(--paper-electric-blue, #3b82ff);
    animation: wbn-border-pulse-gen 2s infinite alternate;
}

@keyframes wbn-border-pulse-gen {
    0% {
        border-color: rgba(59, 130, 255, 0.5);
        box-shadow: 4px 4px 0px rgba(59, 130, 255, 0.3);
    }

    100% {
        border-color: var(--paper-electric-blue, #3b82ff);
        box-shadow: 4px 4px 0px var(--paper-dark, #1a1a2e);
    }
}

.wbn-banner--waiting {
    background: linear-gradient(135deg, rgba(34, 224, 106, 0.05), rgba(59, 130, 255, 0.05));
    border-color: var(--paper-lime-green, #22e06a);
    box-shadow: var(--paper-shadow-hard, 4px 4px 0px #1a1a2e);
}

.wbn-banner--revising {
    background: linear-gradient(135deg, rgba(255, 133, 52, 0.05), rgba(255, 45, 138, 0.05));
    border-color: var(--paper-vivid-orange, #ff8534);
    animation: wbn-border-pulse-rev 2s infinite alternate;
}

@keyframes wbn-border-pulse-rev {
    0% {
        border-color: rgba(255, 133, 52, 0.5);
        box-shadow: 4px 4px 0px rgba(255, 133, 52, 0.3);
    }

    100% {
        border-color: var(--paper-vivid-orange, #ff8534);
        box-shadow: 4px 4px 0px var(--paper-dark, #1a1a2e);
    }
}

.wbn-banner--error {
    background: linear-gradient(135deg, rgba(255, 107, 107, 0.05), rgba(255, 45, 138, 0.05));
    border-color: var(--paper-coral, #ff6b6b);
}

/* ---------- 主栏布局 ---------- */

.wbn-banner-main {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 12px 16px;
    min-height: 48px;
}

.wbn-banner-icon {
    font-size: 1.2rem;
    flex-shrink: 0;
    animation: none;
}

.wbn-banner--generating .wbn-banner-icon {
    animation: wbn-pulse 1.5s ease-in-out infinite;
}

@keyframes wbn-pulse {

    0%,
    100% {
        opacity: 1;
        transform: scale(1);
    }

    50% {
        opacity: 0.6;
        transform: scale(0.95);
    }
}

.wbn-banner-text {
    flex: 1;
    min-width: 0;
}

.wbn-banner-title {
    font-size: 0.9rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
    margin: 0;
    line-height: 1.3;
}

.wbn-banner-subtitle {
    font-size: 0.78rem;
    color: var(--paper-text-secondary, #4a5568);
    margin-top: 2px;
    line-height: 1.3;
}

/* ---------- 进度条 ---------- */

.wbn-banner-progress {
    position: relative;
    width: 100%;
    height: 3px;
    background: rgba(0, 0, 0, 0.06);
    border-radius: 2px;
    margin-top: 6px;
    overflow: hidden;
}

.wbn-banner-progress-bar {
    height: 100%;
    border-radius: 2px;
    background: var(--paper-gradient-aurora, linear-gradient(135deg, #3b82ff, #a855f7));
    transition: width 0.5s ease;
}

/* Indeterminate shimmer overlay on the progress bar track */
.wbn-banner-progress-shimmer {
    position: absolute;
    top: 0;
    left: 0;
    height: 100%;
    width: 40%;
    border-radius: 2px;
    background: linear-gradient(90deg, transparent, rgba(59, 130, 255, 0.4), rgba(168, 85, 247, 0.4), transparent);
    animation: wbn-shimmer 1.8s ease-in-out infinite;
}

@keyframes wbn-shimmer {
    0% {
        left: -40%;
    }

    100% {
        left: 100%;
    }
}

/* Typing dots animation */
.wbn-typing-dots::after {
    content: '';
    animation: wbn-dots 1.5s steps(4, end) infinite;
}

@keyframes wbn-dots {
    0% {
        content: '';
    }

    25% {
        content: '.';
    }

    50% {
        content: '..';
    }

    75% {
        content: '...';
    }

    100% {
        content: '';
    }
}

/* Spinner for generating/revising icon */
.wbn-spinner {
    display: inline-block;
    width: 18px;
    height: 18px;
    border: 2px solid rgba(59, 130, 255, 0.2);
    border-top-color: var(--paper-electric-blue, #3b82ff);
    border-radius: 50%;
    animation: wbn-spin 0.8s linear infinite;
}

.wbn-banner--revising .wbn-spinner {
    border-color: rgba(255, 133, 52, 0.2);
    border-top-color: #ff8534;
}

@keyframes wbn-spin {
    to {
        transform: rotate(360deg);
    }
}

/* ---------- 按钮组 ---------- */

.wbn-banner-actions {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
}

.wbn-banner-btn {
    padding: 6px 14px;
    border-radius: var(--paper-radius-pill, 9999px);
    border: 2px solid var(--paper-dark, #1a1a2e);
    background: var(--paper-bg-secondary, #ffffff);
    color: var(--paper-text-primary, #1a1a2e);
    font-size: 0.8rem;
    font-weight: 700;
    cursor: pointer;
    transition: all 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
    white-space: nowrap;
    box-shadow: 2px 2px 0px var(--paper-dark, #1a1a2e);
    transform: translateY(0);
}

.wbn-banner-btn:hover {
    background: var(--paper-bg-primary, #f0f2f7);
    transform: translateY(-2px);
    box-shadow: 4px 4px 0px var(--paper-dark, #1a1a2e);
}

.wbn-banner-btn:active {
    transform: translateY(1px);
    box-shadow: 1px 1px 0px var(--paper-dark, #1a1a2e);
}

.wbn-banner-btn--primary {
    background: var(--paper-electric-blue, #3b82ff);
    color: white;
}

.wbn-banner-btn--primary:hover {
    background: #2563eb;
    color: white;
}

.wbn-banner-btn--success {
    background: var(--paper-lime-green, #22e06a);
    color: var(--paper-dark, #1a1a2e);
}

.wbn-banner-btn--success:hover {
    background: #1bc95e;
}

.wbn-banner-btn--danger {
    background: var(--paper-coral, #ff6b6b);
    color: white;
}

.wbn-banner-btn--danger:hover {
    background: #ef4444;
    color: white;
}

.wbn-banner-btn--warning {
    background: var(--paper-amber, #f59e0b);
    color: var(--paper-dark, #1a1a2e);
}

.wbn-banner-btn--warning:hover {
    background: #d97706;
}

.wbn-banner-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: translateY(0) !important;
    box-shadow: 2px 2px 0px var(--paper-dark, #1a1a2e) !important;
}

/* ---------- 反馈输入区 ---------- */

.wbn-banner-feedback {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 16px 12px;
}

.wbn-banner-feedback-input {
    flex: 1;
    padding: 8px 14px;
    border-radius: var(--paper-radius-lg, 16px);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    background: var(--paper-bg-primary, #f0f2f7);
    font-size: 0.85rem;
    color: var(--paper-text-primary, #1a1a2e);
    outline: none;
    transition: all 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
}

.wbn-banner-feedback-input:focus {
    border-color: var(--paper-electric-blue, #3b82ff);
    background: var(--paper-bg-secondary, #ffffff);
    box-shadow: var(--paper-shadow-hard-sm, 2px 2px 0px #1a1a2e);
    transform: translateY(-1px);
}

.wbn-banner-feedback-input::placeholder {
    color: var(--paper-text-tertiary, #8896ab);
}

/* ---------- 错误消息 ---------- */

.wbn-banner-error {
    padding: 0 16px 12px;
    font-size: 0.8rem;
    color: var(--paper-coral, #ff6b6b);
    word-break: break-word;
}

/* ---------- 步骤进度指示器 ---------- */

.wbn-banner-steps {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 0 16px 10px;
}

.wbn-banner-step-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: rgba(0, 0, 0, 0.1);
    transition: all 0.3s;
}

.wbn-banner-step-dot--completed {
    background: var(--paper-lime-green, #22e06a);
}

.wbn-banner-step-dot--active {
    background: var(--paper-electric-blue, #3b82ff);
    box-shadow: 0 0 6px rgba(59, 130, 255, 0.4);
    transform: scale(1.25);
}

.wbn-banner-step-dot--error {
    background: var(--paper-coral, #ff6b6b);
}

.wbn-banner-step-label {
    font-size: 0.7rem;
    color: var(--paper-text-tertiary, #8896ab);
    margin-left: 4px;
}

/* ---------- Synopsis 预览 ---------- */

.wbn-synopsis-preview {
    padding: 0 16px 12px;
}

.wbn-synopsis-preview-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
    margin-bottom: 8px;
}

.wbn-synopsis-preview-content {
    max-height: 400px;
    overflow-y: auto;
    background: var(--paper-bg-primary, #f0f2f7);
    border-radius: var(--paper-radius-lg, 16px);
    padding: var(--paper-space-4, 16px);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    font-size: 0.85rem;
    line-height: 1.6;
    color: var(--paper-text-secondary, #4a5568);
    box-shadow: inset 0 2px 4px rgba(0, 0, 0, 0.02);
}

.wbn-synopsis-section {
    margin-bottom: 12px;
}

.wbn-synopsis-section:last-child {
    margin-bottom: 0;
}

.wbn-synopsis-creature {
    display: flex;
    flex-direction: column;
    gap: 2px;
    padding: 6px 0;
    border-bottom: 1px solid rgba(0, 0, 0, 0.04);
}

.wbn-synopsis-creature:last-child {
    border-bottom: none;
}

.wbn-synopsis-creature-id {
    font-weight: 600;
    font-size: 0.82rem;
    color: var(--paper-electric-blue, #3b82ff);
}

.wbn-synopsis-creature-plan {
    font-size: 0.78rem;
    color: var(--paper-text-tertiary, #8896ab);
    white-space: pre-wrap;
}

/* ---------- 角色批次总览 ---------- */

.wbn-batch-breakdown {
    padding: 0 16px 12px;
}

.wbn-batch-breakdown-header {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
    margin-bottom: 8px;
}

.wbn-batch-list {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
}

.wbn-batch-item {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 4px 10px;
    border-radius: var(--paper-radius-pill, 9999px);
    border: 1.5px solid var(--paper-border-color, #e2e8f0);
    background: var(--paper-bg-primary, #f0f2f7);
    transition: all 0.2s;
}

.wbn-batch-item--active {
    border-color: var(--paper-electric-blue, #3b82ff);
    background: rgba(59, 130, 255, 0.06);
    box-shadow: var(--paper-shadow-hard-sm, 2px 2px 0px #1a1a2e);
}

.wbn-batch-item--completed {
    border-color: var(--paper-lime-green, #22e06a);
    background: rgba(34, 224, 106, 0.04);
}

.wbn-batch-item--pending {
    opacity: 0.5;
    border-style: dashed;
}

.wbn-batch-item-label {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    gap: 4px;
}

.wbn-batch-item-label-text {
    font-size: 0.72rem;
    font-weight: 700;
    color: var(--paper-text-primary, #1a1a2e);
}

.wbn-batch-item-badge {
    font-size: 0.6rem;
    font-weight: 600;
    padding: 0px 5px;
    border-radius: var(--paper-radius-pill, 9999px);
    white-space: nowrap;
    line-height: 1.5;
}

.wbn-batch-item--active .wbn-batch-item-badge {
    background: var(--paper-electric-blue, #3b82ff);
    color: white;
}

.wbn-batch-item--completed .wbn-batch-item-badge {
    background: var(--paper-lime-green, #22e06a);
    color: var(--paper-dark, #1a1a2e);
}

.wbn-batch-item--pending .wbn-batch-item-badge {
    background: rgba(0, 0, 0, 0.08);
    color: var(--paper-text-tertiary, #8896ab);
}

.wbn-batch-item-creatures {
    display: inline-flex;
    flex-wrap: wrap;
    gap: 3px;
}

.wbn-batch-creature-tag {
    display: inline-flex;
    align-items: center;
    padding: 1px 6px;
    border-radius: var(--paper-radius-pill, 9999px);
    font-size: 0.7rem;
    font-weight: 500;
    border: 1px solid rgba(0, 0, 0, 0.08);
    background: var(--paper-bg-secondary, #ffffff);
    color: var(--paper-text-secondary, #4a5568);
}

.wbn-batch-item--active .wbn-batch-creature-tag {
    border-color: rgba(59, 130, 255, 0.25);
    color: var(--paper-electric-blue, #3b82ff);
}

.wbn-batch-item--completed .wbn-batch-creature-tag {
    border-color: rgba(34, 224, 106, 0.25);
    color: var(--paper-lime-green-dark, #15803d);
}

.wbn-batch-creature-tag--player {
    border-color: rgba(168, 85, 247, 0.3);
    color: var(--paper-vivid-purple, #a855f7);
}

.wbn-batch-hint {
    margin-top: 8px;
    padding: 6px 10px;
    border-radius: var(--paper-radius-md, 12px);
    background: rgba(255, 193, 7, 0.1);
    border: 1.5px solid rgba(255, 193, 7, 0.3);
    font-size: 0.75rem;
    color: var(--paper-text-secondary, #4a5568);
    line-height: 1.5;
}

/* ---------- Inline QueryUser 表单 ---------- */

.wbn-banner-query {
    padding: 0 12px 8px;
}

.wbn-query-form {
    display: flex;
    flex-direction: column;
    gap: 12px;
    background: var(--paper-bg-primary, #f0f2f7);
    border-radius: var(--paper-radius-lg, 16px);
    padding: var(--paper-space-4, 16px);
    border: 2px solid var(--paper-border-color, #e2e8f0);
}

.wbn-query-title {
    font-size: 0.88rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
    margin-bottom: 4px;
}

.wbn-query-field {
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.wbn-query-label {
    font-size: 0.78rem;
    font-weight: 500;
    color: var(--paper-text-secondary, #4a5568);
}

.wbn-query-input,
.wbn-query-select {
    padding: 8px 12px;
    border-radius: var(--paper-radius-md, 12px);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    background: var(--paper-bg-secondary, #ffffff);
    font-size: 0.85rem;
    color: var(--paper-text-primary, #1a1a2e);
    outline: none;
    transition: all 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
}

.wbn-query-input:focus,
.wbn-query-select:focus {
    border-color: var(--paper-electric-blue, #3b82ff);
    box-shadow: var(--paper-shadow-hard-sm, 2px 2px 0px #1a1a2e);
    transform: translateY(-1px);
}

.wbn-query-multiselect {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
}

.wbn-query-chip {
    display: inline-flex;
    align-items: center;
    padding: 4px 12px;
    border-radius: var(--paper-radius-pill, 9999px);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    background: var(--paper-bg-secondary, #ffffff);
    font-size: 0.8rem;
    cursor: pointer;
    transition: all 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
    user-select: none;
    font-weight: 600;
}

.wbn-query-chip:hover {
    border-color: var(--paper-electric-blue, #3b82ff);
    transform: translateY(-1px);
    box-shadow: 2px 2px 0px var(--paper-border-color, #e2e8f0);
}

.wbn-query-chip.active {
    background: var(--paper-electric-blue-alpha, rgba(59, 130, 255, 0.15));
    border-color: var(--paper-electric-blue, #3b82ff);
    color: var(--paper-electric-blue, #3b82ff);
    font-weight: 500;
}

/* Custom input toggle for select/multiselect */
.wbn-query-custom-row {
    display: flex;
    gap: 6px;
    align-items: center;
}

.wbn-query-custom-row .wbn-query-select {
    flex: 1;
    max-width: 280px;
}

.wbn-query-custom-row .wbn-query-input {
    flex: 1;
    max-width: 280px;
}

.wbn-query-custom-toggle {
    padding: 5px 10px;
    border-radius: 6px;
    border: 1px solid rgba(0, 0, 0, 0.1);
    background: rgba(59, 130, 255, 0.08);
    color: var(--paper-electric-blue, #3b82ff);
    font-size: 0.75rem;
    font-weight: 500;
    cursor: pointer;
    white-space: nowrap;
    transition: all 0.2s;
}

.wbn-query-custom-toggle:hover {
    background: rgba(59, 130, 255, 0.15);
}

.wbn-query-custom-toggle.active {
    background: rgba(0, 0, 0, 0.04);
    color: var(--paper-text-secondary, #4a5568);
    border-color: rgba(0, 0, 0, 0.08);
}

.wbn-query-chip--custom {
    border-style: dashed;
}

.wbn-query-custom-add .wbn-query-input {
    width: 100%;
}

/* ---------- Generating overlay (inside paper-content) ---------- */

.wbn-generating-overlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(255, 255, 255, 0.65);
    backdrop-filter: blur(2px);
    border-radius: 8px;
}

.wbn-generating-overlay-content {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 12px 24px;
    border-radius: 12px;
    background: rgba(255, 255, 255, 0.9);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.08);
    font-size: 0.88rem;
    font-weight: 500;
    color: var(--paper-text-secondary, #4a5568);
}

/* Preview-only notice bar when WB session is active but not generating */
.wbn-preview-notice {
    position: sticky;
    top: 0;
    z-index: 10;
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    background: linear-gradient(135deg, rgba(255, 193, 7, 0.15), rgba(255, 133, 52, 0.12));
    border-bottom: 2px solid rgba(255, 193, 7, 0.4);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
    user-select: none;
}

.wbn-preview-notice-icon {
    font-size: 1rem;
    flex-shrink: 0;
}

/* ---------- Setup 模式 ---------- */

.wbn-banner--setup {
    background: var(--paper-bg-secondary, #ffffff);
    border-color: var(--paper-border-color, #e2e8f0);
}

/* ---------- Resume paused session prompt ---------- */

.wbn-banner-resume {
    margin: 0 16px 12px;
    padding: 10px 14px;
    border-radius: var(--paper-radius-soft, 12px);
    border: 2px dashed var(--paper-amber, #f59e0b);
    background: rgba(245, 158, 11, 0.06);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    flex-wrap: wrap;
}

.wbn-banner-resume-text {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.84rem;
    color: var(--paper-text-secondary, #4a5568);
    min-width: 0;
    flex: 1;
}

.wbn-banner-resume-icon {
    font-size: 1.1rem;
    flex-shrink: 0;
}

.wbn-banner-resume-actions {
    display: flex;
    gap: 6px;
    flex-shrink: 0;
}

.wbn-banner-setup {
    padding: 0 16px 12px;
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.wbn-banner-setup-input {
    width: 100%;
    padding: 12px 16px;
    border-radius: var(--paper-radius-lg, 16px);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    background: var(--paper-bg-primary, #f0f2f7);
    font-size: 0.85rem;
    color: var(--paper-text-primary, #1a1a2e);
    outline: none;
    resize: vertical;
    min-height: 60px;
    transition: all 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    font-family: inherit;
    box-sizing: border-box;
}

.wbn-banner-setup-input:focus {
    border-color: var(--paper-electric-blue, #3b82ff);
    background: var(--paper-bg-secondary, #ffffff);
    box-shadow: var(--paper-shadow-hard-sm, 2px 2px 0px #1a1a2e);
    transform: translateY(-1px);
}

.wbn-banner-setup-input::placeholder {
    color: var(--paper-text-tertiary, #8896ab);
}

.wbn-banner-setup-footer {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 12px;
}

.wbn-banner-setup-right {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-shrink: 0;
}

/* ---------- Game style toggle ---------- */

.wbn-banner-game-style {
    display: flex;
    gap: 0;
    border-radius: 8px;
    border: 1.5px solid var(--paper-dark, #1a1a2e);
    overflow: hidden;
    flex-shrink: 0;
}

.wbn-banner-style-btn {
    padding: 4px 12px;
    font-size: 0.78rem;
    font-weight: 500;
    border: none;
    background: var(--paper-bg-primary, #f0f2f7);
    color: var(--paper-text-secondary, #666);
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
    white-space: nowrap;
}

.wbn-banner-style-btn:not(:last-child) {
    border-right: 1.5px solid var(--paper-dark, #1a1a2e);
}

.wbn-banner-style-btn.active {
    background: var(--paper-dark, #1a1a2e);
    color: var(--paper-bg-primary, #ffffff);
}

.wbn-banner-style-btn:hover:not(.active) {
    background: var(--paper-bg-tertiary, #e2e5ed);
}

/* ---------- Compact attachment bar ---------- */

.wbn-banner-attachments {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 6px;
    flex: 1;
    min-width: 0;
}

.wbn-attach-btn {
    padding: 5px 14px;
    font-size: 0.8rem;
    font-weight: 500;
    border-radius: 8px;
    border: 1.5px solid var(--paper-dark, #1a1a2e);
    background: var(--paper-bg-primary, #f0f2f7);
    color: var(--paper-text-primary, #1a1a2e);
    cursor: pointer;
    transition: border-color 0.15s, color 0.15s, background 0.15s, box-shadow 0.15s;
    white-space: nowrap;
}

.wbn-attach-btn:hover {
    background: var(--paper-bg-secondary, #ffffff);
    box-shadow: 2px 2px 0px var(--paper-dark, #1a1a2e);
    transform: translateY(-1px);
}

.wbn-attach-tag {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 3px 8px;
    border-radius: 6px;
    background: rgba(59, 130, 255, 0.08);
    border: 1px solid rgba(59, 130, 255, 0.2);
    font-size: 0.75rem;
    color: var(--paper-text-secondary, #4a5568);
    max-width: 220px;
}

.wbn-attach-tag--lorebook {
    background: rgba(168, 85, 247, 0.08);
    border-color: rgba(168, 85, 247, 0.2);
}

.wbn-attach-tag-label {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.wbn-attach-tag-remove {
    background: none;
    border: none;
    color: var(--paper-text-tertiary, #8896ab);
    cursor: pointer;
    font-size: 0.9rem;
    line-height: 1;
    padding: 0 1px;
    transition: color 0.15s;
    flex-shrink: 0;
}

.wbn-attach-tag-remove:hover {
    color: var(--paper-error, #ef4444);
}

/* ---------- 内联日志面板 ---------- */

.wbn-banner-log {
    max-height: 200px;
    overflow-y: auto;
    margin: 0 16px 12px;
    padding: 8px 12px;
    background: rgba(0, 0, 0, 0.03);
    border-radius: 8px;
    font-family: monospace;
    font-size: 0.75rem;
    line-height: 1.6;
    color: var(--paper-text-tertiary, #8896ab);
}

.wbn-banner-log-line {
    padding: 1px 0;
    border-bottom: 1px solid rgba(0, 0, 0, 0.03);
    word-break: break-word;
}

.wbn-banner-log-time {
    color: var(--paper-text-quaternary, #aab4c2);
    margin-right: 6px;
    font-size: 0.7rem;
    user-select: all;
}

/* ---------- Draft Review 表单 ---------- */

.wbn-draft-review {
    display: flex;
    flex-direction: column;
    gap: 6px;
    background: rgba(255, 255, 255, 0.6);
    border-radius: 8px;
    padding: 10px;
    border: 1px solid rgba(34, 224, 106, 0.2);
}

.wbn-draft-review-title {
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
    margin-bottom: 2px;
}

/* 2-column grid for text fields */
.wbn-draft-review-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 6px;
}

.wbn-draft-review-field {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.wbn-draft-review-field--full {
    grid-column: 1 / -1;
}

.wbn-draft-review-label {
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--paper-text-secondary, #4a5568);
}

.wbn-draft-review-textarea {
    padding: 4px 8px;
    border-radius: 6px;
    border: 1px solid rgba(0, 0, 0, 0.1);
    background: rgba(255, 255, 255, 0.9);
    font-size: 0.78rem;
    color: var(--paper-text-primary, #1a1a2e);
    outline: none;
    resize: vertical;
    font-family: inherit;
    line-height: 1.4;
}

.wbn-draft-review-textarea:focus {
    border-color: var(--paper-electric-blue, #3b82ff);
}

/* Side-by-side row for regions + organizations */
.wbn-draft-review-row {
    display: flex;
    gap: 8px;
}

.wbn-draft-review-section {
    display: flex;
    flex-direction: column;
    gap: 3px;
}

.wbn-draft-review-section-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--paper-text-primary, #1a1a2e);
}

/* Entity grid: compact cards, 2-3 per row */
.wbn-draft-review-entity-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
}

.wbn-draft-review-entity-card {
    display: flex;
    align-items: center;
    gap: 3px;
    padding: 2px 4px;
    border-radius: 4px;
    border: 1px solid rgba(0, 0, 0, 0.06);
    background: rgba(255, 255, 255, 0.7);
}

.wbn-draft-review-id {
    width: 100px;
    padding: 2px 4px;
    border-radius: 3px;
    border: 1px solid rgba(0, 0, 0, 0.08);
    background: rgba(0, 0, 0, 0.02);
    font-size: 0.72rem;
    font-family: monospace;
    color: var(--paper-text-secondary, #4a5568);
    outline: none;
}

.wbn-draft-review-id:focus {
    border-color: var(--paper-electric-blue, #3b82ff);
}

.wbn-draft-review-name {
    width: 70px;
    padding: 2px 4px;
    border-radius: 3px;
    border: 1px solid rgba(0, 0, 0, 0.1);
    background: rgba(255, 255, 255, 0.9);
    font-size: 0.75rem;
    color: var(--paper-text-primary, #1a1a2e);
    outline: none;
}

.wbn-draft-review-name:focus {
    border-color: var(--paper-electric-blue, #3b82ff);
}

.wbn-draft-review-player {
    display: flex;
    align-items: center;
    gap: 2px;
    font-size: 0.68rem;
    color: var(--paper-text-secondary, #4a5568);
    white-space: nowrap;
    cursor: pointer;
    user-select: none;
}

.wbn-draft-review-remove {
    background: none;
    border: none;
    color: var(--paper-text-tertiary, #8896ab);
    cursor: pointer;
    font-size: 0.85rem;
    line-height: 1;
    padding: 0 2px;
    border-radius: 3px;
    transition: color 0.15s;
}

.wbn-draft-review-remove:hover {
    color: var(--paper-error, #ef4444);
    background: rgba(239, 68, 68, 0.08);
}

/* ---------- 移动端响应式 ---------- */

@media (max-width: 640px) {
    .wbn-banner {
        margin: 8px;
        border-radius: 14px;
    }

    .wbn-banner-setup-footer {
        flex-direction: column;
        align-items: stretch;
    }

    .wbn-banner-setup-right {
        flex-wrap: wrap;
        gap: 8px;
    }

    .wbn-banner-game-style {
        width: 100%;
    }

    .wbn-banner-style-btn {
        flex: 1;
        text-align: center;
    }

    .wbn-banner-btn {
        padding: 8px 14px;
        font-size: 0.82rem;
    }

    .wbn-banner-setup-right .wbn-banner-btn--primary {
        width: 100%;
        text-align: center;
    }

    /* Draft review: single column on mobile */
    .wbn-draft-review-grid {
        grid-template-columns: 1fr;
    }

    .wbn-draft-review-row {
        flex-direction: column;
    }

    /* Feedback input row */
    .wbn-banner-feedback {
        flex-direction: column;
        gap: 8px;
    }

    .wbn-banner-feedback .wbn-banner-actions {
        width: 100%;
        justify-content: stretch;
    }

    .wbn-banner-feedback .wbn-banner-btn {
        flex: 1;
    }

    /* Banner main row */
    .wbn-banner-main {
        flex-wrap: wrap;
        gap: 8px;
    }

    .wbn-banner-actions {
        width: 100%;
        justify-content: flex-end;
    }

    /* Query form chips */
    .wbn-query-custom-row {
        flex-wrap: wrap;
    }

    .wbn-query-custom-row .wbn-query-select,
    .wbn-query-custom-row .wbn-query-input {
        max-width: 100%;
    }

    /* Resume bar */
    .wbn-banner-resume {
        flex-direction: column;
        align-items: stretch;
    }

    .wbn-banner-resume-actions {
        justify-content: flex-end;
    }
}

/**
 * WorldBuilderBanner - 世界构建器顶部横幅
 *
 * 嵌入主编辑器内容区顶部，替代原有模态框。
 * 两大模式：
 *   - Setup 模式（无 session）：显示输入框 + 开始按钮
 *   - Active 模式（有 session）：生成中 → 等待反馈 → 修订中（循环）
 */
import React, { useState, useCallback, useRef, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import type { StateData, CopilotConfig } from '../../api/types'
import type {
    WBNSession,
    WBNPhaseId,
    WBNDraftOutput,
    WBNGameStyle,
    QueryUserRequest,
} from '../../api/worldBuilderNextTypes'
import { WBN_PHASE_IDS } from '../../api/worldBuilderNextTypes'
import {
    advancePhase,
    saveWBNSession,
    startNewSession,
    getProgressInfo,
    getPhaseTab,
    applyPhaseToState,
    initCreatureBatching,
    extractUserDesignNotes,
    getCurrentBatch,
    mergeReferenceFiles,
    mergeLorebooks,
} from '../../api/worldBuilderNextService'
import type { WBNReferenceFile, LorebookData } from '../../api/worldBuilderNextTypes'
import { parseSillyTavernLorebook } from '../../api/lorebookParser'
import { streamWBNPhase, streamWBNRevision } from './worldBuilderNextChat'
import type { WBNToolContext } from './worldBuilderNextChat'
import type { TabType } from '../state-editor/types'
import { createEmptyWorld } from '../state-editor/types'
import './WorldBuilderBanner.css'

// ============================================================================
// Types
// ============================================================================

type BannerMode = 'setup' | 'generating' | 'waiting' | 'revising' | 'error'

interface LogEntry {
    time: number
    text: string
}

export interface WorldBuilderBannerProps {
    session: WBNSession | null
    onSessionChange: (session: WBNSession | null) => void
    state: StateData
    onStateChange: (state: StateData) => void
    onTabChange: (tab: TabType) => void
    config: CopilotConfig
    onClose: () => void
    /** A paused session detected at mount time (from IndexedDB) */
    pausedSession?: WBNSession | null
    /** Called when user chooses to discard the paused session */
    onDiscardPaused?: () => void
}

// ============================================================================
// Inline QueryUser Form
// ============================================================================

const InlineQueryUserForm: React.FC<{
    request: QueryUserRequest
    onSubmit: (data: Record<string, unknown>) => void
    t: (key: string, opts?: Record<string, unknown>) => string
}> = ({ request, onSubmit, t }) => {
    const [formData, setFormData] = useState<Record<string, unknown>>(() => {
        const defaults: Record<string, unknown> = {}
        request.fields.forEach(f => {
            if (f.default_value !== undefined) {
                defaults[f.key] = f.default_value
            } else if (f.type === 'multiselect') {
                defaults[f.key] = []
            } else {
                defaults[f.key] = ''
            }
        })
        return defaults
    })
    // Track which fields are in custom input mode
    const [customInputFields, setCustomInputFields] = useState<Set<string>>(new Set())

    const toggleCustomInput = (fieldKey: string) => {
        setCustomInputFields(prev => {
            const next = new Set(prev)
            if (next.has(fieldKey)) {
                next.delete(fieldKey)
            } else {
                next.add(fieldKey)
            }
            return next
        })
    }

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault()
        onSubmit(formData)
    }

    return (
        <form className="wbn-query-form" onSubmit={handleSubmit}>
            <div className="wbn-query-title">{request.title}</div>
            {request.fields.map(field => (
                <div key={field.key} className="wbn-query-field">
                    <label className="wbn-query-label">{field.label}</label>
                    {field.type === 'select' && field.options ? (
                        customInputFields.has(field.key) ? (
                            <div className="wbn-query-custom-row">
                                <input
                                    type="text"
                                    className="wbn-query-input"
                                    value={(formData[field.key] as string) || ''}
                                    placeholder={t('worldBuilder.queryCustomPlaceholder')}
                                    onChange={e => setFormData(prev => ({ ...prev, [field.key]: e.target.value }))}
                                    autoFocus
                                />
                                <button type="button" className="wbn-query-custom-toggle active" onClick={() => toggleCustomInput(field.key)}>
                                    {t('worldBuilder.queryBackToOptions')}
                                </button>
                            </div>
                        ) : (
                            <div className="wbn-query-custom-row">
                                <select
                                    className="wbn-query-select"
                                    value={(formData[field.key] as string) || ''}
                                    onChange={e => setFormData(prev => ({ ...prev, [field.key]: e.target.value }))}
                                >
                                    <option value="">{t('worldBuilder.querySelectPlaceholder')}</option>
                                    {field.options.map(opt => (
                                        <option key={opt} value={opt}>{opt}</option>
                                    ))}
                                </select>
                                <button type="button" className="wbn-query-custom-toggle" onClick={() => toggleCustomInput(field.key)}>
                                    {t('worldBuilder.queryCustom')}
                                </button>
                            </div>
                        )
                    ) : field.type === 'multiselect' && field.options ? (
                        <div>
                            <div className="wbn-query-multiselect">
                                {field.options.map(opt => {
                                    const selected = ((formData[field.key] as string[]) || []).includes(opt)
                                    return (
                                        <label key={opt} className={`wbn-query-chip ${selected ? 'active' : ''}`}>
                                            <input
                                                type="checkbox"
                                                checked={selected}
                                                onChange={() => {
                                                    const current = (formData[field.key] as string[]) || []
                                                    const next = selected
                                                        ? current.filter(v => v !== opt)
                                                        : [...current, opt]
                                                    setFormData(prev => ({ ...prev, [field.key]: next }))
                                                }}
                                                style={{ display: 'none' }}
                                            />
                                            {opt}
                                        </label>
                                    )
                                })}
                                {/* Render custom-added values not in original options */}
                                {((formData[field.key] as string[]) || [])
                                    .filter(v => !(field.options || []).includes(v))
                                    .map(customVal => (
                                        <label key={customVal} className="wbn-query-chip active wbn-query-chip--custom-value">
                                            <input
                                                type="checkbox"
                                                checked={true}
                                                onChange={() => {
                                                    const current = (formData[field.key] as string[]) || []
                                                    setFormData(prev => ({ ...prev, [field.key]: current.filter(v => v !== customVal) }))
                                                }}
                                                style={{ display: 'none' }}
                                            />
                                            ✏️ {customVal}
                                        </label>
                                    ))
                                }
                                <button
                                    type="button"
                                    className={`wbn-query-chip wbn-query-chip--custom ${customInputFields.has(field.key) ? 'active' : ''}`}
                                    onClick={() => toggleCustomInput(field.key)}
                                >
                                    ✏️ {t('worldBuilder.queryCustomChip')}
                                </button>
                            </div>
                            {customInputFields.has(field.key) && (
                                <div className="wbn-query-custom-add" style={{ marginTop: 6 }}>
                                    <input
                                        type="text"
                                        className="wbn-query-input"
                                        placeholder={t('worldBuilder.queryCustomOptionPlaceholder')}
                                        autoFocus
                                        onKeyDown={e => {
                                            if (e.key === 'Enter') {
                                                e.preventDefault()
                                                const val = (e.target as HTMLInputElement).value.trim()
                                                if (val) {
                                                    const current = (formData[field.key] as string[]) || []
                                                    if (!current.includes(val)) {
                                                        setFormData(prev => ({ ...prev, [field.key]: [...current, val] }))
                                                    }
                                                    ;(e.target as HTMLInputElement).value = ''
                                                }
                                            }
                                        }}
                                    />
                                </div>
                            )}
                        </div>
                    ) : (
                        <input
                            type="text"
                            className="wbn-query-input"
                            value={(formData[field.key] as string) || ''}
                            placeholder={field.default_value || ''}
                            onChange={e => setFormData(prev => ({ ...prev, [field.key]: e.target.value }))}
                        />
                    )}
                </div>
            ))}
            <button type="submit" className="wbn-banner-btn wbn-banner-btn--primary" style={{ marginTop: 8, alignSelf: 'flex-end' }}>
                {t('worldBuilder.querySubmit')}
            </button>
        </form>
    )
}

// ============================================================================
// Helpers
// ============================================================================

/** Convert literal \n sequences (from LLM output) into real newlines */
const fixNewlines = (text: string | undefined): string => {
    if (!text) return ''
    return text.replace(/\\n/g, '\n')
}

// ============================================================================
// Component
// ============================================================================

const WorldBuilderBanner: React.FC<WorldBuilderBannerProps> = ({
    session,
    onSessionChange,
    state,
    onStateChange,
    onTabChange,
    config,
    onClose,
    pausedSession,
    onDiscardPaused,
}) => {
    const { t } = useTranslation('editor')
    const getPhaseLabel = useCallback((phaseId: WBNPhaseId) => t(`worldBuilder.phases.${phaseId}`), [t])
    const [mode, setMode] = useState<BannerMode>(() => session ? 'generating' : 'setup')
    const [feedbackText, setFeedbackText] = useState('')
    const [errorMessage, setErrorMessage] = useState('')
    const [statusText, setStatusText] = useState('')
    const [revisionSummary, setRevisionSummary] = useState('')
    const [showSynopsisPreview, setShowSynopsisPreview] = useState(false)
    // Setup mode state
    const [setupPrompt, setSetupPrompt] = useState('')
    const [gameStyle, setGameStyle] = useState<WBNGameStyle>('narrative')
    const [skipOrgs, setSkipOrgs] = useState(true)
    const [clearBeforeGenerate, setClearBeforeGenerate] = useState(true)
    const [skipExtraction, setSkipExtraction] = useState(false)
    const abortRef = useRef(false)
    const stateRef = useRef(state)
    const sessionRef = useRef(session)
    const isRunningRef = useRef(false)
    // Log events (internal — shown in banner expandable log)
    const [logEvents, setLogEvents] = useState<LogEntry[]>([])
    const [showLog, setShowLog] = useState(false)
    const logEndRef = useRef<HTMLDivElement>(null)

    const onLogEvent = useCallback((event: string) => {
        setLogEvents(prev => [...prev.slice(-200), { time: Date.now(), text: event }])
    }, [])

    const handleExportLog = useCallback(() => {
        const lines: string[] = []
        // Session metadata header
        lines.push('=== World Builder Log Export ===')
        lines.push(`Export Time: ${new Date().toISOString()}`)
        if (sessionRef.current) {
            const s = sessionRef.current
            lines.push(`Session ID: ${s.id}`)
            lines.push(`Status: ${s.status}`)
            lines.push(`Current Phase: ${s.currentPhase}`)
            lines.push(`Game Style: ${s.gameStyle || 'N/A'}`)
            lines.push(`Skip Organizations: ${s.skipOrganizations ?? false}`)
            lines.push(`Skip Extraction: ${s.skipExtraction ?? false}`)
            lines.push(`Created: ${new Date(s.createdAt).toISOString()}`)
            lines.push(`Updated: ${new Date(s.updatedAt).toISOString()}`)
            lines.push(`Initial Prompt: ${s.initialPrompt}`)
            // Phase statuses
            lines.push('')
            lines.push('--- Phase Statuses ---')
            for (const phaseId of WBN_PHASE_IDS) {
                const phase = s.phases[phaseId]
                const outputSize = phase.output ? JSON.stringify(phase.output).length : 0
                lines.push(`  ${phaseId}: ${phase.status}${phase.error ? ` (error: ${phase.error})` : ''}${outputSize ? ` [output: ${outputSize} chars]` : ''}`)
            }
            if (s.creatureBatching) {
                lines.push(`Creature Batching: batch ${s.creatureBatching.currentBatch + 1}/${s.creatureBatching.totalBatches}`)
            }
        }
        lines.push('')
        lines.push('--- Log Entries ---')
        for (const entry of logEvents) {
            const ts = new Date(entry.time).toISOString()
            lines.push(`[${ts}] ${entry.text}`)
        }
        // Phase outputs (for debugging)
        if (sessionRef.current) {
            lines.push('')
            lines.push('--- Phase Outputs (JSON) ---')
            for (const phaseId of WBN_PHASE_IDS) {
                const phase = sessionRef.current.phases[phaseId]
                if (phase.output) {
                    lines.push(`\n== ${phaseId} ==`)
                    lines.push(JSON.stringify(phase.output, null, 2))
                }
            }
        }
        const blob = new Blob([lines.join('\n')], { type: 'text/plain;charset=utf-8' })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19)
        a.download = `world-builder-log-${ts}.txt`
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        URL.revokeObjectURL(url)
    }, [logEvents])

    // Auto-scroll log
    useEffect(() => {
        logEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    }, [logEvents])

    // Local file/lorebook state (multiple files + multiple lorebooks, merged on session start)
    const [setupFiles, setSetupFiles] = useState<WBNReferenceFile[]>([])
    const [setupLorebooks, setSetupLorebooks] = useState<LorebookData[]>([])
    const fileInputRef = useRef<HTMLInputElement>(null)
    const lorebookInputRef = useRef<HTMLInputElement>(null)
    const [lorebookError, setLorebookError] = useState<string>('')

    const handleFileUpload = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return
        const reader = new FileReader()
        reader.onload = () => {
            const content = reader.result as string
            const ext = file.name.split('.').pop()?.toLowerCase() || ''
            const typeMap: Record<string, WBNReferenceFile['type']> = {
                md: 'md', json: 'json', txt: 'txt',
                png: 'image', jpg: 'image', jpeg: 'image', gif: 'image', webp: 'image', svg: 'image',
            }
            setSetupFiles(prev => [...prev, {
                name: file.name,
                content,
                type: typeMap[ext] || 'txt',
                size: file.size,
            }])
        }
        reader.readAsText(file)
        e.target.value = ''
    }, [])

    const handleRemoveFile = useCallback((index: number) => {
        setSetupFiles(prev => prev.filter((_, i) => i !== index))
    }, [])

    const handleLorebookUpload = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return
        setLorebookError('')
        const reader = new FileReader()
        reader.onload = () => {
            try {
                const json = JSON.parse(reader.result as string)
                const parsed = parseSillyTavernLorebook(json, file.name)
                if (!parsed) {
                    setLorebookError(t('worldBuilder.lorebookParseError'))
                    return
                }
                setSetupLorebooks(prev => [...prev, parsed])
            } catch {
                setLorebookError(t('worldBuilder.lorebookParseError'))
            }
        }
        reader.readAsText(file)
        e.target.value = ''
    }, [t])

    const handleRemoveLorebook = useCallback((index: number) => {
        setSetupLorebooks(prev => prev.filter((_, i) => i !== index))
    }, [])

    // Internal queryUser state
    const [pendingQuery, setPendingQuery] = useState<QueryUserRequest | null>(null)
    const pendingQueryResolveRef = useRef<((data: Record<string, unknown>) => void) | null>(null)

    const queryUser = useCallback((request: QueryUserRequest): Promise<Record<string, unknown>> => {
        return new Promise((resolve) => {
            pendingQueryResolveRef.current = resolve
            setPendingQuery(request)
        })
    }, [])

    // Keep refs in sync
    useEffect(() => { stateRef.current = state }, [state])
    useEffect(() => { sessionRef.current = session }, [session])

    // Auto-start generating on mount or when session advances
    useEffect(() => {
        if (!session) return
        const phase = session.phases[session.currentPhase]
        if (phase.status === 'active' && !isRunningRef.current) {
            runPhase()
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [session?.currentPhase, session?.creatureBatching?.currentBatch])

    // ========================================================================
    // Setup → Start Session
    // ========================================================================

    const handleStartSession = useCallback(() => {
        if (!setupPrompt.trim()) return
        // Clear existing data before generating
        if (clearBeforeGenerate) {
            onStateChange({
                World: createEmptyWorld(),
                Creatures: [],
                Regions: [],
                Organizations: [],
                StoryHistory: [],
                GameInitialStory: undefined,
            } as StateData)
        }
        const mergedFile = mergeReferenceFiles(setupFiles)
        const mergedLorebook = mergeLorebooks(setupLorebooks)
        const newSession = startNewSession(setupPrompt.trim(), mergedFile, mergedLorebook, { gameStyle, skipOrganizations: skipOrgs, skipExtraction })
        onSessionChange(newSession)
        setMode('generating')
        setLogEvents([])
    }, [setupPrompt, setupFiles, setupLorebooks, onSessionChange, clearBeforeGenerate, onStateChange, gameStyle, skipOrgs, skipExtraction])

    // ========================================================================
    // Phase Execution
    // ========================================================================

    const runPhase = useCallback(async () => {
        if (isRunningRef.current || !sessionRef.current) return
        isRunningRef.current = true
        abortRef.current = false

        const phaseId = sessionRef.current.currentPhase
        const label = getPhaseLabel(phaseId)
        const batchInfo = phaseId === 'creatures' ? getCurrentBatch(sessionRef.current) : null

        setMode('generating')
        setErrorMessage('')
        setRevisionSummary('')

        if (batchInfo) {
            setStatusText(t('worldBuilder.generatingPhaseBatch', { label, current: batchInfo.batchIndex + 1, total: batchInfo.totalBatches }))
        } else {
            setStatusText(t('worldBuilder.generatingPhase', { label }))
        }
        onLogEvent(t('worldBuilder.logStart', { label }))

        // Update phase status
        const s: WBNSession = { ...sessionRef.current! }
        s.phases = { ...s.phases }
        s.phases[phaseId] = { ...s.phases[phaseId], status: 'generating' }
        onSessionChange(s)
        sessionRef.current = s

        const context: WBNToolContext = {
            state: stateRef.current,
            session: sessionRef.current!,
            config,
            queryUser,
        }

        try {
            const gen = streamWBNPhase(config, sessionRef.current, phaseId, context)

            for await (const event of gen) {
                if (abortRef.current) break

                switch (event.type) {
                    case 'ai_text':
                        // Stream text to log panel (show last 200 chars)
                        onLogEvent(event.text.slice(-200))
                        break

                    case 'extraction_progress':
                        onLogEvent(event.message)
                        setStatusText(event.message)
                        break

                    case 'streaming_progress':
                        if (batchInfo) {
                            setStatusText(t('worldBuilder.streamingProgressBatch', {
                                label, current: batchInfo.batchIndex + 1,
                                total: batchInfo.totalBatches, chars: event.charCount
                            }))
                        } else {
                            setStatusText(t('worldBuilder.streamingProgress', { label, chars: event.charCount }))
                        }
                        break

                    case 'phase_output':
                        handlePhaseOutput(event.phaseId, event.output)
                        break

                    case 'draft_review':
                        // Auto-confirm draft — skip manual review, user can revise via AI feedback
                        handlePhaseOutput('synopsis', event.draft)
                        break

                    case 'validation_retry':
                        if (event.accepted) {
                            onLogEvent(t('worldBuilder.validationAccepted', { attempt: event.attempt, errorCount: event.errors.length }))
                            setStatusText(t('worldBuilder.generatingPhase', { label }))
                        } else {
                            onLogEvent(t('worldBuilder.validationRetry', { attempt: event.attempt, errors: event.errors.slice(0, 3).join('; ') }))
                            setStatusText(t('worldBuilder.validationRetryStatus', { attempt: event.attempt }))
                        }
                        break

                    case 'query_user':
                        onLogEvent(t('worldBuilder.logQueryUser', { title: event.request.title }))
                        setStatusText(t('worldBuilder.waitingInput', { title: event.request.title }))
                        break

                    case 'done':
                        onLogEvent(t('worldBuilder.logDone', { label }))
                        break

                    case 'error':
                        onLogEvent(t('worldBuilder.logError', { error: event.error }))
                        setMode('error')
                        setErrorMessage(event.error)
                        {
                            const ss: WBNSession = { ...sessionRef.current! }
                            ss.phases = { ...ss.phases }
                            ss.phases[phaseId] = { ...ss.phases[phaseId], status: 'error', error: event.error }
                            onSessionChange(ss)
                            sessionRef.current = ss
                            saveWBNSession(ss)
                        }
                        break
                }
            }
        } catch (e) {
            if (!abortRef.current) {
                const errMsg = (e as Error).message
                setMode('error')
                setErrorMessage(errMsg)
                onLogEvent(t('worldBuilder.logException', { error: errMsg }))
            }
        } finally {
            isRunningRef.current = false
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [config, queryUser])

    // ========================================================================
    // Phase Output Handling
    // ========================================================================

    const handlePhaseOutput = useCallback(async (phaseId: WBNPhaseId, output: unknown) => {
        if (!sessionRef.current) return
        // Save output to session
        const s: WBNSession = { ...sessionRef.current }
        s.phases = { ...s.phases }

        // Creatures phase: accumulate across batches (merge by creature_id)
        let mergedOutput = output
        if (phaseId === 'creatures' && s.creatureBatching && s.creatureBatching.currentBatch > 0) {
            const prior = (s.phases[phaseId].output as any)?.creatures as any[] || []
            const incoming = (output as any)?.creatures as any[] || []
            const incomingIds = new Set(incoming.map((c: any) => c.Creature?.creature_id).filter(Boolean))
            const kept = prior.filter((c: any) => !incomingIds.has(c.Creature?.creature_id))
            mergedOutput = { ...(output as any), creatures: [...kept, ...incoming] }
        }

        s.phases[phaseId] = { ...s.phases[phaseId], status: 'completed', output: mergedOutput }
        s.updatedAt = Date.now()

        // Initialize creature batching and extract user design notes after synopsis
        if (phaseId === 'synopsis') {
            initCreatureBatching(s)
            extractUserDesignNotes(s)
        }

        onSessionChange(s)
        sessionRef.current = s
        saveWBNSession(s)

        // Apply data to state (skip synopsis)
        if (phaseId !== 'synopsis') {
            const newState = await applyPhaseToState(s, phaseId, stateRef.current)
            onStateChange(newState)
            stateRef.current = newState

            // Switch to corresponding tab
            const tab = getPhaseTab(phaseId)
            if (tab) {
                onTabChange(tab)
            }
        }

        // Transition to waiting mode
        const label = getPhaseLabel(phaseId)
        setMode('waiting')
        if (phaseId === 'synopsis') {
            const draftOutput = output as WBNDraftOutput
            const creatureCount = draftOutput?.creatures?.length || 0
            const regionCount = draftOutput?.regions?.length || 0
            const orgCount = draftOutput?.organizations?.length || 0
            setStatusText(t('worldBuilder.synopsisGenerated', { label, regions: regionCount, orgs: orgCount, creatures: creatureCount }))
            setShowSynopsisPreview(true)
            // Push draft content to log panel for user review
            const draftFields = [
                { key: 'tone', label: t('worldBuilder.draft.tone') },
                { key: 'opening', label: t('worldBuilder.draft.opening') },
                { key: 'storyline', label: t('worldBuilder.draft.storyline') },
                { key: 'mechanics', label: t('worldBuilder.draft.mechanics') },
                { key: 'protagonist', label: t('worldBuilder.draft.protagonist') },
            ] as const
            const text = draftFields.filter(f => draftOutput?.[f.key]).map(f => `【${f.label}】\n${draftOutput[f.key]}`).join('\n\n')
            if (text) onLogEvent(`\n${t('worldBuilder.logSynopsisHeader')}\n${text}`)
            if (draftOutput?.regions?.length) {
                const regionList = draftOutput.regions.map(r => `- ${r.region_id} — ${r.name}`).join('\n')
                onLogEvent(`\n${t('worldBuilder.logRegionsPlan', { count: regionCount })}\n${regionList}`)
            }
            if (draftOutput?.organizations?.length) {
                const orgList = draftOutput.organizations.map(o => `- ${o.organization_id} — ${o.name}`).join('\n')
                onLogEvent(`\n${t('worldBuilder.logOrgsPlan', { count: orgCount })}\n${orgList}`)
            }
            if (draftOutput?.creatures?.length) {
                const creatureList = draftOutput.creatures
                    .map(c => `- ${c.creature_id} — ${c.name}${c.is_player ? ` ${t('worldBuilder.player')}` : ''}`)
                    .join('\n')
                onLogEvent(`\n${t('worldBuilder.logCreaturesPlan', { count: creatureCount })}\n${creatureList}`)
            }
        } else {
            setStatusText(t('worldBuilder.phaseGenerated', { label }))
        }
        setFeedbackText('')
    }, [onSessionChange, onStateChange, onTabChange])

    // ========================================================================
    // Advance to Next Phase
    // ========================================================================

    const handleAdvance = useCallback(() => {
        if (!sessionRef.current) return
        setShowSynopsisPreview(false)
        const s: WBNSession = { ...sessionRef.current }

        // Re-calculate creature batching when advancing from synopsis
        // (user may have added/removed creatures via revision)
        if (s.currentPhase === 'synopsis') {
            initCreatureBatching(s)
        }

        const hasNext = advancePhase(s)

        if (hasNext) {
            onSessionChange(s)
            sessionRef.current = s
            saveWBNSession(s)
            // Phase execution will auto-trigger via useEffect
        } else {
            // All phases complete
            s.status = 'completed'
            onSessionChange(s)
            sessionRef.current = s
            saveWBNSession(s)

            // Auto-download to prevent data loss
            try {
                const now = new Date()
                const ts = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}_${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}`
                const exportData = { ...stateRef.current, _save_version: 'v2' as const }
                const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' })
                const url = URL.createObjectURL(blob)
                const a = document.createElement('a')
                a.href = url
                a.download = `world-builder-${ts}.json`
                document.body.appendChild(a)
                a.click()
                document.body.removeChild(a)
                URL.revokeObjectURL(url)
                onLogEvent(`${t('worldBuilder.allComplete')} ${t('worldBuilder.autoDownloadCreated')}`)
            } catch (e) {
                console.error('Auto-download after world builder failed:', e)
                onLogEvent(t('worldBuilder.allComplete'))
            }

            onClose()
        }
    }, [onSessionChange, onLogEvent, onClose])

    // ========================================================================
    // Revision
    // ========================================================================

    const handleRevision = useCallback(async () => {
        if (!feedbackText.trim() || !sessionRef.current) return
        if (isRunningRef.current) return
        isRunningRef.current = true

        const phaseId = sessionRef.current.currentPhase
        const userMsg = feedbackText.trim()
        setFeedbackText('')
        setMode('revising')
        setStatusText(t('worldBuilder.revisingPhase', { label: getPhaseLabel(phaseId) }))
        onLogEvent(t('worldBuilder.logRevision', { msg: userMsg }))

        const context: WBNToolContext = {
            state: stateRef.current,
            session: sessionRef.current,
            config,
        }

        try {
            const gen = streamWBNRevision(config, sessionRef.current, phaseId, userMsg, context)

            for await (const event of gen) {
                if (abortRef.current) break

                switch (event.type) {
                    case 'ai_text':
                        onLogEvent(event.text.slice(-200))
                        break

                    case 'streaming_progress':
                        setStatusText(t('worldBuilder.revisingPhase', { label: getPhaseLabel(phaseId) }) + ` (${event.charCount} chars)`)
                        break

                    case 'tool_call_start':
                        onLogEvent(t('worldBuilder.logRevisionTool', { name: event.toolName }))
                        break

                    case 'revision_patch':
                        onLogEvent(t('worldBuilder.logPatch', { summary: event.summary }))
                        setRevisionSummary(prev => prev ? `${prev}; ${event.summary}` : event.summary)
                        // Re-apply current phase to state after patch
                        {
                            const currentOutput = sessionRef.current.phases[phaseId].output
                            if (currentOutput) {
                                const newState = await applyPhaseToState(sessionRef.current, phaseId, stateRef.current)
                                onStateChange(newState)
                                stateRef.current = newState
                            }
                        }
                        break

                    case 'revision_done':
                        onLogEvent(t('worldBuilder.logRevisionDone', { summary: event.summary }))
                        setMode('waiting')
                        setStatusText(t('worldBuilder.revisionDone', { summary: event.summary }))
                        saveWBNSession(sessionRef.current)
                        break

                    case 'done':
                        if (mode !== 'waiting') {
                            setMode('waiting')
                            setStatusText(t('worldBuilder.revisionComplete'))
                        }
                        saveWBNSession(sessionRef.current)
                        break

                    case 'error':
                        onLogEvent(t('worldBuilder.logRevisionError', { error: event.error }))
                        setMode('error')
                        setErrorMessage(event.error)
                        break
                }
            }
        } catch (e) {
            if (!abortRef.current) {
                setMode('error')
                setErrorMessage((e as Error).message)
            }
        } finally {
            isRunningRef.current = false
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [feedbackText, config])

    // ========================================================================
    // Cancel / Retry
    // ========================================================================

    // ========================================================================
    // Pause — interrupt generation, save session, close banner
    // ========================================================================

    const handlePause = useCallback(() => {
        abortRef.current = true
        isRunningRef.current = false

        if (sessionRef.current) {
            const s: WBNSession = { ...sessionRef.current }
            s.status = 'paused'
            s.updatedAt = Date.now()
            // If the current phase was mid-generation, reset it to 'active' so it can be re-run on resume
            const phaseStatus = s.phases[s.currentPhase]?.status
            if (phaseStatus === 'generating') {
                s.phases = { ...s.phases }
                s.phases[s.currentPhase] = { ...s.phases[s.currentPhase], status: 'active' }
            }
            saveWBNSession(s)
            onSessionChange(null)
        }
        onClose()
    }, [onClose, onSessionChange])

    const handleCancel = useCallback(() => {
        abortRef.current = true
        isRunningRef.current = false
        onClose()
    }, [onClose])

    const handleRetry = useCallback(() => {
        if (!sessionRef.current) return
        setMode('generating')
        setErrorMessage('')
        // Reset phase status to active
        const s: WBNSession = { ...sessionRef.current }
        s.phases = { ...s.phases }
        s.phases[s.currentPhase] = {
            ...s.phases[s.currentPhase],
            status: 'active',
            output: undefined,
            error: undefined,
            chatHistory: [],
        }
        onSessionChange(s)
        sessionRef.current = s
        // Directly invoke runPhase — the auto-start Effect won't fire because
        // its dependencies (currentPhase, currentBatch) haven't changed.
        runPhase()
    }, [onSessionChange, runPhase])

    // ========================================================================
    // Render
    // ========================================================================

    // Resume a paused session
    const handleResumePaused = useCallback(() => {
        if (!pausedSession) return
        const s: WBNSession = { ...pausedSession, status: 'active', updatedAt: Date.now() }
        onSessionChange(s)
        saveWBNSession(s)
        setMode('generating')
        setLogEvents([])
    }, [pausedSession, onSessionChange])

    const handleDiscardPaused = useCallback(() => {
        onDiscardPaused?.()
    }, [onDiscardPaused])

    // Setup mode — no session yet
    if (mode === 'setup' || !session) {
        return (
            <div className="wbn-banner wbn-banner--setup">
                <div className="wbn-banner-main">
                    <span className="wbn-banner-icon"></span>
                    <div className="wbn-banner-text">
                        <div className="wbn-banner-title">{t('worldBuilder.title')}</div>
                        <div className="wbn-banner-subtitle">{t('worldBuilder.subtitle')}</div>
                    </div>
                    <div className="wbn-banner-actions">
                        <button className="wbn-banner-btn wbn-banner-btn--danger" onClick={onClose}>
                            {t('worldBuilder.close')}
                        </button>
                    </div>
                </div>

                {/* Resume paused session prompt */}
                {pausedSession && (
                    <div className="wbn-banner-resume">
                        <div className="wbn-banner-resume-text">
                            <span className="wbn-banner-resume-icon">⏸</span>
                            <span>{t('worldBuilder.pausedSessionFound', {
                                phase: getPhaseLabel(pausedSession.currentPhase),
                                date: new Date(pausedSession.updatedAt).toLocaleString(),
                            })}</span>
                        </div>
                        <div className="wbn-banner-resume-actions">
                            <button className="wbn-banner-btn wbn-banner-btn--primary" onClick={handleResumePaused}>
                                {t('worldBuilder.resumeSession')}
                            </button>
                            <button className="wbn-banner-btn wbn-banner-btn--danger" onClick={handleDiscardPaused}>
                                {t('worldBuilder.discardSession')}
                            </button>
                        </div>
                    </div>
                )}
                <div className="wbn-banner-setup">
                    <textarea
                        className="wbn-banner-setup-input"
                        placeholder={t('worldBuilder.placeholder')}
                        value={setupPrompt}
                        onChange={e => setSetupPrompt(e.target.value)}
                        rows={3}
                        onKeyDown={e => {
                            if (e.key === 'Enter' && !e.shiftKey && setupPrompt.trim()) {
                                e.preventDefault()
                                handleStartSession()
                            }
                        }}
                    />
                    <div className="wbn-banner-setup-footer">
                        <div className="wbn-banner-attachments">
                            {/* Hidden file inputs */}
                            <input ref={fileInputRef} type="file" accept=".md,.txt,.json" style={{ display: 'none' }} onChange={handleFileUpload} />
                            <input ref={lorebookInputRef} type="file" accept=".json" style={{ display: 'none' }} onChange={handleLorebookUpload} />

                            {/* File tags + add button */}
                            {setupFiles.map((f, i) => (
                                <span key={i} className="wbn-attach-tag">
                                    <span className="wbn-attach-tag-label" title={f.name}>{f.name}</span>
                                    <button type="button" className="wbn-attach-tag-remove" onClick={() => handleRemoveFile(i)}>&times;</button>
                                </span>
                            ))}
                            <button type="button" className="wbn-attach-btn" onClick={() => fileInputRef.current?.click()}>
                                + {t('worldBuilder.referenceFiles')}
                            </button>

                            {/* Lorebook tags + add button */}
                            {setupLorebooks.map((lb, i) => (
                                <span key={i} className="wbn-attach-tag wbn-attach-tag--lorebook">
                                    <span className="wbn-attach-tag-label" title={lb.filename}>
                                        {lb.name} ({lb.entries.length} entries)
                                    </span>
                                    <button type="button" className="wbn-attach-tag-remove" onClick={() => handleRemoveLorebook(i)}>&times;</button>
                                </span>
                            ))}
                            <button type="button" className="wbn-attach-btn" onClick={() => lorebookInputRef.current?.click()}>
                                + Lorebook
                            </button>

                            {lorebookError && (
                                <span className="wbn-banner-error" style={{ fontSize: '0.72rem', padding: '2px 6px' }}>
                                    {lorebookError}
                                </span>
                            )}
                        </div>
                        <div className="wbn-banner-setup-right">
                            <div className="wbn-banner-game-style">
                                <button
                                    type="button"
                                    className={`wbn-banner-style-btn ${gameStyle === 'narrative' ? 'active' : ''}`}
                                    onClick={() => setGameStyle('narrative')}
                                    title={t('worldBuilder.gameStyle.narrativeDesc')}
                                >
                                    {t('worldBuilder.gameStyle.narrative')}
                                </button>
                                <button
                                    type="button"
                                    className={`wbn-banner-style-btn ${gameStyle === 'numerical' ? 'active' : ''}`}
                                    onClick={() => setGameStyle('numerical')}
                                    title={t('worldBuilder.gameStyle.numericalDesc')}
                                >
                                    {t('worldBuilder.gameStyle.numerical')}
                                </button>
                            </div>
                            <label className="wbn-banner-checkbox" style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: '0.82rem', cursor: 'pointer', userSelect: 'none', whiteSpace: 'nowrap' }}>
                                <input
                                    type="checkbox"
                                    checked={skipOrgs}
                                    onChange={e => setSkipOrgs(e.target.checked)}
                                />
                                {t('worldBuilder.skipOrganizations')}
                            </label>
                            <label className="wbn-banner-checkbox" style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: '0.82rem', cursor: 'pointer', userSelect: 'none', whiteSpace: 'nowrap' }}>
                                <input
                                    type="checkbox"
                                    checked={clearBeforeGenerate}
                                    onChange={e => setClearBeforeGenerate(e.target.checked)}
                                />
                                {t('worldBuilder.clearBeforeGenerate')}
                            </label>
                            {(() => {
                                const totalChars = setupFiles.reduce((sum, f) => sum + (f.content?.length || 0), 0)
                                    + setupLorebooks.reduce((sum, lb) => sum + lb.totalChars, 0)
                                return totalChars > 0 && totalChars <= 100000
                            })() && (
                                <label className="wbn-banner-checkbox" style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: '0.82rem', cursor: 'pointer', userSelect: 'none', whiteSpace: 'nowrap' }}>
                                    <input
                                        type="checkbox"
                                        checked={skipExtraction}
                                        onChange={e => setSkipExtraction(e.target.checked)}
                                    />
                                    {t('worldBuilder.skipExtraction')}
                                </label>
                            )}
                            <button
                                className="wbn-banner-btn wbn-banner-btn--primary"
                                onClick={handleStartSession}
                                disabled={!setupPrompt.trim() || !config.primaryModel.apiKey}
                            >
                                {t('worldBuilder.startBuilding')}
                            </button>
                        </div>
                    </div>
                    {!config.primaryModel.apiKey && (
                        <div className="wbn-banner-error" style={{ padding: '4px 0 0' }}>
                            {t('worldBuilder.configureApiKey')}
                        </div>
