/* 游戏通用模态框样式 (Paper Media Theme) */

.game-modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--paper-border-color-hover);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  backdrop-filter: blur(2px);
}

/* 高优先级模态框（如信息弹窗）需要更高层级 */
.game-modal-high-priority {
  z-index: 1100;
}

.game-modal {
  background: var(--paper-bg-content);
  border-radius: 4px;
  max-width: 600px;
  width: 90%;
  max-height: 80vh;
  overflow: hidden;
  border: 1px solid var(--paper-text-primary);
  box-shadow: 4px 4px 0px var(--paper-shadow-color);
  font-family: inherit;
  display: flex;
  flex-direction: column;
}

.game-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 1.5rem;
  background: var(--paper-bg-primary);
  border-bottom: 2px solid var(--paper-text-primary);
  flex-shrink: 0;
}

.game-modal-header h3 {
