  color: var(--paper-text-primary);
  font-size: 1.1rem;
  font-weight: bold;
  letter-spacing: 0.5px;
}

.game-modal-close {
  background: none;
  border: none;
  color: var(--paper-text-secondary);
  font-size: 1.2rem;
