/**
 * Avatar Registry — 角色表情头像静态注册表
 *
 * 开发者在此注册角色头像。文件放在 avatars/{creatureId}/ 目录下。
 * 支持的表情: normal, happy, angry, sad, surprised, shy, disgusted, dazed
 *
 * 使用方式:
 *   1. 将头像图片放入 avatars/{creatureId}/ 目录
 *   2. 在下方 import 并注册到 avatarRegistry
 *
 * 示例:
 *   import aliceNormal from './alice/normal.png'
 *   import aliceHappy from './alice/happy.png'
 *
 *   avatarRegistry['alice'] = {
 *     normal: aliceNormal,
 *     happy: aliceHappy,
 *   }
 */

import type { GalExpression } from '../types'

type AvatarMap = Record<string, Partial<Record<GalExpression, string>>>

const avatarRegistry: AvatarMap = {
  // ── 在这里注册你的角色头像 ──
  // 'creature_id': {
  //   normal: importedNormalUrl,
  //   happy: importedHappyUrl,
  // },
}

export default avatarRegistry

/**
 * 获取角色头像 URL
 * 优先精确匹配表情，fallback 到 normal
 */
export function getAvatarUrl(creatureId: string, expression?: GalExpression): string | null {
  const entry = avatarRegistry[creatureId]
  if (!entry) return null

  const expr = expression || 'normal'
  if (entry[expr]) return entry[expr]!
  if (expr !== 'normal' && entry.normal) return entry.normal
  return null
}

/**
 * ActGallery — 幕回顾界面
 *
 * 类似 Galgame 存档界面的卡片列表，每一幕显示为一张卡片：
 * - 有 CG → 以 CG 作为封面（后续接入图片生成后替换）
 * - 无 CG → 用章节标题渲染为封面
 * - 点击卡片 → 进入该幕的回放模式
 */

import { useState, useMemo, useCallback } from 'react'
import { useTranslation } from 'react-i18next'
import { useGameStore } from '../stores/gameStore'
import { useCreatureStore } from '../stores/creatureStore'
import { useRegistryStore } from '../stores/registryStore'
import { useSpriteStore } from '../stores/spriteStore'
import { useUIStore } from '../stores/uiStore'
import { useHighlightEntities } from '../hooks'
import type { GalStoryTurn, StorySegment } from '../types'
import { isGalStoryTurn } from '../types'
import { TransparentImg } from './TransparentImg'

const PROLOGUE_KEY = 'prologue'

interface ActGalleryProps {
  open: boolean
  onClose: () => void
}

// ─── 单幕回放组件 ────────────────────────────────────────

function ActReplay({
  turn,
  onBack,
}: {
  turn: GalStoryTurn
  onBack: () => void
}) {
  const { t } = useTranslation('game')
  const creaturesRegistry = useRegistryStore(s => s.creaturesRegistry)
  const playerEntity = useCreatureStore(s => s.playerEntity)
  const getAvatarUrl = useSpriteStore(s => s.getAvatarUrl)
  const typewriterSpeed = useUIStore(s => s.typewriterSpeed)
  const { highlightEntitiesInText } = useHighlightEntities()
  const playerCreatureId = playerEntity?.Creature?.creature_id || ''

  const segments = turn.story || []

  return (
    <div className="act-replay">
      <div className="act-replay-header">
        <button className="act-replay-back" onClick={onBack}>← {t('galgame.startGame.back')}</button>
        <span className="act-replay-title">
          {turn.chapterTitle === PROLOGUE_KEY ? t('galgame.startGame.prologue') : (turn.chapterTitle || t('galgame.unnamedChapter'))}
        </span>
      </div>
      <div className="act-replay-scroll">
        {segments.map((seg) => {
          if (seg.type === 'narrative') {
            return (
              <div key={seg.idx} className="act-replay-narrative">
                {highlightEntitiesInText(seg.content.join('\n'), `replay-${turn.id}-${seg.idx}`)}
              </div>
            )
          }
          const isPlayer = seg.speaker_creature_id === playerCreatureId
          const speakerName = seg.speaker_creature_id
            ? (creaturesRegistry.get(seg.speaker_creature_id)?.name || seg.speaker_creature_id)
            : ''
          const avatarUrl = seg.speaker_creature_id
            ? getAvatarUrl(seg.speaker_creature_id, seg.emotion)
            : null
          const side = isPlayer ? 'right' : 'left'

          return (
            <div key={seg.idx} className={`act-replay-dialogue ${side}`}>
              <div className="act-replay-avatar">
                {avatarUrl ? (
                  <TransparentImg src={avatarUrl} alt={speakerName} draggable={false} />
                ) : (
                  <span>{speakerName.charAt(0)}</span>
                )}
              </div>
              <div className="act-replay-bubble-area">
                <div className="act-replay-speaker">{speakerName}</div>
                <div className="act-replay-bubble">
                  {highlightEntitiesInText(seg.content.join('\n'), `replay-${turn.id}-${seg.idx}`)}
                </div>
                {seg.emotion && seg.emotion !== 'normal' && (
                  <span className={`vn-emotion-badge emotion-${seg.emotion}`}>
                    {t(`galgame.expressions.${seg.emotion}`, seg.emotion)}
                  </span>
                )}
              </div>
            </div>
          )
        })}

        {/* CG */}
        {turn.cg && (
          <div className="act-replay-narrative act-replay-cg">
            <span className="vn-cg-icon">🖼</span>
            <span>{t('galgame.cg.placeholder')}</span>
          </div>
        )}
      </div>
    </div>
  )
}

// ─── 主画廊 ────────────────────────────────────────────

export function ActGallery({ open, onClose }: ActGalleryProps) {
  const { t } = useTranslation('game')
  const galTurns = useGameStore(s => s.galTurns)
  const [replayTurnId, setReplayTurnId] = useState<number | null>(null)

  const storyTurns = useMemo(
    () => galTurns.filter(isGalStoryTurn).filter(t => t.generationPhase === 'done'),
    [galTurns]
  )

  const replayTurn = replayTurnId !== null
    ? storyTurns.find(t => t.id === replayTurnId)
    : null

  if (!open) return null

  // 回放模式
  if (replayTurn) {
    return (
      <div className="act-gallery-overlay" onClick={onClose}>
        <div className="act-gallery-modal act-gallery-replay" onClick={e => e.stopPropagation()}>
          <ActReplay turn={replayTurn} onBack={() => setReplayTurnId(null)} />
        </div>
      </div>
    )
  }

  // 画廊模式
  return (
    <div className="act-gallery-overlay" onClick={onClose}>
      <div className="act-gallery-modal" onClick={e => e.stopPropagation()}>
        <div className="act-gallery-header">
          <h3>{t('galgame.actGallery.title')}</h3>
          <button className="act-gallery-close" onClick={onClose}>×</button>
        </div>

        {storyTurns.length === 0 ? (
          <div className="act-gallery-empty">{t('galgame.actGallery.empty')}</div>
        ) : (
          <div className="act-gallery-grid">
            {storyTurns.map((turn, idx) => {
              const title = turn.chapterTitle === PROLOGUE_KEY
                ? t('galgame.startGame.prologue')
                : (turn.chapterTitle || t('galgame.unnamedChapter'))
              const hasCG = !!turn.cg
              const segCount = (turn.story || []).length
              const dialogueCount = (turn.story || []).filter(s => s.type === 'dialogue').length

              return (
                <button
                  key={turn.id}
                  className="act-gallery-card"
                  onClick={() => setReplayTurnId(turn.id)}
                >
                  {/* 封面区 */}
                  <div className={`act-card-cover ${hasCG ? 'has-cg' : ''}`}>
                    {hasCG ? (
                      <div className="act-card-cg-badge">CG</div>
                    ) : (
                      <div className="act-card-title-cover">
                        <span>{title}</span>
                      </div>
                    )}
                    <div className="act-card-number">#{idx + 1}</div>
                  </div>

                  {/* 信息区 */}
                  <div className="act-card-info">
                    <div className="act-card-title">{title}</div>
                    <div className="act-card-meta">
                      {t('galgame.actGallery.segments', { count: segCount })} · {t('galgame.actGallery.dialogues', { count: dialogueCount })}
                    </div>
                  </div>
                </button>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}

/src/games/custom/components/GalFlow.tsx:
/**
 * VNPresenter — 视觉小说对话界面（一幕一页模式）
 *
 * - 每次只显示一幕内容，用户选择选项后生成新一幕
 * - 新一幕生成完毕后显示"查看下一幕"按钮
 * - 立绘根据 viewport 中心的说话者动态切换
 */

import { useState, useRef, useCallback, useEffect, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { useGameStore } from '../stores/gameStore'
import { useCreatureStore } from '../stores/creatureStore'
import { useUIStore } from '../stores/uiStore'
import { useSpriteStore } from '../stores/spriteStore'
import { useRegistryStore } from '../stores/registryStore'
import { useHighlightEntities } from '../hooks'
import type { GalStoryTurn, PlayerChoice, StorySegment } from '../types'
import { isGalStoryTurn, isErrorTurn } from '../types'
import { TransparentImg } from './TransparentImg'

const PROLOGUE_KEY = 'prologue'

// ─── 单条消息组件（无打字机效果）────────────────────────────

interface SegmentMessageProps {
  segment: StorySegment
  isPlayer: boolean
  speakerName: string
  avatarUrl: string | null
  showAvatar: boolean
  showEmotion: boolean
  onAvatarClick?: (creatureId: string) => void
  highlightText: (text: string, key: string) => React.ReactNode
  keyPrefix: string
}

function SegmentMessage({
  segment,
  isPlayer,
  speakerName,
  avatarUrl,
  showAvatar,
  showEmotion,
  onAvatarClick,
  highlightText,
  keyPrefix,
}: SegmentMessageProps) {
  const { t } = useTranslation('game')

  // 将 content[] 展平为段落（按 \n 拆分）
  const paragraphs = useMemo(() => {
    const result: string[] = []
    for (const item of segment.content) {
      for (const line of item.split('\n')) {
        const trimmed = line.trim()
        if (trimmed) result.push(trimmed)
      }
    }
    return result
  }, [segment.content])

  // ── 叙事消息 ──
  if (segment.type === 'narrative') {
    return (
      <div className="vn-msg narrative" key={keyPrefix}>
        <div className="vn-narrative-box">
          {paragraphs.map((para, pi) => (
            <p key={`${keyPrefix}-p${pi}`} className="vn-narrative-para">
              {highlightText(para, `${keyPrefix}-p${pi}`)}
            </p>
          ))}
        </div>
      </div>
    )
  }

  // ── 对话消息 ──
  const side = isPlayer ? 'right' : 'left'

  return (
    <div
      className={`vn-msg message ${side} ${!showAvatar ? 'continuation' : ''}`}
      key={keyPrefix}
      data-speaker={segment.speaker_creature_id || undefined}
    >
      {/* 头像：仅首条显示 */}
      {showAvatar ? (
        <div
          className="vn-avatar-container"
          onClick={() => segment.speaker_creature_id && onAvatarClick?.(segment.speaker_creature_id)}
        >
          {avatarUrl ? (
            <TransparentImg className="vn-avatar-img" src={avatarUrl} alt={speakerName} draggable={false} />
          ) : (
            <div className="vn-avatar-fallback">
              {speakerName.charAt(0)}
            </div>
          )}
        </div>
      ) : (
        <div className="vn-avatar-spacer" />
      )}

      {/* 气泡 */}
      <div className="vn-bubble-wrapper">
        {showAvatar && <div className="vn-name-tag">{speakerName}</div>}
        <div className="vn-bubble">
          <span className="vn-bubble-text">
            {paragraphs.map((para, pi) => (
              <p key={`${keyPrefix}-p${pi}`} className="vn-bubble-para">
                {highlightText(para, `${keyPrefix}-p${pi}`)}
              </p>
            ))}
          </span>
        </div>
        {showEmotion && segment.emotion && segment.emotion !== 'normal' && (
          <span className={`vn-emotion-badge emotion-${segment.emotion}`}>
            {t(`galgame.expressions.${segment.emotion}`, segment.emotion)}
          </span>
        )}
      </div>
    </div>
  )
}

// ─── 一幕的展示（无播放，直接全部显示）─────────────────────

interface ActPlayerProps {
  turn: GalStoryTurn
  playerCreatureId: string
  onAvatarClick: (creatureId: string) => void
  highlightText: (text: string, key: string) => React.ReactNode
}

// ── 将 segments 展平为气泡：每个 content 元素 = 一个气泡 ──
interface FlatBubble {
  key: string
  segment: StorySegment
  text: string
  isFirstOfGroup: boolean
  isLastOfGroup: boolean
}

function flattenSegments(segments: StorySegment[]): FlatBubble[] {
  const result: FlatBubble[] = []
  for (const seg of segments) {
    if (seg.type === 'narrative') {
      const lines: string[] = []
      for (const item of seg.content) {
        for (const line of item.split('\n')) {
          const trimmed = line.trim()
          if (trimmed) lines.push(trimmed)
        }
      }
      const text = lines.join('\n')
      if (text) {
        result.push({ key: `seg${seg.idx}`, segment: seg, text, isFirstOfGroup: true, isLastOfGroup: true })
      }
    } else {
      const items: string[] = []
      for (const item of seg.content) {
        for (const line of item.split('\n')) {
          const trimmed = line.trim()
          if (trimmed) items.push(trimmed)
        }
      }
      items.forEach((text, ci) => {
        const prev = result.length > 0 ? result[result.length - 1] : null
        const sameAsPrev = prev
          && prev.segment.type === 'dialogue'
          && prev.segment.speaker_creature_id === seg.speaker_creature_id
        result.push({
          key: `seg${seg.idx}-c${ci}`,
          segment: seg,
          text,
          isFirstOfGroup: ci === 0 && !sameAsPrev,
          isLastOfGroup: true,
        })
      })
    }
  }
  // 回填 isLastOfGroup
  for (let i = 0; i < result.length; i++) {
    if (result[i].segment.type !== 'dialogue') continue
    const next = i + 1 < result.length ? result[i + 1] : null
    const nextIsSame = next
      && next.segment.type === 'dialogue'
      && next.segment.speaker_creature_id === result[i].segment.speaker_creature_id
    result[i].isLastOfGroup = !nextIsSame
  }
  return result
}

function ActPlayer({
  turn,
  playerCreatureId,
  onAvatarClick,
  highlightText,
}: ActPlayerProps) {
  const { t } = useTranslation('game')
  const segments = turn.story || []
  const creaturesRegistry = useRegistryStore(s => s.creaturesRegistry)
  const getAvatarUrl = useSpriteStore(s => s.getAvatarUrl)

  const bubbles = useMemo(() => flattenSegments(segments), [segments])

  return (
    <div className="vn-act">
      {/* 章节标题 */}
      {turn.chapterTitle && (
        <div className="vn-chapter-divider">
          <span className="vn-chapter-line" />
          <span className="vn-chapter-label">
            {turn.chapterTitle === PROLOGUE_KEY ? t('galgame.startGame.prologue') : turn.chapterTitle}
          </span>
          <span className="vn-chapter-line" />
        </div>
      )}

      {/* 消息列表 */}
      <div className="vn-messages">
        {bubbles.map((bubble) => {
          const seg = bubble.segment
          const isPlayer = seg.speaker_creature_id === playerCreatureId
          const speakerName = seg.speaker_creature_id
            ? (creaturesRegistry.get(seg.speaker_creature_id)?.name || seg.speaker_creature_id)
            : ''
          const avatarUrl = seg.speaker_creature_id
            ? getAvatarUrl(seg.speaker_creature_id, seg.emotion)
            : null

          const singleContentSeg: StorySegment = {
            ...seg,
            content: [bubble.text],
          }

          return (
            <SegmentMessage
              key={`${turn.id}-${bubble.key}`}
              segment={singleContentSeg}
              isPlayer={isPlayer}
              speakerName={speakerName}
              avatarUrl={avatarUrl}
              showAvatar={bubble.isFirstOfGroup}
              showEmotion={bubble.isLastOfGroup}
              onAvatarClick={onAvatarClick}
              highlightText={highlightText}
              keyPrefix={`${turn.id}-${bubble.key}`}
            />
          )
        })}

        {/* CG 图片 */}
        {turn.cg && (
          <div className="vn-msg narrative vn-cg-message">
            {turn.cgImageUrl ? (
              <img className="vn-cg-image" src={turn.cgImageUrl} alt="CG" draggable={false} />
            ) : (
              <div className="vn-cg-placeholder">
                <span className="vn-cg-icon">🖼</span>
                <span className="vn-cg-label">{t('galgame.cg.placeholder')}</span>
                <div className="vn-dots"><span /><span /><span /></div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  )
}

// ─── 选项面板 ────────────────────────────────────────────

function ChoicesPanel({
  choices,
  disabled,
  showCustomInput,
  playerInput,
  onChoiceSelect,
  onCustomSubmit,
  setShowCustomInput,
  setPlayerInput,
}: {
  choices: PlayerChoice[]
  disabled: boolean
  showCustomInput: boolean
  playerInput: string
  onChoiceSelect: (choice: PlayerChoice) => void
  onCustomSubmit: () => void
  setShowCustomInput: (show: boolean) => void
  setPlayerInput: (input: string) => void
}) {
  const { t } = useTranslation('game')

  return (
    <div className="vn-choices-panel">
      <div className="vn-choices-list">
        {choices.map((choice, idx) => (
          <button
            key={idx}
            className={`vn-choice-btn ${choice.is_special ? 'special' : ''}`}
            onClick={() => onChoiceSelect(choice)}
            disabled={disabled}
          >
            <div className="vn-choice-name">
              {choice.is_special && <span className="vn-special-badge">✦</span>}
              {choice.name}
            </div>
            <div className="vn-choice-desc">{choice.description}</div>
          </button>
        ))}
      </div>

      <div className="vn-custom-section">
        {!showCustomInput ? (
          <button
            className="vn-custom-toggle"
            onClick={() => setShowCustomInput(true)}
            disabled={disabled}
          >
            {t('galgame.choices.customAction')}
          </button>
        ) : (
          <div className="vn-custom-input">
            <textarea
              value={playerInput}
              onChange={(e) => setPlayerInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey && !disabled) {
                  e.preventDefault()
                  onCustomSubmit()
                }
              }}
              placeholder={t('galgame.choices.inputPlaceholder')}
              rows={2}
              autoFocus
            />
            <div className="vn-custom-actions">
              <button onClick={() => setShowCustomInput(false)}>{t('galgame.choices.cancel')}</button>
              <button
                className="vn-custom-submit"
                onClick={onCustomSubmit}
                disabled={!playerInput.trim() || disabled}
              >
                {t('galgame.choices.confirm')}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

