import { useTranslation } from 'react-i18next'
import { useGameStore } from '../stores/gameStore'
import { useModalStore } from '../stores/modalStore'
import { isGalStoryTurn } from '../types'
import type { GalStoryTurn } from '../types'

export function PublishModal() {
  const { t } = useTranslation('game')
  const galTurns = useGameStore(s => s.galTurns)

  const {
    publishModalOpen,
    publishStartTurn,
    publishEndTurn,
    publishTitle,
    publishVisibility,
    publishing,
    closePublishModal,
    setPublishStartTurn,
    setPublishEndTurn,
    setPublishTitle,
    setPublishVisibility,
    setPublishing
  } = useModalStore()

  if (!publishModalOpen) return null

  const storyTurns = galTurns.filter((t): t is GalStoryTurn => isGalStoryTurn(t) && t.generationPhase === 'done')

  const handlePublish = async () => {
    const selectedTurns = storyTurns.slice(publishStartTurn, publishEndTurn + 1)

    if (selectedTurns.length === 0) {
      alert(t('publish.noChaptersSelected'))
      return
    }

    setPublishing(true)
    try {
      const content: Array<{
        type: "text",
        id: string,
        text: string,
      } | {
        type: "game_ref",
        textId: string,
        checkpointId: string,
      }> = []

      for (let idx = 0; idx < selectedTurns.length; idx++) {
        const turn = selectedTurns[idx]
        const textBlockId = `turn-${turn.id}`

        const chapterTitle = turn.chapterTitle || t('publish.chapterDefault', { num: publishStartTurn + idx + 1 })
        let chapterContent = `## ${chapterTitle}\n\n`

        // 将段落转为文本格式
        for (const seg of (turn.story || [])) {
          const text = seg.content.join('\n')
          if (seg.type === 'dialogue' && seg.speaker_creature_id) {
            chapterContent += `**${seg.speaker_creature_id}**: ${text}\n\n`
          } else {
            chapterContent += `*${text}*\n\n`
          }
        }

        content.push({
          type: "text",
          id: textBlockId,
          text: chapterContent.trim(),
        })

        if (turn.checkpointId) {
          content.push({
            type: "game_ref",
            textId: textBlockId,
            checkpointId: turn.checkpointId,
          })
        }
      }

      const result = await window.PublishArticle({
        title: publishTitle || undefined,
        content,
        visibility: publishVisibility
      })

      if (result.success) {
        alert(t('publish.success', { articleId: result.articleId || t('common:unknown') }))
        closePublishModal()
      } else {
        alert(t('publish.failed', { error: result.error || t('common:unknown') }))
      }
    } catch (e) {
      console.error('Failed to publish article:', e)
      alert(t('publish.failed', { error: (e as Error).message }))
    } finally {
      setPublishing(false)
    }
  }

  return (
    <div className="modal-overlay" onClick={closePublishModal}>
      <div className="modal-content publish-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>{t('publish.title')}</h2>
          <button className="modal-close" onClick={closePublishModal}>✕</button>
        </div>
        <div className="modal-body">
          <div className="publish-form-group">
            <label>{t('publish.articleTitle')}</label>
            <input
              type="text"
              value={publishTitle}
              onChange={(e) => setPublishTitle(e.target.value)}
              placeholder={t('publish.titlePlaceholder')}
              className="publish-input"
            />
          </div>

          <div className="publish-form-group">
            <label>{t('publish.visibility')}</label>
            <select
              value={publishVisibility}
              onChange={(e) => setPublishVisibility(e.target.value as any)}
              className="publish-select"
            >
              <option value="PUBLIC">{t('publish.public')}</option>
              <option value="UNLISTED">{t('publish.unlisted')}</option>
              <option value="PRIVATE">{t('publish.private')}</option>
            </select>
          </div>

          <div className="publish-form-group">
            <label>{t('publish.selectRange')}</label>
            <div className="publish-range">
              <div>
                <label>{t('publish.from')}</label>
                <select
                  value={publishStartTurn}
                  onChange={(e) => setPublishStartTurn(parseInt(e.target.value))}
                  className="publish-select-small"
                >
                  {storyTurns.map((turn, idx) => (
                    <option key={turn.id} value={idx}>
                      {idx + 1}. {turn.chapterTitle || t('publish.chapterDefault', { num: idx + 1 })}
                    </option>
                  ))}
                </select>
                <label>{t('publish.chapter')}</label>
              </div>
              <div>
                <label>{t('publish.to')}</label>
                <select
                  value={publishEndTurn}
                  onChange={(e) => setPublishEndTurn(parseInt(e.target.value))}
                  className="publish-select-small"
                >
                  {storyTurns.map((turn, idx) => (
                    <option key={turn.id} value={idx} disabled={idx < publishStartTurn}>
                      {idx + 1}. {turn.chapterTitle || t('publish.chapterDefault', { num: idx + 1 })}
                    </option>
                  ))}
                </select>
                <label>{t('publish.chapter')}</label>
              </div>
            </div>
            <div className="publish-range-hint">
              {t('publish.chapterCount', { count: publishEndTurn - publishStartTurn + 1 })}
            </div>
          </div>

          <div className="publish-preview">
            <h4>{t('publish.previewList')}</h4>
            <div className="publish-chapter-list">
              {storyTurns.slice(publishStartTurn, publishEndTurn + 1).map((turn, idx) => (
                <div key={turn.id} className="publish-chapter-item">
                  <span className="chapter-number">{publishStartTurn + idx + 1}</span>
                  <span className="chapter-title">{turn.chapterTitle || t('publish.chapterDefault', { num: publishStartTurn + idx + 1 })}</span>
                  {turn.checkpointId && <span className="has-checkpoint" title={t('publish.hasCheckpoint')}>💾</span>}
                </div>
              ))}
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-cancel" onClick={closePublishModal} disabled={publishing}>
            {t('common:cancel')}
          </button>
          <button className="btn-primary" onClick={handlePublish} disabled={publishing}>
            {publishing ? t('publish.publishing') : t('publish.confirm')}
          </button>
        </div>
      </div>
    </div>
  )
}

/src/games/custom/components/ResourceMan:
/**
 * ResourceManager — 资源管理器
 *
 * 批量为角色生成立绘和表情头像。
 * 显示每个角色的进度，支持选择性生成。
 */

import { useState, useCallback, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { useCreatureStore } from '../stores/creatureStore'
import { useSpriteStore } from '../stores/spriteStore'
import { runImageGenPipeline, type PipelineState, type PipelinePhase } from '../services/imageGenPipeline'
import type { GalExpression } from '../types'
import type { Creature } from '../../../api/types'

const ALL_EXPRESSIONS: GalExpression[] = [
  'normal', 'happy', 'angry', 'sad', 'surprised', 'shy', 'confused', 'thinking', 'smirk',
]

interface ResourceManagerProps {
  open: boolean
  onClose: () => void
}

export function ResourceManager({ open, onClose }: ResourceManagerProps) {
  const { t } = useTranslation('game')

  const creaturesMap = useCreatureStore(s => s.creaturesMap)
  const playerEntity = useCreatureStore(s => s.playerEntity)

  const hasStanding = useSpriteStore(s => s.hasStanding)
  const getCreatureExpressions = useSpriteStore(s => s.getCreatureExpressions)
  const setSprite = useSpriteStore(s => s.setSprite)
  const removeCreatureSprites = useSpriteStore(s => s.removeCreatureSprites)
  const sprites = useSpriteStore(s => s.sprites) // subscribe to re-render on changes

  const [pipelineState, setPipelineState] = useState<PipelineState | null>(null)
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set())

  // Build creature list
  const creatureList = useMemo(() => {
    const list: Array<{ id: string; name: string; creature: Creature; isPlayer: boolean }> = []
    const playerId = playerEntity?.Creature?.creature_id
    if (playerId && playerEntity?.Creature) {
      list.push({ id: playerId, name: playerEntity.Creature.name || playerId, creature: playerEntity.Creature, isPlayer: true })
    }
    for (const [id, entity] of creaturesMap) {
      if (id !== playerId && entity.Creature) {
        list.push({ id, name: entity.Creature.name || id, creature: entity.Creature, isPlayer: false })
      }
    }
    return list
  }, [creaturesMap, playerEntity, sprites]) // sprites dependency to refresh missing counts

  // Compute missing resources per creature
  const creatureStatus = useMemo(() => {
    return creatureList.map(c => {
      const hasStandingSprite = hasStanding(c.id)
      const existingAvatars = getCreatureExpressions(c.id, 'avatar')
      const missingAvatars = ALL_EXPRESSIONS.filter(e => !existingAvatars.includes(e))
      return {
        ...c,
        hasStanding: hasStandingSprite,
        missingAvatars,
        totalMissing: (hasStandingSprite ? 0 : 1) + missingAvatars.length,
      }
    })
  }, [creatureList, hasStanding, getCreatureExpressions])

  const isRunning = pipelineState?.phase === 'generating-standings' || pipelineState?.phase === 'generating-avatars'

  // Toggle selection
  const toggleSelect = useCallback((id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }, [])

  // Regenerate all resources for a single creature
  const handleRegenerate = useCallback(async (creatureId: string) => {
    const target = creatureStatus.find(c => c.id === creatureId)
    if (!target || isRunning) return

    // 清除该角色的所有图像
    removeCreatureSprites(creatureId)

    // 以全套资源运行 pipeline
    await runImageGenPipeline({
      creatures: [{
        creature: target.creature,
        needStanding: true,
        needAvatars: ALL_EXPRESSIONS,
      }],
      onSpriteReady: (cid, imageType, expression, dataUrl, mimeType) => {
        setSprite(cid, imageType, expression, dataUrl, mimeType)
      },
      onProgress: (state) => {
        setPipelineState({ ...state })
      },
    })
  }, [creatureStatus, isRunning, removeCreatureSprites, setSprite])

  // Select all with missing resources
  const selectAllMissing = useCallback(() => {
    const ids = creatureStatus.filter(c => c.totalMissing > 0).map(c => c.id)
    setSelectedIds(new Set(ids))
  }, [creatureStatus])

  // Run pipeline
  const handleGenerate = useCallback(async () => {
    const targets = creatureStatus.filter(c => selectedIds.has(c.id) && c.totalMissing > 0)
    if (targets.length === 0) return

    await runImageGenPipeline({
      creatures: targets.map(c => ({
        creature: c.creature,
        needStanding: !c.hasStanding,
        needAvatars: c.missingAvatars,
      })),
      onSpriteReady: (creatureId, imageType, expression, dataUrl, mimeType) => {
        setSprite(creatureId, imageType, expression, dataUrl, mimeType)
      },
      onProgress: (state) => {
        setPipelineState({ ...state })
      },
    })
  }, [creatureStatus, selectedIds, setSprite])

  // Get progress for a creature
  const getCreatureProgress = useCallback((creatureId: string) => {
    return pipelineState?.creatures.find(c => c.creatureId === creatureId)
  }, [pipelineState])

  if (!open) return null

  const totalSelected = selectedIds.size
  const totalAPICalls = creatureStatus
    .filter(c => selectedIds.has(c.id))
    .reduce((sum, c) => sum + c.totalMissing, 0)

  return (
    <div className="sprite-manager-overlay" onClick={onClose}>
      <div className="resource-manager-modal" onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="sprite-manager-header">
          <h3>{t('galgame.resourceManager.title')}</h3>
          <button className="sprite-manager-close" onClick={onClose}>×</button>
        </div>

        {/* Toolbar */}
        <div className="resource-toolbar">
          <button
            className="resource-select-all"
            onClick={selectAllMissing}
            disabled={isRunning}
          >
            {t('galgame.resourceManager.selectAll')}
          </button>
          <div className="resource-toolbar-info">
            {totalSelected > 0 && (
              <span>
                {t('galgame.resourceManager.selectedInfo', { count: totalSelected, calls: totalAPICalls })}
              </span>
            )}
          </div>
          <button
            className="resource-generate-btn"
            onClick={handleGenerate}
            disabled={isRunning || totalSelected === 0}
          >
            {isRunning
              ? t('galgame.resourceManager.generating')
              : t('galgame.resourceManager.generate')
            }
          </button>
        </div>

        {/* Creature list */}
        <div className="resource-list">
          {creatureStatus.length === 0 && (
            <div className="sprite-empty-hint">{t('galgame.resourceManager.noCharacters')}</div>
          )}
          {creatureStatus.map(c => {
            const progress = getCreatureProgress(c.id)
            const isSelected = selectedIds.has(c.id)

            return (
              <div key={c.id} className={`resource-item ${isSelected ? 'selected' : ''}`}>
                {/* Checkbox + name */}
                <label className="resource-item-header">
                  <input
                    type="checkbox"
                    checked={isSelected}
                    onChange={() => toggleSelect(c.id)}
                    disabled={isRunning || c.totalMissing === 0}
                  />
                  <span className="resource-item-name">
                    {c.name}
                    {c.isPlayer && <span className="sprite-creature-badge">P</span>}
                  </span>
                  {c.totalMissing === 0 ? (
                    <span className="resource-complete">✓</span>
                  ) : (
                    <span className="resource-missing">
                      {t('galgame.resourceManager.missing', { count: c.totalMissing })}
                    </span>
                  )}
                  {c.totalMissing < 10 && (
                    <button
                      className="resource-regen-btn"
                      onClick={(e) => { e.preventDefault(); handleRegenerate(c.id) }}
                      disabled={isRunning}
                      title={t('galgame.resourceManager.regenerate')}
                    >
                      ↻
                    </button>
                  )}
                </label>

                {/* Status details */}
                <div className="resource-item-detail">
                  <span className={c.hasStanding ? 'has' : 'miss'}>
                    {t('galgame.resourceManager.standing')}: {c.hasStanding ? '✓' : '✗'}
                  </span>
                  <span className={c.missingAvatars.length === 0 ? 'has' : 'miss'}>
                    {t('galgame.resourceManager.avatars')}: {ALL_EXPRESSIONS.length - c.missingAvatars.length}/{ALL_EXPRESSIONS.length}
                  </span>
                </div>

                {/* Progress bar (when running) */}
                {progress && (
                  <div className="resource-progress">
                    <div className="resource-progress-bar">
                      <div
                        className="resource-progress-fill"
                        style={{
                          width: `${((progress.standingDone ? 1 : 0) + progress.avatarsDone) / (1 + progress.avatarsTotal) * 100}%`
                        }}
                      />
                    </div>
                    <span className="resource-progress-text">
                      {!progress.standingDone
                        ? t('galgame.resourceManager.generatingStanding')
                        : progress.avatarsDone < progress.avatarsTotal
                          ? t('galgame.resourceManager.generatingAvatars', { done: progress.avatarsDone, total: progress.avatarsTotal })
                          : '✓'
                      }
                    </span>
                    {progress.standingError && (
                      <div className="resource-error">{progress.standingError}</div>
                    )}
                    {progress.avatarErrors.length > 0 && (
                      <div className="resource-error">{progress.avatarErrors.join('; ')}</div>
                    )}
                  </div>
                )}
              </div>
            )
          })}
        </div>

        {/* Pipeline global status */}
        {pipelineState?.phase === 'done' && (
          <div className="resource-done-banner">
            {t('galgame.resourceManager.done')}
          </div>
        )}
      </div>
    </div>
  )
}

/src/games/custom/components/SpriteManag:
/**
 * SpriteManager — 角色图像配置面板
 *
 * 用户可以为每个角色上传：
 * - 立绘（standing）：在场景中展示的全身/半身图
 * - 表情头像（avatar）：在对话框中展示的小头像
 */

import { useState, useRef, useCallback } from 'react'
import type { SpriteExportData } from '../stores/spriteStore'
import { useTranslation } from 'react-i18next'
import { useCreatureStore } from '../stores/creatureStore'
import { useSpriteStore, type SpriteImageType } from '../stores/spriteStore'
import type { GalExpression } from '../types'

const ALL_EXPRESSIONS: GalExpression[] = [
  'normal', 'happy', 'angry', 'sad', 'surprised', 'shy', 'confused', 'thinking', 'smirk'
]

const EXPRESSION_LABELS: Record<GalExpression, string> = {
  normal: '😐', happy: '😊', angry: '😠', sad: '😢',
  surprised: '😲', shy: '😳', confused: '😕', thinking: '🤔', smirk: '😏',
}

interface SpriteManagerProps {
  open: boolean
  onClose: () => void
}

export function SpriteManager({ open, onClose }: SpriteManagerProps) {
  const { t } = useTranslation('game')
  const creaturesMap = useCreatureStore(s => s.creaturesMap)
  const playerEntity = useCreatureStore(s => s.playerEntity)

  const setSprite = useSpriteStore(s => s.setSprite)
  const removeSprite = useSpriteStore(s => s.removeSprite)
  const removeCreatureSprites = useSpriteStore(s => s.removeCreatureSprites)
  const getAvatarUrl = useSpriteStore(s => s.getAvatarUrl)
  const getStandingUrl = useSpriteStore(s => s.getStandingUrl)
  const getCreatureExpressions = useSpriteStore(s => s.getCreatureExpressions)
  const exportAll = useSpriteStore(s => s.exportAll)
  const importAll = useSpriteStore(s => s.importAll)
  const sprites = useSpriteStore(s => s.sprites) // subscribe to changes

  const [selectedCreatureId, setSelectedCreatureId] = useState<string | null>(null)
  const [activeTab, setActiveTab] = useState<SpriteImageType>('standing')
  const fileInputRef = useRef<HTMLInputElement>(null)
  const importInputRef = useRef<HTMLInputElement>(null)
  const [uploadTarget, setUploadTarget] = useState<{ expression: GalExpression; imageType: SpriteImageType } | null>(null)

  // Build creature list: player first, then NPCs
  const creatureList = (() => {
    const list: Array<{ id: string; name: string; isPlayer: boolean }> = []
    const playerId = playerEntity?.Creature?.creature_id
    if (playerId) {
      list.push({ id: playerId, name: playerEntity?.Creature?.name || playerId, isPlayer: true })
    }
    for (const [id, entity] of creaturesMap) {
      if (id !== playerId) {
        list.push({ id, name: entity.Creature?.name || id, isPlayer: false })
      }
    }
    return list
  })()

  const handleExport = useCallback(async () => {
    const data = await exportAll()
    if (data.sprites.length === 0) return
    const json = JSON.stringify(data)
    const blob = new Blob([json], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `sprites-${new Date().toISOString().slice(0, 10)}.json`
    a.click()
    URL.revokeObjectURL(url)
  }, [exportAll])

  const handleImport = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    try {
      const text = await file.text()
      const data: SpriteExportData = JSON.parse(text)
      const count = await importAll(data)
      console.log(`Imported ${count} sprites`)
    } catch (err) {
      console.error('Import failed:', err)
    }
    e.target.value = ''
  }, [importAll])

  const handleFileSelect = useCallback((imageType: SpriteImageType, expression: GalExpression) => {
    setUploadTarget({ expression, imageType })
    fileInputRef.current?.click()
  }, [])

  const handleFileChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file || !selectedCreatureId || !uploadTarget) return

    const reader = new FileReader()
    reader.onload = () => {
      const dataUrl = reader.result as string
      setSprite(selectedCreatureId, uploadTarget.imageType, uploadTarget.expression, dataUrl, file.type)
      setUploadTarget(null)
    }
    reader.readAsDataURL(file)

    // Reset input so same file can be re-selected
    e.target.value = ''
  }, [selectedCreatureId, uploadTarget, setSprite])

  if (!open) return null

  const selectedCreature = creatureList.find(c => c.id === selectedCreatureId)

  return (
    <div className="sprite-manager-overlay" onClick={onClose}>
      <div className="sprite-manager-modal" onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="sprite-manager-header">
          <h3>{t('galgame.spriteManager.title')}</h3>
          <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
            <button className="sprite-io-btn" onClick={handleExport}>
              {t('galgame.spriteManager.export')}
            </button>
            <button className="sprite-io-btn" onClick={() => importInputRef.current?.click()}>
              {t('galgame.spriteManager.import')}
            </button>
            <button className="sprite-manager-close" onClick={onClose}>×</button>
          </div>
        </div>

        <div className="sprite-manager-body">
          {/* Left: Creature list */}
          <div className="sprite-manager-sidebar">
            <div className="sprite-manager-sidebar-title">
              {t('galgame.spriteManager.characters')}
            </div>
            {creatureList.map(c => (
              <button
                key={c.id}
                className={`sprite-creature-item ${selectedCreatureId === c.id ? 'active' : ''}`}
                onClick={() => setSelectedCreatureId(c.id)}
              >
                <span className="sprite-creature-name">{c.name}</span>
                {c.isPlayer && <span className="sprite-creature-badge">P</span>}
              </button>
            ))}
            {creatureList.length === 0 && (
              <div className="sprite-empty-hint">{t('galgame.spriteManager.noCharacters')}</div>
            )}
          </div>

          {/* Right: Image config */}
          <div className="sprite-manager-content">
            {!selectedCreatureId ? (
              <div className="sprite-empty-hint">{t('galgame.spriteManager.selectCharacter')}</div>
            ) : (
              <>
                {/* Character name */}
                <div className="sprite-content-header">
                  <span className="sprite-content-name">{selectedCreature?.name}</span>
                  <button
                    className="sprite-btn-danger"
                    onClick={() => {
                      removeCreatureSprites(selectedCreatureId)
                    }}
                  >
                    {t('galgame.spriteManager.clearAll')}
                  </button>
                </div>

                {/* Tabs: standing / avatar */}
                <div className="sprite-tabs">
                  <button
                    className={`sprite-tab ${activeTab === 'standing' ? 'active' : ''}`}
                    onClick={() => setActiveTab('standing')}
                  >
                    {t('galgame.spriteManager.standing')}
                  </button>
                  <button
                    className={`sprite-tab ${activeTab === 'avatar' ? 'active' : ''}`}
                    onClick={() => setActiveTab('avatar')}
                  >
                    {t('galgame.spriteManager.avatar')}
                  </button>
                </div>

                {activeTab === 'standing' ? (
                  /* Standing: single image */
                  <div className="sprite-standing-single">
                    <div
                      className="sprite-standing-preview"
                      onClick={() => handleFileSelect('standing', 'normal')}
                    >
                      {getStandingUrl(selectedCreatureId, 'normal') ? (
                        <img src={getStandingUrl(selectedCreatureId, 'normal')!} alt="standing" draggable={false} />
                      ) : (
                        <div className="sprite-expression-empty">+</div>
                      )}
                    </div>
                    {getStandingUrl(selectedCreatureId, 'normal') && (
                      <button
                        className="sprite-btn-danger"
                        onClick={() => removeSprite(selectedCreatureId, 'standing', 'normal')}
                        style={{ marginTop: 8 }}
                      >
                        {t('galgame.spriteManager.clearAll')}
                      </button>
                    )}
                  </div>
                ) : (
                  /* Avatar: expression grid */
                  <div className="sprite-expression-grid">
                    {ALL_EXPRESSIONS.map(expr => {
                      const url = getAvatarUrl(selectedCreatureId, expr)
                      return (
                        <div key={expr} className="sprite-expression-card">
                          <div className="sprite-expression-label">
                            <span>{EXPRESSION_LABELS[expr]}</span>
                            <span>{expr}</span>
                          </div>
                          <div
                            className="sprite-expression-preview"
                            onClick={() => handleFileSelect('avatar', expr)}
                          >
                            {url ? (
                              <img src={url} alt={expr} draggable={false} />
                            ) : (
                              <div className="sprite-expression-empty">+</div>
                            )}
                          </div>
                          {url && (
                            <button
                              className="sprite-expression-remove"
                              onClick={() => removeSprite(selectedCreatureId, 'avatar', expr)}
                            >
                              ×
                            </button>
                          )}
                        </div>
                      )
                    })}
                  </div>
                )}
              </>
            )}
          </div>
        </div>

        {/* Hidden file inputs */}
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          style={{ display: 'none' }}
          onChange={handleFileChange}
        />
        <input
          ref={importInputRef}
          type="file"
          accept=".json"
          style={{ display: 'none' }}
          onChange={handleImport}
        />
      </div>
    </div>
  )
}

/src/games/custom/components/Transparent:
/**
 * TransparentImg — Canvas 去白底的 <img> 替代组件
 *
 * 将白色/接近白色的像素变为透明，保留其他颜色不变暗。
 * 使用 offscreen canvas 处理，结果缓存在内存 Map 中避免重复计算。
 */

import { useState, useEffect, useRef, memo } from 'react'

// ── 全局缓存：src → 处理后的 blob URL ──
const cache = new Map<string, string>()

// ── 白底检测阈值 ──
const WHITE_THRESHOLD = 240   // RGB 全部 > 此值视为白色
const EDGE_SOFTNESS = 20      // 过渡带宽度，避免硬边

function removeWhiteBg(src: string): Promise<string> {
  // 缓存命中
  const cached = cache.get(src)
  if (cached) return Promise.resolve(cached)

  return new Promise((resolve, reject) => {
    const img = new Image()
    img.crossOrigin = 'anonymous'
    img.onload = () => {
      const canvas = document.createElement('canvas')
      canvas.width = img.naturalWidth
      canvas.height = img.naturalHeight
      const ctx = canvas.getContext('2d')
      if (!ctx) { resolve(src); return }

      ctx.drawImage(img, 0, 0)
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height)
      const data = imageData.data

      const lo = WHITE_THRESHOLD - EDGE_SOFTNESS

      for (let i = 0; i < data.length; i += 4) {
        const r = data[i], g = data[i + 1], b = data[i + 2]
        const minC = Math.min(r, g, b)

        if (minC > lo) {
          // 在过渡带内：越接近纯白越透明
          if (minC >= WHITE_THRESHOLD) {
            data[i + 3] = 0 // 完全透明
          } else {
            // 线性过渡
            const t = (WHITE_THRESHOLD - minC) / EDGE_SOFTNESS
            data[i + 3] = Math.round(data[i + 3] * t)
          }
        }
        // 非白色像素保持不变
      }

      ctx.putImageData(imageData, 0, 0)

      canvas.toBlob(blob => {
        if (!blob) { resolve(src); return }
        const url = URL.createObjectURL(blob)
        cache.set(src, url)
        resolve(url)
      }, 'image/png')
    }
    img.onerror = () => resolve(src) // fallback 到原图
    img.src = src
  })
}

interface TransparentImgProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  src: string
  /** 是否禁用去白底（默认 false） */
  noProcess?: boolean
}

export const TransparentImg = memo(function TransparentImg({
  src,
  noProcess,
  ...imgProps
}: TransparentImgProps) {
  const [processedSrc, setProcessedSrc] = useState<string>(src)
  const mountedRef = useRef(true)

  useEffect(() => {
    mountedRef.current = true
    return () => { mountedRef.current = false }
  }, [])

  useEffect(() => {
    if (noProcess || !src) {
      setProcessedSrc(src)
      return
    }

    // 如果缓存里有，直接用
    const cached = cache.get(src)
    if (cached) {
      setProcessedSrc(cached)
      return
    }

    // 先显示原图，后台处理
    setProcessedSrc(src)
    removeWhiteBg(src).then(url => {
      if (mountedRef.current) setProcessedSrc(url)
    })
  }, [src, noProcess])

  return <img {...imgProps} src={processedSrc} />
})

