## 6. 完整工作流

一个自定义游戏的典型生命周期：

```
┌─────────────────────────────────────────────────┐
│  初始化                                          │
│  getGameState() → 获取世界、角色、注册表          │
│  getPlayerEntity() → 获取玩家数据                 │
│  getNPCEntities() → 获取 NPC 数据                 │
│  解析 CustomComponentRegistry → 了解自定义组件    │
│  解析 Player.CustomComponents → 获取组件实例       │
└──────────────────────┬──────────────────────────┘
                       ↓
┌─────────────────────────────────────────────────┐
│  游戏循环                                        │
│                                                  │
│  1. 展示当前状态 (Player/NPC/World)              │
│  2. 等待玩家输入 (选择/自由文本)                   │
│  3. creativeWritingStream()                       │
│     → 流式展示生成内容                            │
│     → done 事件获取 state_changes                 │
│  4. createSave() → 创建临时存档                   │
│  5. updateGameStateAndDocs()                      │
│     → 更新 ECS 状态                               │
│  6. 刷新数据 (getPlayerEntity, getGameState)      │
│  7. createSave() → 创建正式存档                   │
│  8. 回到步骤 1                                    │
└──────────────────────┬──────────────────────────┘
                       ↓
┌─────────────────────────────────────────────────┐
│  错误处理                                        │
│  updateGameStateAndDocs 失败                      │
│  → loadSave(tempCheckpointId) 回滚               │
│  → 重试或提示用户                                 │
│                                                  │
│  creativeWritingStream 失败                       │
│  → reuse_last_collect: true 重试                  │
│  → 跳过 RAG 重新收集，只重新生成                  │
└─────────────────────────────────────────────────┘
```

/src/games/custom_template/index.tsx:
/**
 * Custom Template — 极简示例游戏
 *
 * 本文件演示游戏引擎的三大核心 API：
 *   1. 数据获取 — getGameState / getPlayerEntity / getNPCEntities
 *   2. 流式创意写作 — creativeWritingStream
 *   3. 游戏状态更新 — updateGameStateAndDocs
 *
 * 完全自包含，不依赖 games/components、Zustand、i18next 或任何 CSS 文件。
 * 适合作为用户自定义游戏前端的起点。
 */

import { useState } from 'react'

// ── 类型化服务 API（唯一外部依赖）──────────────────────────────
import {
  getGameState,
  getPlayerEntity,
  getNPCEntities,
  creativeWritingStream,
  updateGameStateAndDocs,
  createSave,
  loadSave,
  listSaves,
} from '../utils'

import type {
  StateData,
  PlayerEntityOutput,
  NPCEntitiesOutput,
  CreativeWritingOutput,
  UpdateGameStateAndDocsOutput,
  CreateGameSaveOutput,
  ListGameSavesOutput,
} from '../../api/types'
import { formatSettingChange } from '../../api/types'

// ── Props ──────────────────────────────────────────────────────
interface CustomTemplateProps {
  onBack: () => void
}

// ═══════════════════════════════════════════════════════════════
// 主组件
// ═══════════════════════════════════════════════════════════════

export default function CustomTemplateGame({ onBack }: CustomTemplateProps) {
  // ── Section 1: 数据获取 ──────────────────────────────────────
  const [gameState, setGameState] = useState<StateData | null>(null)
  const [player, setPlayer] = useState<PlayerEntityOutput | null>(null)
  const [npcs, setNpcs] = useState<NPCEntitiesOutput | null>(null)

  // ── Section 2: 创意写作 ──────────────────────────────────────
  const [createRequest, setCreateRequest] = useState('写一段简短的冒险故事开头')
  const [thinkingInstruction, setThinkingInstruction] = useState('思考角色当前的处境和可能的发展')
  const [previousOverview, setPreviousOverview] = useState('')
  const [outputSchema, setOutputSchema] = useState('string')
  const [streamContent, setStreamContent] = useState('')
  const [streamReasoning, setStreamReasoning] = useState('')
  const [streamThinking, setStreamThinking] = useState('')
  const [streamStatus, setStreamStatus] = useState<'idle' | 'streaming' | 'done' | 'error'>('idle')
  const [streamError, setStreamError] = useState('')
  const [lastResult, setLastResult] = useState<CreativeWritingOutput | null>(null)

  // ── Section 3: 状态更新 ──────────────────────────────────────
  const [newEvent, setNewEvent] = useState('')
  const [stateChangesText, setStateChangesText] = useState('')
  const [settingChangesText, setSettingChangesText] = useState('')
  const [settingChangesRaw, setSettingChangesRaw] = useState<any[] | null>(null) // 原始结构化数据
  const [updateResult, setUpdateResult] = useState<UpdateGameStateAndDocsOutput | null>(null)
  const [updating, setUpdating] = useState(false)

  // ── Section 4: 存档 ──────────────────────────────────────────
  const [saves, setSaves] = useState<ListGameSavesOutput | null>(null)
  const [lastSave, setLastSave] = useState<CreateGameSaveOutput | null>(null)

  // ── 通用加载状态 ─────────────────────────────────────────────
  const [loading, setLoading] = useState<Record<string, boolean>>({})

  const setLoadingKey = (key: string, value: boolean) =>
    setLoading(prev => ({ ...prev, [key]: value }))

  // ═════════════════════════════════════════════════════════════
  // Section 1: 数据获取处理函数
  // ═════════════════════════════════════════════════════════════

  const handleLoadGameState = async () => {
    setLoadingKey('gameState', true)
    try {
      const result = await getGameState()
      if (result.success && result.data) {
        setGameState(result.data)
      }
    } catch (e) {
      console.error('Failed to load game state:', e)
    }
    setLoadingKey('gameState', false)
  }

  const handleLoadPlayer = async () => {
    setLoadingKey('player', true)
    try {
      const result = await getPlayerEntity()
      setPlayer(result)
    } catch (e) {
      console.error('Failed to load player:', e)
    }
    setLoadingKey('player', false)
  }

  const handleLoadNPCs = async () => {
    setLoadingKey('npcs', true)
    try {
      const result = await getNPCEntities()
      setNpcs(result)
    } catch (e) {
      console.error('Failed to load NPCs:', e)
    }
    setLoadingKey('npcs', false)
  }

  // ═════════════════════════════════════════════════════════════
  // Section 2: 创意写作流式生成
  // ═════════════════════════════════════════════════════════════

  const handleCreativeWrite = async () => {
    // 重置状态
    setStreamContent('')
    setStreamReasoning('')
    setStreamThinking('')
    setStreamError('')
    setStreamStatus('streaming')
    setLastResult(null)

    try {
      await creativeWritingStream({
        create_request: createRequest,
        thinking_instruction: thinkingInstruction,
        previous_content_overview: previousOverview,
        output_content_schema: outputSchema,

        // 流式回调 — 这是核心：根据 event_type 处理不同阶段的数据
        callback: (streamEvent) => {
          const { event_type, event_data } = streamEvent

          switch (event_type) {
            // RAG 收集器更新：展示从设定文档中检索到的相关内容
            case 'collector_result_update': {
              const data = event_data as Partial<CreativeWritingOutput>
              if (data.collector_results) {
                setStreamReasoning(
                  `[RAG 收集] 找到 ${data.collector_results.length} 个相关实体`
                )
              }
              break
            }

            // 推理更新：展示 LLM 的推理过程
            case 'reasoning_update': {
              const data = event_data as Partial<CreativeWritingOutput>
              if (data.reasoning) setStreamReasoning(data.reasoning)
              if (data.collector_results) {
                // collector_results 也可能随 reasoning_update 一起到达
              }
              break
            }

            // 结果增量更新：流式接收生成的内容
            case 'result_update': {
              const data = event_data as Partial<CreativeWritingOutput>
              if (data.content !== undefined) {
                // content 的类型取决于 output_content_schema
                // schema 为 "string" 时 content 就是字符串
                // schema 为对象时 content 是对应的对象（流式中可能是部分数据）
                setStreamContent(
                  typeof data.content === 'string'
                    ? data.content
                    : JSON.stringify(data.content, null, 2)
                )
              }
              if (data.thinking) setStreamThinking(data.thinking)
              break
            }

            // 生成完成：获取最终结果，含 state_changes 和 setting_changes
            case 'done': {
              const data = event_data as Partial<CreativeWritingOutput>
              setStreamStatus('done')
              setLastResult(data as CreativeWritingOutput)

              // 自动填充到 Section 3 的输入框，方便用户直接更新状态
              if (data.content) {
                setNewEvent(
                  typeof data.content === 'string'
                    ? data.content.slice(0, 200)
                    : JSON.stringify(data.content).slice(0, 200)
                )
              }
              if (data.state_changes?.service_calls?.length) {
                setStateChangesText(data.state_changes.service_calls.map((c: any) => `${c.name}: ${c.suggestion}`).join('\n'))
              }
              if (data.setting_changes?.length) {
                setSettingChangesRaw(data.setting_changes)
                setSettingChangesText(data.setting_changes.map(formatSettingChange).join('\n'))
              }
              break
            }

            // 错误处理
            case 'error': {
              const err = event_data as Error
              setStreamStatus('error')
              setStreamError(err.message || String(err))
              break
            }
          }
        },
      })
    } catch (e: any) {
      setStreamStatus('error')
      setStreamError(e.message || String(e))
    }
  }

  // ═════════════════════════════════════════════════════════════
  // Section 3: 更新游戏状态
  // ═════════════════════════════════════════════════════════════

  const handleUpdateState = async () => {
    setUpdating(true)
    setUpdateResult(null)
    try {
      const result = await updateGameStateAndDocs({
        new_event: newEvent,
        state_changes: {
          related_creature_ids: [],
          related_region_ids: [],
          related_organization_ids: [],
          service_calls: stateChangesText.split('\n').filter(Boolean).map(s => {
            const idx = s.indexOf(':')
            return idx > 0 ? { name: s.slice(0, idx).trim(), suggestion: s.slice(idx + 1).trim() } : { name: 'unknown', suggestion: s }
          })
        },
        setting_changes: settingChangesRaw || settingChangesText.split('\n').filter(Boolean),
      })
      setUpdateResult(result)
    } catch (e: any) {
      setUpdateResult({ success: false, error: e.message || String(e) })
    }
    setUpdating(false)
  }

  // ═════════════════════════════════════════════════════════════
  // Section 4: 存档管理
  // ═════════════════════════════════════════════════════════════

  const handleCreateSave = async () => {
    setLoadingKey('save', true)
    try {
      const result = await createSave({ title: 'Custom Template Save' })
      setLastSave(result)
    } catch (e) {
      console.error('Failed to create save:', e)
    }
    setLoadingKey('save', false)
  }

  const handleListSaves = async () => {
    setLoadingKey('saves', true)
    try {
      const result = await listSaves()
      setSaves(result)
    } catch (e) {
      console.error('Failed to list saves:', e)
    }
    setLoadingKey('saves', false)
  }

  const handleLoadSave = async (checkpointId: string) => {
    setLoadingKey('loadSave', true)
    try {
      await loadSave(checkpointId)
      // 重新加载数据以反映存档状态
      await handleLoadGameState()
      await handleLoadPlayer()
    } catch (e) {
      console.error('Failed to load save:', e)
    }
    setLoadingKey('loadSave', false)
  }

  // ═════════════════════════════════════════════════════════════
  // 渲染
  // ═════════════════════════════════════════════════════════════

  return (
    <div style={{ padding: 24, maxWidth: 960, margin: '0 auto', fontFamily: 'system-ui, sans-serif' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 24 }}>
        <button onClick={onBack}>← Back</button>
        <h1 style={{ margin: 0 }}>Custom Template Game</h1>
      </div>

      {/* ════════════════════════════════════════════════════════
          Section 1: 数据获取
          ════════════════════════════════════════════════════════ */}
      <section style={{ marginBottom: 32 }}>
        <h2>1. 数据获取 (Game Data)</h2>
        <p style={{ color: '#666' }}>
          演示如何获取游戏中的各类数据：世界状态、玩家、NPC、地域、组织等。
        </p>

        <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
          <button onClick={handleLoadGameState} disabled={loading.gameState}>
            {loading.gameState ? '加载中...' : '📦 加载游戏状态'}
          </button>
          <button onClick={handleLoadPlayer} disabled={loading.player}>
            {loading.player ? '加载中...' : '🧑 加载玩家'}
          </button>
          <button onClick={handleLoadNPCs} disabled={loading.npcs}>
            {loading.npcs ? '加载中...' : '👥 加载 NPC'}
          </button>
        </div>

        {/* 游戏状态概览 */}
        {gameState && (
          <details open>
            <summary><strong>GameState (World / Regions / Organizations)</strong></summary>

            <h4>World</h4>
            <JsonBlock data={gameState.World} />

            {gameState.Regions && (
              <>
                <h4>Regions ({gameState.Regions.length})</h4>
                <JsonBlock data={gameState.Regions} />
              </>
            )}

            {gameState.Organizations && (
              <>
                <h4>Organizations ({gameState.Organizations.length})</h4>
                <JsonBlock data={gameState.Organizations} />
              </>
            )}

            {gameState.Creatures && (
              <>
                <h4>Creatures ({gameState.Creatures.length})</h4>
                <JsonBlock data={gameState.Creatures} />
              </>
            )}
          </details>
        )}

        {/* 玩家实体 */}
        {player && (
          <details open>
            <summary>
              <strong>Player Entity</strong>
              {player.Creature?.name && ` — ${player.Creature.name}`}
            </summary>
            <JsonBlock data={player} />
          </details>
        )}

        {/* NPC 列表 */}
        {npcs && (
          <details open>
            <summary><strong>NPCs ({npcs.count})</strong></summary>
            <JsonBlock data={npcs} />
          </details>
        )}
      </section>

      {/* ════════════════════════════════════════════════════════
          Section 2: 创意写作流式生成
          ════════════════════════════════════════════════════════ */}
      <section style={{ marginBottom: 32 }}>
        <h2>2. CreativeWritingStream (流式创意写作)</h2>
        <p style={{ color: '#666' }}>
          演示如何调用 LLM 流式生成内容。引擎会自动进行 RAG 检索相关设定文档。
        </p>

        {/* 创作请求 */}
        <label>
          <strong>create_request</strong> — 创作请求（告诉 LLM 写什么）
        </label>
        <textarea
          value={createRequest}
          onChange={e => setCreateRequest(e.target.value)}
          rows={3}
          style={{ width: '100%', marginBottom: 8 }}
        />

        {/* 思考指令 */}
        <label>
          <strong>thinking_instruction</strong> — 思考指令（引导 LLM 如何思考）
        </label>
        <textarea
          value={thinkingInstruction}
          onChange={e => setThinkingInstruction(e.target.value)}
          rows={2}
          style={{ width: '100%', marginBottom: 8 }}
        />

        {/* 之前内容概览 */}
        <label>
          <strong>previous_content_overview</strong> — 之前内容概览（上下文摘要）
        </label>
        <textarea
          value={previousOverview}
          onChange={e => setPreviousOverview(e.target.value)}
          rows={2}
          style={{ width: '100%', marginBottom: 8 }}
        />

        {/* 输出 schema */}
        <label>
          <strong>output_content_schema</strong> — 输出结构定义
          <span style={{ color: '#999', marginLeft: 8 }}>
            例: "string" 或 {`"{title: string, content: string}"`}
          </span>
        </label>
        <input
          value={outputSchema}
          onChange={e => setOutputSchema(e.target.value)}
          style={{ width: '100%', marginBottom: 12 }}
        />

        <button
          onClick={handleCreativeWrite}
          disabled={streamStatus === 'streaming' || !createRequest.trim()}
        >
          {streamStatus === 'streaming' ? '⏳ 生成中...' : '✨ 开始生成'}
        </button>

        {/* 流式输出展示 */}
        {streamStatus !== 'idle' && (
          <div style={{ marginTop: 12 }}>
            <div style={{ marginBottom: 4, color: streamStatus === 'error' ? 'red' : '#333' }}>
              状态: <strong>{streamStatus}</strong>
            </div>

            {streamError && (
              <div style={{ color: 'red', marginBottom: 8 }}>
                错误: {streamError}
              </div>
            )}

            {streamReasoning && (
              <details>
                <summary>Reasoning / RAG</summary>
                <pre style={preStyle}>{streamReasoning}</pre>
              </details>
            )}

            {streamThinking && (
              <details>
                <summary>Thinking</summary>
                <pre style={preStyle}>{streamThinking}</pre>
              </details>
            )}

            {streamContent && (
              <>
                <strong>生成内容:</strong>
                <pre style={preStyle}>{streamContent}</pre>
              </>
            )}

            {lastResult && (
              <details>
                <summary>完整结果 (含 state_changes / setting_changes)</summary>
                <JsonBlock data={lastResult} />
              </details>
            )}
          </div>
        )}
      </section>

      {/* ════════════════════════════════════════════════════════
          Section 3: 更新游戏状态
          ════════════════════════════════════════════════════════ */}
      <section style={{ marginBottom: 32 }}>
        <h2>3. UpdateGameStateAndDocs (更新游戏状态)</h2>
        <p style={{ color: '#666' }}>
          将新事件和状态变更发送给引擎，引擎会自动生成并执行 Lua 代码来更新 ECS。
          通常在 CreativeWritingStream 完成后调用。
        </p>

        <label><strong>new_event</strong> — 新发生的事件描述</label>
        <textarea
          value={newEvent}
          onChange={e => setNewEvent(e.target.value)}
          rows={3}
          style={{ width: '100%', marginBottom: 8 }}
        />

        <label>
          <strong>state_changes</strong> — 状态变化列表（每行一条）
        </label>
        <textarea
          value={stateChangesText}
          onChange={e => setStateChangesText(e.target.value)}
          rows={3}
          style={{ width: '100%', marginBottom: 8 }}
          placeholder="玩家获得了 10 经验值&#10;NPC 张三好感度 +5"
        />

        <label>
          <strong>setting_changes</strong> — 设定变更列表（每行一条）
        </label>
        <textarea
          value={settingChangesText}
          onChange={e => setSettingChangesText(e.target.value)}
          rows={2}
          style={{ width: '100%', marginBottom: 12 }}
          placeholder="新增地点: 黑暗森林深处的古老神殿"
        />

        <button
          onClick={handleUpdateState}
          disabled={updating || !newEvent.trim()}
        >
          {updating ? '⏳ 更新中...' : '🔄 更新游戏状态'}
        </button>

        {updateResult && (
          <div style={{ marginTop: 12 }}>
            <div style={{ color: updateResult.success ? 'green' : 'red', marginBottom: 8 }}>
              {updateResult.success ? '✅ 更新成功' : `❌ 更新失败: ${updateResult.error}`}
            </div>
            <details open>
              <summary>更新结果详情</summary>
              <JsonBlock data={updateResult} />
            </details>
          </div>
        )}
      </section>

      {/* ════════════════════════════════════════════════════════
          Section 4: 存档管理
          ════════════════════════════════════════════════════════ */}
      <section style={{ marginBottom: 32 }}>
        <h2>4. 存档管理 (Save / Load)</h2>
        <p style={{ color: '#666' }}>
          演示存档的创建、列表和加载。
        </p>

        <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
          <button onClick={handleCreateSave} disabled={loading.save}>
            {loading.save ? '保存中...' : '💾 创建存档'}
          </button>
          <button onClick={handleListSaves} disabled={loading.saves}>
            {loading.saves ? '加载中...' : '📋 列出存档'}
          </button>
        </div>

        {lastSave && (
          <div style={{ marginBottom: 8 }}>
            最新存档: <code>{(lastSave as any).checkpoint_id || JSON.stringify(lastSave)}</code>
          </div>
        )}

        {saves && (
          <details open>
            <summary>存档列表</summary>
            <JsonBlock data={saves} />
          </details>
        )}
      </section>
    </div>
  )
}

// ── 工具组件 ────────────────────────────────────────────────────

/** 简单的 JSON 展示块 */
function JsonBlock({ data }: { data: unknown }) {
  return (
    <pre style={preStyle}>
      {JSON.stringify(data, null, 2)}
    </pre>
  )
}

const preStyle: React.CSSProperties = {
  background: '#f5f5f5',
  padding: 12,
  borderRadius: 4,
  overflow: 'auto',
  maxHeight: 400,
  fontSize: 12,
  lineHeight: 1.4,
}

/src/games/ink/InkGame.css:
@import url('https://fonts.googleapis.com/css2?family=Ma+Shan+Zheng&family=Noto+Serif+SC:wght@300;400;700&display=swap');

/* 全局重置与基础样式 */
.ink-game {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: row;
  background: var(--paper-bg-primary);
  /* 米黄色纸张背景 */
  color: var(--paper-text-primary);
  /* 深褐色/黑色墨水 */
  font-family: 'Noto Serif SC', 'Georgia', serif;
  overflow: hidden;
}

/* 滚动条美化 (适配浅色纸媒) */
.ink-game ::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

.ink-game ::-webkit-scrollbar-track {
  background: transparent;
}

.ink-game ::-webkit-scrollbar-thumb {
  background: var(--paper-border-color);
  border-radius: 0;
}

.ink-game ::-webkit-scrollbar-thumb:hover {
  background: var(--paper-border-color-hover);
}

/* 极简边栏 */
.ink-game .slim-sidebar {
  width: 60px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  padding: 1.5rem 0;
  background: var(--paper-bg-tertiary);
  /* 稍微深一点的纸张色用于侧边栏 */
  border-right: 1px solid var(--paper-border-color);
  /* 墨水色细线 */
  z-index: 100;
}

.ink-game .sidebar-top,
.ink-game .sidebar-bottom {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1.25rem;
  width: 100%;
}

.ink-game .sidebar-icon-btn {
  background: transparent;
  color: var(--paper-text-secondary);
  border: none;
  width: 44px;
  height: 44px;
  border-radius: 4px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.3rem;
  transition: all 0.2s;
}

.ink-game .sidebar-icon-btn:hover {
  background: var(--paper-hover-bg);
  color: var(--paper-text-primary);
}

.ink-game .sidebar-icon-btn.active {
  background: var(--paper-active-bg);
  color: var(--paper-electric-blue);
  /* 传统朱砂红印泥色 */
  border-left: 2px solid var(--paper-electric-blue);
  border-radius: 0 4px 4px 0;
}

.ink-game .sidebar-icon-btn.toggle-panel-btn {
  font-size: 1rem;
}

.ink-game .sidebar-divider {
  width: 32px;
  height: 1px;
  background: var(--paper-border-color);
  margin: 0.25rem 0;
}

/* ========== 移动端专属顶部栏 ========== */
.ink-game .mobile-ink-header {
  display: none;
}

/* 主布局 */
.ink-game .ink-layout {
  flex: 1;
  display: flex;
  position: relative;
  overflow: hidden;
  min-height: 0;
}

/* 左侧面板 */
.ink-game .left-panel {
  width: 340px;
  background: var(--paper-bg-secondary);
  /* 主体书页背景更亮一点 */
  border-right: 1px solid var(--paper-border-color);
  display: flex;
  flex-direction: column;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  flex-shrink: 0;
  position: relative;
  z-index: 50;
}

.ink-game .left-panel .panel-header {
  padding: 1.5rem 1.5rem 1rem 1.5rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 2px solid #e1dcd1;
}

.ink-game .left-panel .panel-header h2 {
  font-family: inherit;
  font-size: 0.95rem;
  font-weight: bold;
  letter-spacing: 2px;
  color: var(--paper-text-primary);
  margin: 0;
  text-transform: uppercase;
}

.ink-game .left-panel .panel-add-btn {
  background: transparent;
  color: var(--paper-text-primary);
  border: 1px solid var(--paper-text-primary);
  width: 24px;
  height: 24px;
  font-size: 1.2rem;
  line-height: 1;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s, color 0.2s;
}

.ink-game .left-panel .panel-add-btn:hover {
  background: var(--paper-text-primary);
  color: var(--paper-bg-primary);
}

.ink-game .left-panel .panel-content {
  flex: 1;
  overflow-y: auto;
  padding: 3rem 1rem 1rem 1rem;
}

.ink-game .left-panel.closed {
  width: 0;
  border-right: none;
  opacity: 0;
  pointer-events: none;
  overflow: hidden;
}

/* 移动端遮罩 */
.panel-overlay {
  display: none;
}

/* 右侧内容区 */
.ink-game .right-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: transparent;
  overflow: hidden;
  position: relative;
}

/* 主标题栏 */
.ink-game .main-header {
  height: 64px;
  padding: 0 2rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 3px double var(--paper-border-color);
  flex-shrink: 0;
}

.ink-game .header-right {
  display: flex;
  align-items: center;
  gap: 1rem;
}

/* ========== 章节跳转 ========== */
.chapter-jump-wrapper {
  position: relative;
}

.chapter-jump-trigger {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  border: 1.5px solid var(--paper-border-color, #e2e8f0);
  border-radius: 6px;
  background: var(--paper-bg-primary, #f0f2f7);
  color: var(--paper-text-secondary, #4a5568);
  font-size: 0.78rem;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.15s;
  white-space: nowrap;
}

.chapter-jump-trigger:hover {
  background: var(--paper-bg-secondary, #fff);
  border-color: var(--paper-text-tertiary);
}

.chapter-jump-menu {
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  z-index: 100;
  min-width: 240px;
  max-width: 320px;
  background: var(--paper-bg-secondary, #fff);
  border: 2px solid var(--paper-border-color, #e2e8f0);
  border-radius: 12px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);
  padding: 6px;
  animation: chapter-menu-in 0.15s ease-out;
}

@keyframes chapter-menu-in {
  from { opacity: 0; transform: translateY(-6px); }
  to { opacity: 1; transform: translateY(0); }
}

.chapter-jump-header {
  padding: 6px 10px 4px;
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--paper-text-tertiary, #8896ab);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.chapter-jump-list {
  max-height: 50vh;
  overflow-y: auto;
}

.chapter-jump-item {
  display: flex;
  align-items: baseline;
  gap: 8px;
  width: 100%;
  padding: 8px 10px;
  border: none;
  background: transparent;
  font-family: inherit;
  font-size: 0.85rem;
  color: var(--paper-text-primary, #1a1a2e);
  cursor: pointer;
  border-radius: 8px;
  transition: background 0.12s;
  text-align: left;
  line-height: 1.4;
}

.chapter-jump-item:hover,
.chapter-jump-item:active {
  background: var(--paper-bg-primary, #f0f2f7);
}

.chapter-jump-num {
  flex-shrink: 0;
  width: 1.6em;
  text-align: right;
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--paper-text-tertiary, #8896ab);
}

.chapter-jump-label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* PC 端：隐藏移动端的章节按钮 */
.ink-game .chapter-jump-btn {
  display: none;
}

/* 统一设置面板按钮与控件样式 (适用于模态框内) */
.paper-settings-panel .narrative-person-btn {
  background: transparent;
  border: 1px solid var(--paper-text-primary);
  color: var(--paper-text-primary);
  font-family: inherit;
  font-size: 0.9rem;
  padding: 6px 12px;
  cursor: pointer;
  white-space: nowrap;
  transition: all 0.2s;
}

.paper-settings-panel .narrative-person-btn:hover {
  background: var(--paper-hover-bg);
}

.paper-settings-panel .dice-mode-btn {
  background: transparent;
  border: 1px solid var(--paper-text-primary);
  color: var(--paper-text-primary);
  font-family: inherit;
  font-size: 0.9rem;
  padding: 6px 12px;
  cursor: pointer;
  white-space: nowrap;
  transition: all 0.2s;
}

.paper-settings-panel .dice-mode-btn:hover {
  background: var(--paper-hover-bg);
}

.paper-settings-panel .dice-mode-btn.off {
  color: var(--paper-text-tertiary);
  border-color: var(--paper-text-tertiary);
  text-decoration: line-through;
}

.paper-settings-panel .dice-mode-btn.visible {
  border-color: var(--paper-electric-blue);
  color: var(--paper-electric-blue);
}

.paper-settings-panel .dice-mode-btn.hidden {
  border-style: dashed;
}

.paper-settings-panel .paragraph-slider {
  display: flex;
  align-items: center;
  gap: 0.8rem;
  font-size: 0.9rem;
  color: var(--paper-text-primary);
}

.paper-settings-panel .paragraph-slider label {
  white-space: nowrap;
  min-width: 5em;
}

.paper-settings-panel .paragraph-slider input[type="range"] {
  flex: 1;
  height: 2px;
  background: var(--paper-border-color);
  accent-color: var(--paper-text-primary);
  cursor: pointer;
  appearance: none;
}

.paper-settings-panel .paragraph-slider input[type="range"]::-webkit-slider-thumb {
  appearance: none;
  width: 14px;
  height: 14px;
  background: var(--paper-text-primary);
  border-radius: 50%;
  cursor: pointer;
}

.paper-settings-panel .auto-scroll-toggle {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.9rem;
  color: var(--paper-text-primary);
  cursor: pointer;
  user-select: none;
  white-space: nowrap;
}

.paper-settings-panel .auto-scroll-toggle input[type="checkbox"] {
  accent-color: var(--paper-text-primary);
  width: 16px;
  height: 16px;
  cursor: pointer;
  border: 1px solid var(--paper-text-primary);
}

.paper-settings-panel .api-config-btn {
  background: transparent;
  border: 1px solid var(--paper-text-primary);
  color: var(--paper-text-primary);
  font-family: inherit;
  font-size: 0.9rem;
  padding: 6px 12px;
  cursor: pointer;
  white-space: nowrap;
  transition: all 0.2s;
}

.paper-settings-panel .api-config-btn:hover {
  background: var(--paper-hover-bg);
}

/* ========== 统一设置模态框 (纸媒风格) ========== */
.paper-settings-overlay {
  position: fixed;
  inset: 0;
  z-index: 200;
  background: rgba(244, 241, 234, 0.8);
  backdrop-filter: blur(2px);
  display: flex;
  align-items: center;
  justify-content: center;
}

.paper-settings-panel {
  width: 90%;
  max-width: 420px;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-text-primary);
  box-shadow: 6px 6px 0px var(--paper-shadow-color);
  padding: 0;
  animation: paperSlideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes paperSlideUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.paper-settings-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 1.5rem;
  border-bottom: 2px solid var(--paper-text-primary);
}

.paper-settings-header h3 {
  margin: 0;
  font-size: 1.1rem;
  color: var(--paper-text-primary);
  letter-spacing: 2px;
}

.paper-settings-header button {
  background: none;
  border: none;
  color: var(--paper-text-secondary);
  font-size: 1.2rem;
  cursor: pointer;
  padding: 0.2rem;
}

.paper-settings-header button:hover {
  color: var(--paper-electric-blue);
}

.paper-settings-body {
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.paper-settings-footer {
  margin-top: 1rem;
  padding-top: 1rem;
  border-top: 1px dashed var(--paper-border-color);
  display: flex;
  justify-content: center;
}

.paper-settings-footer .game-time {
  font-style: italic;
  color: var(--paper-text-secondary);
  font-size: 0.85rem;
}

.ink-game .header-breadcrumbs {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-family: inherit;
  font-size: 0.85rem;
  color: var(--paper-text-tertiary);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.ink-game .breadcrumb-tab {
  cursor: pointer;
  padding: 4px 12px;
  border-radius: 3px;
  transition: all 0.2s;
  color: var(--paper-text-tertiary);
  user-select: none;
}

.ink-game .breadcrumb-tab:hover {
  color: var(--paper-text-secondary);
  background: var(--paper-bg-secondary);
}

.ink-game .breadcrumb-tab.active {
  color: var(--paper-text-primary);
  font-weight: bold;
  background: var(--paper-bg-secondary);
}

.ink-game .breadcrumb-separator {
  color: var(--paper-border-color);
  pointer-events: none;
  user-select: none;
}

/* 小说流容器 */
.ink-game .ink-flow {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem 2rem;
  scroll-behavior: smooth;
  padding-bottom: 2rem;
}

/* 加载更早历史的按钮区域 */
.load-more-turns {
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: 2rem;
  padding: 1rem 0;
  position: relative;
}

.load-more-turns::before,
.load-more-turns::after {
  content: '';
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, transparent, var(--paper-border-color), transparent);
  max-width: 150px;
}

.load-more-btn {
  background: transparent;
  border: 1px solid var(--paper-border-color-hover);
  color: var(--paper-text-secondary);
  padding: 0.5rem 1.5rem;
  border-radius: 20px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all 0.2s;
  letter-spacing: 1px;
  margin: 0 1rem;
}

.load-more-btn:hover {
  background: var(--paper-hover-bg);
  color: var(--paper-text-primary);
  border-color: var(--paper-text-primary);
}

/* 单个回合块 */
.ink-turn {
  margin-bottom: 2rem;
  animation: fadeIn 0.5s ease-out;
  max-width: 900px;
  margin-left: auto;
  margin-right: auto;
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* 剧情块 */
.story-block {
  background: transparent;
  padding: 1.5rem 2rem;
  position: relative;
}

.novel-content p {
  line-height: 2.2;
  margin-bottom: 1.5rem;
  font-size: 1.15rem;
  color: var(--paper-text-primary);
  text-align: justify;
  text-indent: 2em;
  /* 纸媒版式：首行缩进 */
  letter-spacing: 0.5px;
}

.novel-content p:last-child {
  margin-bottom: 0;
}

/* 打字机光标 */
.novel-content.typewriter-active p:last-child::after {
  content: '▎';
  animation: typewriter-blink 0.8s infinite;
  color: var(--paper-electric-blue);
  margin-left: 2px;
}

@keyframes typewriter-blink {

  0%,
  100% {
    opacity: 1;
  }

  50% {
    opacity: 0;
  }
}

.story-divider {
  text-align: center;
  color: var(--paper-border-color-hover);
  margin: 2rem 0;
  letter-spacing: 0.5rem;
  font-size: 1.2rem;
}

/* 章节标题 */
.chapter-hint {
  font-family: inherit;
  font-size: 1.5rem;
  color: var(--paper-electric-blue);
  /* 朱砂红 */
  margin-bottom: 1rem;
  padding-bottom: 0.8rem;
  border-bottom: 2px solid rgba(139, 43, 26, 0.2);
  text-align: center;
  font-weight: bold;
}

.chapter-header {
  display: flex;
  align-items: center;
  justify-content: center;
  /* 纸媒风格通常居中标题 */
  margin-bottom: 1rem;
}

/* 玩家行动块 */
.action-block {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  margin: 2.5rem 0;
  padding-right: 1.5rem;
  /* 留出页边距 */
  border-right: 4px double var(--paper-border-color);
}

.action-label {
  font-size: 0.85rem;
  color: var(--paper-text-secondary);
  margin-bottom: 0.5rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-style: italic;
}

.special-action-badge {
  background: transparent;
  color: var(--paper-electric-blue);
  border: 1px solid var(--paper-electric-blue);
  padding: 0.1rem 0.4rem;
  font-size: 0.75rem;
  font-style: normal;
}

.custom-action-badge {
  background: transparent;
  color: var(--paper-text-primary);
  border: 1px dashed var(--paper-text-primary);
  padding: 0.1rem 0.4rem;
  font-size: 0.75rem;
  font-style: normal;
}

.action-content {
  background: transparent;
  color: var(--paper-text-primary);
  padding: 0;
  font-size: 1.1rem;
  font-weight: bold;
  text-align: right;
}

/* ============ 玩家选项样式 (纸媒排版) ============ */
.player-choices-container {
  margin-top: 2rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--paper-border-color);
}

.choices-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 1rem;
  justify-content: center;
}

.choices-icon {
  font-size: 1.2rem;
  color: var(--paper-text-primary);
}

.choices-title {
  font-size: 1.1rem;
  color: var(--paper-text-primary);
  font-weight: bold;
  letter-spacing: 2px;
}

.choices-list {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.choice-button {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  padding: 1.2rem 1.5rem;
  background: transparent;
  border: 1px solid var(--paper-text-primary);
  cursor: pointer;
  transition: all 0.2s ease;
  text-align: left;
  width: 100%;
  position: relative;
}

.choice-button::before {
  content: '';
  position: absolute;
  top: 4px;
  left: 4px;
  right: -4px;
  bottom: -4px;
  border: 1px solid var(--paper-border-color-hover);
  z-index: -1;
  transition: all 0.2s;
}

.choice-button:hover:not(:disabled) {
  background: var(--paper-hover-bg);
  transform: translate(-2px, -2px);
}

.choice-button:hover:not(:disabled)::before {
  top: 6px;
  left: 6px;
  right: -6px;
  bottom: -6px;
  border-style: dashed;
}

.choice-button:disabled {
  opacity: 0.4;
  cursor: not-allowed;
  border-style: dashed;
}

.choice-button.special {
  border: 2px solid var(--paper-electric-blue);
  /* 印泥红变体 */
}

.choice-button.special::before {
  border: 1px solid rgba(139, 43, 26, 0.3);
}

.choice-button.special:hover:not(:disabled) {
  background: rgba(139, 43, 26, 0.03);
}

.choice-name {
  font-size: 1.1rem;
  font-weight: bold;
  color: var(--paper-text-primary);
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
}

.choice-button.special .choice-name {
  color: var(--paper-electric-blue);
}

.special-badge {
  font-size: 0.9rem;
}

.choice-description {
  font-size: 0.95rem;
  color: #555;
  line-height: 1.5;
  padding-left: 1.5rem;
}

/* 导演指令区域 (便签风格) */
/* ─── OOC Instructions Section ─── */
.ooc-instructions-section {
  margin-top: 1.5rem;
  padding-top: 1rem;
  border-top: 2px dotted var(--paper-border-color);
}

.ooc-instructions-header {
  margin-bottom: 0.5rem;
}

.ooc-instructions-title {
  font-size: 0.9rem;
  color: var(--paper-electric-blue);
  font-weight: bold;
}

.ooc-instructions-list {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  margin-bottom: 0.6rem;
}

.ooc-instruction-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.5rem;
  padding: 0.5rem 0.7rem;
  background: var(--paper-bg-content);
  border: 1px solid var(--paper-border-color);
  border-left: 3px solid var(--paper-electric-blue);
  font-size: 0.88rem;
}

.ooc-instruction-content {
  flex: 1;
  color: var(--paper-text-primary);
  line-height: 1.4;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.ooc-instruction-meta {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  flex-shrink: 0;
}

.ooc-instruction-duration {
  font-size: 0.75rem;
  color: var(--paper-text-secondary);
  white-space: nowrap;
}

.ooc-instruction-edit-btn,
.ooc-instruction-delete-btn {
  background: none;
  border: none;
  cursor: pointer;
  padding: 0.15rem 0.25rem;
  font-size: 0.8rem;
  opacity: 0.6;
  transition: opacity 0.15s;
}

.ooc-instruction-edit-btn:hover:not(:disabled),
.ooc-instruction-delete-btn:hover:not(:disabled) {
  opacity: 1;
}

.ooc-instruction-edit-btn:disabled,
.ooc-instruction-delete-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

/* OOC Form */
.ooc-form {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.8rem;
  background: var(--paper-bg-content);
  border: 1px solid var(--paper-border-color);
  border-left: 3px solid var(--paper-electric-blue);
}

.ooc-form textarea {
  width: 100%;
  background: transparent;
  border: none;
  border-bottom: 1px dashed rgba(139, 43, 26, 0.3);
  color: var(--paper-text-primary);
  padding: 0.5rem 0;
  font-size: 0.95rem;
  font-family: inherit;
  resize: vertical;
  line-height: 1.5;
}

.ooc-form textarea:focus {
  outline: none;
  border-bottom-color: var(--paper-electric-blue);
}

.ooc-form-options {
  display: flex;
  gap: 1rem;
  align-items: center;
  font-size: 0.85rem;
  color: var(--paper-text-secondary);
}

.ooc-duration-option {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  cursor: pointer;
}

.ooc-duration-option input[type="radio"] {
  accent-color: var(--paper-electric-blue);
}

.ooc-duration-input {
  width: 3rem;
  padding: 0.15rem 0.3rem;
  margin-left: 0.3rem;
  background: transparent;
  border: 1px solid var(--paper-border-color);
  color: var(--paper-text-primary);
  font-size: 0.85rem;
  text-align: center;
}

.ooc-form-actions {
  display: flex;
  justify-content: flex-end;
  gap: 0.5rem;
}

.ooc-cancel-btn,
.ooc-confirm-btn {
  padding: 0.3rem 0.8rem;
  font-size: 0.82rem;
  cursor: pointer;
  border: 1px solid var(--paper-border-color);
  transition: all 0.15s;
}

.ooc-cancel-btn {
  background: transparent;
  color: var(--paper-text-secondary);
}

.ooc-cancel-btn:hover {
  background: var(--paper-text-secondary);
  color: var(--paper-bg-primary);
}

.ooc-confirm-btn {
  background: rgba(139, 43, 26, 0.08);
  color: var(--paper-electric-blue);
  font-weight: bold;
  border-color: var(--paper-electric-blue);
}

.ooc-confirm-btn:hover:not(:disabled) {
  background: rgba(139, 43, 26, 0.2);
}

.ooc-confirm-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* Add button */
.ooc-add-btn {
  padding: 0.5rem 1rem;
  background: rgba(139, 43, 26, 0.05);
  border: 1px dashed rgba(139, 43, 26, 0.6);
  color: var(--paper-electric-blue);
  cursor: pointer;
  font-size: 0.85rem;
  transition: all 0.2s;
  width: 100%;
  text-align: center;
}

.ooc-add-btn:hover:not(:disabled) {
  background: rgba(139, 43, 26, 0.15);
  border-style: solid;
}

.ooc-add-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* 行动历史中的 OOC 指令显示 (backward compat) */
.action-ooc-note {
  display: flex;
  align-items: flex-start;
  gap: 0.4rem;
  margin-top: 0.5rem;
  padding: 0.6rem;
  background: transparent;
  border: 1px solid var(--paper-border-color);
  border-left: 3px solid var(--paper-electric-blue);
  font-size: 0.9rem;
  color: var(--paper-text-primary);
  font-style: italic;
  max-width: 400px;
}

.action-ooc-note-icon {
  flex-shrink: 0;
}

.action-ooc-note-text {
  line-height: 1.5;
}

/* 自定义输入区域 (原稿纸风格) */
.custom-input-section {
  margin-top: 1.5rem;
  padding-top: 1rem;
  border-top: 1px solid var(--paper-border-color);
}

.show-custom-input-btn {
  padding: 0.75rem 1.25rem;
  background: transparent;
  border: 1px solid var(--paper-text-primary);
  color: var(--paper-text-primary);
  cursor: pointer;
  font-size: 0.95rem;
  width: 100%;
  transition: all 0.2s;
  letter-spacing: 1px;
}

.show-custom-input-btn:hover:not(:disabled) {
  background: var(--paper-hover-bg);
  box-shadow: 2px 2px 0px var(--paper-shadow-color);
}

.show-custom-input-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  border-style: dashed;
}

.custom-input-area {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.custom-input-area textarea {
  width: 100%;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-border-color);
  padding: 1rem;
  color: var(--paper-text-primary);
  font-family: inherit;
  font-size: 1.05rem;
  resize: none;
  line-height: 1.8;
  /* 原稿纸横线效果 */
  background-image: linear-gradient(var(--paper-border-color) 1px, transparent 1px);
  background-size: 100% 1.8em;
  background-position: 0 calc(1rem + 1em - 1px);
}

.custom-input-area textarea:focus {
  outline: none;
  border-color: var(--paper-text-primary);
}

.custom-input-actions {
  display: flex;
  justify-content: flex-end;
  gap: 0.5rem;
}

.custom-input-actions .cancel-btn {
  padding: 0.5rem 1rem;
  background: transparent;
  border: 1px solid var(--paper-text-secondary);
  color: var(--paper-text-secondary);
  cursor: pointer;
  font-size: 0.9rem;
  transition: all 0.2s;
}

.custom-input-actions .cancel-btn:hover {
  background: var(--paper-text-secondary);
  color: var(--paper-bg-primary);
}

.custom-input-actions .confirm-btn {
  padding: 0.5rem 1rem;
  background: var(--paper-text-primary);
  border: 1px solid var(--paper-text-primary);
  color: var(--paper-bg-primary);
  cursor: pointer;
  font-size: 0.9rem;
  font-weight: 600;
  transition: all 0.2s;
}

.custom-input-actions .confirm-btn:hover:not(:disabled) {
  background: #2ea043;
}

.custom-input-actions .confirm-btn:disabled {
  background: rgba(35, 134, 54, 0.4);
  color: rgba(255, 255, 255, 0.4);
  cursor: not-allowed;
}

/* 状态指示器 */
.phase-indicator {
  position: absolute;
  bottom: 1rem;
  left: 50%;
  transform: translateX(-50%);
  padding: 0.75rem 1.5rem;
  background: rgba(13, 17, 23, 0.95);
  border: 1px solid rgba(88, 166, 255, 0.3);
  border-radius: 20px;
  color: #58a6ff;
  font-size: 0.9rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  animation: pulse 2s infinite;
  z-index: 10;
  cursor: pointer;
  user-select: none;
  transition: background 0.2s, border-color 0.2s;
}

.phase-indicator:hover {
  background: rgba(13, 17, 23, 1);
  border-color: rgba(88, 166, 255, 0.6);
}

@keyframes pulse {

  0%,
  100% {
    opacity: 1;
  }

  50% {
    opacity: 0.7;
  }
}

/* 高亮样式 */
.creature-name-highlight {
  color: #58a6ff;
  font-weight: 500;
  border-bottom: 1px dashed rgba(88, 166, 255, 0.4);
  cursor: pointer;
  padding: 0 2px;
  transition: all 0.2s;
}

.creature-name-highlight:hover {
  background: rgba(88, 166, 255, 0.15);
  color: #79c0ff;
}

.organization-name-highlight {
  color: #a371f7;
  font-weight: 500;
  border-bottom: 1px dashed rgba(163, 113, 247, 0.4);
  cursor: pointer;
  padding: 0 2px;
  transition: all 0.2s;
}

.organization-name-highlight:hover {
  background: rgba(163, 113, 247, 0.15);
}

.location-name-highlight {
  color: #3fb950;
  font-weight: 500;
  border-bottom: 1px dashed rgba(63, 185, 80, 0.4);
  cursor: pointer;
  padding: 0 2px;
  transition: all 0.2s;
}

.location-name-highlight:hover {
  background: rgba(63, 185, 80, 0.15);
}

.entry-name-highlight {
  text-decoration: underline;
  text-decoration-style: dotted;
  text-underline-offset: 3px;
  color: #e3b341;
}

.entry-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  margin-left: 2px;
  background: rgba(227, 179, 65, 0.2);
  border: 1px solid rgba(227, 179, 65, 0.4);
  border-radius: 50%;
  color: #e3b341;
  font-size: 10px;
  font-weight: bold;
  cursor: pointer;
  vertical-align: middle;
  transition: all 0.2s;
}

.entry-button:hover {
  background: rgba(227, 179, 65, 0.4);
}

.dialogue-text {
  color: var(--paper-dialogue-text);
  font-weight: normal;
  background: var(--paper-hover-bg);
  border-radius: 4px;
  padding: 0.1em 0.3em;
  margin: 0 0.1em;
  box-shadow: inset 0 0 0 1px var(--paper-shadow-color);
}

/* ========== 可折叠区块样式 ========== */
.ink-game .collapsible-section {
  margin: 0.75rem 0;
  border-radius: 4px;
  overflow: hidden;
  border: 1px solid var(--paper-border-color);
  background: var(--paper-bg-content);
}

.ink-game .collapsible-section.collapsed .collapsible-content {
  display: none;
}

.ink-game .collapsible-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.6rem 1rem;
  background: var(--paper-bg-primary);
  cursor: pointer;
  transition: background 0.2s;
  user-select: none;
}

.ink-game .collapsible-header:hover {
  background: #e9e5db;
}

.ink-game .collapse-icon {
  font-size: 0.75rem;
  color: var(--paper-text-secondary);
  width: 1rem;
  text-align: center;
}

.ink-game .section-title {
  font-size: 0.9rem;
  font-weight: bold;
  color: var(--paper-text-primary);
  flex: 1;
}

.ink-game .generating-indicator {
  font-size: 0.8rem;
  color: #2ea043;
  animation: pulse 1.5s infinite;
}

.ink-game .collapsible-content {
  padding: 0.75rem 1rem;
  border-top: 1px dashed var(--paper-border-color);
  max-height: 400px;
  overflow-y: auto;
}

/* Collector 区块 */
.ink-game .collector-section {
  border-color: #86b4d9;
  /* 柔和的墨蓝 */
}

.ink-game .collector-section .collapsible-header {
  background: rgba(134, 180, 217, 0.15);
}

.ink-game .collector-item {
  padding: 0.5rem;
  margin-bottom: 0.5rem;
  border-radius: 4px;
  background: var(--paper-bg-secondary);
  border-left: 3px solid var(--paper-text-secondary);
  border-top: 1px solid var(--paper-border-color);
  border-right: 1px solid var(--paper-border-color);
  border-bottom: 1px solid var(--paper-border-color);
}

.ink-game .collector-item.selected {
  border-left-color: #2ea043;
  background: rgba(46, 160, 67, 0.05);
}

.ink-game .collector-item.rejected {
  border-left-color: var(--paper-electric-blue);
  opacity: 0.7;
  background: rgba(139, 43, 26, 0.05);
}

.ink-game .collector-entity {
  font-weight: bold;
  color: var(--paper-text-primary);
  margin-bottom: 0.25rem;
  font-size: 0.9rem;
}

.ink-game .collector-outline {
  font-size: 0.85rem;
  color: #5a5550;
  line-height: 1.6;
  padding: 0.5rem 0.75rem;
  margin-bottom: 0.5rem;
  background: rgba(0, 0, 0, 0.03);
  border-left: 3px solid rgba(0, 0, 0, 0.12);
  border-radius: 0 4px 4px 0;
}

.ink-game .collector-thinking {
  font-size: 0.85rem;
  color: #4a4540;
  line-height: 1.5;
}

.ink-game .collector-docs {
  margin-top: 0.5rem;
  padding-left: 1rem;
  border-left: 1px solid var(--paper-border-color);
}

.ink-game .doc-item {
  margin-bottom: 0.5rem;
  padding-left: 0.5rem;
}

.ink-game .doc-path {
  font-size: 0.85rem;
  color: var(--paper-text-secondary);
  padding: 0.25rem 0;
}

.ink-game .doc-item.selected .doc-path {
  color: #0550ae;
  font-weight: bold;
}

.ink-game .doc-thinking {
  font-size: 0.8rem;
  color: var(--paper-text-secondary);
  padding: 0.25rem 0 0.25rem 1.5rem;
  line-height: 1.4;
  font-style: italic;
}

.ink-game .doc-phase-badge {
  display: inline-block;
  font-size: 0.7rem;
  padding: 0.1rem 0.35rem;
  border-radius: 2px;
  margin-left: 0.4rem;
  vertical-align: middle;
  border: 1px solid currentColor;
}

.ink-game .doc-phase-badge.thinking {
  background: rgba(136, 87, 255, 0.05);
  color: #753fb9;
}

.ink-game .doc-phase-badge.writing {
  background: rgba(5, 80, 174, 0.05);
  color: #0550ae;
}

.ink-game .doc-phase-badge.updating {
  background: rgba(140, 102, 20, 0.05);
  color: #8c6614;
}

/* Reasoning 区块 */
.ink-game .reasoning-section {
  border-color: #dcb36b;
}

.ink-game .reasoning-section .collapsible-header {
  background: rgba(220, 179, 107, 0.15);
}

.ink-game .reasoning-content pre,
.ink-game .reasoning-section pre {
  margin: 0;
  white-space: pre-wrap;
  word-wrap: break-word;
  font-size: 0.85rem;
  color: #7d6023;
  line-height: 1.6;
  font-family: inherit;
}

/* Thinking 区块 */
.ink-game .thinking-section {
  border-color: #aca1cc;
}

.ink-game .thinking-section .collapsible-header {
  background: rgba(117, 63, 185, 0.1);
}

.ink-game .thinking-content pre,
.ink-game .thinking-section pre {
  margin: 0;
  white-space: pre-wrap;
  word-wrap: break-word;
  font-size: 0.85rem;
  color: #4a4540;
  line-height: 1.6;
  font-family: inherit;
}

/* 状态与设定变更建议区块 */
.ink-game .changes-section {
  border-color: #8fb1bd;
}

.ink-game .changes-section .collapsible-header {
  background: rgba(143, 177, 189, 0.15);
}

.ink-game .changes-content {
  padding: 0.5rem 0;
}

.ink-game .change-item {
  display: flex;
  align-items: flex-start;
  padding: 0.4rem 0;
  border-bottom: 1px dashed var(--paper-border-color);
}

.ink-game .change-item:last-child {
  border-bottom: none;
}

.ink-game .change-bullet {
  color: #276277;
  font-weight: bold;
  margin-right: 0.5rem;
  flex-shrink: 0;
}

.ink-game .change-text {
  color: var(--paper-text-primary);
  line-height: 1.6;
  font-size: 0.9rem;
}

/* Update 区块 */
.ink-game .update-section {
  border-color: var(--paper-border-color);
}

.ink-game .update-section.success {
  border-color: #2ea043;
}

.ink-game .update-section.success .collapsible-header {
  background: rgba(46, 160, 67, 0.1);
}

.ink-game .update-section.error {
  border-color: var(--paper-electric-blue);
}

.ink-game .update-section.error .collapsible-header {
  background: rgba(139, 43, 26, 0.1);
}

.ink-game .update-section.updating .collapsible-header {
  background: rgba(134, 180, 217, 0.15);
}

.ink-game .retry-inline-btn {
  padding: 0.25rem 0.6rem;
  background: rgba(139, 43, 26, 0.05);
  border: 1px solid rgba(139, 43, 26, 0.3);
  border-radius: 4px;
  color: var(--paper-electric-blue);
  cursor: pointer;
  font-size: 0.8rem;
  transition: all 0.2s;
  margin-left: auto;
}

.ink-game .retry-inline-btn:hover {
  background: rgba(139, 43, 26, 0.1);
  border-color: var(--paper-electric-blue);
}

.ink-game .update-detail {
  margin-bottom: 1rem;
}

.ink-game .update-detail strong {
  display: block;
  color: var(--paper-text-secondary);
  font-size: 0.85rem;
  font-weight: bold;
  margin-bottom: 0.5rem;
}

.ink-game .update-detail pre {
  margin: 0;
  padding: 0.75rem;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-border-color);
  border-radius: 2px;
  font-size: 0.8rem;
  color: #4a4540;
  white-space: pre-wrap;
  word-wrap: break-word;
  max-height: 200px;
  overflow-y: auto;
  font-family: inherit;
}

.ink-game .error-content {
  background: rgba(139, 43, 26, 0.02);
}

.ink-game .error-content .error-message {
  color: var(--paper-electric-blue);
  font-weight: bold;
  margin-bottom: 0.75rem;
}

.ink-game .error-detail {
  margin-top: 0.75rem;
}

.ink-game .call-result {
  color: var(--paper-text-primary);
  font-size: 0.85rem;
  margin-top: 0.2rem;
}

.ink-game .call-result.failed {
  color: var(--paper-electric-blue);
}

.ink-game .call-error {
  color: var(--paper-electric-blue);
  font-style: italic;
  font-size: 0.8rem;
  margin-left: 1.5rem;
}

.ink-game .call-args {
  font-size: 0.75rem;
  margin: 0.2rem 0 0.2rem 1.5rem;
  padding: 0.3rem 0.5rem;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 4px;
  max-height: 150px;
  overflow-y: auto;
  white-space: pre-wrap;
  word-break: break-all;
}

/* 错误块 */
.ink-game .error-turn-block {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 1rem 1.5rem;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-electric-blue);
  border-radius: 4px;
  margin: 1rem 0;
}

.ink-game .error-turn-block .error-icon {
  font-size: 1.5rem;
}

.ink-game .error-turn-block .error-message {
  flex: 1;
  color: var(--paper-electric-blue);
  font-size: 0.95rem;
}

.ink-game .error-turn-block .error-actions {
  display: flex;
  gap: 0.5rem;
}

.ink-game .error-turn-block .retry-btn {
  padding: 0.5rem 1rem;
  background: transparent;
  border: 1px solid var(--paper-electric-blue);
  border-radius: 4px;
  color: var(--paper-electric-blue);
  cursor: pointer;
  font-size: 0.9rem;
  transition: all 0.2s;
}

.ink-game .error-turn-block .retry-btn:hover {
  background: var(--paper-electric-blue);
  color: var(--paper-bg-secondary);
}

/* 生成中的占位符 */
.ink-game .generating-placeholder {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  padding: 2rem;
  color: #8b949e;
}

.ink-game .loading-spinner-small {
  animation: spin 1.5s linear infinite;
  font-size: 1.25rem;
}

@keyframes spin {
  from {
    transform: rotate(0deg);
  }

  to {
    transform: rotate(360deg);
  }
}

/* Story block 生成状态 */
.ink-game .story-block.generating {
  border-left: 3px solid #58a6ff;
}

.ink-game .story-block.complete {
  border-left: 3px solid transparent;
}

/* 开始界面 */
.start-container {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--paper-bg-tertiary); /* 与侧边栏配套的桌面底色 */
  position: relative;
  padding: 2rem;
  overflow: hidden;
}

.start-content.paper-panel {
  position: relative;
  z-index: 10;
  background: var(--paper-bg-content);
  border: 1px solid var(--paper-border-color);
  border-right: 4px solid var(--paper-border-color); /* 书页边缘厚度特效 */
  border-bottom: 4px solid var(--paper-border-color);
  border-radius: 2px 6px 6px 2px;
  padding: 4rem 5rem;
  max-width: 800px;
  width: 95%;
  max-height: 90vh;
  display: flex;
  flex-direction: column;
  text-align: center;
  box-shadow: 10px 10px 25px var(--paper-active-bg);
}

.game-intro {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.game-intro .title {
  font-size: 2.8rem;
  margin-bottom: 0.5rem;
  color: var(--paper-text-primary);
  font-weight: 700;
  letter-spacing: 4px;
}

.divider-ornament {
  width: 60px;
  height: 3px;
  background: var(--paper-electric-blue); /* 印泥红点缀 */
  margin: 1.5rem auto;
  border-radius: 2px;
}

.game-intro .subtitle {
  color: var(--paper-text-secondary);
  font-size: 1.1rem;
  line-height: 1.8;
  margin-bottom: 2.5rem;
  font-style: italic;
  flex-shrink: 0;
}

.background-preview.scrollable-paper {
  background: transparent;
  padding: 0 1rem;
  margin-bottom: 2.5rem;
  text-align: justify;
  overflow-y: auto;
  border-top: 1px dashed var(--paper-border-color);
  border-bottom: 1px dashed var(--paper-border-color);
  flex: 1; /* 撑满剩余空间滚动 */
}

/* 自定义滚动条样式(针对书页) */
.background-preview.scrollable-paper::-webkit-scrollbar {
  width: 6px;
}
.background-preview.scrollable-paper::-webkit-scrollbar-track {
  background: transparent;
}
.background-preview.scrollable-paper::-webkit-scrollbar-thumb {
  background: var(--paper-border-color);
  border-radius: 3px;
}

.background-preview .section-title {
  font-size: 1.2rem;
  color: var(--paper-electric-blue);
  margin: 1.5rem 0 1rem;
  text-align: center;
  font-weight: bold;
  letter-spacing: 2px;
}

.background-story-text {
  font-size: 1.05rem;
  color: #4a4540;
  line-height: 2;
  text-indent: 2em;
  white-space: pre-wrap;
  padding-bottom: 1.5rem;
}

.start-btn.paper-btn {
  align-self: center;
  padding: 1rem 3.5rem;
  background: var(--paper-bg-content);
  border: 2px solid var(--paper-electric-blue);
  border-radius: 4px;
  color: var(--paper-electric-blue);
  font-size: 1.25rem;
  font-weight: bold;
  letter-spacing: 4px;
  cursor: pointer;
  transition: all 0.3s;
  box-shadow: 4px 4px 0px rgba(139, 43, 26, 0.1);
  font-family: inherit;
  margin-top: auto;
  flex-shrink: 0;
}

.start-btn.paper-btn:hover {
  background: rgba(139, 43, 26, 0.05);
  transform: translateY(-2px);
  box-shadow: 6px 6px 0px rgba(139, 43, 26, 0.15);
}

/* 模态框样式 */
.ink-game .modal {
  background: var(--paper-bg-content);
  /* 米白纸面 */
  border: 1px solid var(--paper-border-color);
  border-radius: 8px;
  /* 弱化圆角 */
  max-width: 600px;
  width: 90%;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  box-shadow: 4px 4px 0px var(--paper-shadow-color);
  /* 纸张投影 */
}

.ink-game .modal-header {
  background: transparent;
  border-bottom: 2px solid var(--paper-text-primary);
  /* 实线分隔 */
  padding: 1rem 1.5rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.ink-game .modal-header h2,
.ink-game .modal-header h3 {
  color: var(--paper-text-primary);
  margin: 0;
  font-weight: bold;
}

.ink-game .modal-close {
  background: transparent;
  border: none;
  color: var(--paper-text-secondary);
  font-size: 1.25rem;
  cursor: pointer;
  padding: 0.25rem;
  transition: color 0.2s;
}

.ink-game .modal-close:hover {
  color: var(--paper-electric-blue);
  /* 红色悬停 */
}

.ink-game .modal-content,
.ink-game .modal-body {
  padding: 1.5rem;
  max-height: 60vh;
  overflow-y: auto;
  white-space: pre-wrap;
  line-height: 1.8;
  color: var(--paper-text-primary);
  word-wrap: break-word;
}

.ink-game .modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--paper-border-color-hover);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

/* Modal Footer & Generic Inputs */
.ink-game .modal-footer {
  padding: 1rem 1.5rem;
  border-top: 1px dashed var(--paper-border-color);
  display: flex;
  justify-content: flex-end;
  gap: 1rem;
}

.ink-game .modal-footer button {
  padding: 0.5rem 1.25rem;
  border-radius: 4px;
  font-size: 0.95rem;
  cursor: pointer;
  transition: all 0.2s;
}

.ink-game .btn-cancel {
  background: transparent;
  border: 1px solid var(--paper-text-secondary);
  color: var(--paper-text-secondary);
}

.ink-game .btn-cancel:hover {
  background: var(--paper-text-secondary);
  color: var(--paper-bg-primary);
}

.ink-game .btn-primary {
  background: var(--paper-text-primary);
  border: 1px solid var(--paper-text-primary);
  color: var(--paper-bg-primary);
  font-weight: bold;
}

.ink-game .btn-primary:hover:not(:disabled) {
  background: #2ea043;
  border-color: #2ea043;
}

.ink-game .btn-primary:disabled {
  background: var(--paper-border-color-hover);
  border-color: transparent;
  cursor: not-allowed;
}

/* 响应式适配 - 竖屏/移动端优化 */
@media (max-width: 768px) {

  .ink-game {
    flex-direction: column;
  }

  .ink-game .slim-sidebar {
    display: none;
  }

  .ink-game .ink-layout {
    flex-direction: column;
  }

  .ink-game .mobile-ink-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0 0.25rem;
    height: 48px;
    background: var(--paper-bg-tertiary);
    border-bottom: 1px solid var(--paper-border-color);
    flex-shrink: 0;
  }

  .ink-game .mobile-ink-header .header-left,
  .ink-game .mobile-ink-header .header-right {
    display: flex;
    align-items: center;
    gap: 0;
  }

  .ink-game .mobile-ink-header .icon-btn {
    background: transparent;
    border: none;
    font-size: 1.2rem;
    color: var(--paper-text-secondary);
    cursor: pointer;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: var(--paper-radius-md);
    transition: background 0.15s;
  }

  .ink-game .mobile-ink-header .icon-btn:hover {
    background: var(--paper-bg-secondary);
  }

  .ink-game .mobile-ink-header .icon-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }

  .ink-game .mobile-tabs {
    display: flex;
    align-items: center;
    gap: 2px;
    background: var(--paper-bg-secondary);
    border-radius: 6px;
    padding: 2px;
  }

  .ink-game .mobile-tab {
    background: transparent;
    border: none;
    font-family: inherit;
    font-size: 0.75rem;
    color: var(--paper-text-tertiary);
    cursor: pointer;
    padding: 4px 10px;
    border-radius: 4px;
    transition: all 0.2s;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: 500;
  }

  .ink-game .mobile-tab.active {
    background: var(--paper-bg-primary);
    color: var(--paper-text-primary);
    font-weight: bold;
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
  }

  /* ========== 移动端"更多"菜单 ========== */
  .ink-game .mobile-ink-header .header-right {
    position: relative;
  }

  .ink-game .mobile-more-btn {
    font-size: 1.4rem !important;
    font-weight: bold;
    letter-spacing: 1px;
  }

  .ink-game .mobile-more-menu {
    position: absolute;
    top: calc(100% + 4px);
    right: 0;
    z-index: 100;
    min-width: 200px;
    background: var(--paper-bg-secondary, #fff);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    border-radius: 12px;
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);
    padding: 6px;
    animation: mobile-menu-in 0.15s ease-out;
  }

  @keyframes mobile-menu-in {
    from {
      opacity: 0;
      transform: translateY(-6px) scale(0.95);
    }
    to {
      opacity: 1;
      transform: translateY(0) scale(1);
    }
  }

  .ink-game .mobile-menu-item {
    display: flex;
    align-items: center;
    gap: 10px;
    width: 100%;
    padding: 10px 12px;
    border: none;
    background: transparent;
    font-family: inherit;
    font-size: 0.88rem;
    color: var(--paper-text-primary, #1a1a2e);
    cursor: pointer;
    border-radius: 8px;
    transition: background 0.12s;
    text-align: left;
  }

  .ink-game .mobile-menu-item:hover,
  .ink-game .mobile-menu-item:active {
    background: var(--paper-bg-primary, #f0f2f7);
  }

  .ink-game .mobile-menu-item:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }

  .ink-game .mobile-menu-icon {
    flex-shrink: 0;
    width: 1.2em;
    text-align: center;
    font-size: 1.1rem;
  }

  .ink-game .mobile-menu-divider {
    height: 1px;
    background: var(--paper-border-color, #e2e8f0);
    margin: 4px 8px;
  }

  .ink-game .mobile-menu-lang-active {
    color: var(--paper-accent, #8b2b1a);
    font-weight: 600;
  }

  /* 移动端章节跳转 */
  .ink-game .chapter-jump-btn {
    display: inline-flex !important;
  }

  .ink-game .desktop-chapter-jump {
    display: none;
  }

  .ink-game .chapter-jump-menu {
    right: 0;
    left: auto;
    min-width: 200px;
    max-width: 70vw;
  }

  /* ========== 顶部栏简化 ========== */
  .ink-game .ink-header {
    padding: 0 0.75rem;
    height: 48px;
    display: none; /* Already replaced by mobile-ink-header */
  }

  .ink-game .ink-header h1 {
    font-size: 1rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 120px;
  }

  .ink-game .game-time {
    display: none;
  }

  .ink-game .main-header {
    display: none;
  }

  .ink-game .mobile-settings-btn {
    display: flex !important;
  }

  .ink-game > .ink-layout .header-actions {
    gap: 0.25rem;
  }

  .ink-game > .ink-layout .header-actions button {
    padding: 0.35rem 0.6rem;
    font-size: 0.8rem;
    min-height: 36px;
  }

  /* 移动端仅显示核心按钮（世界、返回），仅限游戏内 header，不影响 modal */
  .ink-game > .ink-layout .header-actions button:not(.back-btn):not(.world-btn) {
    display: none;
  }

  /* ========== 小说流阅读优化 ========== */
  .ink-game .ink-flow {
    padding: 0.75rem;
    padding-bottom: 1.5rem;
  }

  .ink-game .story-block {
    padding: 1rem;
    border-radius: 6px;
  }

  .ink-game .novel-content p {
    font-size: 1rem;
    line-height: 2;
    text-align: left;
    /* 移动端左对齐更易读 */
    margin-bottom: 1rem;
  }

  .ink-game .chapter-hint {
    font-size: 1.2rem;
  }

  .ink-turn {
    margin-bottom: 1.5rem;
  }

  /* ========== 左侧面板抽屉化 ========== */
  .ink-game .left-panel {
    position: fixed;
    top: 48px;
    left: 0;
    bottom: 0;
    height: calc(100% - 48px);
    width: 85%;
    max-width: 320px;
    box-shadow: 10px 0 30px rgba(0, 0, 0, 0.5);
    background: var(--paper-bg-secondary);
    border-right: 1px solid var(--paper-border-color);
    z-index: 60;
    transform: translateX(0);
    opacity: 1;
    pointer-events: auto;
    overflow: visible;
  }

  .ink-game .left-panel.closed {
    transform: translateX(-100%);
    box-shadow: none;
    opacity: 0;
    pointer-events: none;
  }

  .panel-overlay {
    display: block;
    position: fixed;
    top: 48px;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    backdrop-filter: blur(2px);
    z-index: 55;
    animation: fadeIn 0.3s ease-out;
  }

  /* ========== 选项按钮触屏优化 ========== */
  .choice-button {
    padding: 1rem;
    min-height: 48px;
    border-radius: 10px;
  }

  .choice-name {
    font-size: 1.05rem;
  }

  .choice-description {
    font-size: 0.9rem;
    line-height: 1.5;
  }

  .ooc-add-btn {
    min-height: 44px;
    font-size: 0.9rem;
  }

  .ooc-form textarea {
    font-size: 16px;
  }

  .player-choices-container {
    margin-top: 1.5rem;
    padding-top: 1rem;
  }

  .show-custom-input-btn {
    min-height: 48px;
    font-size: 1rem;
  }

  .custom-input-area textarea {
    font-size: 16px;
    /* 防止 iOS 自动缩放 */
    min-height: 80px;
  }

  .custom-input-actions button {
    min-height: 44px;
    padding: 0.6rem 1.2rem;
  }

  /* ========== 可折叠区块触屏优化 ========== */
  .ink-game .collapsible-header {
    min-height: 44px;
    padding: 0.75rem 1rem;
  }

  .ink-game .collapsible-content {
    max-height: 250px;
    padding: 0.5rem 0.75rem;
  }

  .ink-game .section-title {
    font-size: 0.85rem;
  }

  /* ========== 玩家行动块优化 ========== */
  .action-block {
    margin: 1.5rem 0;
  }

  .action-content {
    padding: 0.75rem 1rem;
    font-size: 0.95rem;
    max-width: 85%;
  }

  /* ========== 状态指示器 ========== */
  .phase-indicator {
    padding: 0.6rem 1rem;
    font-size: 0.85rem;
    bottom: 0.75rem;
  }

  /* ========== 高亮样式触屏优化 ========== */
  .creature-name-highlight,
  .organization-name-highlight,
  .location-name-highlight {
    padding: 0.1rem 0.3rem;
  }

  .entry-button {
    width: 20px;
    height: 20px;
    font-size: 11px;
  }

  /* ========== 开始界面优化 ========== */
  .start-container {
    padding: 0.5rem;
    align-items: stretch;
  }

  .start-content.paper-panel {
    padding: 1.5rem 1.2rem;
    max-height: 100%;
    width: 100%;
    border-right-width: 2px;
    border-bottom-width: 2px;
    box-shadow: 4px 4px 12px var(--paper-active-bg);
  }

  .game-intro .title {
    font-size: 1.6rem;
    letter-spacing: 2px;
    margin-bottom: 0.3rem;
  }

  .divider-ornament {
    margin: 0.8rem auto;
  }

  .game-intro .subtitle {
    font-size: 0.9rem;
    line-height: 1.6;
    margin-bottom: 1rem;
  }

  .background-preview .section-title {
    font-size: 1rem;
    margin: 0.8rem 0 0.6rem;
  }

  .background-story-text {
    font-size: 0.9rem;
    line-height: 1.8;
    padding-bottom: 0.8rem;
  }

  .background-preview.scrollable-paper {
    padding: 0 0.5rem;
    margin-bottom: 1rem;
  }

  .start-btn.paper-btn {
    min-height: 44px;
    font-size: 1rem;
    padding: 0.75rem 2rem;
    flex-shrink: 0;
  }

  /* ========== 世界概览面板全屏化 ========== */
  .world-overview-panel {
    width: 100%;
    max-width: 100%;
    max-height: 100%;
    height: 100%;
    border-radius: 0;
  }

  .world-overview-header {
    padding: 0.75rem 1rem;
  }

  .world-overview-tabs {
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
  }

  .world-overview-tab {
    padding: 0.75rem 0.5rem;
    font-size: 0.85rem;
    white-space: nowrap;
  }

  .world-overview-content {
    padding: 1rem;
    overflow-x: hidden;
  }

  .world-overview-item {
    min-height: 48px;
    padding: 0.75rem;
  }

  .world-overview-item .item-name {
    white-space: normal;
    word-break: break-all;
  }

  .world-overview-item .item-desc {
    white-space: normal;
  }

  .world-overview-region .region-locations {
    padding-left: 0;
  }
}

/* 调试模态框 */
.debug-modal {
  max-width: 800px;
}

.debug-input {
  margin-bottom: 1rem;
}

.debug-input label {
  display: block;
  color: #8b949e;
  margin-bottom: 0.5rem;
  font-size: 0.9rem;
}

.debug-input textarea {
  width: 100%;
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 8px;
  padding: 0.8rem;
  color: #e6edf3;
  font-family: 'Consolas', monospace;
  font-size: 0.9rem;
  resize: vertical;
}

.debug-result {
  background: rgba(0, 0, 0, 0.3);
  border-radius: 8px;
  padding: 1rem;
}

.debug-error {
  color: #f85149;
}

.debug-output {
  color: #3fb950;
  margin-bottom: 0.5rem;
}

.debug-return pre {
  margin: 0;
  background: rgba(0, 0, 0, 0.3);
  padding: 0.5rem;
  border-radius: 4px;
  font-size: 0.85rem;
  overflow-x: auto;
}

/* 发布文章模态框 */
.publish-modal {
  max-width: 600px;
  width: 90%;
}

.publish-form-group {
  margin-bottom: 1.5rem;
}

.publish-form-group label {
  display: block;
  color: var(--paper-text-secondary);
  margin-bottom: 0.5rem;
  font-size: 0.9rem;
  font-weight: bold;
}

.publish-input,
.publish-select {
  width: 100%;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-border-color);
  border-radius: 4px;
  padding: 0.8rem;
  color: var(--paper-text-primary);
  font-size: 0.95rem;
}

.publish-input:focus,
.publish-select:focus {
  outline: none;
  border-color: var(--paper-text-primary);
}

.publish-range {
  display: flex;
  gap: 1rem;
  align-items: center;
}

.publish-range>div {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.publish-select-small {
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-border-color);
  border-radius: 4px;
  padding: 0.5rem;
  color: var(--paper-text-primary);
  font-size: 0.9rem;
}

.publish-range-hint {
  margin-top: 0.5rem;
  color: var(--paper-text-secondary);
  font-size: 0.85rem;
  font-style: italic;
}

.publish-preview {
  background: var(--paper-bg-content);
  border: 1px solid var(--paper-border-color);
  border-radius: 4px;
  padding: 1rem;
  box-shadow: inset 1px 1px 3px var(--paper-hover-bg);
  /* 纸面凹印质感 */
}

.publish-preview h4 {
  margin: 0 0 0.8rem 0;
  color: var(--paper-text-primary);
  font-size: 0.9rem;
  font-weight: bold;
}

.publish-chapter-list {
  max-height: 200px;
  overflow-y: auto;
}

.publish-chapter-item {
  display: flex;
  align-items: center;
  gap: 0.8rem;
  padding: 0.5rem;
  margin-bottom: 0.4rem;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-border-color);
  border-radius: 4px;
  transition: background 0.2s;
}

.publish-chapter-item:hover {
  background: var(--paper-bg-primary);
  border-color: var(--paper-text-primary);
}

.publish-chapter-item .chapter-number {
  flex-shrink: 0;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  border: 1px solid var(--paper-text-primary);
  border-radius: 4px;
  color: var(--paper-text-primary);
  font-weight: bold;
  font-size: 0.85rem;
  font-family: inherit;
}

.publish-chapter-item .chapter-title {
  flex: 1;
  color: var(--paper-text-primary);
  font-size: 0.95rem;
}

