  border-radius: 8px;
  margin-bottom: 0.5rem;
}

/* ========== 世界概览面板样式 ========== */
.world-overview-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--paper-border-color-hover);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
  animation: fadeIn 0.2s ease-out;
}

.world-overview-panel {
  width: 90%;
  max-width: 600px;
  max-height: 80vh;
  background: var(--paper-bg-content);
  /* 米白纸张背景 */
  border: 1px solid var(--paper-border-color);
  /* 细深色边框 */
  border-radius: 8px;
  /* 弱化圆角 */
  display: flex;
  flex-direction: column;
  box-shadow: 4px 4px 0px var(--paper-shadow-color);
  /* 报纸风格投影 */
  animation: slideUp 0.3s ease-out;
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.world-overview-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.5rem;
  border-bottom: 2px solid var(--paper-text-primary);
  /* 强调下划线 */
}

.world-overview-header h3 {
  margin: 0;
  font-size: 1.25rem;
  font-weight: bold;
  letter-spacing: 1px;
  color: var(--paper-text-primary);
}

.world-overview-close {
  background: transparent;
  border: none;
  color: var(--paper-text-secondary);
  font-size: 1.2rem;
  cursor: pointer;
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  transition: all 0.2s;
}

.world-overview-close:hover {
  background: var(--paper-hover-bg);
  color: var(--paper-electric-blue);
  /* 悬停变红 */
}

.world-overview-tabs {
  display: flex;
  border-bottom: 1px solid var(--paper-border-color);
  background: var(--paper-bg-primary);
}

.world-overview-tab {
  flex: 1;
  padding: 0.75rem 1rem;
  background: transparent;
  border: none;
  color: var(--paper-text-secondary);
  font-weight: 600;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
  border-right: 1px solid var(--paper-border-color);
}

.world-overview-tab:last-child {
  border-right: none;
}

.world-overview-tab:hover {
  background: var(--paper-hover-bg);
  color: var(--paper-text-primary);
}

.world-overview-tab.active {
  color: var(--paper-text-primary);
  background: var(--paper-bg-content);
}

.world-overview-tab.active::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--paper-electric-blue);
  /* 红色指引条 */
}

.world-overview-content {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem;
}

.world-overview-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.world-overview-empty {
  text-align: center;
  color: var(--paper-text-secondary);
  padding: 2rem;
  font-style: italic;
  font-size: 0.95rem;
}

.world-overview-item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem 1rem;
  background: var(--paper-bg-secondary);
  border: 1px solid var(--paper-border-color);
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
}

.world-overview-item:hover {
  background: var(--paper-bg-primary);
  border-color: var(--paper-text-primary);
  transform: translateX(4px);
  box-shadow: -2px 0 0 var(--paper-electric-blue);
  /* 左侧边线强调 */
}

.world-overview-item .item-icon {
  font-size: 1.2rem;
  flex-shrink: 0;
}

.world-overview-item .item-info {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 0.2rem;
}

.world-overview-item .item-name {
  font-size: 0.95rem;
  font-weight: bold;
  color: var(--paper-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.world-overview-item .item-desc {
  font-size: 0.8rem;
  color: var(--paper-text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.world-overview-item .item-arrow {
  color: var(--paper-text-secondary);
  font-size: 1.2rem;
  font-family: inherit;
  flex-shrink: 0;
  opacity: 0.5;
}

.world-overview-item:hover .item-arrow {
  color: var(--paper-electric-blue);
  opacity: 1;
}

/* 地域分组样式 */
.world-overview-region {
  margin-bottom: 2rem;
}

.world-overview-region .region-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding-bottom: 0.5rem;
  margin-bottom: 1rem;
  border-bottom: 2px dotted var(--paper-border-color);
}

.world-overview-region .region-icon {
  font-size: 1.1rem;
}

.world-overview-region .region-name {
  font-weight: bold;
  color: var(--paper-text-primary);
  flex: 1;
}

.world-overview-region .region-count {
  font-size: 0.8rem;
  color: var(--paper-text-secondary);
}

/* 导演笔记样式 */
.director-section {
  margin-bottom: 1.5rem;
}

.director-section-title {
  font-size: 0.85rem;
  font-weight: bold;
  color: var(--paper-text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 0.5rem 0;
  margin-bottom: 0.75rem;
  border-bottom: 1px dashed var(--paper-border-color);
}

.director-note-item {
  cursor: default !important;
  background: var(--paper-bg-secondary);
  border-left: 3px solid var(--paper-electric-blue);
}

.director-note-item:hover {
  transform: none !important;
  box-shadow: none !important;
  border-color: var(--paper-electric-blue);
  background: var(--paper-bg-secondary);
}

.director-note-item .item-name {
  white-space: normal !important;
  line-height: 1.6;
  font-family: inherit;
}

.director-flag-item {
  cursor: default !important;
}

.director-flag-item:hover {
  transform: none !important;
  box-shadow: none !important;
  background: var(--paper-bg-secondary);
  border-color: var(--paper-border-color);
}

.director-flag-item code {
  background: var(--paper-hover-bg);
  padding: 0.1rem 0.4rem;
  border-radius: 3px;
  font-size: 0.85rem;
  color: var(--paper-text-primary);
  border: 1px solid var(--paper-shadow-color);
}

.world-overview-region .region-locations {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding-left: 0.5rem;
}

.world-overview-region .location-item {
  flex-direction: row;
  align-items: center;
  gap: 0.75rem;
  border-left: 2px solid var(--paper-border-color);
  margin-left: 0.5rem;
  padding-left: 0.5rem;
  background: var(--paper-bg-secondary);
  border-radius: 4px;
  border-top: 1px solid var(--paper-border-color);
  border-right: 1px solid var(--paper-border-color);
  border-bottom: 1px solid var(--paper-border-color);
}

.world-overview-region .location-item:hover {
  border-left: 3px solid var(--paper-electric-blue);
  /* 悬停强调红色 */
  background: var(--paper-bg-content);
}

/* ========== 图片生成开关样式 ========== */
.ink-game .image-gen-toggle {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  cursor: pointer;
  padding: 0.4rem 0.8rem;
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.2s;
  font-size: 0.85rem;
  user-select: none;
}

.ink-game .image-gen-toggle:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: rgba(255, 255, 255, 0.2);
}

.ink-game .image-gen-toggle input[type="checkbox"] {
  accent-color: #f0a030;
  width: 14px;
  height: 14px;
  cursor: pointer;
}

.ink-game .image-gen-toggle .toggle-label {
  color: #c9d1d9;
  font-size: 0.85rem;
  white-space: nowrap;
}

/* ============ 掷骰判定样式 ============ */

/* 选项上的难度提示 */
.choice-button .choice-difficulty-hint {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 0.4rem;
  font-size: 0.8rem;
}

.choice-button .difficulty-tag {
  background: rgba(255, 165, 0, 0.2);
  color: #ffa500;
  padding: 0.1rem 0.5rem;
  border-radius: 4px;
  font-weight: 600;
  font-size: 0.75rem;
  white-space: nowrap;
}

.choice-button .difficulty-reason {
  color: #8b949e;
  font-style: italic;
}

.choice-button .dice-badge {
  font-size: 0.9rem;
  margin-right: 0.1rem;
}

.choice-button.has-dice {
  border-color: rgba(255, 165, 0, 0.3);
}

.choice-button.has-dice:hover:not(:disabled) {
  border-color: rgba(255, 165, 0, 0.5);
}

/* 行动块上的骰子结果徽章 */
.dice-result-badge {
  padding: 0.1rem 0.5rem;
  border-radius: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  margin-left: 0.3rem;
}

.dice-result-badge.success {
  background: rgba(63, 185, 80, 0.2);
  color: #3fb950;
}

.dice-result-badge.fail {
  background: rgba(248, 81, 73, 0.2);
  color: #f85149;
}

/* 掷骰面板 */
.dice-roll-container {
  margin-top: 2rem;
  padding: 1.5rem;
  border: 1px solid rgba(255, 165, 0, 0.3);
  border-radius: 12px;
  background: rgba(255, 165, 0, 0.05);
  animation: fadeIn 0.3s ease-out;
}

.dice-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.dice-icon {
  font-size: 1.3rem;
}

.dice-title {
  font-size: 1.1rem;
  color: #ffa500;
  font-weight: 600;
}

.dice-choice-info {
  margin-bottom: 1.25rem;
  padding: 0.75rem 1rem;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 8px;
}

.dice-choice-name {
  color: #e6edf3;
  font-weight: 500;
  margin-bottom: 0.3rem;
}

.dice-reason {
  color: #8b949e;
  font-size: 0.85rem;
  font-style: italic;
}

/* 难度条 */
.dice-difficulty-section {
  margin-bottom: 1.5rem;
}

.dice-difficulty-label {
  display: flex;
  justify-content: space-between;
  margin-bottom: 0.5rem;
  font-size: 0.85rem;
  color: #8b949e;
}

.dice-difficulty-value {
  color: #ffa500;
  font-weight: 600;
}

.dice-difficulty-bar {
  height: 8px;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 4px;
  position: relative;
  overflow: visible;
}

.dice-difficulty-fill {
  height: 100%;
  border-radius: 4px;
  background: linear-gradient(90deg,
      #3fb950 0%,
      #e3b341 40%,
      #ffa500 65%,
      #f85149 100%);
  transition: width 0.3s ease;
}

.dice-roll-marker {
  position: absolute;
  top: 50%;
  transform: translate(-50%, -50%);
  width: 16px;
  height: 16px;
  border-radius: 50%;
  border: 2px solid;
  transition: left 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
  z-index: 2;
}

.dice-roll-marker.success {
  background: rgba(63, 185, 80, 0.8);
  border-color: #3fb950;
  box-shadow: 0 0 8px rgba(63, 185, 80, 0.5);
}

.dice-roll-marker.fail {
  background: rgba(248, 81, 73, 0.8);
  border-color: #f85149;
  box-shadow: 0 0 8px rgba(248, 81, 73, 0.5);
}

.dice-roll-marker.retry {
  z-index: 3;
  width: 18px;
  height: 18px;
}

/* 掷骰动作区域 */
.dice-action-area {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1rem;
}

.dice-roll-btn {
  padding: 0.8rem 2rem;
  background: var(--paper-bg-content);
  border: 2px dashed var(--paper-electric-blue); /* 印泥红边框 */
  border-radius: 4px;
  color: var(--paper-electric-blue);
  font-family: inherit;
  font-size: 1.1rem;
  font-weight: bold;
  letter-spacing: 2px;
  cursor: pointer;
  transition: all 0.2s;
  box-shadow: 2px 2px 0px rgba(139, 43, 26, 0.1);
}

.dice-roll-btn:hover {
  background: rgba(139, 43, 26, 0.05); /* 淡淡的一层红墨水底 */
  transform: translateY(-1px);
  box-shadow: 3px 3px 0px rgba(139, 43, 26, 0.15);
}

.dice-rolling-animation {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 1rem;
  color: var(--paper-electric-blue);
  font-weight: bold;
}

.dice-spinning {
  font-size: 1.5rem;
  animation: diceRoll 0.6s ease-in-out infinite;
}

@keyframes diceRoll {
  0% {
    transform: rotate(0deg) scale(1);
  }

  25% {
    transform: rotate(90deg) scale(1.2);
  }

  50% {
    transform: rotate(180deg) scale(1);
  }

  75% {
    transform: rotate(270deg) scale(1.2);
  }

  100% {
    transform: rotate(360deg) scale(1);
  }
}

/* 骰子结果展示 */
.dice-result-area {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1rem;
  width: 100%;
}

.dice-result-display {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.6rem 1.5rem;
  background: var(--paper-bg-secondary);
  border: 2px solid var(--paper-border-color);
  border-radius: 4px;
  box-shadow: 2px 2px 0px var(--paper-shadow-color);
  color: var(--paper-text-primary);
  animation: resultReveal 0.3s ease-out;
}

@keyframes resultReveal {
  from {
    opacity: 0;
    transform: scale(0.95); /* 降低纸张弹跳幅度 */
  }

  to {
    opacity: 1;
    transform: scale(1);
  }
}

.dice-result-display.success {
  background: rgba(74, 103, 65, 0.05);
  border-color: #4a6741; /* 老式档案绿 */
  box-shadow: 2px 2px 0px rgba(74, 103, 65, 0.15);
}

.dice-result-display.fail {
  background: rgba(139, 43, 26, 0.05);
  border-color: var(--paper-electric-blue); /* 印泥红 */
  box-shadow: 2px 2px 0px rgba(139, 43, 26, 0.15);
}

.dice-result-display.superseded {
  background: transparent;
  border-color: var(--paper-border-color);
  border-style: dashed;
  box-shadow: none;
  opacity: 0.7;
}

.dice-result-number {
  font-size: 1.8rem;
  font-weight: 700;
  font-family: inherit;
  color: var(--paper-text-primary);
}

.dice-result-display.success .dice-result-number {
  color: #4a6741;
}

.dice-result-display.fail .dice-result-number {
  color: var(--paper-electric-blue);
}

.dice-result-display.superseded .dice-result-number {
  color: var(--paper-text-secondary);
  text-decoration: line-through;
}

.dice-result-label {
  font-size: 1rem;
  font-weight: bold;
  color: var(--paper-text-primary);
}

.dice-result-display.success .dice-result-label {
  color: #4a6741;
}

.dice-result-display.fail .dice-result-label {
  color: var(--paper-electric-blue);
}

.superseded-label {
  color: var(--paper-text-secondary) !important;
  font-weight: normal !important;
  font-size: 0.85rem !important;
  font-style: italic;
}

.dice-result-actions {
  display: flex;
  gap: 0.75rem;
  margin-top: 0.5rem;
}

.dice-retry-btn {
  padding: 0.6rem 1.2rem;
  background: var(--paper-bg-content);
  border: 1px dashed var(--paper-text-secondary);
  border-radius: 4px;
  color: #4a4540;
  font-size: 0.95rem;
  font-weight: bold;
  cursor: pointer;
  transition: all 0.2s;
  box-shadow: 1px 1px 0px var(--paper-shadow-color);
}

.dice-retry-btn:hover {
  background: var(--paper-bg-primary);
  border-color: var(--paper-text-primary);
  color: var(--paper-text-primary);
}

.dice-confirm-btn {
  padding: 0.6rem 1.5rem;
  background: var(--paper-bg-content);
  border: 1px solid #4a6741;
  border-radius: 4px;
  color: #4a6741;
  font-size: 0.95rem;
  font-weight: bold;
  cursor: pointer;
  transition: all 0.2s;
  box-shadow: 1px 1px 0px rgba(74, 103, 65, 0.2);
}

.dice-confirm-btn:hover {
  background: rgba(74, 103, 65, 0.05);
}

.dice-cancel-btn {
  display: block;
  width: 100%;
  padding: 0.5rem;
  background: transparent;
  border: none;
  color: var(--paper-text-secondary);
  font-size: 0.85rem;
  cursor: pointer;
  text-align: center;
  transition: color 0.2s;
  text-decoration: underline dashed;
}

.dice-cancel-btn:hover {
  color: var(--paper-electric-blue); /* 变为红色警示 */
}

/* ==================== Refresh Button & Overlay ==================== */

.ink-game .header-refresh-btn {
  background: transparent;
  color: var(--paper-text-secondary);
  border: 1px solid var(--paper-border-color);
  width: 32px;
  height: 32px;
  border-radius: 4px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
  transition: all 0.2s;
  padding: 0;
  line-height: 1;
}

.ink-game .header-refresh-btn:hover {
  background: var(--paper-active-bg);
  color: var(--paper-text-primary);
  border-color: var(--paper-border-color-hover);
}

.ink-game .header-refresh-btn:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

.ink-game .header-refresh-btn .spinning {
  display: inline-block;
  animation: refresh-spin 1s linear infinite;
}

@keyframes refresh-spin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.ink-game .refresh-overlay {
  position: fixed;
  inset: 0;
  z-index: 2000;
  background: rgba(244, 241, 234, 0.7);
  backdrop-filter: blur(2px);
  display: flex;
  align-items: center;
  justify-content: center;
}

.ink-game .refresh-spinner {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.75rem;
  color: var(--paper-text-secondary);
  font-size: 0.95rem;
  font-family: 'Noto Serif SC', 'Georgia', serif;
}

.ink-game .refresh-spinner > span:first-child {
  font-size: 2rem;
  display: inline-block;
  animation: refresh-spin 1.2s linear infinite;
}

/* ==================== GM Mode Chat ==================== */

.gm-chat {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

.gm-chat-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.75rem 1.5rem;
  border-bottom: 1px solid var(--paper-border-color);
  font-weight: bold;
  font-size: 0.9rem;
  color: var(--paper-text-secondary);
  flex-shrink: 0;
}

.gm-clear-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 1rem;
  opacity: 0.5;
  transition: opacity 0.2s;
  padding: 4px;
}

.gm-clear-btn:hover:not(:disabled) {
  opacity: 1;
}

.gm-chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 1rem 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.gm-empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  flex: 1;
  gap: 0.75rem;
  color: var(--paper-text-tertiary);
  min-height: 200px;
}

.gm-empty-icon {
  font-size: 3rem;
  opacity: 0.4;
}

.gm-empty-text {
  font-size: 0.9rem;
  text-align: center;
  max-width: 300px;
  line-height: 1.6;
}

/* Message bubbles */
.gm-message {
  display: flex;
  max-width: 90%;
}

.gm-message-user {
  align-self: flex-end;
  margin-left: auto;
}

.gm-message-assistant {
  align-self: flex-start;
  margin-right: auto;
  max-width: 95%;
}

.gm-bubble {
  padding: 0.75rem 1rem;
  border-radius: 8px;
  line-height: 1.6;
  font-size: 0.9rem;
  word-break: break-word;
}

.gm-bubble-user {
  background: var(--paper-accent-bg, #e8dcc8);
  color: var(--paper-text-primary);
  border-bottom-right-radius: 2px;
}

.gm-bubble-assistant {
  background: var(--paper-bg-secondary);
  color: var(--paper-text-primary);
  border: 1px solid var(--paper-border-color);
  border-bottom-left-radius: 2px;
  width: 100%;
}

/* Phase indicator */
.gm-phase-indicator {
  font-size: 0.8rem;
  color: var(--paper-text-tertiary);
  margin-bottom: 0.5rem;
  animation: gm-pulse 1.5s ease-in-out infinite;
}

@keyframes gm-pulse {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}

/* Analysis content */
.gm-analysis {
  white-space: pre-wrap;
  line-height: 1.7;
}

.gm-error {
  color: #c44;
  font-style: italic;
}

/* Proposed changes */
.gm-changes {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--paper-border-color);
}

.gm-changes-header {
  font-weight: bold;
  margin-bottom: 0.5rem;
  font-size: 0.85rem;
}

.gm-changes-group {
  margin-bottom: 0.5rem;
}

.gm-changes-label {
  font-size: 0.8rem;
  color: var(--paper-text-tertiary);
  margin-bottom: 0.25rem;
  font-weight: bold;
}

/* Approval buttons */
.gm-approval-buttons {
  display: flex;
  gap: 0.5rem;
  margin-top: 0.75rem;
}

.gm-btn {
  padding: 6px 16px;
  border: 1px solid var(--paper-border-color);
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.85rem;
  font-family: inherit;
  transition: all 0.2s;
  background: var(--paper-bg-primary);
  color: var(--paper-text-primary);
}

.gm-btn:hover:not(:disabled) {
  background: var(--paper-bg-secondary);
}

.gm-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.gm-btn-approve {
  border-color: #4a8;
  color: #4a8;
}

.gm-btn-approve:hover:not(:disabled) {
  background: rgba(68, 170, 136, 0.1);
}

.gm-btn-reject {
  border-color: #c66;
  color: #c66;
}

.gm-btn-reject:hover:not(:disabled) {
  background: rgba(204, 102, 102, 0.1);
}

.gm-btn-retry {
  margin-top: 0.5rem;
  border-color: var(--paper-text-tertiary);
}

/* Status indicators */
.gm-status {
  margin-top: 0.5rem;
  padding: 0.5rem;
  border-radius: 4px;
  font-size: 0.85rem;
}

.gm-status-applying {
  color: var(--paper-text-tertiary);
  animation: gm-pulse 1.5s ease-in-out infinite;
}

.gm-status-applied {
  color: #4a8;
}

.gm-status-failed {
  color: #c66;
}

.gm-status-rejected {
  color: var(--paper-text-tertiary);
  font-style: italic;
}

.gm-error-detail {
  margin-top: 0.25rem;
  font-size: 0.8rem;
  color: var(--paper-text-tertiary);
}

/* Input area */
.gm-chat-input {
  display: flex;
  gap: 0.5rem;
  padding: 0.75rem 1.5rem;
  border-top: 1px solid var(--paper-border-color);
  background: var(--paper-bg-primary);
  flex-shrink: 0;
  align-items: flex-end;
}

.gm-chat-input textarea {
  flex: 1;
  resize: none;
  border: 1px solid var(--paper-border-color);
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
  font-family: inherit;
  font-size: 0.9rem;
  line-height: 1.5;
  background: var(--paper-bg-secondary);
  color: var(--paper-text-primary);
  min-height: 42px;
  max-height: 120px;
}

.gm-chat-input textarea:focus {
  outline: none;
  border-color: var(--paper-text-tertiary);
}

.gm-chat-input textarea:disabled {
  opacity: 0.5;
}

.gm-send-btn {
  width: 42px;
  height: 42px;
  border: 1px solid var(--paper-border-color);
  border-radius: 6px;
  background: var(--paper-bg-secondary);
  color: var(--paper-text-primary);
  cursor: pointer;
  font-size: 1.2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  flex-shrink: 0;
}

.gm-send-btn:hover:not(:disabled) {
  background: var(--paper-bg-tertiary);
}

.gm-send-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* Reuse existing collapsible section styles inside GM bubbles */
.gm-bubble-assistant .collapsible-section {
  margin: 0.5rem 0;
  font-size: 0.85rem;
}

/* Mobile responsive */
@media (max-width: 768px) {
  .gm-chat-messages {
    padding: 0.75rem;
  }

  .gm-message {
    max-width: 95%;
  }

  .gm-message-assistant {
    max-width: 100%;
  }

  .gm-chat-input {
    padding: 0.5rem 0.75rem;
  }
}

/* ========== 剧情事件模态框 ========== */

.events-modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--paper-border-color-hover);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
  animation: fadeIn 0.2s ease-out;
}

.events-modal-panel {
  width: 90%;
  max-width: 650px;
  max-height: 80vh;
  background: var(--paper-bg-content);
  border: 1px solid var(--paper-border-color);
  border-radius: 8px;
  display: flex;
  flex-direction: column;
  box-shadow: 4px 4px 0px var(--paper-shadow-color);
  animation: slideUp 0.3s ease-out;
}

.events-modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.5rem;
  border-bottom: 2px solid var(--paper-text-primary);
}

.events-modal-header h3 {
  margin: 0;
  font-size: 1.1rem;
  font-weight: 700;
}

.events-modal-close {
  background: none;
  border: none;
  font-size: 1.2rem;
  cursor: pointer;
  color: var(--paper-text-secondary);
  padding: 0.25rem 0.5rem;
}

.events-modal-close:hover {
  color: var(--paper-text-primary);
}

.events-modal-body {
  flex: 1;
  overflow-y: auto;
  padding: 1rem 1.5rem;
}

.events-modal-empty {
  text-align: center;
  color: var(--paper-text-secondary);
  padding: 2rem 0;
  font-style: italic;
}

.events-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.event-card {
  border: 1px solid var(--paper-border-color);
  border-radius: 6px;
  overflow: hidden;
  transition: border-color 0.2s;
}

.event-card:hover {
  border-color: var(--paper-text-secondary);
}

.event-card-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.625rem 0.875rem;
  cursor: pointer;
  user-select: none;
  background: var(--paper-bg-primary);
}

.event-card-header:hover {
  background: var(--paper-bg-hover);
}

.event-expand-icon {
  font-size: 0.7rem;
  color: var(--paper-text-secondary);
  flex-shrink: 0;
  width: 1rem;
  text-align: center;
}

.event-card-title {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.5rem;
  min-width: 0;
}

.event-title {
  font-weight: 600;
  font-size: 0.95rem;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.event-time {
  font-size: 0.75rem;
  color: var(--paper-text-secondary);
  white-space: nowrap;
  flex-shrink: 0;
}

.event-card-summary {
  padding: 0.375rem 0.875rem 0.625rem 2.375rem;
  font-size: 0.85rem;
  color: var(--paper-text-secondary);
  line-height: 1.4;
}

.event-card-content {
  padding: 0.75rem 0.875rem;
  border-top: 1px dashed var(--paper-border-color);
  background: var(--paper-bg-primary);
}

.event-card-content pre {
  white-space: pre-wrap;
  word-break: break-word;
  font-family: inherit;
  font-size: 0.875rem;
  line-height: 1.5;
  margin: 0;
  color: var(--paper-text-primary);
}

.event-related {
  margin-top: 0.75rem;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.375rem;
  font-size: 0.8rem;
}

.event-related-label {
  color: var(--paper-text-secondary);
}

.event-related-tag {
  background: var(--paper-bg-content);
  border: 1px solid var(--paper-border-color);
  border-radius: 3px;
  padding: 0.125rem 0.375rem;
  font-size: 0.75rem;
  color: var(--paper-text-secondary);
}

.event-updated {
  margin-top: 0.5rem;
  font-size: 0.75rem;
  color: var(--paper-text-secondary);
  font-style: italic;
}

/* 移动端适配 */
@media (max-width: 768px) {
  .events-modal-panel {
    width: 95%;
    max-height: 85vh;
  }

  .events-modal-header {
    padding: 0.75rem 1rem;
  }

  .events-modal-body {
    padding: 0.75rem 1rem;
  }

  .event-card-header {
    padding: 0.5rem 0.75rem;
  }

  .event-card-summary {
    padding: 0.25rem 0.75rem 0.5rem 2rem;
  }

  .event-card-content {
    padding: 0.5rem 0.75rem;
  }
}

