export function RewriteHistoryModal({ scrollToBottom }: { scrollToBottom: (force: boolean) => void }) {
  const { t } = useTranslation(['game', 'common'])
  const inkTurns = useGameStore(s => s.inkTurns)
  const rewriteHistory = useGameStore(s => s.rewriteHistory)

  const {
    rewriteModalOpen,
    rewriteTargetTurnId,
    rewriteUserOpinion,
    closeRewriteModal,
    setRewriteUserOpinion,
  } = useModalStore()

  if (!rewriteModalOpen || rewriteTargetTurnId === null) return null

  // 找到目标回合及之后的中间回合
  const targetIndex = inkTurns.findIndex(t => t.id === rewriteTargetTurnId && isStoryTurn(t))
  if (targetIndex < 0) return null
  const targetTurn = inkTurns[targetIndex] as StoryTurn

  const intermediateTurns = inkTurns.slice(targetIndex + 1)
  const futureRounds: Array<{ action?: PlayerActionTurn; story?: StoryTurn }> = []
  let currentRound: { action?: PlayerActionTurn; story?: StoryTurn } = {}

  for (const turn of intermediateTurns) {
    if (isPlayerActionTurn(turn)) {
      if (currentRound.action || currentRound.story) {
        futureRounds.push(currentRound)
        currentRound = {}
      }
      currentRound.action = turn as PlayerActionTurn
    } else if (isStoryTurn(turn)) {
      currentRound.story = turn as StoryTurn
    }
  }
  if (currentRound.action || currentRound.story) {
    futureRounds.push(currentRound)
  }

  const limitedRounds = futureRounds.slice(0, 9)

  const handleConfirm = async () => {
    closeRewriteModal()
    await rewriteHistory(rewriteTargetTurnId, rewriteUserOpinion, scrollToBottom)
  }

  return (
    <div className="game-modal-overlay" onClick={closeRewriteModal}>
      <div className="game-modal rewrite-history-modal" onClick={(e) => e.stopPropagation()}>
        <div className="game-modal-header">
          <h3>{t('game:ink.rewrite.modalTitle')}</h3>
          <button className="game-modal-close" onClick={closeRewriteModal}>✕</button>
        </div>
        <div className="game-modal-content" style={{ padding: '1.5rem' }}>
          {/* 回档目标 */}
          <div className="rewrite-target-info">
            <div className="rewrite-target-label">{t('game:ink.rewrite.rewindTo')}</div>
            <div className="rewrite-target-chapter">{targetTurn.chapterHint || t('game:ink.unnamedChapter')}</div>
          </div>

          {/* 将被压缩的回合预览 */}
          <div className="rewrite-rounds-preview">
            <div className="rewrite-rounds-label">
              {t('game:ink.rewrite.roundsToCompress', { count: limitedRounds.length })}
              {futureRounds.length > 9 && (
                <span className="rewrite-rounds-warning">
                  {t('game:ink.rewrite.maxRoundsWarning', { total: futureRounds.length })}
                </span>
              )}
            </div>
            <div className="rewrite-rounds-list">
              {limitedRounds.map((round, idx) => (
                <div key={idx} className="rewrite-round-item">
                  <span className="rewrite-round-number">{idx + 1}</span>
                  <div className="rewrite-round-content">
                    {round.action && (
                      <div className="rewrite-round-action">{round.action.playerAction}</div>
                    )}
                    {round.story && (
                      <div className="rewrite-round-chapter">{round.story.chapterHint || t('game:ink.unnamedChapter')}</div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* 用户干涉意见 */}
          <div className="rewrite-opinion-section">
            <label className="rewrite-opinion-label">{t('game:ink.rewrite.opinionLabel')}</label>
            <span className="rewrite-opinion-hint">{t('game:ink.rewrite.opinionHint')}</span>
            <textarea
              className="rewrite-opinion-input"
              value={rewriteUserOpinion}
              onChange={(e) => setRewriteUserOpinion(e.target.value)}
              placeholder={t('game:ink.rewrite.opinionPlaceholder')}
              rows={4}
              autoFocus
            />
          </div>
        </div>
        <div className="game-modal-footer" style={{ padding: '1rem 1.5rem', display: 'flex', justifyContent: 'flex-end', gap: '1rem', borderTop: '1px solid #d1cec7' }}>
          <button
            className="btn-cancel"
            onClick={closeRewriteModal}
          >
            {t('common:cancel')}
          </button>
          <button
            className="btn-primary"
            onClick={handleConfirm}
            disabled={limitedRounds.length === 0}
          >
            {t('game:ink.rewrite.confirm')}
          </button>
        </div>
      </div>
    </div>
  )
}

export function PublishCheckpointModal() {
  const { t } = useTranslation(['game', 'common'])
  const {
    publishCheckpointModalOpen,
    publishCheckpointId,
    publishCheckpointListed,
    publishingCheckpoint,
    closePublishCheckpointModal,
    setPublishCheckpointListed,
    setPublishingCheckpoint,
  } = useModalStore()

  if (!publishCheckpointModalOpen || !publishCheckpointId) return null

  const handlePublish = async () => {
    setPublishingCheckpoint(true)
    try {
      const result = await window.PublishCheckpoint({
        checkpointId: publishCheckpointId,
        isListed: publishCheckpointListed,
      })
      if (result.success) {
        alert(t('game:ink.publishCheckpoint.success'))
        closePublishCheckpointModal()
      } else {
        alert(t('game:ink.publishCheckpoint.failed', { error: result.error || '' }))
      }
    } catch (e) {
      alert(t('game:ink.publishCheckpoint.failed', { error: (e as Error).message }))
    } finally {
      setPublishingCheckpoint(false)
    }
  }

  return (
    <div className="game-modal-overlay" onClick={closePublishCheckpointModal}>
