      >
        {diceMode === 'off' ? `🎲 ${t('ink.settings.diceOff')}` : diceMode === 'visible' ? `🎲 ${t('ink.settings.diceVisible')}` : `🎲 ${t('ink.settings.diceHidden')}`}
