                    <div className="game-time">{t('ink.time.format', { year: gameTime.year, month: gameTime.month, day: gameTime.day, hour: gameTime.hour, minute: gameTime.minute.toString().padStart(2, '0') })}</div>
                  )}
                </div>
              </div>
              
              {activeTab === 'gameplay' ? (
                <>
                  {renderInkFlow()}

