    0% {
        transform: scale(0.95);
        opacity: 0;
    }

    60% {
        transform: scale(1.02);
    }

    100% {
        transform: scale(1);
        opacity: 1;
    }
}

/* Shimmer / iridescent sweep on selected items */
@keyframes dp-shimmer {
    0% {
        background-position: -200% 0;
    }

    100% {
        background-position: 200% 0;
    }
}

/* Glow pulse for active/dirty indicators */
@keyframes dp-glow-pulse {
    0%,
    100% {
        box-shadow: 0 0 4px currentColor;
    }

    50% {
        box-shadow: 0 0 12px currentColor;
    }
}

/* Gradient color shift (for decorative backgrounds) */
@keyframes dp-gradient-shift {
    0% {
        background-position: 0% 50%;
    }

    50% {
        background-position: 100% 50%;
    }

    100% {
        background-position: 0% 50%;
    }
}

/* Fade in from below */
@keyframes dp-fade-up {
    0% {
        opacity: 0;
        transform: translateY(8px);
    }

    100% {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Slide in from right */
@keyframes dp-slide-in-right {
    0% {
        opacity: 0;
        transform: translateX(12px);
    }

    100% {
        opacity: 1;
        transform: translateX(0);
    }
}

/* Confetti-style sparkle */
@keyframes dp-sparkle {
    0%,
    100% {
        opacity: 0;
        transform: scale(0.5) rotate(0deg);
    }

    50% {
        opacity: 1;
        transform: scale(1) rotate(180deg);
    }
}

/* Spin */
@keyframes dp-spin {
    from {
        transform: rotate(0deg);
    }

    to {
        transform: rotate(360deg);
    }
}

/* ========== Utility Classes ========== */

.dp-editor .dp-animate-bounce-in {
    animation: dp-bounce-in 0.3s ease-out;
}

.dp-editor .dp-animate-fade-up {
    animation: dp-fade-up 0.25s ease-out;
}

.dp-editor .dp-animate-slide-in {
    animation: dp-slide-in-right 0.25s ease-out;
}

/* ========== Interactive Hover Effects ========== */

/* Scale bounce on hover */
.dp-editor .dp-hover-bounce {
    transition: transform var(--dp-transition-bounce);
}

.dp-editor .dp-hover-bounce:hover {
    transform: scale(1.04);
}

/* Lift on hover */
.dp-editor .dp-hover-lift {
    transition: all var(--dp-transition-bounce);
}

.dp-editor .dp-hover-lift:hover {
    transform: translateY(-3px);
    box-shadow: var(--dp-shadow-lg);
}

/* Color shift on hover */
.dp-editor .dp-hover-glow:hover {
    box-shadow: var(--dp-glow-blue);
}

/* ========== Loading Spinner ========== */

.dp-editor .dp-spinner {
    width: 24px;
    height: 24px;
    border: 3px solid var(--dp-border-color);
    border-top-color: var(--dp-electric-blue);
    border-radius: 50%;
    animation: dp-spin 0.8s linear infinite;
}

/* ========== Staggered Card Grid Animation ========== */

.dp-entity-card-grid > .dp-entity-card {
    animation: dp-bounce-in 0.3s ease-out both;
}

.dp-entity-card-grid > .dp-entity-card:nth-child(1) { animation-delay: 0ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(2) { animation-delay: 30ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(3) { animation-delay: 60ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(4) { animation-delay: 90ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(5) { animation-delay: 120ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(6) { animation-delay: 150ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(7) { animation-delay: 180ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(8) { animation-delay: 210ms; }
.dp-entity-card-grid > .dp-entity-card:nth-child(n+9) { animation-delay: 240ms; }

