/* ============================================================================
   Dopamine Modals - Edit modal for bento grid cards
   ============================================================================ */

/* Overlay */
.dp-modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.45);
    backdrop-filter: blur(6px);
    -webkit-backdrop-filter: blur(6px);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    animation: dp-fade-in 0.15s ease-out;
}

@keyframes dp-fade-in {
    from {
        opacity: 0;
    }

    to {
        opacity: 1;
    }
}

/* Modal container */
.dp-modal {
    background: var(--dp-bg-secondary, #ffffff);
    border: 2.5px solid var(--dp-dark, #1a1a2e);
    border-radius: var(--dp-radius-xl, 20px);
    box-shadow: 6px 6px 0px var(--dp-dark, #1a1a2e);
    max-height: 85vh;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    animation: dp-modal-in 0.2s var(--dp-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
}

@keyframes dp-modal-in {
    from {
        opacity: 0;
        transform: scale(0.95) translateY(10px);
    }

    to {
        opacity: 1;
        transform: scale(1) translateY(0);
    }
}

/* Size variants */
.dp-modal.dp-modal-normal {
    width: min(640px, 92vw);
}

.dp-modal.dp-modal-wide {
    width: min(900px, 94vw);
}

.dp-modal.dp-modal-full {
    width: min(1200px, 96vw);
}

/* Header */
.dp-modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--dp-space-4, 16px) var(--dp-space-5, 20px);
    border-bottom: 2px solid var(--dp-border-color, #e2e8f0);
    flex-shrink: 0;
}

.dp-modal-header h3 {
    margin: 0;
    font-family: var(--dp-font-display, 'Nunito', sans-serif);
    font-weight: var(--dp-font-weight-bold, 700);
    font-size: var(--dp-font-size-lg, 1.1rem);
    color: var(--dp-text-primary, #1a1a2e);
    display: flex;
    align-items: center;
    gap: var(--dp-space-2, 8px);
}

.dp-modal-icon {
    font-size: 1.2em;
}

.dp-modal-close {
    background: var(--dp-bg-tertiary, #f1f5f9);
    border: 2px solid var(--dp-border-color, #e2e8f0);
    border-radius: var(--dp-radius-md, 12px);
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    color: var(--dp-text-secondary, #64748b);
    font-size: 0.9rem;
    transition: all 0.15s;
}

.dp-modal-close:hover {
    background: var(--dp-coral, #ff6b6b);
    color: white;
    border-color: var(--dp-coral, #ff6b6b);
}

/* Body - scrollable content */
.dp-modal-body {
    flex: 1;
    overflow-y: auto;
    padding: var(--dp-space-5, 20px);
}

.dp-modal-body::-webkit-scrollbar {
    width: 6px;
}

.dp-modal-body::-webkit-scrollbar-track {
    background: transparent;
}

.dp-modal-body::-webkit-scrollbar-thumb {
    background: var(--dp-border-color, #e2e8f0);
    border-radius: 3px;
}

/* ============================================================================
   Bento Summary Cards - compact display views within bento grid
   ============================================================================ */

/* Summary header with title + edit button */
.dp-bento-summary-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--dp-space-3, 12px);
}

.dp-bento-summary-header .section-title {
    margin: 0;
    font-size: var(--dp-font-size-base, 0.95rem);
}

/* Edit button (pencil icon) */
.dp-bento-edit-btn {
    background: var(--dp-electric-blue, #3b82ff);
    color: white;
    border: 2px solid var(--dp-dark, #1a1a2e);
    border-radius: var(--dp-radius-pill, 9999px);
    padding: 4px 12px;
    font-weight: 700;
    font-size: var(--dp-font-size-xs, 0.78rem);
    cursor: pointer;
    transition: all 0.2s var(--dp-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    box-shadow: 2px 2px 0px var(--dp-dark, #1a1a2e);
    display: flex;
    align-items: center;
    gap: 4px;
    flex-shrink: 0;
}

.dp-bento-edit-btn:hover {
    transform: translateY(-1px);
    box-shadow: 3px 3px 0px var(--dp-dark, #1a1a2e);
}

/* Chip/tag list for summary display */
.dp-bento-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
}

.dp-bento-chip {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 3px 10px;
    border-radius: var(--dp-radius-pill, 9999px);
    background: var(--dp-bg-tertiary, #f1f5f9);
    border: 1.5px solid var(--dp-border-color, #e2e8f0);
    font-size: var(--dp-font-size-xs, 0.78rem);
    font-weight: 600;
    color: var(--dp-text-secondary, #64748b);
    white-space: nowrap;
}

.dp-bento-chip.chip-active {
    background: var(--dp-lime-green, #84ff57);
    border-color: var(--dp-dark, #1a1a2e);
    color: var(--dp-dark, #1a1a2e);
}

.dp-bento-chip.chip-inactive {
    background: var(--dp-bg-tertiary, #f1f5f9);
    opacity: 0.6;
}

.dp-bento-chip.chip-blue {
    background: rgba(59, 130, 255, 0.12);
    border-color: var(--dp-electric-blue, #3b82ff);
    color: var(--dp-electric-blue, #3b82ff);
}

.dp-bento-chip.chip-pink {
    background: rgba(255, 45, 138, 0.1);
    border-color: var(--dp-hot-pink, #ff2d8a);
    color: var(--dp-hot-pink, #ff2d8a);
}

/* Summary stat row */
.dp-bento-stat {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: var(--dp-font-size-sm, 0.85rem);
    color: var(--dp-text-secondary, #64748b);
    margin-bottom: var(--dp-space-2, 8px);
}

.dp-bento-stat-number {
    font-weight: var(--dp-font-weight-extrabold, 800);
    font-size: var(--dp-font-size-lg, 1.1rem);
    color: var(--dp-text-primary, #1a1a2e);
}

/* Compact time display */
.dp-bento-time-display {
    font-family: var(--dp-font-display, 'Nunito', sans-serif);
    font-weight: var(--dp-font-weight-extrabold, 800);
    font-size: 1.5rem;
    color: var(--dp-text-primary, #1a1a2e);
    line-height: 1.2;
    margin-top: var(--dp-space-2, 8px);
}

.dp-bento-time-detail {
    font-size: var(--dp-font-size-sm, 0.85rem);
    color: var(--dp-text-tertiary, #94a3b8);
    margin-top: 4px;
}

/* Empty state in summary */
.dp-bento-empty {
    text-align: center;
    padding: var(--dp-space-4, 16px) var(--dp-space-2, 8px);
    color: var(--dp-text-tertiary, #94a3b8);
    font-size: var(--dp-font-size-sm, 0.85rem);
}

/* Preview list for notes/logs */
.dp-bento-preview-list {
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.dp-bento-preview-item {
    font-size: var(--dp-font-size-xs, 0.78rem);
    color: var(--dp-text-secondary, #64748b);
    padding: 4px 8px;
    background: var(--dp-bg-tertiary, #f1f5f9);
    border-radius: var(--dp-radius-sm, 8px);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ============================================================================
   Bento Mini Cards - per-item cards within bento grid sections
   ============================================================================ */

/* Grid of mini cards */
.dp-bento-item-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 8px;
}

/* Vertical list of mini cards (for log entries, notes) */
.dp-bento-item-list {
    display: flex;
    flex-direction: column;
    gap: 6px;
    max-height: 400px;
    overflow-y: auto;
}

.dp-bento-item-list::-webkit-scrollbar {
    width: 4px;
}

.dp-bento-item-list::-webkit-scrollbar-thumb {
    background: var(--dp-border-color, #e2e8f0);
    border-radius: 2px;
}

/* Horizontal mini card variant (single row: badge + title) */
.dp-bento-mini-card.dp-mini-card-horizontal {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 12px;
}

.dp-bento-mini-card.dp-mini-card-horizontal .dp-mini-card-title {
    margin-bottom: 0;
    white-space: normal;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.dp-mini-card-badge {
    font-size: var(--dp-font-size-xs, 0.78rem);
    font-weight: 700;
    color: var(--dp-electric-blue, #3b82ff);
    background: rgba(59, 130, 255, 0.1);
    border: 1.5px solid rgba(59, 130, 255, 0.2);
    border-radius: var(--dp-radius-pill, 9999px);
    padding: 2px 8px;
    white-space: nowrap;
    flex-shrink: 0;
}

/* Individual mini card (clickable → opens edit modal) */
.dp-bento-mini-card {
    background: var(--dp-bg-tertiary, #f1f5f9);
    border: 1.5px solid var(--dp-border-color, #e2e8f0);
    border-radius: var(--dp-radius-lg, 16px);
    padding: 10px 12px;
    cursor: pointer;
    transition: all 0.2s var(--dp-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    position: relative;
    overflow: hidden;
}

.dp-bento-mini-card:hover {
    border-color: var(--dp-electric-blue, #3b82ff);
    box-shadow: 3px 3px 0px var(--dp-electric-blue, #3b82ff);
    transform: translateY(-2px);
}

.dp-mini-card-title {
    font-weight: 700;
    font-size: var(--dp-font-size-sm, 0.85rem);
    color: var(--dp-text-primary, #1a1a2e);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-bottom: 2px;
}

.dp-mini-card-desc {
    font-size: var(--dp-font-size-xs, 0.78rem);
    color: var(--dp-text-tertiary, #94a3b8);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.dp-mini-card-meta {
    font-size: 0.7rem;
    color: var(--dp-text-tertiary, #94a3b8);
    margin-top: 2px;
    opacity: 0.7;
}

/* Responsive: mini cards on mobile */
@media (max-width: 768px) {
    .dp-bento-item-grid {
        grid-template-columns: 1fr 1fr;
    }
}

@media (max-width: 480px) {
    .dp-bento-item-grid {
        grid-template-columns: 1fr;
    }
}



/* Responsive: modal on mobile */
@media (max-width: 768px) {
    .dp-modal {
        max-height: 92vh;
        border-radius: var(--dp-radius-xl, 20px) var(--dp-radius-xl, 20px) 0 0;
        margin-top: auto;
    }

    .dp-modal.dp-modal-normal,
    .dp-modal.dp-modal-wide,
    .dp-modal.dp-modal-full {
        width: 100vw;
    }

    .dp-modal-overlay {
        align-items: flex-end;
    }
}

/* ============================================================================
   Game Selection Cards (Overrides for legacy .game-card inside .dp-modal)
   ============================================================================ */

.dp-modal .game-select-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--dp-space-4, 16px);
    margin-bottom: var(--dp-space-4, 16px);
}

@media (max-width: 480px) {
    .dp-modal .game-select-grid {
        grid-template-columns: 1fr;
    }
}

.dp-modal .game-card {
    background: var(--dp-bg-tertiary, #e8ecf4);
    border: 2px solid var(--dp-border-color, #e2e8f0);
    border-radius: var(--dp-radius-lg, 16px);
    padding: var(--dp-space-5, 20px) var(--dp-space-4, 16px);
    text-align: center;
    cursor: pointer;
    transition: all 0.2s var(--dp-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.dp-modal .game-card:hover {
    border-color: var(--dp-candy-purple, #a855f7);
    transform: translateY(-4px);
    box-shadow: 4px 4px 0px var(--dp-candy-purple, #a855f7);
    background: var(--dp-bg-secondary, #ffffff);
}

.dp-modal .game-card .game-icon {
    font-size: 2.5rem;
    margin-bottom: var(--dp-space-3, 12px);
    filter: drop-shadow(0 4px 8px rgba(0, 0, 0, 0.1));
}

.dp-modal .game-card h4 {
    margin: 0 0 var(--dp-space-2, 8px) 0;
    color: var(--dp-text-primary, #1a1a2e);
    font-size: var(--dp-font-size-lg, 1.125rem);
    font-weight: var(--dp-font-weight-extrabold, 800);
    font-family: var(--dp-font-display, 'Nunito', sans-serif);
}

.dp-modal .game-card p {
    margin: 0;
    color: var(--dp-text-secondary, #4a5568);
    font-size: var(--dp-font-size-sm, 0.875rem);
    line-height: 1.4;
}

