/* ============================================================================
   Dopamine Tabs - Horizontal navigation tabs (replaces EditorSidebar)
   ============================================================================ */

.dp-tabs {
    display: flex;
    align-items: center;
    gap: var(--dp-space-1);
    padding: var(--dp-space-2) var(--dp-space-4);
    background: var(--dp-bg-secondary);
    border-bottom: 2px solid var(--dp-border-color);
    overflow-x: auto;
    flex-shrink: 0;
    /* Hide scrollbar but keep scrollable */
    scrollbar-width: none;
    -ms-overflow-style: none;
}

.dp-tabs::-webkit-scrollbar {
    display: none;
}

/* Tab group separator */
.dp-tabs .dp-tab-separator {
    width: 2px;
    height: 24px;
    background: var(--dp-border-color);
    border-radius: var(--dp-radius-pill);
    flex-shrink: 0;
    margin: 0 var(--dp-space-1);
}

/* Individual tab button */
.dp-tab-btn {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 7px 16px;
    border: 2px solid transparent;
    border-radius: var(--dp-radius-pill);
    background: transparent;
    color: var(--dp-text-secondary);
    font-size: var(--dp-font-size-sm);
    font-weight: var(--dp-font-weight-semibold);
    cursor: pointer;
    white-space: nowrap;
    transition: all var(--dp-transition-bounce);
    flex-shrink: 0;
}

.dp-tab-btn:hover {
    background: var(--dp-bg-tertiary);
    color: var(--dp-text-primary);
    transform: scale(1.05);
}

.dp-tab-btn:active {
    transform: scale(0.97);
}

/* Active tab */
.dp-tab-btn.active {
    background: var(--dp-gradient-aurora);
    color: white;
    border-color: var(--dp-text-primary);
    box-shadow: var(--dp-shadow-hard-sm);
    font-weight: var(--dp-font-weight-bold);
}

/* Tab icon */
.dp-tab-btn .dp-tab-icon {
    font-size: 1rem;
    line-height: 1;
}

/* Tab badge (error count) */
.dp-tab-btn .dp-tab-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 18px;
    height: 18px;
    padding: 0 5px;
    border-radius: var(--dp-radius-pill);
    background: var(--dp-coral);
    color: white;
    font-size: 0.65rem;
    font-weight: var(--dp-font-weight-extrabold);
}

/* Disabled state (world builder running) */
.dp-tab-btn:disabled {
    opacity: 0.45;
    cursor: not-allowed;
    pointer-events: none;
}

.dp-tab-btn:disabled:hover {
    background: transparent;
    transform: none;
}

/* Group label (optional, visible on wider screens) */
.dp-tabs .dp-tab-group-label {
    font-size: var(--dp-font-size-xs);
    font-weight: var(--dp-font-weight-extrabold);
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--dp-text-tertiary);
    padding: 0 var(--dp-space-2);
    white-space: nowrap;
    flex-shrink: 0;
}

