/* ============================================================================
   Dopamine Design System - Variables & Tokens
   All scoped under .dp-editor to prevent style pollution
   ============================================================================ */

.dp-editor {
    /* ========== Vibrant Color Palette ========== */

    /* Primary accent colors - high saturation */
    --dp-electric-blue: #3b82ff;
    --dp-hot-pink: #ff2d8a;
    --dp-lime-green: #22e06a;
    --dp-vivid-orange: #ff8534;
    --dp-candy-purple: #a855f7;
    --dp-sunny-yellow: #ffd60a;
    --dp-cyan: #06d6e0;
    --dp-coral: #ff6b6b;

    /* Alpha variants */
    --dp-electric-blue-alpha: rgba(59, 130, 255, 0.15);
    --dp-hot-pink-alpha: rgba(255, 45, 138, 0.15);
    --dp-lime-green-alpha: rgba(34, 224, 106, 0.15);
    --dp-candy-purple-alpha: rgba(168, 85, 247, 0.15);
    --dp-sunny-yellow-alpha: rgba(255, 214, 10, 0.15);

    /* ========== Background System - Light & Bright ========== */

    --dp-bg-primary: #f0f2f7;
    /* Light gray-blue base */
    --dp-bg-secondary: #ffffff;
    /* Pure white for cards */
    --dp-bg-tertiary: #e8ecf4;
    /* Slightly darker for hover/selection */
    --dp-bg-elevated: #ffffff;
    /* Elevated cards */
    --dp-bg-content: #f5f7fb;
    /* Content area */
    --dp-bg-glass: rgba(255, 255, 255, 0.75);
    /* Glassmorphism */
    --dp-bg-glass-strong: rgba(255, 255, 255, 0.92);

    /* ========== Gradients ========== */

    --dp-gradient-aurora: linear-gradient(135deg, #3b82ff, #a855f7, #ff2d8a);
    --dp-gradient-sunset: linear-gradient(135deg, #ff8534, #ff2d8a, #a855f7);
    --dp-gradient-candy: linear-gradient(135deg, #22e06a, #3b82ff, #a855f7);
    --dp-gradient-ocean: linear-gradient(135deg, #06d6e0, #3b82ff, #a855f7);
    --dp-gradient-warm: linear-gradient(135deg, #ffd60a, #ff8534, #ff2d8a);
    --dp-gradient-mesh: radial-gradient(at 20% 30%, rgba(59, 130, 255, 0.12) 0%, transparent 50%),
        radial-gradient(at 80% 70%, rgba(168, 85, 247, 0.1) 0%, transparent 50%),
        radial-gradient(at 50% 50%, rgba(255, 45, 138, 0.08) 0%, transparent 60%);

    /* ========== Text Colors ========== */

    --dp-text-primary: #1a1a2e;
    /* Near-black with blue tint */
    --dp-text-secondary: #4a5568;
    /* Medium gray */
    --dp-text-tertiary: #8896ab;
    /* Light gray */
    --dp-text-inverse: #ffffff;
    --dp-text-accent: var(--dp-electric-blue);

    /* ========== Border System ========== */

    --dp-border-color: rgba(0, 0, 0, 0.08);
    --dp-border-color-hover: rgba(0, 0, 0, 0.15);
    --dp-border-color-focus: var(--dp-electric-blue);

    /* Neubrutalism borders */
    --dp-border-thick: 2.5px solid #1a1a2e;
    --dp-shadow-hard: 4px 4px 0px #1a1a2e;
    --dp-shadow-hard-sm: 2px 2px 0px #1a1a2e;
    --dp-shadow-hard-blue: 4px 4px 0px var(--dp-electric-blue);
    --dp-shadow-hard-pink: 4px 4px 0px var(--dp-hot-pink);
    --dp-shadow-hard-purple: 4px 4px 0px var(--dp-candy-purple);

    /* ========== Soft Shadows ========== */

    --dp-shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06), 0 1px 2px rgba(0, 0, 0, 0.04);
    --dp-shadow-md: 0 4px 12px rgba(0, 0, 0, 0.08);
    --dp-shadow-lg: 0 10px 25px rgba(0, 0, 0, 0.1);
    --dp-shadow-xl: 0 20px 40px rgba(0, 0, 0, 0.12);

    /* Glow effects */
    --dp-glow-blue: 0 0 20px rgba(59, 130, 255, 0.35);
    --dp-glow-pink: 0 0 20px rgba(255, 45, 138, 0.35);
    --dp-glow-purple: 0 0 20px rgba(168, 85, 247, 0.35);
    --dp-glow-green: 0 0 20px rgba(34, 224, 106, 0.35);

    /* ========== Typography ========== */

    --dp-font-display: 'Nunito', 'Outfit', 'Inter', system-ui, sans-serif;
    --dp-font-body: 'Inter', 'Nunito', system-ui, sans-serif;
    --dp-font-mono: 'JetBrains Mono', 'Fira Code', monospace;

    --dp-font-size-xs: 0.75rem;
    --dp-font-size-sm: 0.875rem;
    --dp-font-size-base: 1rem;
    --dp-font-size-lg: 1.125rem;
    --dp-font-size-xl: 1.25rem;
    --dp-font-size-2xl: 1.5rem;
    --dp-font-size-3xl: 1.875rem;

    --dp-font-weight-normal: 400;
    --dp-font-weight-medium: 500;
    --dp-font-weight-semibold: 600;
    --dp-font-weight-bold: 700;
    --dp-font-weight-extrabold: 800;

    --dp-line-height-tight: 1.25;
    --dp-line-height-normal: 1.5;
    --dp-line-height-relaxed: 1.75;

    /* ========== Spacing ========== */

    --dp-space-1: 0.25rem;
    --dp-space-2: 0.5rem;
    --dp-space-3: 0.75rem;
    --dp-space-4: 1rem;
    --dp-space-5: 1.25rem;
    --dp-space-6: 1.5rem;
    --dp-space-8: 2rem;
    --dp-space-10: 2.5rem;
    --dp-space-12: 3rem;

    /* ========== Border Radius ========== */

    --dp-radius-sm: 6px;
    --dp-radius-md: 10px;
    --dp-radius-lg: 14px;
    --dp-radius-xl: 20px;
    --dp-radius-2xl: 24px;
    --dp-radius-pill: 9999px;

    /* ========== Transitions ========== */

    --dp-transition-fast: 0.15s ease;
    --dp-transition-normal: 0.2s ease;
    --dp-transition-slow: 0.3s ease;
    --dp-transition-bounce: 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);

    /* ========== Layout ========== */

    --dp-header-height: 56px;
    --dp-tabs-height: 48px;
    --dp-copilot-width: 360px;
    --dp-copilot-width-collapsed: 48px;
    --dp-entity-grid-max-height: 280px;

    /* ========== Z-Index ========== */

    --dp-z-dropdown: 100;
    --dp-z-sticky: 200;
    --dp-z-float-outline: 500;
    --dp-z-modal-backdrop: 900;
    --dp-z-modal: 1000;
    --dp-z-tooltip: 1100;
}

/* ========== Base Reset for .dp-editor ========== */

.dp-editor {
    font-family: var(--dp-font-body);
    font-size: var(--dp-font-size-base);
    line-height: var(--dp-line-height-normal);
    color: var(--dp-text-primary);
    background: var(--dp-bg-primary);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

.dp-editor *,
.dp-editor *::before,
.dp-editor *::after {
    box-sizing: border-box;
}

.dp-editor button {
    font-family: inherit;
}

.dp-editor input,
.dp-editor textarea,
.dp-editor select {
    font-family: inherit;
    font-size: inherit;
}

/* Custom scrollbar - colorful */
.dp-editor ::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

.dp-editor ::-webkit-scrollbar-track {
    background: transparent;
}

.dp-editor ::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, var(--dp-electric-blue), var(--dp-candy-purple));
    border-radius: var(--dp-radius-pill);
    border: 2px solid transparent;
    background-clip: content-box;
}

.dp-editor ::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(180deg, var(--dp-hot-pink), var(--dp-candy-purple));
    background-clip: content-box;
}

/src/styles/editor/appinfo.css:
/* ============================================================================
   AppInfo Page - 应用信息页面布局
   ============================================================================ */

.appinfo-page {
    display: flex;
    justify-content: center;
    padding: var(--spacing-8) var(--spacing-6);
}

.appinfo-container {
    width: 100%;
    max-width: 720px;
    display: flex;
    flex-direction: column;
    gap: var(--spacing-5);
}

/* 页面标题 */
.appinfo-header {
    text-align: center;
    margin-bottom: var(--spacing-4);
}

.appinfo-header h2 {
    font-size: var(--font-size-2xl);
    font-weight: var(--font-weight-bold);
    color: var(--text-primary);
    margin: 0 0 var(--spacing-2);
    letter-spacing: var(--letter-spacing-tight);
}

.appinfo-header p {
    font-size: var(--font-size-sm);
    color: var(--text-tertiary);
    margin: 0;
}

/* 表单卡片 */
.appinfo-card {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-xl);
    padding: var(--spacing-5) var(--spacing-6);
    transition: border-color var(--transition-fast);
}

.appinfo-card:hover {
    border-color: var(--border-color-hover);
}

.appinfo-card-title {
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
    color: var(--accent-primary);
    margin-bottom: var(--spacing-4);
    padding-bottom: var(--spacing-2);
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

/* 表单提示文字 */
.appinfo-card .form-hint {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    margin-top: var(--spacing-1);
}

/* 必填标记 */
.appinfo-card .required-mark {
    color: var(--accent-red);
}

/* 发布区域 */
.appinfo-publish-section {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-3);
    padding-top: var(--spacing-4);
    border-top: 1px solid rgba(255, 255, 255, 0.06);
}

/* 状态横幅 */
.appinfo-status-banner {
    padding: var(--spacing-4);
    border-radius: var(--radius-lg);
    border: 1px solid;
}

.appinfo-status-banner.ready {
    background: var(--accent-green-alpha);
    border-color: var(--accent-green);
}

.appinfo-status-banner.incomplete {
    background: rgba(245, 158, 11, 0.1);
    border-color: var(--accent-primary);
}

.appinfo-status-title {
    font-weight: var(--font-weight-semibold);
    font-size: var(--font-size-sm);
    margin-bottom: var(--spacing-1);
}

.appinfo-status-banner.ready .appinfo-status-title {
    color: var(--accent-green);
}

.appinfo-status-banner.incomplete .appinfo-status-title {
    color: var(--accent-primary);
}

.appinfo-status-desc {
    font-size: var(--font-size-xs);
    color: var(--text-secondary);
}

/* 发布按钮 */
.appinfo-publish-btn {
    width: 100%;
    padding: var(--spacing-4);
    font-size: var(--font-size-base);
    font-weight: var(--font-weight-bold);
    color: var(--text-inverse);
    background: linear-gradient(135deg, var(--accent-primary), var(--accent-primary-hover));
    border: none;
    border-radius: var(--radius-lg);
    cursor: pointer;
    transition: all var(--transition-fast);
}

.appinfo-publish-btn:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: var(--shadow-glow-primary);
}

.appinfo-publish-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* 发布说明 */
.appinfo-publish-note {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    text-align: center;
}

/* 响应式 */
@media (max-width: 640px) {
    .appinfo-page {
        padding: var(--spacing-4) var(--spacing-3);
    }

    .appinfo-card {
        padding: var(--spacing-4);
    }

    .appinfo-card .form-grid {
        grid-template-columns: 1fr;
    }
}

/src/styles/editor/buttons.css:
/* ============================================================================
   Buttons - 按钮变体
   ============================================================================ */

/* 基础工具栏按钮 */
.btn-toolbar {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--spacing-2);
    padding: var(--spacing-2) var(--spacing-4);
    border: 1px solid transparent;
    border-radius: var(--radius-lg);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    cursor: pointer;
    transition: all var(--transition-fast);
    white-space: nowrap;
}

.btn-toolbar:hover:not(:disabled) {
    background: var(--btn-neutral-bg-hover);
    border-color: var(--border-color-hover);
    transform: none;
}

.btn-toolbar:active:not(:disabled) {
    transform: translateY(0);
}

.btn-toolbar:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Loading 状态 - 按钮内 spinner */
@keyframes btn-spinner {
    to { transform: rotate(360deg); }
}

.btn-toolbar.btn-loading {
    position: relative;
    pointer-events: none;
    opacity: 0.7;
}

.btn-toolbar.btn-loading::after {
    content: '';
    position: absolute;
    right: 6px;
    top: 50%;
    width: 14px;
    height: 14px;
    margin-top: -7px;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: white;
    border-radius: var(--radius-full);
    animation: btn-spinner 0.6s linear infinite;
}

/* Primary 按钮 - 纯色强调 (Save / Launch) */
.btn-toolbar.btn-primary {
    background: var(--accent-blue);
    color: white;
    font-weight: var(--font-weight-semibold);
    border: none;
}

.btn-toolbar.btn-primary:hover:not(:disabled) {
    background: var(--accent-blue-hover);
    box-shadow: var(--shadow-glow-blue);
    transform: none;
}

/* Success 按钮 - 绿色 */
.btn-toolbar.btn-success {
    background: var(--accent-green);
    color: white;
    border: none;
}

.btn-toolbar.btn-success:hover:not(:disabled) {
    background: #34d399;
    box-shadow: 0 0 15px var(--accent-green-alpha);
}

/* Game 按钮 - 中性灰 (下拉菜单触发器) */
.btn-toolbar.btn-game {
    background: var(--btn-neutral-bg);
    color: var(--btn-neutral-text);
    font-weight: var(--font-weight-medium);
    border: 1px solid var(--btn-neutral-border);
}

.btn-toolbar.btn-game:hover:not(:disabled) {
    background: var(--btn-neutral-bg-hover);
    border-color: var(--border-color-hover);
    box-shadow: none;
    transform: none;
}

/* AI 按钮 - 中性灰 */
.btn-toolbar.btn-ai {
    background: var(--btn-neutral-bg);
    color: var(--btn-neutral-text);
    font-weight: var(--font-weight-medium);
    border: 1px solid var(--btn-neutral-border);
}

.btn-toolbar.btn-ai:hover:not(:disabled) {
    background: var(--btn-neutral-bg-hover);
    border-color: var(--border-color-hover);
    box-shadow: none;
    transform: none;
}

.btn-toolbar.btn-ai.active {
    background: rgba(99, 102, 241, 0.15);
    border-color: rgba(99, 102, 241, 0.3);
    color: var(--accent-blue-hover);
    box-shadow: none;
}

/* Danger 按钮 - 红色 */
.btn-toolbar.btn-danger {
    background: var(--accent-red);
    color: white;
    border: none;
}

.btn-toolbar.btn-danger:hover:not(:disabled) {
    background: #f87171;
    box-shadow: 0 0 15px var(--accent-red-alpha);
}

/* Settings 按钮 - 中性灰 */
.btn-toolbar.btn-settings {
    background: var(--btn-neutral-bg);
    color: var(--btn-neutral-text);
    font-weight: var(--font-weight-medium);
    border: 1px solid var(--btn-neutral-border);
}

.btn-toolbar.btn-settings:hover:not(:disabled) {
    background: var(--btn-neutral-bg-hover);
    border-color: var(--border-color-hover);
    box-shadow: none;
    transform: none;
}

/* 添加按钮 */
.btn-add {
    display: inline-flex;
    align-items: center;
    gap: var(--spacing-1);
    padding: var(--spacing-2) var(--spacing-3);
    border: none;
    border-radius: var(--radius-lg);
    background: var(--accent-green);
    color: white;
    cursor: pointer;
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    transition: all var(--transition-fast);
}

.btn-add:hover {
    background: #34d399;
    transform: none;
    box-shadow: 0 4px 12px var(--accent-green-alpha);
}

/* 小型添加按钮 */
.btn-add-small {
    display: inline-flex;
    align-items: center;
    gap: var(--spacing-1);
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--accent-blue);
    border-radius: var(--radius-md);
    background: rgba(59, 130, 246, 0.1);
    color: var(--accent-blue);
    cursor: pointer;
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    transition: all var(--transition-fast);
    margin-top: var(--spacing-2);
}

.btn-add-small:hover {
    background: var(--accent-blue);
    color: white;
    transform: translateY(-1px);
    box-shadow: 0 4px 12px var(--accent-blue-alpha);
}

/* 删除按钮 */
.btn-remove {
    width: 28px;
    height: 28px;
    border: none;
    border-radius: var(--radius-full);
    background: var(--accent-red);
    color: white;
    cursor: pointer;
    font-size: var(--font-size-lg);
    font-weight: var(--font-weight-bold);
    line-height: 1;
    transition: all var(--transition-fast);
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
}

.btn-remove:hover {
    background: #f87171;
    transform: scale(1.1);
    box-shadow: 0 4px 12px var(--accent-red-alpha);
}

/* 复制按钮 */
.btn-copy {
    width: 28px;
    height: 28px;
    border: none;
    border-radius: var(--radius-full);
    background: var(--accent-blue);
    color: white;
    cursor: pointer;
    font-size: var(--font-size-sm);
    line-height: 1;
    transition: all var(--transition-fast);
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
}

.btn-copy:hover {
    background: #60a5fa;
    transform: scale(1.1);
    box-shadow: 0 4px 12px var(--accent-blue-alpha);
}

/* 小型删除按钮 - 图标式，hover 显色 */
.btn-remove-small {
    width: 28px;
    height: 28px;
    border: none;
    border-radius: var(--radius-full);
    background: transparent;
    color: var(--text-secondary);
    cursor: pointer;
    font-size: 14px;
    line-height: 1;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    transition: all var(--transition-fast);
    opacity: 0.45;
}

.btn-remove-small:hover {
    background: rgba(239, 68, 68, 0.15);
    color: var(--accent-red);
    opacity: 1;
}

/* 折叠按钮 */
.btn-collapse {
    width: 24px;
    height: 24px;
    padding: 0;
    border: none;
    background: var(--bg-tertiary);
    color: var(--text-secondary);
    border-radius: var(--radius-sm);
    cursor: pointer;
    font-size: var(--font-size-xs);
    transition: all var(--transition-fast);
    flex-shrink: 0;
    display: flex;
    align-items: center;
