    font-weight: var(--font-weight-medium);
    transition: all var(--transition-fast);
}

.btn-delete:hover {
    background: var(--accent-red);
    border-color: var(--accent-red);
    color: white;
}

/* 按钮组 */
.btn-group {
    display: flex;
    gap: var(--spacing-2);
}

/src/styles/editor/cards.css:
/* ============================================================================
   Cards - 卡片和列表项 - Modern Polished
   ============================================================================ */

/* 列表项容器 */
.list-items {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-4);
}

/* 基础列表项卡片 - Glass Effect */
.list-item {
    background: rgba(30, 41, 59, 0.4);
    /* Semi-transparent slate */
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: var(--radius-xl);
    padding: var(--spacing-4);
    margin-bottom: var(--spacing-3);
    transition: all var(--transition-normal);
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    position: relative;
    overflow: hidden;
    /* For shine effects */
}

.list-item:hover {
    background: rgba(30, 41, 59, 0.6);
    border-color: rgba(255, 255, 255, 0.12);
    transform: none;
    box-shadow: none;
}

/* 光泽效果 (Optional Shine) */
.list-item::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg,
            rgba(255, 255, 255, 0) 0%,
            rgba(255, 255, 255, 0.1) 50%,
            rgba(255, 255, 255, 0) 100%);
    opacity: 0.5;
}

/* 可折叠卡片 */
.list-item.collapsible {
    padding: 0;
}

.list-item.collapsible .item-header {
    padding: var(--spacing-3) var(--spacing-4);
    margin-bottom: 0;
    cursor: pointer;
    transition: background var(--transition-fast);
    border-radius: var(--radius-xl);
    /* Matches card radius */
    user-select: none;
}

.list-item.collapsible .item-header:hover {
    background: rgba(255, 255, 255, 0.03);
}

/* Collapsed state adjustments */
.list-item.collapsible.collapsed {
    background: rgba(30, 41, 59, 0.2);
    /* Dimmer when collapsed */
}

.list-item.collapsible> :not(.item-header) {
    padding: 0 var(--spacing-4) var(--spacing-4) var(--spacing-4);
    animation: fadeIn 0.3s ease;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(-5px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* 特殊卡片变体 */
.list-item.player-item {
    border-left: 3px solid var(--accent-primary);
    background: linear-gradient(to right, rgba(245, 158, 11, 0.05), rgba(30, 41, 59, 0.4));
}

.list-item.region-item {
    border-left: 3px solid var(--accent-green);
    background: linear-gradient(to right, rgba(16, 185, 129, 0.05), rgba(30, 41, 59, 0.4));
}

.list-item.relationship-item {
    border-left: 3px solid #f472b6;
    background: linear-gradient(to right, rgba(244, 114, 182, 0.05), rgba(30, 41, 59, 0.4));
}

.list-item.entry-item {
    padding: var(--spacing-2);
}

/* Item Header */
.item-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-3);
    gap: var(--spacing-2);
}

.item-header-actions {
    display: flex;
    gap: var(--spacing-2);
    align-items: center;
}

/* Item Title */
.item-title {
    font-weight: 600;
    color: var(--text-primary);
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    flex: 1;
    font-size: 0.95rem;
    letter-spacing: 0.01em;
}

/* Player Badge */
.player-badge {
    background: var(--accent-primary);
    color: white;
    padding: 2px 8px;
    border-radius: 6px;
    font-size: 0.75rem;
    font-weight: 700;
    box-shadow: 0 2px 4px rgba(245, 158, 11, 0.3);
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

/* 列表项 body 区域 */
.list-item .item-body {
    margin-top: var(--spacing-3);
    padding-top: var(--spacing-3);
    border-top: 1px solid rgba(255, 255, 255, 0.05);
}

.list-item .item-body label {
    display: block;
    margin-bottom: var(--spacing-2);
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-medium);
    color: var(--text-primary);
    opacity: 0.5;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

/* Modern Textarea */
.list-item .item-body textarea {
    width: 100%;
    min-height: 120px;
    padding: var(--spacing-3);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-lg);
    background: rgba(0, 0, 0, 0.2);
    color: var(--text-primary);
    font-size: 0.9rem;
    line-height: 1.6;
    resize: vertical;
    font-family: var(--font-mono);
    transition: all var(--transition-fast);
    box-sizing: border-box;
}

.list-item .item-body textarea:focus {
    outline: none;
    border-color: var(--accent-blue);
    background: rgba(0, 0, 0, 0.3);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

.list-item .item-body textarea::placeholder {
    color: var(--text-tertiary);
    opacity: 0.7;
}

/* 列表项头部输入框 */
.list-item .item-header input[type="text"] {
    flex: 1;
    min-width: 200px;
    padding: 6px 12px;
    border: 1px solid transparent;
    border-radius: var(--radius-md);
    background: rgba(0, 0, 0, 0.2);
    color: var(--text-primary);
    font-size: 0.9rem;
    font-weight: 500;
    transition: all var(--transition-fast);
}

.list-item .item-header input[type="text"]:hover {
    background: rgba(0, 0, 0, 0.3);
}

.list-item .item-header input[type="text"]:focus {
    outline: none;
    border-color: var(--accent-blue);
    background: rgba(0, 0, 0, 0.4);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

/* 子列表 */
.sub-list {
    background: rgba(0, 0, 0, 0.15);
    border-radius: var(--radius-lg);
    padding: var(--spacing-3);
    margin-top: var(--spacing-4);
    border: 1px solid rgba(255, 255, 255, 0.03);
}

.sub-list-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-3);
    font-size: 0.8rem;
    color: var(--text-tertiary);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sub-item {
    background: rgba(255, 255, 255, 0.02);
    border-radius: var(--radius-md);
    padding: var(--spacing-2) var(--spacing-3);
    margin-bottom: var(--spacing-2);
    border: 1px solid transparent;
    transition: all var(--transition-fast);
}

.sub-item:hover {
    background: rgba(255, 255, 255, 0.05);
    border-color: rgba(255, 255, 255, 0.05);
}

.sub-item:last-child {
    margin-bottom: 0;
}

/* 列表编辑器 */
.list-editor {
    background: transparent;
    /* Remove heavy background */
    border-radius: var(--radius-xl);
    padding: 0;
    /* Remove padding */
    margin-bottom: var(--spacing-6);
    border: none;
    /* Remove border */
}

.list-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-5);
    padding-bottom: var(--spacing-2);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    /* Divider */
}

.list-header h4 {
    margin: 0;
    color: var(--text-primary);
    font-size: 1.1rem;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
}

/* 玩家状态列表 - Special Style */
.player-state-list {
    background: linear-gradient(135deg, rgba(245, 158, 11, 0.1), transparent);
    border: 1px dashed var(--accent-primary);
    padding: var(--spacing-4);
    border-radius: var(--radius-lg);
}

/* ============================================================================
   Status Editor Cards - 状态编辑器卡片
   ============================================================================ */

.statuses-list {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-4);
    margin-top: var(--spacing-4);
}

.status-item-card {
    background: rgba(30, 41, 59, 0.5);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-lg);
    padding: var(--spacing-4);
    transition: all var(--transition-normal);
}

.status-item-card:hover {
    background: rgba(30, 41, 59, 0.7);
    border-color: rgba(255, 255, 255, 0.15);
}

.status-card-header {
    display: grid;
    grid-template-columns: 1fr 1fr auto;
    gap: var(--spacing-3);
    align-items: end;
    margin-bottom: var(--spacing-4);
    padding-bottom: var(--spacing-3);
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.status-template-select,
.status-instance-id {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-1);
}

.status-template-select label,
.status-instance-id label {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    font-weight: var(--font-weight-medium);
}

.status-template-select select,
.status-instance-id input {
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
}

.status-template-select select:focus,
.status-instance-id input:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

.instance-id-input-group {
    display: flex;
    gap: var(--spacing-2);
}

.instance-id-input-group input {
    flex: 1;
}

.btn-dice {
    padding: var(--spacing-2);
    background: var(--bg-tertiary);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    cursor: pointer;
    transition: all var(--transition-fast);
}

.btn-dice:hover {
    background: var(--accent-blue-alpha);
    border-color: var(--accent-blue);
}

.template-info-box {
    background: rgba(59, 130, 246, 0.1);
    border: 1px solid rgba(59, 130, 246, 0.2);
    border-radius: var(--radius-md);
    padding: var(--spacing-3);
    margin-bottom: var(--spacing-4);
}

.template-info-box .template-name {
    font-weight: var(--font-weight-semibold);
    color: var(--accent-blue);
    margin-bottom: var(--spacing-1);
}

.template-info-box .template-desc {
    font-size: var(--font-size-sm);
    color: var(--text-secondary);
    margin-bottom: var(--spacing-1);
}

.template-info-box .template-hint {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    font-style: italic;
}

.status-value-area {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-2);
}

.status-value-area>label {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    font-weight: var(--font-weight-medium);
}

.status-remark-area {
    margin-top: var(--spacing-3);
}

.status-remark-area input {
    width: 100%;
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
}

/* Schema value editor nested styles */
.status-value-area .form-group {
    margin-bottom: var(--spacing-2);
}

.status-value-area .form-group label {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    font-size: var(--font-size-sm);
    color: var(--text-secondary);
}

/* ============================================================================
   Skills Editor - 技艺编辑器
   ============================================================================ */

.skill-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: var(--spacing-3);
    margin-top: var(--spacing-3);
}

.skill-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    padding: var(--spacing-2) var(--spacing-3);
    background: rgba(30, 41, 59, 0.4);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: var(--radius-md);
    transition: all var(--transition-fast);
}

.skill-item:hover {
    background: rgba(30, 41, 59, 0.6);
    border-color: rgba(255, 255, 255, 0.12);
}

.skill-item select {
    flex: 1;
    min-width: 100px;
    padding: var(--spacing-1) var(--spacing-2);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
}

.skill-item input[type="number"] {
    width: 70px !important;
    padding: var(--spacing-1) var(--spacing-2);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--accent-blue);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
    text-align: center;
}

.skill-item .btn-remove-small {
    padding: var(--spacing-1);
    width: 24px;
    height: 24px;
    font-size: 0.7rem;
    border-radius: var(--radius-sm);
    background: rgba(239, 68, 68, 0.1);
    border: none;
    color: var(--accent-red);
    cursor: pointer;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;
}

.skill-item .btn-remove-small:hover {
    background: var(--accent-red);
    color: white;
}

/* ============================================================================
   Moves Editor - 招式编辑器（与技艺编辑器保持一致布局）
   ============================================================================ */

.moves-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: var(--spacing-3);
    margin-top: var(--spacing-3);
}

.move-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    padding: var(--spacing-2) var(--spacing-3);
    background: rgba(30, 41, 59, 0.4);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: var(--radius-md);
    transition: all var(--transition-fast);
}

.move-item:hover {
    background: rgba(30, 41, 59, 0.6);
    border-color: rgba(255, 255, 255, 0.12);
}

.move-item select {
    flex: 1;
    min-width: 100px;
    padding: var(--spacing-1) var(--spacing-2);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
}

.move-item .btn-remove-small {
    padding: var(--spacing-1);
    width: 24px;
    height: 24px;
    font-size: 0.7rem;
    border-radius: var(--radius-sm);
    background: rgba(239, 68, 68, 0.1);
    border: none;
    color: var(--accent-red);
    cursor: pointer;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 1;
}

.move-item .btn-remove-small:hover {
    background: var(--accent-red);
    color: white;
}

/* Subsection styling */
.subsection h4 {
    margin: 0 0 var(--spacing-3) 0;
    font-size: var(--font-size-base);
    font-weight: var(--font-weight-semibold);
    color: var(--text-primary);
}

/* ============================================================================
   Inventory Editor - 背包编辑器
   ============================================================================ */

.inventory-list {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--spacing-3);
    margin-top: var(--spacing-3);
}

/* Header row with labels - spans full width */
.inventory-header {
    grid-column: 1 / -1;
    display: none;
    /* Hide header since items are now compact cards */
}

.inventory-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    padding: var(--spacing-2) var(--spacing-3);
    background: rgba(30, 41, 59, 0.4);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: var(--radius-md);
    transition: all var(--transition-fast);
}

.inventory-item:hover {
    background: rgba(30, 41, 59, 0.6);
    border-color: rgba(255, 255, 255, 0.12);
}

.inventory-item select {
    flex: 1;
    min-width: 0;
    padding: var(--spacing-1) var(--spacing-2);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
}

.inventory-item input[type="number"] {
    width: 60px !important;
    flex-shrink: 0;
    padding: var(--spacing-1) var(--spacing-2);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--accent-green);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
    text-align: center;
}

.inventory-item .btn-remove-small {
    padding: var(--spacing-1);
    width: 28px;
    height: 28px;
    font-size: 0.7rem;
    border-radius: var(--radius-sm);
    background: rgba(239, 68, 68, 0.1);
    border: none;
    color: var(--accent-red);
    cursor: pointer;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    justify-content: center;
}

.inventory-item .btn-remove-small:hover {
    background: var(--accent-red);
    color: white;
}

/* ============================================================================
   Location Cards - 地点卡片
   ============================================================================ */

.location-card {
    padding: var(--spacing-4);
    margin-bottom: var(--spacing-4);
    background: linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(15, 23, 42, 0.7));
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-lg);
    border-left: 3px solid var(--accent-primary);
}

.location-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-3);
    padding-bottom: var(--spacing-2);
    border-bottom: 1px dashed rgba(255, 255, 255, 0.1);
}

.location-card-header .location-title {
    font-weight: var(--font-weight-semibold);
    color: var(--accent-primary);
    font-size: var(--font-size-base);
}

/* Textarea in forms - better visibility */
.form-group textarea {
    border: 1px solid rgba(255, 255, 255, 0.15);
    background: rgba(15, 23, 42, 0.6);
    border-radius: var(--radius-md);
    padding: var(--spacing-3);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    resize: vertical;
    min-height: 60px;
}

.form-group textarea:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

/* ============================================================================
   Path Cards - 路径卡片
   ============================================================================ */

.path-card {
    padding: var(--spacing-4);
    margin-top: var(--spacing-2);
    margin-bottom: var(--spacing-3);
    background: linear-gradient(135deg, rgba(30, 41, 59, 0.4), rgba(15, 23, 42, 0.6));
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: var(--radius-lg);
    border-left: 3px solid var(--accent-blue);
}

.path-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-3);
}

.path-card-header .path-title {
    font-weight: var(--font-weight-semibold);
    color: var(--accent-blue);
    font-size: var(--font-size-sm);
}

.path-section {
    padding: var(--spacing-3);
    background: rgba(0, 0, 0, 0.15);
    border-radius: var(--radius-md);
    margin-bottom: var(--spacing-3);
}

.path-section-title {
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-semibold);
    color: var(--text-tertiary);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: var(--spacing-2);
}

.path-arrow {
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    color: var(--accent-blue);
    margin: var(--spacing-2) 0;
}

/* Toggle switch for discovered */
.toggle-group {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
}

.toggle-switch {
    position: relative;
    width: 44px;
    height: 24px;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: rgba(100, 116, 139, 0.5);
    transition: 0.3s;
    border-radius: 24px;
}

.toggle-slider:before {
    position: absolute;
    content: "";
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    transition: 0.3s;
    border-radius: 50%;
}

.toggle-switch input:checked+.toggle-slider {
    background-color: var(--accent-green);
}

.toggle-switch input:checked+.toggle-slider:before {
    transform: translateX(20px);
}

/* ============================================================================
   Registry Cards - 注册项卡片 (技艺、招式、物品、状态模板)
   ============================================================================ */

.registry-card {
    padding: var(--spacing-4);
    margin-bottom: var(--spacing-4);
    background: linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(15, 23, 42, 0.7));
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-lg);
    border-left: 3px solid var(--accent-blue);
    transition: all var(--transition-fast);
}

.registry-card:hover {
    border-color: rgba(255, 255, 255, 0.15);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.2);
}

.registry-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-3);
    padding-bottom: var(--spacing-3);
    border-bottom: 1px dashed rgba(255, 255, 255, 0.1);
    gap: var(--spacing-3);
}

.registry-card-header .name-input {
    flex: 1;
    padding: var(--spacing-2) var(--spacing-3);
    font-weight: var(--font-weight-semibold);
    font-size: var(--font-size-lg);
    color: var(--text-primary);
    background: transparent;
    border: 1px solid transparent;
    border-radius: var(--radius-md);
    transition: all var(--transition-fast);
}

.registry-card-header .name-input:hover {
    background: rgba(255, 255, 255, 0.05);
    border-color: rgba(255, 255, 255, 0.1);
}

.registry-card-header .name-input:focus {
    outline: none;
    background: var(--bg-secondary);
    border-color: var(--accent-blue);
}

.registry-card-header .btn-delete {
    padding: var(--spacing-2) var(--spacing-3);
    background: rgba(239, 68, 68, 0.15);
    border: 1px solid rgba(239, 68, 68, 0.3);
    border-radius: var(--radius-md);
    color: var(--accent-red);
    font-size: var(--font-size-sm);
    cursor: pointer;
    transition: all var(--transition-fast);
    display: flex;
    align-items: center;
    gap: var(--spacing-1);
}

.registry-card-header .btn-delete:hover {
    background: var(--accent-red);
    border-color: var(--accent-red);
    color: white;
}

/* Different accent colors for different types */
.registry-card.skill-card {
    border-left-color: #8b5cf6;
    /* 紫色 - 技艺 */
}

.registry-card.move-card {
    border-left-color: #f59e0b;
    /* 橙色 - 招式 */
}

.registry-card.item-card {
    border-left-color: #10b981;
    /* 绿色 - 物品 */
}

.registry-card.status-template-card {
    border-left-color: #ec4899;
    /* 粉色 - 状态模板 */
}

/* Schema editor section styling */
.schema-section {
    padding: var(--spacing-3);
    margin-top: var(--spacing-3);
    background: rgba(0, 0, 0, 0.15);
    border-radius: var(--radius-md);
    border: 1px dashed rgba(255, 255, 255, 0.1);
}

.schema-section-title {
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
    color: var(--accent-blue);
    margin-bottom: var(--spacing-2);
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
}

