/* ============================================================================
   Collapsible - 折叠面板
   ============================================================================ */

.collapsible-section {
    margin-bottom: var(--spacing-4);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-xl);
    /* overflow: hidden 已移除，避免截断 tooltip::after 伪元素 */
    background: var(--bg-secondary);
    position: relative;
}

.collapsible-section.collapsed .collapsible-content {
    display: none;
}

/* 折叠面板头部 */
.section-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--spacing-3) var(--spacing-4);
    background: var(--bg-tertiary);
    cursor: pointer;
    user-select: none;
    transition: background var(--transition-fast);
    /* 顶部圆角，与父容器 border-radius 对齐（因父级移除了 overflow:hidden） */
    border-radius: var(--radius-xl) var(--radius-xl) 0 0;
}

/* 当 section-header 是父级最后一个子元素（内容折叠时），四角全圆 */
.section-header:last-child {
    border-radius: var(--radius-xl);
}

.section-header:hover {
    background: rgba(51, 65, 85, 0.8);
}

.section-header-left {
    display: flex;
    align-items: center;
    gap: var(--spacing-3);
}

.section-header-title {
    font-weight: var(--font-weight-semibold);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
}

.section-header-count {
    color: var(--text-tertiary);
    font-size: var(--font-size-xs);
}

.section-header-icon {
    color: var(--text-secondary);
    font-size: var(--font-size-sm);
    transition: transform var(--transition-fast);
}

.collapsible-section.collapsed .section-header-icon {
    transform: rotate(-90deg);
}

.collapsible-section .section-content {
    padding: var(--spacing-4);
}

/* 折叠面板内容 */
.collapsible-content {
    padding: var(--spacing-4);
}

/* 人格特质区块 - 紫色左边框 */
.collapsible-section.section-personality {
    border-color: rgba(99, 102, 241, 0.25);
}

.collapsible-section.section-personality .section-header {
    border-left: 3px solid rgba(99, 102, 241, 0.6);
    background: rgba(99, 102, 241, 0.04);
}

.collapsible-section.section-personality .section-header:hover {
    background: rgba(99, 102, 241, 0.08);
}

/* 情感状态区块 - 粉色左边框 */
.collapsible-section.section-emotion {
    border-color: rgba(244, 114, 182, 0.25);
}

.collapsible-section.section-emotion .section-header {
    border-left: 3px solid rgba(244, 114, 182, 0.6);
    background: rgba(244, 114, 182, 0.04);
}

.collapsible-section.section-emotion .section-header:hover {
    background: rgba(244, 114, 182, 0.08);
}

/* 验证面板 - 特殊样式 */
.validation-panel {
    background: var(--bg-secondary);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-xl);
    margin-bottom: var(--spacing-6);
    overflow: hidden;
}

.validation-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--spacing-3) var(--spacing-4);
    background: var(--bg-tertiary);
    cursor: pointer;
}

.validation-header:hover {
    background: rgba(51, 65, 85, 0.8);
}

.validation-status {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
}

.validation-status.valid {
    color: var(--accent-green);
}

.validation-status.invalid {
    color: var(--accent-red);
}

.validation-status.warning {
    color: var(--accent-primary);
}

.validation-content {
    padding: var(--spacing-4);
    max-height: 300px;
    overflow-y: auto;
}

.validation-item {
    display: flex;
    align-items: flex-start;
    gap: var(--spacing-3);
    padding: var(--spacing-2) 0;
    border-bottom: 1px solid var(--border-color);
}

.validation-item:last-child {
    border-bottom: none;
}

.validation-icon {
    flex-shrink: 0;
    width: 20px;
    height: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.validation-icon.error {
    color: var(--accent-red);
}

.validation-icon.warning {
    color: var(--accent-primary);
}

.validation-icon.info {
    color: var(--accent-blue);
}

.validation-message {
    flex: 1;
    font-size: var(--font-size-sm);
    color: var(--text-secondary);
}

/src/styles/editor/forms.css:
/* ============================================================================
   Forms - 表单和输入框
   ============================================================================ */

/* 表单网格 */
.form-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--spacing-3);
}

@media (max-width: 768px) {
    .form-grid {
        grid-template-columns: 1fr;
    }
}

.form-grid.compact {
    display: grid;
    grid-template-columns: minmax(150px, 200px) 1fr auto;
    gap: var(--spacing-2);
    align-items: center;
}

/* 表单组 */
.form-group {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-1);
}

.form-card {
    background: rgba(255, 255, 255, 0.03);
    border-radius: var(--radius-xl);
    border: 1px solid rgba(255, 255, 255, 0.06);
    padding: var(--spacing-5) var(--spacing-6);
    margin-bottom: var(--spacing-4);
    transition: border-color var(--transition-fast);
}

.form-card:hover {
    border-color: rgba(255, 255, 255, 0.10);
}

/* 区块标题 */
.section-title {
    font-size: var(--font-size-xl);
    font-weight: var(--font-weight-semibold);
    color: var(--text-primary);
    margin: 0 0 var(--spacing-6) 0;
    letter-spacing: var(--letter-spacing-tight);
}

.form-group.full-width {
    grid-column: 1 / -1;
}

.form-group.flex-grow {
    flex: 1;
}

.form-group label {
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-medium);
    color: var(--text-primary);
    opacity: 0.6;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

/* 输入框基础样式 */
.form-group input,
.form-group select,
.form-group textarea {
    padding: var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-lg);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    transition: all var(--transition-fast);
}

.form-group input,
.form-group select {
    word-break: break-all;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* Placeholder 样式 */
.form-group input::placeholder,
.form-group textarea::placeholder {
    font-size: var(--font-size-sm);
    color: var(--text-primary);
    opacity: 0.3;
}

/* Focus 状态 - 克制的发光边框 */
.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

/* Error 状态 - 红色边框（镜像 focus 蓝色模式） */
.form-input-error,
.form-group input.form-input-error,
.form-group select.form-input-error,
.form-group textarea.form-input-error {
    border-color: var(--accent-red) !important;
    box-shadow: 0 0 0 1px var(--accent-red-alpha) !important;
    outline: none;
}

/* 内联错误消息 */
.form-field-error {
    font-size: var(--font-size-xs);
    color: var(--accent-red);
    margin-top: 4px;
    display: flex;
    align-items: center;
    gap: 4px;
}

/* Hover 状态 */
.form-group input:hover:not(:focus),
.form-group select:hover:not(:focus),
.form-group textarea:hover:not(:focus) {
    border-color: var(--border-color-hover);
}

.form-group textarea {
    min-height: 80px;
    resize: vertical;
    overflow-y: auto;
    overflow-x: hidden;
    word-wrap: break-word;
    white-space: pre-wrap;
}

/* 全宽文本域 */
.full-textarea {
    width: 100%;
    min-height: 120px;
    padding: var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-lg);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    resize: vertical;
    transition: all var(--transition-fast);
}

.full-textarea:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

.full-textarea:hover:not(:focus) {
    border-color: var(--border-color-hover);
}

/* 键值输入 */
.key-input {
    flex: 1;
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-lg);
    background: var(--bg-secondary);
    color: var(--accent-primary);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
}

/* 属性编辑器 */
.attrs-editor {
    margin-top: var(--spacing-4);
}

.attrs-editor>label {
    display: block;
    font-size: var(--font-size-sm);
    color: var(--text-secondary);
    margin-bottom: var(--spacing-2);
}

.attrs-grid {
    display: grid;
    grid-template-columns: repeat(6, 1fr);
    gap: var(--spacing-2);
}

.attr-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: var(--bg-tertiary);
    border-radius: var(--radius-lg);
    padding: var(--spacing-2);
}

.attr-label {
    font-size: var(--font-size-xs);
    color: var(--accent-primary);
    font-weight: var(--font-weight-bold);
    margin-bottom: var(--spacing-1);
}

.attr-item input {
    width: 100%;
    padding: var(--spacing-1);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--text-primary);
    text-align: center;
    font-size: var(--font-size-sm);
}

/* ============================================================================
   String Array Editor - 字符串数组编辑器
   ============================================================================ */

.string-array-editor {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-2);
}

/* 数组项 - 输入框和删除按钮水平排列 */
.array-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
}

.array-item input {
    flex: 1;
    padding: var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-lg);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    transition: all var(--transition-fast);
}

.array-item input:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

.array-item input:hover:not(:focus) {
    border-color: var(--border-color-hover);
}

/* 内联删除按钮 - 紧凑但可见 */
.btn-remove-inline {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    flex-shrink: 0;
    border: none;
    border-radius: var(--radius-md);
    background: rgba(239, 68, 68, 0.15);
    color: var(--accent-red);
    cursor: pointer;
    font-size: var(--font-size-base);
    transition: all var(--transition-fast);
}

.btn-remove-inline:hover {
    background: var(--accent-red);
    color: white;
    transform: scale(1.05);
}

/* ============================================================================
   Schema Value Editor - 模式值编辑器
   ============================================================================ */

.schema-value-editor {
    width: 100%;
}

.schema-value-editor input,
.schema-value-editor select,
.schema-value-editor textarea {
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    width: 100%;
    transition: all var(--transition-fast);
}

.schema-value-editor input:focus,
.schema-value-editor select:focus,
.schema-value-editor textarea:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

.schema-value-hint {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    margin-bottom: var(--spacing-2);
    font-style: italic;
}

/* Object fields - Grid layout */
.schema-object-fields {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: var(--spacing-4);
}

.schema-object-field {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-1);
}

.schema-field-label {
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
    color: var(--accent-blue);
    display: flex;
    align-items: center;
    gap: var(--spacing-1);
}

.schema-field-label .required-mark {
    color: var(--accent-red);
}

.schema-field-label .field-description {
    font-size: var(--font-size-xs);
    color: var(--text-tertiary);
    cursor: help;
}

/* Nested object styling */
.schema-object.depth-1,
.schema-object.depth-2,
.schema-object.depth-3 {
    padding: var(--spacing-3);
    background: rgba(0, 0, 0, 0.1);
    border-radius: var(--radius-md);
    border-left: 2px solid var(--accent-blue);
}

/* Array styling */
.schema-array-items {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-2);
}

.schema-array-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    padding: var(--spacing-2);
    background: rgba(0, 0, 0, 0.1);
    border-radius: var(--radius-md);
}

.schema-array-item> :first-child {
    flex: 1;
}

.schema-empty-hint {
    font-size: var(--font-size-sm);
    color: var(--text-tertiary);
    font-style: italic;
    padding: var(--spacing-2);
}

.schema-depth-limit {
    font-size: var(--font-size-sm);
    color: var(--accent-red);
    padding: var(--spacing-2);
    background: rgba(239, 68, 68, 0.1);
    border-radius: var(--radius-md);
}

/* ============================================================================
   Type Schema Editor - 类型结构编辑器 (用于定义状态模板的数据结构)
   ============================================================================ */

.type-schema-editor {
    width: 100%;
}

/* 类型选择行 */
.type-schema-editor .schema-type-row {
    display: flex;
    gap: var(--spacing-3);
    align-items: center;
    margin-bottom: var(--spacing-3);
}

.type-schema-editor .schema-type-select {
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    min-width: 160px;
    cursor: pointer;
    transition: all var(--transition-fast);
}

.type-schema-editor .schema-type-select:hover {
    border-color: rgba(255, 255, 255, 0.2);
}

.type-schema-editor .schema-type-select:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

.type-schema-editor .schema-description {
    flex: 1;
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    transition: all var(--transition-fast);
}

.type-schema-editor .schema-description:focus {
    outline: none;
    border-color: var(--accent-blue);
    box-shadow: 0 0 0 1px var(--accent-blue-alpha);
}

/* 对象属性区域 */
.type-schema-editor .schema-properties {
    padding: var(--spacing-4);
    background: rgba(0, 0, 0, 0.15);
    border-radius: var(--radius-md);
    border: 1px dashed rgba(255, 255, 255, 0.1);
}

.type-schema-editor .schema-section-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--spacing-3);
    padding-bottom: var(--spacing-2);
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.type-schema-editor .schema-section-header>span {
    font-weight: var(--font-weight-semibold);
    color: var(--accent-blue);
    font-size: var(--font-size-sm);
}

/* 单个属性项 */
.type-schema-editor .schema-property-item {
    padding: var(--spacing-3);
    margin-bottom: var(--spacing-3);
    background: rgba(30, 41, 59, 0.4);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: var(--radius-md);
    border-left: 3px solid var(--accent-green);
}

.type-schema-editor .schema-property-item:last-child {
    margin-bottom: 0;
}

.type-schema-editor .property-header {
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
    margin-bottom: var(--spacing-2);
    padding-bottom: var(--spacing-2);
    border-bottom: 1px dashed rgba(255, 255, 255, 0.1);
}

.type-schema-editor .property-name {
    flex: 1;
    padding: var(--spacing-2) var(--spacing-3);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--accent-primary);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
}

.type-schema-editor .property-name:focus {
    outline: none;
    border-color: var(--accent-blue);
}

.type-schema-editor .required-checkbox {
    display: flex;
    align-items: center;
    gap: var(--spacing-1);
    font-size: var(--font-size-sm);
    color: var(--text-secondary);
    cursor: pointer;
    padding: var(--spacing-1) var(--spacing-2);
    border-radius: var(--radius-sm);
    transition: all var(--transition-fast);
}

.type-schema-editor .required-checkbox:hover {
    background: rgba(255, 255, 255, 0.05);
}

.type-schema-editor .required-checkbox input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: var(--accent-green);
    cursor: pointer;
}

.type-schema-editor .btn-remove-inline {
    padding: var(--spacing-1) var(--spacing-2);
    background: rgba(239, 68, 68, 0.1);
    border: 1px solid rgba(239, 68, 68, 0.2);
    border-radius: var(--radius-sm);
    color: var(--accent-red);
    font-size: 0.75rem;
    cursor: pointer;
    transition: all var(--transition-fast);
}

.type-schema-editor .btn-remove-inline:hover {
    background: var(--accent-red);
    color: white;
}

.type-schema-editor .property-schema {
    padding-left: var(--spacing-3);
    border-left: 2px solid rgba(255, 255, 255, 0.1);
}

/* 数组 items 编辑 */
.type-schema-editor .schema-array-items {
    padding: var(--spacing-4);
    background: rgba(0, 0, 0, 0.15);
    border-radius: var(--radius-md);
    border: 1px dashed rgba(255, 255, 255, 0.1);
}

.type-schema-editor .array-items-editor {
    padding-left: var(--spacing-3);
    border-left: 2px solid var(--accent-blue);
}

/* 嵌套深度样式 */
.type-schema-editor.depth-1,
.type-schema-editor.depth-2,
.type-schema-editor.depth-3,
.type-schema-editor.depth-4 {
    margin-top: var(--spacing-2);
}

.type-schema-editor.depth-1 .schema-properties,
.type-schema-editor.depth-2 .schema-properties,
.type-schema-editor.depth-3 .schema-properties {
    background: rgba(0, 0, 0, 0.1);
}

/* 空属性提示 */
.type-schema-editor .schema-empty-hint {
    text-align: center;
    padding: var(--spacing-4);
    color: var(--text-tertiary);
    font-style: italic;
    font-size: var(--font-size-sm);
}

/* ============================================================================
   SelectWithQuickCreate - 带快速新建功能的下拉选择器
   ============================================================================ */

.select-quick-create-wrapper {
    display: flex;
    gap: var(--spacing-2);
    align-items: center;
}

.select-quick-create-wrapper .select-with-create {
    flex: 1;
}

.btn-quick-create {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    flex-shrink: 0;
    border: 1px solid var(--accent-green);
    border-radius: var(--radius-md);
    background: rgba(34, 197, 94, 0.1);
    color: var(--accent-green);
    cursor: pointer;
    transition: all var(--transition-fast);
}

.btn-quick-create:hover:not(:disabled) {
    background: var(--accent-green);
    color: white;
    transform: scale(1.05);
}

.btn-quick-create:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ============================================================================
   SearchFilter 容器 & 输入框
   ============================================================================ */

.search-filter-container {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-2);
}

.search-input {
    width: 100%;
    padding: 8px 12px;
    border-radius: var(--radius-md);
    border: 1px solid rgba(255, 255, 255, 0.1);
    background: rgba(0, 0, 0, 0.2);
    color: var(--text-primary);
    font-size: var(--font-size-sm);
    outline: none;
    transition: border-color var(--transition-fast);
    box-sizing: border-box;
}

.search-input:focus {
    border-color: var(--accent-blue);
}

.search-input::placeholder {
    color: var(--text-tertiary);
    font-size: var(--font-size-sm);
}

/* ============================================================================
   SearchFilter 排序选择器 & 空结果提示
   ============================================================================ */

.search-sort-select {
    padding: 4px 6px;
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    font-size: var(--font-size-xs);
    cursor: pointer;
    flex-shrink: 0;
}

.search-sort-select:focus {
    outline: none;
    border-color: var(--accent-blue);
}

.search-no-results {
    padding: var(--spacing-6);
    text-align: center;
    color: var(--text-tertiary);
    font-style: italic;
    font-size: var(--font-size-sm);
}

/* ============================================================================
   特质滑块提示 Tooltip
   ============================================================================ */

.trait-hint-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.08);
    color: var(--text-tertiary);
    font-size: 10px;
    font-style: italic;
    cursor: help;
    position: relative;
    flex-shrink: 0;
    user-select: none;
    transition: background var(--transition-fast);
}

.trait-hint-icon:hover {
    background: rgba(255, 255, 255, 0.16);
    color: var(--text-secondary);
}

.trait-hint-icon::after {
    content: attr(data-hint);
    position: absolute;
    bottom: calc(100% + 8px);
    left: 50%;
    transform: translateX(-50%);
    background: #0f172a;
    color: #e2e8f0;
    padding: 8px 12px;
    border-radius: 8px;
    font-size: 0.72rem;
    font-weight: 400;
    font-style: normal;
    white-space: normal;
    max-width: 240px;
    min-width: 140px;
    z-index: 200;
    border: 1px solid rgba(255, 255, 255, 0.12);
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.6);
    pointer-events: none;
    line-height: 1.5;
    text-align: left;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.15s, visibility 0.15s;
}

.trait-hint-icon:hover::after {
    opacity: 1;
    visibility: visible;
}

/* ============================================================================
   属性卡片网格
   ============================================================================ */

.attrs-card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(110px, 1fr));
    gap: 10px;
    margin-bottom: 12px;
}

.attr-card {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.07);
    border-radius: var(--radius-lg);
    padding: 10px 12px;
    display: flex;
    flex-direction: column;
    gap: 6px;
    transition: border-color var(--transition-fast);
}

.attr-card:hover {
    border-color: rgba(255, 255, 255, 0.15);
}

.attr-card-label {
    font-size: 0.67rem;
    font-weight: 700;
