/src/styles/editor/header.css:
/* ============================================================================
   Header - 头部和工具栏 - Modern Polished
   ============================================================================ */

/* 头部容器 */
.editor-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0 var(--spacing-6);
    background: rgba(3, 7, 18, 0.6);
    /* Glass base */
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    /* Subtle border */
    flex-shrink: 0;
    height: var(--header-height);
    z-index: 20;
}

/* 头部左侧区域 */
.editor-header-left {
    display: flex;
    align-items: center;
    gap: 16px;
}

.editor-header h2 {
    margin: 0;
    font-size: 1.25rem;
    font-weight: 700;
    letter-spacing: -0.01em;
    background: linear-gradient(to right, #f8fafc, #94a3b8);
    background-clip: text;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    display: flex;
    align-items: center;
    gap: var(--spacing-2);
}

/* 模式指示器 */
.mode-indicator {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 6px 4px 10px;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.2s;
    border: 1px solid rgba(255, 255, 255, 0.1);
    background: rgba(255, 255, 255, 0.04);
    user-select: none;
}

.mode-indicator:hover {
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(255, 255, 255, 0.15);
}

.mode-indicator.simple {
    border-color: rgba(251, 191, 36, 0.3);
    background: rgba(251, 191, 36, 0.08);
}

.mode-indicator.simple:hover {
    background: rgba(251, 191, 36, 0.12);
}

.mode-indicator.full {
    border-color: rgba(99, 102, 241, 0.3);
    background: rgba(99, 102, 241, 0.08);
}

.mode-indicator.full:hover {
    background: rgba(99, 102, 241, 0.12);
}

.mode-indicator-icon {
    font-size: 0.9rem;
    line-height: 1;
}

.mode-indicator-label {
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text-secondary);
    white-space: nowrap;
}

.mode-indicator.simple .mode-indicator-label {
    color: #fbbf24;
}

.mode-indicator.full .mode-indicator-label {
    color: #818cf8;
}

.mode-indicator-switch {
    padding: 2px 8px;
    font-size: 0.7rem;
    font-weight: 500;
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 4px;
    background: rgba(255, 255, 255, 0.06);
    color: var(--text-muted);
    cursor: pointer;
    transition: all 0.15s;
    white-space: nowrap;
}

.mode-indicator-switch:hover {
    background: rgba(255, 255, 255, 0.12);
    color: var(--text-primary);
}

/* 未保存标记 */
.dirty-indicator {
    -webkit-text-fill-color: var(--accent-primary);
    font-size: 0.6rem;
    animation: dirtyPulse 2s ease-in-out infinite;
}

@keyframes dirtyPulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.4; }
}

/* 工具栏 */
.toolbar {
    display: flex;
    gap: var(--spacing-3);
    align-items: center;
}

/* 下拉菜单 */
.dropdown-menu {
    position: relative;
    display: inline-block;
}

.dropdown-content {
    position: absolute;
    top: calc(100% + 4px);
    right: 0;
    /* Align right */
    min-width: 220px;
    background: rgba(17, 24, 39, 0.95);
    /* Deep opaque */
    backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-xl);
    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.5), 0 4px 6px -2px rgba(0, 0, 0, 0.3);
    z-index: var(--z-dropdown);
    overflow: hidden;
    padding: var(--spacing-1);
    animation: dropdownFadeIn 0.2s cubic-bezier(0.16, 1, 0.3, 1);
    transform-origin: top right;
}

@keyframes dropdownFadeIn {
    from {
        opacity: 0;
        transform: scale(0.95) translateY(-4px);
    }

    to {
        opacity: 1;
        transform: scale(1) translateY(0);
    }
}

.dropdown-content button {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 8px 12px;
    border: none;
    background: transparent;
    color: var(--text-secondary);
    text-align: left;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    border-radius: var(--radius-md);
    transition: all var(--transition-fast);
}

.dropdown-content button:hover:not(:disabled) {
    background: var(--accent-blue);
    color: white;
}

.dropdown-content button:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

.dropdown-content button.danger:hover {
    background: var(--accent-red);
    color: white;
}

.dropdown-content .shortcut {
    font-size: 0.75rem;
    opacity: 0.6;
    margin-left: var(--spacing-4);
    font-family: var(--font-mono);
}

/* 撤销/重做历史步数徽章 */
.history-badge {
    font-size: var(--font-size-xs);
    opacity: 0.6;
    font-weight: var(--font-weight-normal);
    margin-left: 2px;
}

.dropdown-content button:hover .shortcut {
    opacity: 0.9;
    color: white;
}

.dropdown-info {
    padding: 8px 12px;
    font-size: inherit;
    color: rgba(255, 255, 255, 0.55);
    cursor: default;
}

.dropdown-hint {
    margin: 0 8px 4px;
    padding: 4px 8px;
    font-size: 11px;
    color: rgba(255, 255, 255, 0.45);
    background: rgba(255, 255, 255, 0.05);
    border-left: 2px solid rgba(255, 255, 255, 0.15);
    border-radius: 0 3px 3px 0;
    cursor: default;
    line-height: 1.4;
}

.dropdown-divider {
    height: 1px;
    background: rgba(255, 255, 255, 0.08);
    margin: 4px 0;
}

