/src/styles/editor/layout.css:
/* ============================================================================
   Layout - 核心布局结构
   ============================================================================ */

/* 外层 wrapper - 全屏编辑器容器 */
/* 外层 wrapper - 全屏编辑器容器 */
.game-init-editor-wrapper {
    display: flex;
    width: 100vw;
    height: 100vh;
    overflow: hidden;
    /* Subtler, deep radial gradient background */
    background: radial-gradient(circle at top right, #1e293b, #030712 80%), #030712;
    position: fixed;
    top: 0;
    left: 0;
}

/* 主编辑器容器 */
.game-init-editor {
    display: flex;
    flex-direction: column;
    flex: 1;
    min-width: 0;
    height: 100%;
    background: var(--bg-primary);
    color: var(--text-primary);
    font-family: var(--font-sans);
    overflow: hidden;
    transition: flex var(--transition-slow);
}

/* 主内容区：侧边栏 + 内容面板 */
.editor-main {
    display: flex;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

/* 内容区域 */
.editor-content {
    flex: 1;
    overflow-y: auto;
    overflow-x: hidden;
    padding: var(--spacing-8);
    background: var(--bg-content);
}

/* 编辑器区块 */
.editor-section {
    margin-bottom: var(--spacing-8);
}

.editor-section h3 {
    margin: 0 0 var(--spacing-6);
    padding-bottom: var(--spacing-3);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    color: var(--text-primary);
    font-size: var(--font-size-xl);
    font-weight: var(--font-weight-semibold);
    letter-spacing: var(--letter-spacing-tight);
}

/* 空状态提示 */
.empty-hint {
    text-align: center;
    padding: var(--spacing-8);
    color: var(--text-tertiary);
    font-style: italic;
}

/* 空状态卡片 */
.list-items .empty-state {
    padding: var(--spacing-12) var(--spacing-4);
    text-align: center;
    color: var(--text-tertiary);
    background: var(--bg-secondary);
    border: 2px dashed var(--border-color-hover);
    border-radius: var(--radius-xl);
}

.list-items .empty-state p {
    margin: var(--spacing-2) 0;
}

.list-items .empty-state p:first-child {
    font-size: var(--font-size-base);
    color: var(--text-secondary);
    font-weight: var(--font-weight-medium);
}

.list-items .empty-state .hint {
    font-size: var(--font-size-sm);
    color: var(--text-tertiary);
}

/* 字段提示 */
.field-hint {
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-normal);
    color: var(--text-primary);
    opacity: 0.5;
    line-height: var(--line-height-normal);
    margin: 0 0 var(--spacing-8) 0;
}

/* ============================================================================
   Redesigned Split Editor Layout
   ============================================================================ */

.editor-maximize-container {
    display: flex;
    height: 100%;
    width: 100%;
    /* Adjust based on header height */
    background: rgba(0, 0, 0, 0.2);
    border-radius: var(--radius-lg);
    border: 1px solid rgba(255, 255, 255, 0.05);
    overflow: hidden;
}

/* When editor-content directly contains editor-maximize-container, remove padding */
.editor-content:has(> .editor-maximize-container) {
    padding: 0;
}

.editor-maximize-container>* {
    min-height: 0;
    /* Fix flex overflow */
}

/* Left components tree */
.editor-left-sidebar {
    width: 280px;
    background: var(--bg-submenu);
    border-right: 1px solid rgba(255, 255, 255, 0.05);
    display: flex;
    flex-direction: column;
}

/* Right sidebar for outline */
.editor-right-sidebar {
    width: 240px;
    background: var(--bg-submenu);
    border-left: 1px solid rgba(255, 255, 255, 0.05);
    display: flex;
    flex-direction: column;
}

.sidebar-header {
    padding: var(--spacing-3) var(--spacing-4);
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--text-secondary);
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: rgba(255, 255, 255, 0.02);
}

.sidebar-actions {
    display: flex;
    gap: 4px;
}

.sidebar-actions button {
    background: transparent;
    border: none;
    color: var(--text-tertiary);
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.sidebar-actions button:hover {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-primary);
}

.tree-scroll-container {
    flex: 1;
    overflow-y: auto;
    padding: var(--spacing-2);
}

/* Right Editor Area */
.editor-main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: var(--bg-content);
}

.document-editor {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.editor-toolbar {
    height: 48px;
    padding: 0 var(--spacing-4);
    display: flex;
    align-items: center;
    justify-content: space-between;
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    background: rgba(15, 23, 42, 0.3);
}

.toolbar-group {
    display: flex;
    gap: 4px;
    align-items: center;
}

.toolbar-group button {
    background: transparent;
    border: none;
    color: var(--text-secondary);
    padding: 6px;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.2s;
}

.toolbar-group button:hover {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-primary);
}

.toolbar-divider {
    width: 1px;
    height: 16px;
    background: rgba(255, 255, 255, 0.1);
    margin: 0 8px;
}

.toolbar-path {
    font-family: var(--font-mono);
    font-size: 0.8rem;
    color: var(--text-tertiary);
    opacity: 0.7;
}

.editor-textarea {
    flex: 1;
    background: transparent;
    border: none;
    resize: none;
    padding: 20px 28px;
    color: var(--text-primary);
    font-family: monospace;
    font-size: 1rem;
    line-height: 1.75;
}

.editor-textarea:focus,
.setting-editor-textarea:focus {
    outline: none;
    border: none !important;
    box-shadow: none !important;
    background: transparent !important;
}

.editor-footer {
    height: 32px;
    padding: 0 var(--spacing-4);
    border-top: 1px solid rgba(255, 255, 255, 0.05);
    display: flex;
    gap: 16px;
    align-items: center;
    font-size: 0.75rem;
    color: var(--text-tertiary);
    background: rgba(15, 23, 42, 0.3);
}

.empty-editor-state {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    color: var(--text-tertiary);
    gap: var(--spacing-4);
}

/* Context Menu */
.context-menu {
    position: fixed;
    z-index: 9999;
    background: #1e293b;
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 8px;
    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.5), 0 4px 6px -2px rgba(0, 0, 0, 0.3);
    min-width: 160px;
    padding: 4px;
    display: flex;
    flex-direction: column;
}

.context-menu-header {
    padding: 8px 12px;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--text-tertiary);
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    margin-bottom: 4px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 200px;
}

.context-menu button {
    text-align: left;
    background: transparent;
    border: none;
    color: var(--text-secondary);
    padding: 8px 12px;
    font-size: 0.9rem;
    cursor: pointer;
    border-radius: 4px;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: all 0.15s;
}

.context-menu button:hover {
    background: var(--accent-primary);
    color: white;
}

.context-menu button.danger:hover {
    background: var(--accent-danger);
}

.context-divider {
    height: 1px;
    background: rgba(255, 255, 255, 0.1);
    margin: 4px 0;
}

