/* ============================================================================
   Modals - 模态框样式
   ============================================================================ */

/* AI/游戏 弹窗样式 */
.ai-modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.7);
    display: flex;
    align-items: center;
    justify-content: center;
