/src/styles/paper/animations.css:
/* ============================================================================
   Dopamine Animations - Micro-interactions and visual effects
   ============================================================================ */

/* ========== Keyframe Definitions ========== */

/* Bounce-in for cards and panels */
@keyframes paper-bounce-in {
    0% {
        transform: scale(0.95);
        opacity: 0;
    }

    60% {
        transform: scale(1.02);
    }

    100% {
        transform: scale(1);
        opacity: 1;
    }
}

/* Shimmer / iridescent sweep on selected items */
@keyframes paper-shimmer {
    0% {
        background-position: -200% 0;
    }

    100% {
        background-position: 200% 0;
    }
}

/* Glow pulse for active/dirty indicators */
@keyframes paper-glow-pulse {
    0%,
    100% {
        box-shadow: 0 0 4px currentColor;
    }

    50% {
        box-shadow: 0 0 12px currentColor;
    }
}

/* Gradient color shift (for decorative backgrounds) */
@keyframes paper-gradient-shift {
    0% {
        background-position: 0% 50%;
    }

    50% {
        background-position: 100% 50%;
    }

    100% {
        background-position: 0% 50%;
    }
}

/* Fade in from below */
@keyframes paper-fade-up {
    0% {
        opacity: 0;
        transform: translateY(8px);
    }

    100% {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Slide in from right */
@keyframes paper-slide-in-right {
    0% {
        opacity: 0;
        transform: translateX(12px);
    }

    100% {
        opacity: 1;
        transform: translateX(0);
    }
}

/* Confetti-style sparkle */
@keyframes paper-sparkle {
    0%,
    100% {
        opacity: 0;
        transform: scale(0.5) rotate(0deg);
    }

    50% {
        opacity: 1;
        transform: scale(1) rotate(180deg);
    }
}

/* Spin */
@keyframes paper-spin {
    from {
        transform: rotate(0deg);
    }

    to {
        transform: rotate(360deg);
    }
}

/* ========== Utility Classes ========== */

.paper-editor .paper-animate-bounce-in {
    animation: paper-bounce-in 0.3s ease-out;
}

.paper-editor .paper-animate-fade-up {
    animation: paper-fade-up 0.25s ease-out;
}

.paper-editor .paper-animate-slide-in {
    animation: paper-slide-in-right 0.25s ease-out;
}

/* ========== Interactive Hover Effects ========== */

/* Scale bounce on hover */
.paper-editor .paper-hover-bounce {
    transition: transform var(--paper-transition-bounce);
}

.paper-editor .paper-hover-bounce:hover {
    transform: scale(1.04);
}

/* Lift on hover */
.paper-editor .paper-hover-lift {
    transition: all var(--paper-transition-bounce);
}

.paper-editor .paper-hover-lift:hover {
    transform: translateY(-3px);
    box-shadow: var(--paper-shadow-lg);
}

/* Color shift on hover */
.paper-editor .paper-hover-glow:hover {
    /* removed glow */
}

/* ========== Loading Spinner ========== */

.paper-editor .paper-spinner {
    width: 24px;
    height: 24px;
    border: 3px solid var(--paper-border-color);
    border-top-color: var(--paper-electric-blue);
    border-radius: 50%;
