/* ============================================================================
   Dopamine Modals - Edit modal for bento grid cards
   ============================================================================ */

/* Overlay */
.paper-modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.45);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    animation: paper-fade-in 0.15s ease-out;
}

@keyframes paper-fade-in {
    from {
        opacity: 0;
    }

    to {
        opacity: 1;
    }
}

/* Modal container */
.paper-modal {
    background: var(--paper-bg-secondary, #ffffff);
    border: 2.5px solid var(--paper-dark, #1a1a2e);
    border-radius: var(--paper-radius-xl, 20px);
    box-shadow: 6px 6px 0px var(--paper-dark, #1a1a2e);
    max-width: 95vw;
    max-height: 85vh;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    animation: paper-modal-in 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
}

@keyframes paper-modal-in {
    from {
        opacity: 0;
        transform: scale(0.95) translateY(10px);
    }

    to {
        opacity: 1;
        transform: scale(1) translateY(0);
    }
}

/* Size variants */
.paper-modal.paper-modal-normal {
    width: min(640px, 92vw);
}

.paper-modal.paper-modal-wide {
    width: min(900px, 94vw);
}

.paper-modal.paper-modal-full {
    width: min(1200px, 96vw);
}

/* Header */
.paper-modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--paper-space-4, 16px) var(--paper-space-5, 20px);
    border-bottom: 2px solid var(--paper-border-color, #e2e8f0);
    flex-shrink: 0;
}

.paper-modal-header h3 {
    margin: 0;
    font-family: var(--paper-font-display, 'Nunito', sans-serif);
    font-weight: var(--paper-font-weight-bold, 700);
    font-size: var(--paper-font-size-lg, 1.1rem);
    color: var(--paper-text-primary, #1a1a2e);
    display: flex;
    align-items: center;
    gap: var(--paper-space-2, 8px);
}

.paper-modal-icon {
    font-size: 1.2em;
}

.paper-modal-close {
    background: var(--paper-bg-tertiary, #f1f5f9);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    border-radius: var(--paper-radius-md, 12px);
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    color: var(--paper-text-secondary, #64748b);
    font-size: 0.9rem;
    transition: all 0.15s;
}

.paper-modal-close:hover {
    background: var(--paper-coral, #ff6b6b);
    color: white;
    border-color: var(--paper-coral, #ff6b6b);
}

/* Body - scrollable content */
.paper-modal-body {
    flex: 1;
    overflow-y: auto;
    padding: var(--paper-space-5, 20px);
}

.paper-modal-body::-webkit-scrollbar {
    width: 6px;
}

.paper-modal-body::-webkit-scrollbar-track {
    background: transparent;
}

.paper-modal-body::-webkit-scrollbar-thumb {
    background: var(--paper-border-color, #e2e8f0);
    border-radius: 3px;
}

/* ============================================================================
   Bento Summary Cards - compact display views within bento grid
   ============================================================================ */

/* Summary header with title + edit button */
.paper-bento-summary-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--paper-space-3, 12px);
}

.paper-bento-summary-header .section-title {
    margin: 0;
    font-size: var(--paper-font-size-base, 0.95rem);
}

/* Edit button (pencil icon) */
.paper-bento-edit-btn {
    background: var(--paper-electric-blue, #3b82ff);
    color: white;
    border: 2px solid var(--paper-dark, #1a1a2e);
    border-radius: var(--paper-radius-pill, 9999px);
    padding: 4px 12px;
    font-weight: 700;
    font-size: var(--paper-font-size-xs, 0.78rem);
    cursor: pointer;
    transition: all 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    box-shadow: 2px 2px 0px var(--paper-dark, #1a1a2e);
    display: flex;
    align-items: center;
    gap: 4px;
    flex-shrink: 0;
}

.paper-bento-edit-btn:hover {
    transform: translateY(-1px);
    box-shadow: 3px 3px 0px var(--paper-dark, #1a1a2e);
}

/* Chip/tag list for summary display */
.paper-bento-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
}

.paper-bento-chip {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 3px 10px;
    border-radius: var(--paper-radius-pill, 9999px);
    background: var(--paper-bg-tertiary, #f1f5f9);
    border: 1.5px solid var(--paper-border-color, #e2e8f0);
    font-size: var(--paper-font-size-xs, 0.78rem);
    font-weight: 600;
    color: var(--paper-text-secondary, #64748b);
    white-space: normal;
    word-break: break-word;
}

.paper-bento-chip.chip-active {
    background: var(--paper-lime-green-alpha, rgba(92, 98, 86, 0.15));
    border-color: var(--paper-lime-green, #5c6256);
    color: var(--paper-lime-green, #5c6256);
}

.paper-bento-chip.chip-inactive {
    background: var(--paper-bg-tertiary, #f1f5f9);
    opacity: 0.6;
}

.paper-bento-chip.chip-blue {
    background: rgba(59, 130, 255, 0.12);
    border-color: var(--paper-electric-blue, #3b82ff);
    color: var(--paper-electric-blue, #3b82ff);
}

.paper-bento-chip.chip-pink {
    background: rgba(255, 45, 138, 0.1);
    border-color: var(--paper-hot-pink, #ff2d8a);
    color: var(--paper-hot-pink, #ff2d8a);
}

/* Summary stat row */
.paper-bento-stat {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: var(--paper-font-size-sm, 0.85rem);
    color: var(--paper-text-secondary, #64748b);
    margin-bottom: var(--paper-space-2, 8px);
}

.paper-bento-stat-number {
    font-weight: var(--paper-font-weight-extrabold, 800);
    font-size: var(--paper-font-size-lg, 1.1rem);
    color: var(--paper-text-primary, #1a1a2e);
}

/* Compact time display */
.paper-bento-time-display {
    font-family: var(--paper-font-display, 'Nunito', sans-serif);
    font-weight: var(--paper-font-weight-extrabold, 800);
    font-size: 1.5rem;
    color: var(--paper-text-primary, #1a1a2e);
    line-height: 1.2;
    margin-top: var(--paper-space-2, 8px);
}

.paper-bento-time-detail {
    font-size: var(--paper-font-size-sm, 0.85rem);
    color: var(--paper-text-tertiary, #94a3b8);
    margin-top: 4px;
}

/* Empty state in summary */
.paper-bento-empty {
    text-align: center;
    padding: var(--paper-space-4, 16px) var(--paper-space-2, 8px);
    color: var(--paper-text-tertiary, #94a3b8);
    font-size: var(--paper-font-size-sm, 0.85rem);
}

/* Preview list for notes/logs */
.paper-bento-preview-list {
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.paper-bento-preview-item {
    font-size: var(--paper-font-size-xs, 0.78rem);
    color: var(--paper-text-secondary, #64748b);
    padding: 4px 8px;
    background: var(--paper-bg-tertiary, #f1f5f9);
    border-radius: var(--paper-radius-sm, 8px);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ============================================================================
   Bento Mini Cards - per-item cards within bento grid sections
   ============================================================================ */

/* Grid of mini cards */
.paper-bento-item-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 8px;
}

/* Vertical list of mini cards (for log entries, notes) */
.paper-bento-item-list {
    display: flex;
    flex-direction: column;
    gap: 6px;
    max-height: 400px;
    overflow-y: auto;
}

.paper-bento-item-list::-webkit-scrollbar {
    width: 4px;
}

.paper-bento-item-list::-webkit-scrollbar-thumb {
    background: var(--paper-border-color, #e2e8f0);
    border-radius: 2px;
}

/* Horizontal mini card variant (single row: badge + title) */
.paper-bento-mini-card.paper-mini-card-horizontal {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 12px;
}

.paper-bento-mini-card.paper-mini-card-horizontal .paper-mini-card-title {
    margin-bottom: 0;
    white-space: normal;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.paper-mini-card-badge {
    font-size: var(--paper-font-size-xs, 0.78rem);
    font-weight: 700;
    color: var(--paper-electric-blue, #3b82ff);
    background: rgba(59, 130, 255, 0.1);
    border: 1.5px solid rgba(59, 130, 255, 0.2);
    border-radius: var(--paper-radius-pill, 9999px);
    padding: 2px 8px;
    white-space: nowrap;
    flex-shrink: 0;
}

/* Individual mini card (clickable → opens edit modal) */
.paper-bento-mini-card {
    background: var(--paper-bg-tertiary, #f1f5f9);
    border: 1.5px solid var(--paper-border-color, #e2e8f0);
    border-radius: var(--paper-radius-lg, 16px);
    padding: 10px 12px;
    cursor: pointer;
    transition: all 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    position: relative;
    overflow: hidden;
}

.paper-bento-mini-card:hover {
    border-color: var(--paper-electric-blue, #3b82ff);
    box-shadow: 3px 3px 0px var(--paper-electric-blue, #3b82ff);
    transform: translateY(-2px);
}

.paper-mini-card-title {
    font-weight: 700;
    font-size: var(--paper-font-size-sm, 0.85rem);
    color: var(--paper-text-primary, #1a1a2e);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-bottom: 2px;
}

.paper-mini-card-desc {
    font-size: var(--paper-font-size-xs, 0.78rem);
    color: var(--paper-text-tertiary, #94a3b8);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.paper-mini-card-meta {
    font-size: 0.7rem;
    color: var(--paper-text-tertiary, #94a3b8);
    margin-top: 2px;
    opacity: 0.7;
}

/* Responsive: mini cards on mobile */
@media (max-width: 768px) {
    .paper-bento-item-grid {
        grid-template-columns: 1fr 1fr;
    }
}

@media (max-width: 480px) {
    .paper-bento-item-grid {
        grid-template-columns: 1fr;
    }
}



/* Responsive: modal on mobile */
@media (max-width: 768px) {
    .paper-modal {
        width: 100vw !important;
        max-width: 100vw;
        max-height: 92vh;
        border-radius: var(--paper-radius-xl, 20px) var(--paper-radius-xl, 20px) 0 0;
        margin-top: auto;
        box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.15);
    }

    .paper-modal-overlay {
        align-items: flex-end;
    }
}

/* ============================================================================
   Game Selection Cards (Overrides for legacy .game-card inside .paper-modal)
   ============================================================================ */

.paper-modal .game-select-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--paper-space-4, 16px);
    margin-bottom: var(--paper-space-4, 16px);
}

@media (max-width: 480px) {
    .paper-modal .game-select-grid {
        grid-template-columns: 1fr;
    }
}

.paper-modal .game-card {
    background: var(--paper-bg-tertiary, #e8ecf4);
    border: 2px solid var(--paper-border-color, #e2e8f0);
    border-radius: var(--paper-radius-lg, 16px);
    padding: var(--paper-space-5, 20px) var(--paper-space-4, 16px);
    text-align: center;
    cursor: pointer;
    transition: all 0.2s var(--paper-ease-bounce, cubic-bezier(0.34, 1.56, 0.64, 1));
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.paper-modal .game-card:hover {
    border-color: var(--paper-candy-purple, #a855f7);
    transform: translateY(-4px);
    box-shadow: 4px 4px 0px var(--paper-candy-purple, #a855f7);
    background: var(--paper-bg-secondary, #ffffff);
}

.paper-modal .game-card .game-icon {
    font-size: 2.5rem;
    margin-bottom: var(--paper-space-3, 12px);
    filter: drop-shadow(0 4px 8px rgba(0, 0, 0, 0.1));
}

.paper-modal .game-card h4 {
    margin: 0 0 var(--paper-space-2, 8px) 0;
    color: var(--paper-text-primary, #1a1a2e);
    font-size: var(--paper-font-size-lg, 1.125rem);
    font-weight: var(--paper-font-weight-extrabold, 800);
    font-family: var(--paper-font-display, 'Nunito', sans-serif);
}

.paper-modal .game-card p {
    margin: 0;
    color: var(--paper-text-secondary, #4a5568);
    font-size: var(--paper-font-size-sm, 0.875rem);
    line-height: 1.4;
}

/* ============================================================================
   Publishing Spinner
   ============================================================================ */

.publishing-spinner {
    width: 48px;
    height: 48px;
    border: 4px solid rgba(255, 255, 255, 0.25);
    border-top-color: white;
    border-radius: 50%;
    animation: publishing-spin 0.8s linear infinite;
}

@keyframes publishing-spin {
    to { transform: rotate(360deg); }
}

