    --paper-gradient-candy: linear-gradient(135deg, #33302e, #262423);
    --paper-gradient-ocean: linear-gradient(135deg, #211f1e, #1c1b1a);
    --paper-gradient-warm: linear-gradient(135deg, #262423, #1c1b1a);

    /* ========== Text Colors (Inverted for dark mode) ========== */
    --paper-text-primary: #eaddcf;   /* Bone white/Off-white */
    --paper-text-secondary: #b3aba1; /* Light graphite */
    --paper-text-tertiary: #878077;  /* Muted graphite */
